import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import { SecurityService, SecurityConfig } from '../services/securityService';
import { Lock, Clock, Calendar, Shield, Sun, LogOut, Loader2 } from 'lucide-react';

interface AccessGuardProps {
    children: React.ReactNode;
}

interface AccessStatus {
    allowed: boolean;
    reason: 'sunday' | 'outside_hours' | 'invalid_ip' | 'revoked' | null;
    config: SecurityConfig | null;
    nextOpenTime: string | null;
}

const CACHE_KEY = 'gw_security_config_cache';

const getCachedConfig = (): SecurityConfig | null => {
    try {
        const cached = localStorage.getItem(CACHE_KEY);
        return cached ? JSON.parse(cached) : null;
    } catch { return null; }
};

const cacheConfig = (config: SecurityConfig) => {
    try { localStorage.setItem(CACHE_KEY, JSON.stringify(config)); } catch { /* silently fail */ }
};

const parseTime = (timeStr?: string): number => {
    if (!timeStr || typeof timeStr !== 'string') return 0;
    const [h, m] = timeStr.split(':').map(Number);
    return (h || 0) + ((m || 0) / 60);
};

const formatTimeDisplay = (timeStr?: string): string => {
    if (!timeStr || typeof timeStr !== 'string') return 'N/A';
    const [h, m] = timeStr.split(':').map(Number);
    const suffix = h >= 12 ? 'PM' : 'AM';
    const displayHour = h % 12 || 12;
    return `${displayHour}:${(m || 0).toString().padStart(2, '0')} ${suffix}`;
};

export const checkAccess = (
    config: SecurityConfig,
    userRole: string | undefined,
    clientIp: string = '127.0.0.1',
    sessionRevoked: boolean = false,
    now?: Date
): AccessStatus => {
    // 1. Hard revoke check (applies to EVERYONE, even Admins, though Admins shouldn't be revoked typically)
    if (sessionRevoked) {
        return { allowed: false, reason: 'revoked', config, nextOpenTime: null };
    }

    // Admins always bypass IP and Time restrictions
    if (userRole === 'Admin') {
        return { allowed: true, reason: null, config, nextOpenTime: null };
    }

    const safeConfig = config || { officeIp: '192.168.1.1', workStartTime: '08:00', workEndTime: '18:00', blockSundays: true };

    // 2. IP check (Only restrict if IP is not localhost and not matching the office IP)
    // Localhost fallback ensures we don't lock ourselves out in local dev if config is wrong
    if (safeConfig.officeIp && safeConfig.officeIp.trim() !== '') {
        if (clientIp !== '127.0.0.1' && clientIp !== '::1' && clientIp !== 'localhost' && clientIp !== 'unknown' && clientIp !== safeConfig.officeIp) {
            return { allowed: false, reason: 'invalid_ip', config: safeConfig, nextOpenTime: null };
        }
    }

    const currentDate = now || new Date();
    const dayOfWeek = currentDate.getDay(); // 0 = Sunday
    const currentHour = currentDate.getHours();
    const currentMinute = currentDate.getMinutes();
    const currentTimeVal = currentHour + (currentMinute / 60);

    const startVal = parseTime(safeConfig.workStartTime || '08:00');
    const endVal = parseTime(safeConfig.workEndTime || '18:00');

    // Sunday check
    if (dayOfWeek === 0 && safeConfig.blockSundays) {
        return {
            allowed: false,
            reason: 'sunday',
            config: safeConfig,
            nextOpenTime: `Monday at ${formatTimeDisplay(safeConfig.workStartTime || '08:00')}`
        };
    }

    // Office hours check
    if (currentTimeVal < startVal || currentTimeVal >= endVal) {
        const isAfterClose = currentTimeVal >= endVal;
        if (isAfterClose) {
            // If it's Saturday after close and Sundays are blocked, next open is Monday
            if (dayOfWeek === 6 && safeConfig.blockSundays) {
                return {
                    allowed: false, reason: 'outside_hours', config: safeConfig,
                    nextOpenTime: `Monday at ${formatTimeDisplay(safeConfig.workStartTime || '08:00')}`
                };
            }
            return {
                allowed: false, reason: 'outside_hours', config: safeConfig,
                nextOpenTime: `Tomorrow at ${formatTimeDisplay(safeConfig.workStartTime || '08:00')}`
            };
        }
        return {
            allowed: false, reason: 'outside_hours', config: safeConfig,
            nextOpenTime: `Today at ${formatTimeDisplay(safeConfig.workStartTime || '08:00')}`
        };
    }

    return { allowed: true, reason: null, config: safeConfig, nextOpenTime: null };
};

const AccessGuard: React.FC<AccessGuardProps> = ({ children }) => {
    const { user, logout } = useAuth();
    const [status, setStatus] = useState<AccessStatus>({ allowed: true, reason: null, config: null, nextOpenTime: null });
    const [currentTime, setCurrentTime] = useState(new Date());
    const [configLoaded, setConfigLoaded] = useState(false);

    const evaluateAccess = useCallback(async () => {
        try {
            const data = await SecurityService.getStatus();
            cacheConfig(data.config);

            const accessResult = checkAccess(data.config, user?.role, data.clientIp, data.sessionRevoked);
            setStatus(accessResult);

            // If session is revoked, forcefully log the user out on the client side
            if (accessResult.reason === 'revoked') {
                logout();
            }
        } catch {
            // Fall back to cached config
            const cached = getCachedConfig();
            if (cached) {
                setStatus(checkAccess(cached, user?.role, '127.0.0.1', false));
            }
        }
        setConfigLoaded(true);
    }, [user?.role, logout]);

    // Initial check + periodic re-check every 30 seconds
    useEffect(() => {
        evaluateAccess();
        const interval = setInterval(() => {
            evaluateAccess();
            setCurrentTime(new Date());
        }, 30_000);
        return () => clearInterval(interval);
    }, [evaluateAccess]);

    // Live clock tick every second for the lock screen
    useEffect(() => {
        if (!status.allowed) {
            const tick = setInterval(() => setCurrentTime(new Date()), 1000);
            return () => clearInterval(tick);
        }
    }, [status.allowed]);

    // Block completely with a loader while fetching config on first run
    // Prevents 'flash of unprotected content' and accidental Supabase queries
    if (!configLoaded) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-slate-900">
                <Loader2 className="w-10 h-10 text-blue-500 animate-spin" />
            </div>
        );
    }

    // If access is allowed, render normally
    if (status.allowed) return <>{children}</>;

    // ─── Lock Screen ───
    const timeString = currentTime.toLocaleTimeString('en-US', {
        hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true
    });
    const dateString = currentTime.toLocaleDateString('en-US', {
        weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
    });

    const isSunday = status.reason === 'sunday';
    const isInvalidIp = status.reason === 'invalid_ip';
    const isRevoked = status.reason === 'revoked';

    return (
        <div className="access-guard-overlay">
            {/* Animated Background */}
            <div className="access-guard-bg">
                <div className="access-guard-orb access-guard-orb-1" />
                <div className="access-guard-orb access-guard-orb-2" />
                <div className="access-guard-orb access-guard-orb-3" />
                <div className="access-guard-grid" />
            </div>

            {/* Lock Card */}
            <div className="access-guard-card">
                {/* Glowing Lock Icon */}
                <div className="access-guard-icon-ring" style={{ borderColor: isInvalidIp || isRevoked ? '#ef4444' : undefined }}>
                    <div className="access-guard-icon-inner" style={{ backgroundColor: isInvalidIp || isRevoked ? '#fee2e2' : undefined, color: isInvalidIp || isRevoked ? '#dc2626' : undefined }}>
                        {isSunday ? <Sun size={32} /> : (isInvalidIp ? <Shield size={32} /> : <Lock size={32} />)}
                    </div>
                    <div className="access-guard-icon-pulse" style={{ backgroundColor: isInvalidIp || isRevoked ? 'rgba(239, 68, 68, 0.4)' : undefined }} />
                </div>

                {/* Live Clock */}
                <div className="access-guard-clock">{timeString}</div>
                <div className="access-guard-date">{dateString}</div>

                {/* Message */}
                <div className="access-guard-divider" />

                <h2 className="access-guard-title">
                    {isSunday ? 'Sunday Rest Day'
                        : isInvalidIp ? 'Unauthorized Network'
                            : isRevoked ? 'Session Terminated'
                                : 'Outside Office Hours'}
                </h2>

                <p className="access-guard-subtitle">
                    {isSunday
                        ? 'The system is closed on Sundays to ensure a healthy work-life balance for all staff.'
                        : isInvalidIp
                            ? `For security reasons, access is strictly limited to the authorized office local network (IP target: ${status.config?.officeIp || 'Configured Office IP'}).`
                            : isRevoked
                                ? 'Your active session has been manually revoked by an Administrator.'
                                : `System access is restricted to office hours (${formatTimeDisplay(status.config?.workStartTime || '08:00')} – ${formatTimeDisplay(status.config?.workEndTime || '18:00')}).`}
                </p>

                {/* Info Cards */}
                <div className="access-guard-info-grid">
                    <div className="access-guard-info-card">
                        {isInvalidIp || isRevoked ? (
                            <Shield size={16} className="access-guard-info-icon" style={{ color: '#ef4444' }} />
                        ) : (
                            <Clock size={16} className="access-guard-info-icon" />
                        )}
                        <div>
                            <span className="access-guard-info-label">{isInvalidIp || isRevoked ? 'Status' : 'Opens Next'}</span>
                            <span className="access-guard-info-value" style={{ color: isInvalidIp || isRevoked ? '#ef4444' : undefined }}>
                                {isInvalidIp ? 'Access Blocked' : isRevoked ? 'Token Revoked' : status.nextOpenTime}
                            </span>
                        </div>
                    </div>
                    <div className="access-guard-info-card">
                        {isSunday
                            ? <Calendar size={16} className="access-guard-info-icon" />
                            : <Shield size={16} className="access-guard-info-icon" />
                        }
                        <div>
                            <span className="access-guard-info-label">{isSunday ? 'Policy' : 'Role'}</span>
                            <span className="access-guard-info-value">{isSunday ? 'Weekly Rest' : user?.role || 'Staff'}</span>
                        </div>
                    </div>
                </div>

                {/* User Info */}
                <div className="access-guard-user">
                    <div className="access-guard-avatar">
                        {(user?.name || 'U').charAt(0).toUpperCase()}
                    </div>
                    <div className="access-guard-user-info">
                        <span className="access-guard-user-name">{user?.name || 'User'}</span>
                        <span className="access-guard-user-email">{user?.email || ''}</span>
                    </div>
                </div>

                {/* Actions */}
                <button className="access-guard-logout" onClick={() => logout()}>
                    <LogOut size={16} />
                    Sign Out
                </button>

                <p className="access-guard-footer">
                    Contact your administrator if you need emergency access.
                </p>
            </div>
        </div>
    );
};

export default AccessGuard;

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { supabase } from '../../services/supabase';
import { Activity, Filter, Search, Check, ChevronDown, AlertCircle, RefreshCw } from 'lucide-react';

interface AuditLog {
    id: string;
    action: string;
    details: any;
    ip_address: string;
    created_at: string;
    user_id: string;
    user_email?: string; // Joined
    user_role?: string; // Joined
}

const MODULES = [
    'All Modules',
    'Jobs & Orders',
    'Candidates',
    'Partners',
    'Finance',
    'Documents',
    'Access Control',
    'System Setup',
    'General Engine'
];

const PAGE_SIZE = 50;

const AuditLogViewer: React.FC = () => {
    const [logs, setLogs] = useState<AuditLog[]>([]);
    const [loading, setLoading] = useState(true);
    const [loadingMore, setLoadingMore] = useState(false);
    const [hasMore, setHasMore] = useState(true);
    const [page, setPage] = useState(0);
    const [error, setError] = useState<string | null>(null);
    const [hideLogins, setHideLogins] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [filterModule, setFilterModule] = useState('All Modules');
    const [showFilterDropdown, setShowFilterDropdown] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setShowFilterDropdown(false);
            }
        };

        if (showFilterDropdown) {
            document.addEventListener('mousedown', handleClickOutside);
        }

        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, [showFilterDropdown]);

    const fetchLogs = async (isLoadMore = false) => {
        if (!isLoadMore) {
            setLoading(true);
            setPage(0);
        } else {
            setLoadingMore(true);
        }
        setError(null);

        const currentPage = isLoadMore ? page + 1 : 0;

        try {
            const { data, error: fetchError } = await supabase
                .from('audit_logs')
                .select(`
                    *,
                    profiles:user_id (email, role)
                `)
                .order('created_at', { ascending: false })
                .range(currentPage * PAGE_SIZE, (currentPage + 1) * PAGE_SIZE - 1);

            if (fetchError) {
                console.error('Error fetching logs:', fetchError);
                setError(fetchError.message);
            } else if (data) {
                const formattedData = data.map(log => ({
                    ...log,
                    user_email: Array.isArray(log?.profiles) ? log.profiles[0]?.email : log?.profiles?.email,
                    user_role: Array.isArray(log?.profiles) ? log.profiles[0]?.role : log?.profiles?.role
                }));

                if (isLoadMore) {
                    setLogs(prev => {
                        const existingIds = new Set(prev.map(l => l.id));
                        const uniqueNew = formattedData.filter(l => !existingIds.has(l.id));
                        return [...prev, ...uniqueNew];
                    });
                } else {
                    setLogs(formattedData);
                }

                setHasMore(data.length === PAGE_SIZE);
                setPage(currentPage);
            }
        } catch (err: any) {
            console.error('Exception fetching logs:', err);
            setError(err.message || 'An unexpected error occurred while fetching logs');
        } finally {
            setLoading(false);
            setLoadingMore(false);
        }
    };

    useEffect(() => {
        fetchLogs();
    }, []);

    const getModuleName = (action: string) => {
        if (!action || typeof action !== 'string') return 'General Engine';
        const a = action.toUpperCase();
        if (a.includes('CANDIDATE') || a.includes('SELECTION')) return 'Candidates';
        if (a.includes('DEMAND_ORDER') || a.includes('JOB')) return 'Jobs & Orders';
        if (a.includes('FINANCE') || a.includes('INVOICE')) return 'Finance';
        if (a.includes('EMPLOYER')) return 'Partners';
        if (a.includes('DOCUMENT')) return 'Documents';
        if (a.includes('USER') || a.includes('LOGIN') || a.includes('LOGOUT')) return 'Access Control';
        if (a.includes('SYSTEM') || a.includes('DIAGNOSTICS') || a.includes('WORKFLOW')) return 'System Setup';
        return 'General Engine';
    };

    const extractTargetId = (details: any) => {
        if (!details || typeof details !== 'object') return '-';
        const possibleIds = [
            details.candidateId, details.orderId, details.employerId,
            details.userId, details.targetUserId, details.documentId,
            details.jobId, details.selectionId, details.invoiceId
        ];
        const found = possibleIds.find(id => id !== undefined && id !== null);

        if (!found) return '-';
        const foundStr = String(found);
        return foundStr.length > 20 ? `${foundStr.substring(0, 8)}...` : foundStr;
    };

    const getSeverity = (action: string) => {
        if (!action || typeof action !== 'string') return { level: 'Low', color: 'text-green-700 bg-green-50 border-green-200' };
        const a = action.toUpperCase();
        if (a.includes('DELETE') || a.includes('REMOVE') || a.includes('REJECT') || a.includes('FAIL') || a.includes('SECURITY') || a.includes('EXPORT') || a.includes('ERROR') || a.includes('FATAL')) {
            return { level: 'High', color: 'text-red-700 bg-red-50 border-red-200' };
        }
        if (a.includes('UPDATE') || a.includes('EDIT') || a.includes('MODIFY') || a.includes('ADVANCED') || a.includes('WORKFLOW') || a.includes('STATUS') || a.includes('INVOICE') || a.includes('PAYMENT') || a.includes('SETTINGS')) {
            return { level: 'Medium', color: 'text-yellow-700 bg-yellow-50 border-yellow-200' };
        }
        return { level: 'Low', color: 'text-green-700 bg-green-50 border-green-200' };
    };

    const displayedLogs = useMemo(() => {
        return logs.filter(log => {
            const actionSafe = typeof log.action === 'string' ? log.action : '';

            // 1. Hide routine logins toggle
            if (hideLogins && (actionSafe.includes('LOGIN') || actionSafe.includes('LOGOUT'))) {
                return false;
            }

            // 2. Module Filter
            if (filterModule !== 'All Modules' && getModuleName(actionSafe) !== filterModule) {
                return false;
            }

            // 3. Deep search algorithm
            if (searchQuery.trim() !== '') {
                const query = searchQuery.toLowerCase().trim();

                const moduleName = getModuleName(actionSafe).toLowerCase();
                const actionStr = actionSafe.toLowerCase().replace(/_/g, ' ');
                const emailStr = (log.user_email || 'System Service').toLowerCase();
                const roleStr = (log.user_role || '').toLowerCase();
                const idStr = (log.user_id || '').toLowerCase();
                const targetIdStr = String(extractTargetId(log.details) || '').toLowerCase();
                const ipStr = (log.ip_address || '').toLowerCase();

                let detailsStr = '';
                try {
                    detailsStr = typeof log.details === 'object' && log.details !== null ? JSON.stringify(log.details).toLowerCase() : '';
                } catch (e) {
                    detailsStr = '';
                }

                const matches =
                    moduleName.includes(query) ||
                    actionStr.includes(query) ||
                    emailStr.includes(query) ||
                    roleStr.includes(query) ||
                    idStr.includes(query) ||
                    targetIdStr.includes(query) ||
                    ipStr.includes(query) ||
                    detailsStr.includes(query);

                if (!matches) {
                    return false;
                }
            }

            return true;
        });
    }, [logs, hideLogins, searchQuery, filterModule]);

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col h-full">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between flex-wrap gap-4">
                <div>
                    <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                        Audit Logs
                        {loading && !loadingMore && <RefreshCw size={14} className="animate-spin text-blue-500" />}
                    </h2>
                    <p className="text-slate-500 text-sm">System activity and security events</p>
                </div>
                <div className="flex items-center gap-3">
                    <button
                        onClick={() => fetchLogs()}
                        disabled={loading}
                        className="p-1.5 text-slate-400 hover:text-blue-600 transition-colors disabled:opacity-50"
                        title="Refresh Logs"
                    >
                        <RefreshCw size={16} />
                    </button>
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                        <input
                            type="text"
                            placeholder="Search user, action, ID..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="pl-9 pr-4 py-2 text-sm border border-slate-200 rounded-lg outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 w-64 bg-slate-50 focus:bg-white transition-all"
                        />
                    </div>
                    <button
                        onClick={() => setHideLogins(!hideLogins)}
                        className={`text-xs px-3 py-1.5 rounded-lg border font-medium transition-colors ${hideLogins ? 'bg-blue-50 border-blue-200 text-blue-700' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}`}
                    >
                        Hide Routine Logins
                    </button>
                    <div className="relative" ref={dropdownRef}>
                        <button
                            onClick={() => setShowFilterDropdown(!showFilterDropdown)}
                            className={`px-3 py-1.5 rounded-lg border transition-all flex items-center gap-2 outline-none ${filterModule !== 'All Modules' || showFilterDropdown ? 'bg-blue-50 border-blue-200 text-blue-700 shadow-sm' : 'bg-white border-slate-200 text-slate-600 hover:text-slate-800 hover:bg-slate-50'}`}
                        >
                            <Filter size={16} className={filterModule !== 'All Modules' ? 'text-blue-500' : 'text-slate-400'} />
                            <span className={`text-xs font-semibold ${filterModule !== 'All Modules' ? 'text-blue-700' : 'text-slate-600'}`}>
                                {filterModule !== 'All Modules' ? filterModule : 'Filter'}
                            </span>
                            <ChevronDown size={14} className={`transition-transform duration-200 ${showFilterDropdown ? 'rotate-180' : ''} ${filterModule !== 'All Modules' ? 'text-blue-400' : 'text-slate-400'}`} />
                        </button>

                        {showFilterDropdown && (
                            <div className="absolute right-0 mt-2 w-56 bg-white border border-slate-200 rounded-xl shadow-lg z-50 overflow-hidden transform opacity-100 scale-100 transition-all origin-top-right">
                                <div className="px-4 py-3 bg-slate-50/50 border-b border-slate-100">
                                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                                        Filter by Module
                                    </span>
                                </div>
                                <div className="p-1 max-h-64 overflow-y-auto [&::-webkit-scrollbar]:w-1.5 [&::-webkit-scrollbar-thumb]:bg-slate-200 hover:[&::-webkit-scrollbar-thumb]:bg-slate-300 [&::-webkit-scrollbar-thumb]:rounded-full">
                                    {MODULES.map(mod => (
                                        <button
                                            key={mod}
                                            onClick={() => {
                                                setFilterModule(mod);
                                                setShowFilterDropdown(false);
                                            }}
                                            className={`w-full text-left px-3 py-2 text-sm rounded-lg transition-colors flex items-center justify-between group ${filterModule === mod ? 'bg-blue-50/80 text-blue-700 font-medium' : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'}`}
                                        >
                                            <span>{mod}</span>
                                            {filterModule === mod && (
                                                <Check size={14} className="text-blue-600" />
                                            )}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {error && (
                <div className="mx-6 mt-4 p-3 bg-red-50 border border-red-200 rounded-lg flex items-center gap-3 text-red-700 text-sm">
                    <AlertCircle size={18} />
                    <span>{error}</span>
                </div>
            )}

            <div className="overflow-x-auto rounded-b-xl flex-1">
                <table className="w-full text-left text-sm">
                    <thead className="bg-slate-50 text-slate-600 font-medium text-xs border-b border-slate-200">
                        <tr>
                            <th className="px-6 py-4 whitespace-nowrap">Timestamp</th>
                            <th className="px-6 py-4">User</th>
                            <th className="px-6 py-4">Module</th>
                            <th className="px-6 py-4">Action</th>
                            <th className="px-6 py-4">Severity</th>
                            <th className="px-6 py-4">Details</th>
                            <th className="px-6 py-4">Status</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                        {loading && logs.length === 0 ? (
                            Array.from({ length: 5 }).map((_, i) => (
                                <tr key={`skeleton-${i}`} className="animate-pulse">
                                    <td className="px-6 py-4"><div className="h-4 bg-slate-100 rounded w-24"></div></td>
                                    <td className="px-6 py-4"><div className="h-4 bg-slate-100 rounded w-32"></div></td>
                                    <td className="px-6 py-4"><div className="h-4 bg-slate-100 rounded w-20"></div></td>
                                    <td className="px-6 py-4"><div className="h-4 bg-slate-100 rounded w-24"></div></td>
                                    <td className="px-6 py-4"><div className="h-4 bg-slate-100 rounded w-16"></div></td>
                                    <td className="px-6 py-4"><div className="h-4 bg-slate-100 rounded w-48"></div></td>
                                    <td className="px-6 py-4"><div className="h-4 bg-slate-100 rounded w-16"></div></td>
                                </tr>
                            ))
                        ) : displayedLogs.length === 0 && !loading ? (
                            <tr>
                                <td colSpan={7} className="px-6 py-12 text-center text-slate-500">
                                    No activity logs found for your current filters.
                                </td>
                            </tr>
                        ) : (
                            displayedLogs.map(log => {
                                const actionSafe = typeof log.action === 'string' ? log.action : 'UNKNOWN';
                                return (
                                    <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                                        <td className="px-6 py-4 text-slate-500 text-xs whitespace-nowrap">
                                            {log.created_at ? new Date(log.created_at).toLocaleString() : '-'}
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="font-medium text-slate-900 leading-tight flex items-center gap-2">
                                                {log.user_email || 'System'}
                                                {log.user_role && <span className="text-[9px] uppercase tracking-wider font-bold bg-slate-100 text-slate-500 px-1 inline-block rounded">{log.user_role}</span>}
                                            </div>
                                            {log.user_id && (
                                                <div className="text-[10px] text-slate-400 font-mono mt-0.5" title={log.user_id}>
                                                    {log.user_id.substring(0, 8)}...
                                                </div>
                                            )}
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className="text-slate-600 font-medium text-xs whitespace-nowrap">
                                                {getModuleName(actionSafe)}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className="inline-flex items-center px-1.5 py-0.5 rounded border border-slate-200 bg-white text-slate-700 text-[10px] font-bold tracking-tight uppercase shadow-sm whitespace-nowrap">
                                                {actionSafe.replace(/_/g, ' ')}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className={`inline-flex items-center px-2 py-0.5 rounded border text-[10px] font-bold uppercase tracking-wider ${getSeverity(actionSafe).color}`}>
                                                {getSeverity(actionSafe).level}
                                            </span>
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="flex flex-wrap gap-x-2 gap-y-1">
                                                {log.details && typeof log.details === 'object' && !Array.isArray(log.details) && Object.keys(log.details).length > 0 ? (
                                                    Object.entries(log.details).map(([k, v]) => {
                                                        const skipKeys = ['candidateId', 'orderId', 'employerId', 'userId', 'targetUserId', 'jobId', 'selectionId', 'invoiceId'];
                                                        if (skipKeys.includes(k)) return null;

                                                        return (
                                                            <div key={k} className="text-[11px] bg-slate-50 border border-slate-100 px-1.5 py-0.5 rounded leading-tight flex items-start max-w-full">
                                                                <span className="text-slate-400 capitalize mr-1 whitespace-nowrap">{k.replace(/([A-Z])/g, ' $1').trim()}:</span>
                                                                <span className="font-mono text-slate-700 font-medium truncate" title={typeof v === 'object' ? '{...}' : String(v)}>
                                                                    {typeof v === 'object' ? '{...}' : String(v)}
                                                                </span>
                                                            </div>
                                                        )
                                                    })
                                                ) : (
                                                    <span className="text-[11px] text-slate-400 italic">No additional context</span>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-1.5 text-green-600">
                                                <div className="w-1.5 h-1.5 rounded-full bg-green-500"></div>
                                                <span className="text-[10px] uppercase font-bold tracking-wider">Success</span>
                                            </div>
                                            <div className="text-[9px] text-slate-400 font-mono mt-0.5 whitespace-nowrap">{log.ip_address}</div>
                                        </td>
                                    </tr>
                                )
                            })
                        )}
                    </tbody>
                </table>
            </div>

            {!loading && displayedLogs.length > 0 && (
                <div className="p-4 border-t border-slate-100 flex justify-center bg-slate-50 mt-auto rounded-b-xl">
                    {hasMore ? (
                        <button
                            onClick={() => fetchLogs(true)}
                            disabled={loadingMore}
                            className="px-5 py-2 bg-white border border-slate-200 text-slate-700 font-medium text-sm rounded-lg hover:bg-blue-50 hover:text-blue-700 hover:border-blue-200 transition-colors shadow-sm disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                        >
                            {loadingMore && <RefreshCw size={14} className="animate-spin" />}
                            {loadingMore ? 'Crunching logs...' : 'Load Older Logs'}
                        </button>
                    ) : (
                        <span className="text-slate-400 text-sm italic">You've reached the end of the audit trail</span>
                    )}
                </div>
            )}
        </div>
    );
};

export default AuditLogViewer;

import React, { useState, useEffect } from 'react';
import { User, UserRole } from '../../types';
import { X, Save, User as UserIcon, Mail } from 'lucide-react';
import { supabase } from '../../services/supabase';
import { UserService } from '../../services/userService';

interface UserDialogProps {
    isOpen: boolean;
    onClose: () => void;
    user?: User | null;
    onSave: () => void;
}

const UserDialog: React.FC<UserDialogProps> = ({ isOpen, onClose, user, onSave }) => {
    const [formData, setFormData] = useState({
        email: '',
        name: '',
        role: 'Viewer' as UserRole,
        status: 'Active' as 'Active' | 'Inactive' | 'Pending',
        password: '' // Only for new users
    });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (user) {
            setFormData({
                email: user.email,
                name: user.name,
                role: user.role,
                status: user.status as 'Active' | 'Inactive' | 'Pending',
                password: ''
            });
        } else {
            setFormData({
                email: '',
                name: '',
                role: 'Viewer',
                status: 'Active',
                password: ''
            });
        }
        setError(null);
    }, [user, isOpen]);

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        try {
            if (user) {
                // Safety check: Don't allow changing role of master admins via UI if needed
                // But generally Admin can manage others. 
                // However, we should prevent accidental downgrade of auth@suhara.com
                if (['auth@suhara.com'].includes(user.email) && formData.role !== 'Admin') {
                    throw new Error("Cannot downgrade role of master admin account.");
                }

                await UserService.updateUser(user.id, {
                    name: formData.name,
                    role: formData.role,
                    status: formData.status
                });
            } else {
                if (!formData.password) {
                    throw new Error("Initial Password is required for new users.");
                }

                if (formData.password.length < 8) {
                    throw new Error("Password must be at least 8 characters long.");
                }

                // Create new user via UserService (handles edge function + audit logs)
                await UserService.createUser({
                    email: formData.email,
                    password: formData.password,
                    name: formData.name,
                    role: formData.role,
                    status: formData.status
                });
            }

            onSave();
            onClose();
        } catch (err: any) {
            setError(err.message || 'Failed to save user');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden">
                <div className="px-6 py-4 border-b flex items-center justify-between bg-slate-50">
                    <h3 className="text-lg font-bold text-slate-800">
                        {user ? 'Edit User' : 'Create New User'}
                    </h3>
                    <button onClick={onClose} className="text-slate-400 hover:text-slate-600">
                        <X size={20} />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="p-6 space-y-4">
                    {error && (
                        <div className="p-3 bg-red-50 text-red-600 text-sm rounded-lg border border-red-200">
                            {error}
                        </div>
                    )}

                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Full Name</label>
                        <div className="relative">
                            <UserIcon size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input
                                type="text"
                                value={formData.name}
                                onChange={e => setFormData({ ...formData, name: e.target.value })}
                                className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                                placeholder="John Doe"
                            />
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Email Address</label>
                        <div className="relative">
                            <Mail size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input
                                type="email"
                                disabled={!!user} // Cannot change email easily without auth re-verification
                                value={formData.email}
                                onChange={e => setFormData({ ...formData, email: e.target.value })}
                                className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none disabled:bg-slate-100 disabled:text-slate-500"
                                placeholder="john@example.com"
                            />
                        </div>
                    </div>

                    {!user && (
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Initial Password</label>
                            <input
                                type="password"
                                value={formData.password}
                                onChange={e => setFormData({ ...formData, password: e.target.value })}
                                className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                                placeholder="••••••••"
                            />
                        </div>
                    )}

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Role</label>
                            <select
                                value={formData.role}
                                onChange={e => setFormData({ ...formData, role: e.target.value as UserRole })}
                                className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                            >
                                <option value="Viewer">Viewer</option>
                                <option value="Recruiter">Recruiter</option>
                                <option value="Manager">Manager</option>
                                <option value="HR">HR</option>
                                <option value="Admin">Admin</option>
                                <option value="Finance">Finance</option>
                                <option value="Compliance">Compliance</option>
                                <option value="Operations">Operations</option>
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Status</label>
                            <select
                                value={formData.status}
                                onChange={e => setFormData({ ...formData, status: e.target.value as 'Active' | 'Inactive' | 'Pending' })}
                                className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                            >
                                <option value="Active">Active</option>
                                <option value="Inactive">Inactive</option>
                                <option value="Pending">Pending</option>
                            </select>
                        </div>
                    </div>

                    <div className="flex justify-end gap-3 mt-6">
                        <button
                            type="button"
                            onClick={onClose}
                            className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            disabled={loading}
                            className="flex items-center gap-2 px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50"
                        >
                            {loading ? 'Saving...' : (
                                <>
                                    <Save size={18} />
                                    Save User
                                </>
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default UserDialog;

import React, { useEffect, useState } from 'react';
import { supabase } from '../../services/supabase';
import { User } from '../../types';
import { Plus, Search, Shield, Calendar, Edit2, Trash2, User as UserIcon } from 'lucide-react';
import UserDialog from './UserDialog';
import { UserService } from '../../services/userService';
import { useAuth } from '../../context/AuthContext';
import { usePermission } from '../../hooks/usePermission';

const UserList: React.FC = () => {
    const { hasPermission } = usePermission();
    const { user: currentUser } = useAuth();
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [selectedUser, setSelectedUser] = useState<User | null>(null);

    const fetchUsers = async () => {
        setLoading(true);
        try {
            const data = await UserService.getUsers();
            setUsers(data);
        } catch (error) {
            console.error('Error fetching users:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchUsers();
    }, []);

    const handleCreate = () => {
        setSelectedUser(null);
        setIsDialogOpen(true);
    };

    const handleEdit = (user: User) => {
        setSelectedUser(user);
        setIsDialogOpen(true);
    };

    const handleDelete = async (user: User) => {
        // Safety check: Don't allow deleting master admins or self
        const protectedEmails = ['auth@suhara.com'];
        if (protectedEmails.includes(user.email)) {
            alert('Cannot delete master admin account.');
            return;
        }

        if (user.id === currentUser?.id) {
            alert('Cannot delete your own account.');
            return;
        }

        if (!window.confirm(`Are you sure you want to delete user "${user.name}"? This action cannot be undone.`)) return;

        setLoading(true);
        try {
            await UserService.deleteUser(user.id);
            await fetchUsers();
        } catch (err: any) {
            console.error('Failed to delete user:', err);
            alert('Failed to delete user: ' + (err.message || 'Unknown error'));
        } finally {
            setLoading(false);
        }
    };

    // Filter users
    const filteredUsers = users.filter(user =>
        user.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        user.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
        user.role.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const stats = {
        total: users.length,
        active: users.filter(u => u.status === 'Active').length,
        admins: users.filter(u => u.role === 'Admin').length,
        newUsers: users.filter(u => {
            if (!u.createdAt) return false;
            const date = new Date(u.createdAt);
            const now = new Date();
            return date.getMonth() === now.getMonth() && date.getFullYear() === now.getFullYear();
        }).length
    };

    return (
        <div className="space-y-6">
            {/* Stats Grid */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
                    <div>
                        <p className="text-slate-500 text-xs font-bold uppercase tracking-wider">Total Users</p>
                        <h3 className="text-2xl font-bold text-slate-800 mt-1">{stats.total}</h3>
                    </div>
                    <div className="p-3 bg-blue-50 text-blue-600 rounded-lg">
                        <UserIcon size={24} />
                    </div>
                </div>
                <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
                    <div>
                        <p className="text-slate-500 text-xs font-bold uppercase tracking-wider">Active Users</p>
                        <h3 className="text-2xl font-bold text-slate-800 mt-1">{stats.active}</h3>
                    </div>
                    <div className="p-3 bg-green-50 text-green-600 rounded-lg">
                        <Shield size={24} />
                    </div>
                </div>
                <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
                    <div>
                        <p className="text-slate-500 text-xs font-bold uppercase tracking-wider">Admins</p>
                        <h3 className="text-2xl font-bold text-slate-800 mt-1">{stats.admins}</h3>
                    </div>
                    <div className="p-3 bg-purple-50 text-purple-600 rounded-lg">
                        <Shield size={24} />
                    </div>
                </div>
                <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
                    <div>
                        <p className="text-slate-500 text-xs font-bold uppercase tracking-wider">New (Month)</p>
                        <h3 className="text-2xl font-bold text-slate-800 mt-1">{stats.newUsers}</h3>
                    </div>
                    <div className="p-3 bg-indigo-50 text-indigo-600 rounded-lg">
                        <Calendar size={24} />
                    </div>
                </div>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                {/* Header */}
                <div className="p-6 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                    <div>
                        <h2 className="text-xl font-bold text-slate-800">User Management</h2>
                        <p className="text-slate-500 text-sm">Manage system access and permissions</p>
                    </div>
                    <div className="flex items-center gap-3">
                        <div className="relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                            <input
                                type="text"
                                placeholder="Search users..."
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="pl-10 pr-4 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none w-64"
                            />
                        </div>
                        {hasPermission('users.manage') && (
                            <button
                                onClick={handleCreate}
                                className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium"
                            >
                                <Plus size={18} />
                                Add User
                            </button>
                        )}
                    </div>
                </div>

                {/* List */}
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm">
                        <thead className="bg-slate-50 text-slate-600 font-medium border-b border-slate-200">
                            <tr>
                                <th className="px-6 py-4">User</th>
                                <th className="px-6 py-4">Role</th>
                                <th className="px-6 py-4">Status</th>
                                <th className="px-6 py-4">Last Login</th>
                                <th className="px-6 py-4 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {loading ? (
                                Array.from({ length: 5 }).map((_, i) => (
                                    <tr key={i} className="animate-pulse">
                                        <td className="px-6 py-4"><div className="h-10 bg-slate-100 rounded-full w-48"></div></td>
                                        <td className="px-6 py-4"><div className="h-6 bg-slate-100 rounded w-20"></div></td>
                                        <td className="px-6 py-4"><div className="h-6 bg-slate-100 rounded w-16"></div></td>
                                        <td className="px-6 py-4"><div className="h-6 bg-slate-100 rounded w-24"></div></td>
                                        <td className="px-6 py-4"></td>
                                    </tr>
                                ))
                            ) : filteredUsers.length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="px-6 py-12 text-center text-slate-500">
                                        No users found matching your search.
                                    </td>
                                </tr>
                            ) : (
                                filteredUsers.map(user => (
                                    <tr key={user.id} className="hover:bg-slate-50 transition-colors group">
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-3">
                                                <img
                                                    src={user.avatar}
                                                    alt={user.name}
                                                    className="w-10 h-10 rounded-full object-cover border border-slate-200"
                                                />
                                                <div>
                                                    <div className="font-medium text-slate-900">{user.name}</div>
                                                    <div className="text-slate-500 text-xs">{user.email}</div>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium border
                                            ${user.role === 'Admin' ? 'bg-purple-50 text-purple-700 border-purple-200' :
                                                    user.role === 'Manager' ? 'bg-blue-50 text-blue-700 border-blue-200' :
                                                        user.role === 'HR' ? 'bg-teal-50 text-teal-700 border-teal-200' :
                                                            user.role === 'Recruiter' ? 'bg-indigo-50 text-indigo-700 border-indigo-200' :
                                                                user.role === 'Finance' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' :
                                                                    'bg-slate-100 text-slate-700 border-slate-200'
                                                }`}
                                            >
                                                <Shield size={12} />
                                                {user.role}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium border
                                            ${user.status === 'Active' ? 'bg-green-50 text-green-700 border-green-200' : 'bg-red-50 text-red-700 border-red-200'}`}
                                            >
                                                <span className={`w-1.5 h-1.5 rounded-full ${user.status === 'Active' ? 'bg-green-500' : 'bg-red-500'}`}></span>
                                                {user.status}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-2 text-slate-500">
                                                <Calendar size={14} />
                                                {user.lastLogin ? new Date(user.lastLogin).toLocaleDateString() : 'Never'}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            {hasPermission('users.manage') && (
                                                <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <button
                                                        onClick={() => handleEdit(user)}
                                                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                                                        title="Edit User"
                                                    >
                                                        <Edit2 size={16} />
                                                    </button>
                                                    <button
                                                        onClick={() => handleDelete(user)}
                                                        className={`p-2 rounded-lg transition-colors ${['auth@suhara.com'].includes(user.email) || user.id === currentUser?.id
                                                            ? 'text-slate-200 cursor-not-allowed'
                                                            : 'text-slate-400 hover:text-red-600 hover:bg-red-50'}`}
                                                        title={['auth@suhara.com'].includes(user.email) ? "Master Admin Protected" : "Delete User"}
                                                        disabled={['auth@suhara.com'].includes(user.email) || user.id === currentUser?.id}
                                                    >
                                                        <Trash2 size={16} />
                                                    </button>
                                                </div>
                                            )}
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>

                <UserDialog
                    isOpen={isDialogOpen}
                    onClose={() => setIsDialogOpen(false)}
                    user={selectedUser}
                    onSave={fetchUsers}
                />
            </div>
        </div>
    );
};

export default UserList;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import {
    Database,
    Download,
    RotateCcw,
    Trash2,
    Clock,
    Shield,
    CheckCircle2,
    AlertCircle,
    HardDrive,
    ArrowDownToLine,
    ArrowUpFromLine,
    RefreshCw,
    Package,
    Eye,
    X,
    ChevronDown,
    ChevronUp,
    History,
    Zap,
    ShieldCheck,
    AlertTriangle,
    Users,
    Briefcase,
    Target,
    DollarSign,
    ScrollText,
    Settings,
    UserCircle,
    Timer,
    Info,
    FileCheck,
    FileWarning,
    Plus,
    Minus
} from 'lucide-react';
import {
    BackupService,
    BackupHistoryEntry,
    BackupModule,
    BackupDiff,
    RestoreResult,
    BackupStats
} from '../services/backupService';
import { useAuth } from '../context/AuthContext';

// ─── Module Config ──────────────────────────────────────────
const MODULE_CONFIG: Record<BackupModule, { label: string; icon: React.ComponentType<any>; color: string }> = {
    candidates: { label: 'Candidates', icon: Users, color: 'text-blue-500' },
    jobs: { label: 'Jobs', icon: Briefcase, color: 'text-emerald-500' },
    employers: { label: 'Employers', icon: Target, color: 'text-violet-500' },
    finance_transactions: { label: 'Transactions', icon: DollarSign, color: 'text-amber-500' },
    finance_invoices: { label: 'Invoices', icon: ScrollText, color: 'text-orange-500' },
    audit_logs: { label: 'Audit Logs', icon: Shield, color: 'text-red-500' },
    settings: { label: 'Settings', icon: Settings, color: 'text-slate-500' },
    profiles: { label: 'User Profiles', icon: UserCircle, color: 'text-cyan-500' },
};

const ALL_MODULES: BackupModule[] = Object.keys(MODULE_CONFIG) as BackupModule[];

// ─── Component ──────────────────────────────────────────────
const BackupManager: React.FC = () => {
    const { user } = useAuth();
    const fileInputRef = useRef<HTMLInputElement>(null);

    // State
    const [history, setHistory] = useState<BackupHistoryEntry[]>([]);
    const [isCreating, setIsCreating] = useState(false);
    const [isRestoring, setIsRestoring] = useState(false);
    const [isRefreshing, setIsRefreshing] = useState(false);
    const [selectedModules, setSelectedModules] = useState<BackupModule[]>([...ALL_MODULES]);
    const [backupLabel, setBackupLabel] = useState('');
    const [backupDescription, setBackupDescription] = useState('');
    const [showCreateForm, setShowCreateForm] = useState(false);
    const [showRestoreModal, setShowRestoreModal] = useState<string | null>(null);
    const [showDiffModal, setShowDiffModal] = useState<string | null>(null);
    const [restoreModules, setRestoreModules] = useState<BackupModule[]>([]);
    const [restoreResult, setRestoreResult] = useState<RestoreResult | null>(null);
    const [diffs, setDiffs] = useState<BackupDiff[]>([]);
    const [loadingDiff, setLoadingDiff] = useState(false);
    const [notification, setNotification] = useState<{ type: 'success' | 'error' | 'info'; message: string } | null>(null);
    const [expandedEntry, setExpandedEntry] = useState<string | null>(null);
    const [autoBackupInterval, setAutoBackupInterval] = useState(0);
    const [storageInfo, setStorageInfo] = useState({ used: 0, count: 0 });
    const [deleteConfirm, setDeleteConfirm] = useState<string | null>(null);
    const [importError, setImportError] = useState<string | null>(null);

    // ── Load Data ──
    const loadData = useCallback(() => {
        setHistory(BackupService.getBackupHistory());
        setAutoBackupInterval(BackupService.getAutoBackupInterval());
        setStorageInfo(BackupService.getStorageUsed());
    }, []);

    const handleRefresh = async () => {
        setIsRefreshing(true);
        // Artificial delay so the spin animation is visible to the user
        await new Promise(r => setTimeout(r, 600));
        loadData();
        setIsRefreshing(false);
        showNotification('success', 'Backup history synchronized');
    };

    useEffect(() => {
        loadData();
        // Check for auto-backup on mount
        BackupService.checkAndRunAutoBackup().then(ran => {
            if (ran) {
                loadData();
                showNotification('info', 'Auto-backup completed successfully');
            }
        });
    }, [loadData]);

    // ── Notifications ──
    const showNotification = (type: 'success' | 'error' | 'info', message: string) => {
        setNotification({ type, message });
        setTimeout(() => setNotification(null), 5000);
    };

    // ── Create Backup ──
    const handleCreateBackup = async () => {
        setIsCreating(true);
        try {
            const backup = await BackupService.createBackup({
                label: backupLabel || undefined,
                description: backupDescription,
                modules: selectedModules,
                createdBy: user?.name || user?.email || 'Admin',
                tags: [],
            });
            loadData();
            setShowCreateForm(false);
            setBackupLabel('');
            setBackupDescription('');
            setSelectedModules([...ALL_MODULES]);
            showNotification('success', `Backup "${backup.manifest.label}" created successfully — ${BackupService.formatBytes(backup.manifest.sizeBytes)}`);
        } catch (e: any) {
            showNotification('error', `Backup failed: ${e.message || 'Unknown error'}`);
        } finally {
            setIsCreating(false);
        }
    };

    // ── Download Backup ──
    const handleDownload = async (backupId: string) => {
        const success = await BackupService.downloadBackup(backupId);
        if (success) {
            showNotification('success', 'Backup file downloaded');
        } else {
            showNotification('error', 'Failed to download backup — data may have been removed');
        }
    };

    // ── Import Backup ──
    const handleImport = async (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (!file) return;

        setImportError(null);
        const result = await BackupService.importBackupFromFile(file);
        if (result.success) {
            loadData();
            showNotification('success', `Backup "${result.backup?.manifest.label}" imported successfully`);
        } else {
            setImportError(result.error || 'Import failed');
            showNotification('error', result.error || 'Failed to import backup');
        }

        // Reset file input
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    // ── Restore Backup ──
    const handleRestore = async () => {
        if (!showRestoreModal) return;
        setIsRestoring(true);
        setRestoreResult(null);

        try {
            const result = await BackupService.restoreBackup(showRestoreModal, {
                modules: restoreModules.length > 0 ? restoreModules : undefined,
                createPreRestoreBackup: true,
                createdBy: user?.name || user?.email || 'Admin',
            });
            setRestoreResult(result);
            loadData();

            if (result.success) {
                showNotification('success', `Restored ${result.modulesRestored.length} modules successfully`);
            } else {
                showNotification('error', `Restore completed with ${result.errors.length} errors`);
            }
        } catch (e: any) {
            showNotification('error', `Restore failed: ${e.message}`);
        } finally {
            setIsRestoring(false);
        }
    };

    // ── Compare Backup ──
    const handleCompare = async (backupId: string) => {
        setShowDiffModal(backupId);
        setLoadingDiff(true);
        try {
            const result = await BackupService.compareWithCurrent(backupId);
            setDiffs(result);
        } catch {
            setDiffs([]);
        } finally {
            setLoadingDiff(false);
        }
    };

    // ── Delete Backup ──
    const handleDelete = async (backupId: string) => {
        await BackupService.deleteBackup(backupId);
        loadData();
        setDeleteConfirm(null);
        showNotification('info', 'Backup deleted');
    };

    // ── Auto Backup Config ──
    const handleAutoBackupChange = (hours: number) => {
        setAutoBackupInterval(hours);
        BackupService.setAutoBackupInterval(hours);
        if (hours > 0) {
            showNotification('info', `Auto-backup set to every ${hours} hour${hours > 1 ? 's' : ''}`);
        } else {
            showNotification('info', 'Auto-backup disabled');
        }
    };

    // ── Toggle Module Selection ──
    const toggleModule = (module: BackupModule, list: BackupModule[], setter: (m: BackupModule[]) => void) => {
        setter(list.includes(module) ? list.filter(m => m !== module) : [...list, module]);
    };

    // ── Module Badge ──
    const ModuleBadge: React.FC<{ module: BackupModule; small?: boolean }> = ({ module, small }) => {
        const config = MODULE_CONFIG[module];
        if (!config) return null;
        const Icon = config.icon;
        return (
            <span className={`inline-flex items-center gap-1 ${small ? 'px-1.5 py-0.5 text-[10px]' : 'px-2 py-1 text-xs'} bg-slate-100 text-slate-700 rounded-full font-medium`}>
                <Icon size={small ? 10 : 12} className={config.color} />
                {config.label}
            </span>
        );
    };

    // ── Stats Summary ──
    const StatsSummary: React.FC<{ stats: BackupStats }> = ({ stats }) => (
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mt-3">
            {[
                { label: 'Candidates', value: stats.candidates, color: 'text-blue-600 bg-blue-50' },
                { label: 'Jobs', value: stats.jobs, color: 'text-emerald-600 bg-emerald-50' },
                { label: 'Employers', value: stats.employers, color: 'text-violet-600 bg-violet-50' },
                { label: 'Transactions', value: stats.transactions, color: 'text-amber-600 bg-amber-50' },
            ].map(s => (
                <div key={s.label} className={`${s.color} rounded-lg px-3 py-2 text-center`}>
                    <p className="text-lg font-bold">{s.value}</p>
                    <p className="text-[10px] font-medium opacity-70">{s.label}</p>
                </div>
            ))}
        </div>
    );

    // ── Format time ago ──
    const timeAgo = (dateStr: string) => {
        const diff = Date.now() - new Date(dateStr).getTime();
        const mins = Math.floor(diff / 60000);
        if (mins < 1) return 'Just now';
        if (mins < 60) return `${mins}m ago`;
        const hours = Math.floor(mins / 60);
        if (hours < 24) return `${hours}h ago`;
        const days = Math.floor(hours / 24);
        if (days < 30) return `${days}d ago`;
        return new Date(dateStr).toLocaleDateString();
    };

    return (
        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">

            {/* ═══ Notification Toast ═══ */}
            {notification && (
                <div className={`fixed top-4 right-4 z-[9999] flex items-center gap-3 px-5 py-3 rounded-xl shadow-2xl border transition-all animate-in slide-in-from-right-8 duration-300 ${notification.type === 'success' ? 'bg-emerald-50 border-emerald-200 text-emerald-800' :
                    notification.type === 'error' ? 'bg-red-50 border-red-200 text-red-800' :
                        'bg-blue-50 border-blue-200 text-blue-800'
                    }`}>
                    {notification.type === 'success' ? <CheckCircle2 size={18} /> :
                        notification.type === 'error' ? <AlertCircle size={18} /> :
                            <Info size={18} />}
                    <span className="text-sm font-medium">{notification.message}</span>
                    <button onClick={() => setNotification(null)} className="ml-2 opacity-60 hover:opacity-100">
                        <X size={14} />
                    </button>
                </div>
            )}

            {/* ═══ Header Section ═══ */}
            <div className="bg-white border border-slate-200 rounded-xl p-6 relative overflow-hidden shadow-sm">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                    <div>
                        <h3 className="text-lg font-bold text-slate-800 mb-1">Backup & Restore Center</h3>
                        <p className="text-sm text-slate-500">Manage data snapshots, local imports, and auto-backups.</p>
                    </div>

                    <div className="flex items-center gap-6 text-center bg-slate-50 border border-slate-100 rounded-lg px-6 py-3">
                        <div>
                            <p className="text-xl font-bold text-slate-800">{storageInfo.count}</p>
                            <p className="text-[10px] text-slate-500 uppercase tracking-widest font-semibold mt-0.5">Backups</p>
                        </div>
                        <div className="w-px h-8 bg-slate-200" />
                        <div>
                            <p className="text-xl font-bold text-slate-800">{BackupService.formatBytes(storageInfo.used)}</p>
                            <p className="text-[10px] text-slate-500 uppercase tracking-widest font-semibold mt-0.5">Storage</p>
                        </div>
                    </div>
                </div>

                {/* Quick Actions */}
                <div className="flex flex-wrap items-center gap-3 mt-6 pt-6 border-t border-slate-100">
                    <button
                        onClick={() => setShowCreateForm(!showCreateForm)}
                        className="flex items-center gap-2 px-4 py-2 bg-slate-900 hover:bg-slate-800 text-white font-medium rounded-lg transition-colors text-sm"
                    >
                        <ArrowDownToLine size={16} />
                        Create Backup
                    </button>
                    <button
                        onClick={() => fileInputRef.current?.click()}
                        className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 hover:bg-slate-50 text-slate-700 font-medium rounded-lg transition-colors text-sm"
                    >
                        <ArrowUpFromLine size={16} />
                        Import Backup
                    </button>
                    <input
                        ref={fileInputRef}
                        type="file"
                        accept=".json"
                        onChange={handleImport}
                        className="hidden"
                    />

                    {/* Auto-Backup Toggle */}
                    <div className="flex items-center gap-2 ml-auto bg-slate-50 border border-slate-200 rounded-lg px-3 py-2">
                        <Timer size={14} className="text-slate-500" />
                        <span className="text-xs text-slate-600 font-medium hidden sm:inline">Auto-backup:</span>
                        <select
                            value={autoBackupInterval}
                            onChange={(e) => handleAutoBackupChange(Number(e.target.value))}
                            className="bg-transparent text-sm text-slate-800 font-medium outline-none cursor-pointer appearance-none pl-1 pr-2"
                        >
                            <option value={0}>Off</option>
                            <option value={1}>Every 1h</option>
                            <option value={4}>Every 4h</option>
                            <option value={12}>Every 12h</option>
                            <option value={24}>Daily</option>
                        </select>
                    </div>
                </div>
            </div>

            {/* ═══ Create Backup Form ═══ */}
            {showCreateForm && (
                <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-6 animate-in slide-in-from-top-4 duration-300">
                    <div className="flex items-center justify-between mb-6">
                        <h4 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                            <Package size={20} className="text-slate-500" />
                            New Backup Configuration
                        </h4>
                        <button onClick={() => setShowCreateForm(false)} className="text-slate-400 hover:text-slate-600">
                            <X size={20} />
                        </button>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">Backup Label</label>
                            <input
                                type="text"
                                value={backupLabel}
                                onChange={(e) => setBackupLabel(e.target.value)}
                                placeholder={`Backup ${new Date().toLocaleDateString()}`}
                                className="w-full px-4 py-2 border border-slate-200 hover:border-slate-300 rounded-lg focus:ring-2 focus:ring-slate-100 focus:border-slate-400 outline-none text-sm transition-all"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">Description (optional)</label>
                            <input
                                type="text"
                                value={backupDescription}
                                onChange={(e) => setBackupDescription(e.target.value)}
                                placeholder="e.g. Before major update..."
                                className="w-full px-4 py-2 border border-slate-200 hover:border-slate-300 rounded-lg focus:ring-2 focus:ring-slate-100 focus:border-slate-400 outline-none text-sm transition-all"
                            />
                        </div>
                    </div>

                    {/* Module Selection */}
                    <div className="mb-6">
                        <div className="flex items-center justify-between mb-3">
                            <label className="text-sm font-medium text-slate-700">Select Modules to Backup</label>
                            <button
                                onClick={() => setSelectedModules(selectedModules.length === ALL_MODULES.length ? [] : [...ALL_MODULES])}
                                className="text-xs text-blue-600 hover:text-blue-800 font-medium"
                            >
                                {selectedModules.length === ALL_MODULES.length ? 'Deselect All' : 'Select All'}
                            </button>
                        </div>
                        <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                            {ALL_MODULES.map(mod => {
                                const config = MODULE_CONFIG[mod];
                                const Icon = config.icon;
                                const selected = selectedModules.includes(mod);
                                return (
                                    <button
                                        key={mod}
                                        onClick={() => toggleModule(mod, selectedModules, setSelectedModules)}
                                        className={`flex items-center gap-2 px-3 py-2.5 rounded-lg border text-sm font-medium transition-all ${selected
                                            ? 'border-slate-300 bg-slate-50 text-slate-800 shadow-sm'
                                            : 'border-slate-200 bg-white text-slate-500 hover:border-slate-300 hover:text-slate-700'
                                            }`}
                                    >
                                        <Icon size={16} className={selected ? 'text-slate-800' : 'text-slate-400'} />
                                        {config.label}
                                        {selected && <CheckCircle2 size={12} className="ml-auto text-slate-800" />}
                                    </button>
                                );
                            })}
                        </div>
                    </div>

                    <div className="flex justify-end gap-3 mt-6">
                        <button
                            onClick={() => setShowCreateForm(false)}
                            className="px-5 py-2 text-slate-600 hover:text-slate-800 font-medium text-sm rounded-lg hover:bg-slate-50 transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            onClick={handleCreateBackup}
                            disabled={isCreating || selectedModules.length === 0}
                            className="flex items-center gap-2 px-6 py-2 bg-slate-900 hover:bg-slate-800 text-white font-medium rounded-lg transition-colors disabled:opacity-50 disabled:pointer-events-none text-sm"
                        >
                            {isCreating ? (
                                <>
                                    <RefreshCw size={16} className="animate-spin" />
                                    Creating...
                                </>
                            ) : (
                                <>
                                    <ArrowDownToLine size={16} />
                                    Create Backup Now
                                </>
                            )}
                        </button>
                    </div>
                </div>
            )}

            {/* ═══ Import Error ═══ */}
            {importError && (
                <div className="bg-red-50 border border-red-200 rounded-xl p-4 flex items-start gap-3 animate-in fade-in duration-200">
                    <FileWarning size={18} className="text-red-500 mt-0.5 shrink-0" />
                    <div className="flex-1">
                        <p className="text-sm font-medium text-red-800">Import Failed</p>
                        <p className="text-xs text-red-600 mt-1">{importError}</p>
                    </div>
                    <button onClick={() => setImportError(null)} className="text-red-400 hover:text-red-600">
                        <X size={16} />
                    </button>
                </div>
            )}

            {/* ═══ Backup History ═══ */}
            <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
                <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between">
                    <h4 className="font-bold text-slate-800 flex items-center gap-2">
                        <History size={18} className="text-slate-500" />
                        Backup History
                        <span className="text-xs text-slate-400 font-normal ml-1">({history.length} backups)</span>
                    </h4>
                    <button
                        onClick={handleRefresh}
                        disabled={isRefreshing}
                        className={`text-slate-400 hover:text-slate-800 transition-colors ${isRefreshing ? 'opacity-50 cursor-not-allowed' : ''}`}
                        title="Refresh history"
                    >
                        <RefreshCw size={16} className={isRefreshing ? 'animate-spin' : ''} />
                    </button>
                </div>

                {history.length === 0 ? (
                    <div className="p-12 text-center">
                        <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center mx-auto mb-4">
                            <Database size={28} className="text-slate-400" />
                        </div>
                        <p className="text-slate-500 font-medium mb-1">No backups yet</p>
                        <p className="text-sm text-slate-400 mb-4">Create your first backup to protect your data</p>
                        <button
                            onClick={() => setShowCreateForm(true)}
                            className="inline-flex items-center gap-2 px-4 py-2 bg-slate-900 text-white font-medium rounded-lg text-sm hover:bg-slate-800 transition-colors"
                        >
                            <ArrowDownToLine size={16} />
                            Create First Backup
                        </button>
                    </div>
                ) : (
                    <div className="divide-y divide-slate-100">
                        {history.map((entry) => {
                            const isExpanded = expandedEntry === entry.id;
                            return (
                                <div key={entry.id} className="group hover:bg-slate-50/50 transition-colors">
                                    {/* Main Row */}
                                    <div className="px-6 py-4 flex items-center gap-4">
                                        {/* Icon */}
                                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 ${entry.isAutoBackup ? 'bg-slate-100' : 'bg-blue-50'
                                            }`}>
                                            {entry.isAutoBackup ? (
                                                <Zap size={18} className="text-slate-500" />
                                            ) : (
                                                <Package size={18} className="text-blue-600" />
                                            )}
                                        </div>

                                        {/* Info */}
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-center gap-2 mb-0.5">
                                                <h5 className="font-bold text-slate-800 text-sm truncate">{entry.label}</h5>
                                                {entry.isAutoBackup && (
                                                    <span className="text-[9px] px-1.5 py-0.5 bg-slate-200 text-slate-600 rounded-full font-bold uppercase tracking-wider">Auto</span>
                                                )}
                                                {entry.restoredAt && (
                                                    <span className="text-[9px] px-1.5 py-0.5 bg-green-100 text-green-700 rounded-full font-bold uppercase tracking-wider">Restored</span>
                                                )}
                                                {entry.tags?.map(tag => (
                                                    <span key={tag} className="text-[9px] px-1.5 py-0.5 bg-blue-100 text-blue-600 rounded-full font-medium">{tag}</span>
                                                ))}
                                            </div>
                                            <div className="flex items-center gap-3 text-xs text-slate-400">
                                                <span className="flex items-center gap-1">
                                                    <Clock size={11} />
                                                    {timeAgo(entry.createdAt)}
                                                </span>
                                                <span>•</span>
                                                <span>{BackupService.formatBytes(entry.sizeBytes)}</span>
                                                <span>•</span>
                                                <span>{entry.modules.length} modules</span>
                                                <span>•</span>
                                                <span>by {entry.createdBy}</span>
                                            </div>
                                        </div>

                                        {/* Actions */}
                                        <div className="flex items-center gap-1 shrink-0">
                                            <button
                                                onClick={() => handleDownload(entry.id)}
                                                title="Download .json"
                                                className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                                            >
                                                <Download size={16} />
                                            </button>
                                            <button
                                                onClick={() => handleCompare(entry.id)}
                                                title="Compare with current"
                                                className="p-2 text-slate-400 hover:text-violet-600 hover:bg-violet-50 rounded-lg transition-colors"
                                            >
                                                <Eye size={16} />
                                            </button>
                                            <button
                                                onClick={() => {
                                                    setShowRestoreModal(entry.id);
                                                    setRestoreModules([]);
                                                    setRestoreResult(null);
                                                }}
                                                title="Restore this backup"
                                                className="p-2 text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-lg transition-colors"
                                            >
                                                <RotateCcw size={16} />
                                            </button>
                                            <button
                                                onClick={() => setDeleteConfirm(entry.id)}
                                                title="Delete backup"
                                                className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                            >
                                                <Trash2 size={16} />
                                            </button>
                                            <button
                                                onClick={() => setExpandedEntry(isExpanded ? null : entry.id)}
                                                className="p-2 text-slate-400 hover:text-slate-600 rounded-lg transition-colors"
                                            >
                                                {isExpanded ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
                                            </button>
                                        </div>
                                    </div>

                                    {/* Expanded Details */}
                                    {isExpanded && (
                                        <div className="px-6 pb-4 animate-in slide-in-from-top-2 duration-200">
                                            <div className="bg-slate-50 rounded-xl p-4 ml-14">
                                                {entry.description && (
                                                    <p className="text-sm text-slate-600 mb-3 italic">"{entry.description}"</p>
                                                )}

                                                {/* Modules included */}
                                                <div className="mb-3">
                                                    <p className="text-xs font-medium text-slate-500 mb-2">Modules Included:</p>
                                                    <div className="flex flex-wrap gap-1.5">
                                                        {entry.modules.map(mod => (
                                                            <ModuleBadge key={mod} module={mod} small />
                                                        ))}
                                                    </div>
                                                </div>

                                                {/* Stats */}
                                                <StatsSummary stats={entry.stats} />

                                                {/* Metadata */}
                                                <div className="mt-3 grid grid-cols-2 gap-2 text-xs text-slate-500">
                                                    <div>
                                                        <span className="font-medium">Created:</span>{' '}
                                                        {new Date(entry.createdAt).toLocaleString()}
                                                    </div>
                                                    <div>
                                                        <span className="font-medium">Checksum:</span>{' '}
                                                        <code className="text-[10px] bg-slate-200 px-1.5 py-0.5 rounded font-mono">{entry.checksum.substring(0, 16)}...</code>
                                                    </div>
                                                    {entry.restoredAt && (
                                                        <div className="col-span-2">
                                                            <span className="font-medium text-emerald-600">Last Restored:</span>{' '}
                                                            {new Date(entry.restoredAt).toLocaleString()}
                                                        </div>
                                                    )}
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {/* Delete Confirmation */}
                                    {deleteConfirm === entry.id && (
                                        <div className="px-6 pb-4 animate-in fade-in duration-200">
                                            <div className="bg-red-50 border border-red-200 rounded-xl p-4 ml-14 flex items-center justify-between">
                                                <div className="flex items-center gap-2 text-red-800">
                                                    <AlertTriangle size={16} />
                                                    <span className="text-sm font-medium">Delete this backup permanently?</span>
                                                </div>
                                                <div className="flex gap-2">
                                                    <button
                                                        onClick={() => setDeleteConfirm(null)}
                                                        className="px-3 py-1.5 text-xs font-medium text-slate-600 hover:bg-white rounded-lg transition-colors"
                                                    >
                                                        Cancel
                                                    </button>
                                                    <button
                                                        onClick={() => handleDelete(entry.id)}
                                                        className="px-3 py-1.5 text-xs font-bold text-white bg-red-600 hover:bg-red-500 rounded-lg transition-colors"
                                                    >
                                                        Delete
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>

            {/* ═══ Restore Modal ═══ */}
            {showRestoreModal && (
                <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                    <div className="bg-white rounded-xl shadow-lg w-full max-w-lg max-h-[90vh] overflow-y-auto animate-in zoom-in-95 duration-200">
                        <div className="p-6">
                            <div className="flex items-center justify-between mb-6">
                                <h4 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                                    <RotateCcw size={20} className="text-emerald-600" />
                                    Restore Backup
                                </h4>
                                <button onClick={() => { setShowRestoreModal(null); setRestoreResult(null); }} className="text-slate-400 hover:text-slate-600">
                                    <X size={20} />
                                </button>
                            </div>

                            {!restoreResult ? (
                                <>
                                    {/* Safety Notice */}
                                    <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 mb-6 flex items-start gap-3">
                                        <ShieldCheck size={18} className="text-amber-600 mt-0.5 shrink-0" />
                                        <div>
                                            <p className="text-sm font-medium text-amber-800">Safety First</p>
                                            <p className="text-xs text-amber-700 mt-1">
                                                A safety backup of your current data will be created automatically before restoring.
                                                You can always roll back.
                                            </p>
                                        </div>
                                    </div>

                                    {/* Module Selection for Restore */}
                                    <div className="mb-6">
                                        <div className="flex items-center justify-between mb-3">
                                            <label className="text-sm font-medium text-slate-700">Select modules to restore</label>
                                            <span className="text-xs text-slate-400">Leave empty = restore all</span>
                                        </div>
                                        <div className="grid grid-cols-2 gap-2">
                                            {(() => {
                                                const backup = history.find(h => h.id === showRestoreModal);
                                                return (backup?.modules || ALL_MODULES).map(mod => {
                                                    const config = MODULE_CONFIG[mod];
                                                    if (!config) return null;
                                                    const Icon = config.icon;
                                                    const selected = restoreModules.includes(mod);
                                                    return (
                                                        <button
                                                            key={mod}
                                                            onClick={() => toggleModule(mod, restoreModules, setRestoreModules)}
                                                            className={`flex items-center gap-2 px-3 py-2 rounded-lg border text-xs font-medium transition-all ${selected
                                                                ? 'border-emerald-300 bg-emerald-50 text-emerald-700'
                                                                : 'border-slate-200 text-slate-500 hover:border-slate-300'
                                                                }`}
                                                        >
                                                            <Icon size={14} className={selected ? config.color : 'text-slate-400'} />
                                                            {config.label}
                                                            {selected && <CheckCircle2 size={10} className="ml-auto text-emerald-500" />}
                                                        </button>
                                                    );
                                                });
                                            })()}
                                        </div>
                                    </div>

                                    {/* Restore Button */}
                                    <div className="flex gap-3">
                                        <button
                                            onClick={() => { setShowRestoreModal(null); setRestoreResult(null); }}
                                            className="flex-1 px-4 py-2.5 text-slate-600 hover:bg-slate-100 font-medium text-sm rounded-lg transition-colors"
                                        >
                                            Cancel
                                        </button>
                                        <button
                                            onClick={handleRestore}
                                            disabled={isRestoring}
                                            className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-slate-900 hover:bg-slate-800 text-white font-medium text-sm rounded-lg transition-colors disabled:opacity-50"
                                        >
                                            {isRestoring ? (
                                                <>
                                                    <RefreshCw size={16} className="animate-spin" />
                                                    Restoring...
                                                </>
                                            ) : (
                                                <>
                                                    <RotateCcw size={16} />
                                                    Restore Now
                                                </>
                                            )}
                                        </button>
                                    </div>
                                </>
                            ) : (
                                /* Restore Result */
                                <div className="animate-in fade-in duration-300">
                                    <div className={`p-4 rounded-xl mb-4 ${restoreResult.success ? 'bg-emerald-50 border border-emerald-200' : 'bg-red-50 border border-red-200'}`}>
                                        <div className="flex items-center gap-2 mb-2">
                                            {restoreResult.success ? (
                                                <CheckCircle2 size={20} className="text-emerald-600" />
                                            ) : (
                                                <AlertCircle size={20} className="text-red-600" />
                                            )}
                                            <h5 className={`font-bold text-sm ${restoreResult.success ? 'text-emerald-800' : 'text-red-800'}`}>
                                                {restoreResult.success ? 'Restore Completed Successfully' : 'Restore Completed with Errors'}
                                            </h5>
                                        </div>

                                        {/* Modules Restored */}
                                        <div className="mt-3">
                                            <p className="text-xs font-medium text-slate-600 mb-1">Modules Restored:</p>
                                            <div className="flex flex-wrap gap-1.5">
                                                {restoreResult.modulesRestored.map(mod => (
                                                    <ModuleBadge key={mod} module={mod} small />
                                                ))}
                                            </div>
                                        </div>

                                        {/* Errors */}
                                        {restoreResult.errors.length > 0 && (
                                            <div className="mt-3">
                                                <p className="text-xs font-bold text-red-700 mb-1">Errors:</p>
                                                <ul className="text-xs text-red-600 space-y-1 list-disc list-inside">
                                                    {restoreResult.errors.map((err, i) => <li key={i}>{err}</li>)}
                                                </ul>
                                            </div>
                                        )}

                                        {/* Warnings */}
                                        {restoreResult.warnings.length > 0 && (
                                            <div className="mt-3">
                                                <p className="text-xs font-bold text-amber-700 mb-1">Warnings:</p>
                                                <ul className="text-xs text-amber-600 space-y-1 list-disc list-inside">
                                                    {restoreResult.warnings.map((w, i) => <li key={i}>{w}</li>)}
                                                </ul>
                                            </div>
                                        )}

                                        {restoreResult.rollbackAvailable && (
                                            <p className="mt-3 text-xs text-slate-500 flex items-center gap-1">
                                                <ShieldCheck size={12} className="text-emerald-500" />
                                                A pre-restore safety backup was created. You can roll back anytime.
                                            </p>
                                        )}
                                    </div>

                                    <button
                                        onClick={() => { setShowRestoreModal(null); setRestoreResult(null); }}
                                        className="w-full px-4 py-2.5 bg-slate-900 hover:bg-slate-800 text-white font-medium text-sm rounded-lg transition-colors"
                                    >
                                        Done
                                    </button>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* ═══ Diff Modal ═══ */}
            {showDiffModal && (
                <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                    <div className="bg-white rounded-xl shadow-lg w-full max-w-lg animate-in zoom-in-95 duration-200">
                        <div className="p-6">
                            <div className="flex items-center justify-between mb-6">
                                <h4 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                                    <Eye size={20} className="text-violet-600" />
                                    Compare with Current Data
                                </h4>
                                <button onClick={() => setShowDiffModal(null)} className="text-slate-400 hover:text-slate-600">
                                    <X size={20} />
                                </button>
                            </div>

                            {loadingDiff ? (
                                <div className="py-12 text-center">
                                    <RefreshCw size={24} className="text-blue-500 animate-spin mx-auto mb-3" />
                                    <p className="text-sm text-slate-500">Comparing data...</p>
                                </div>
                            ) : diffs.length === 0 ? (
                                <div className="py-8 text-center text-slate-500">
                                    <FileCheck size={32} className="mx-auto mb-2 text-slate-400" />
                                    <p className="text-sm">No comparison data available</p>
                                </div>
                            ) : (
                                <div className="space-y-3">
                                    {diffs.map(diff => {
                                        const config = MODULE_CONFIG[diff.module];
                                        const Icon = config?.icon || Database;
                                        return (
                                            <div key={diff.module} className="p-4 rounded-xl border border-slate-200 hover:border-slate-300 transition-colors">
                                                <div className="flex items-center gap-2 mb-3">
                                                    <Icon size={16} className={config?.color || 'text-slate-500'} />
                                                    <span className="font-bold text-sm text-slate-800">{config?.label || diff.module}</span>
                                                </div>
                                                <div className="grid grid-cols-3 gap-2">
                                                    <div className="bg-emerald-50 rounded-lg p-2 text-center">
