const CandidateDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { candidates, updateCandidateInState, removeCandidateFromState, refreshCandidates } = useCandidates();
  const { user } = useAuth();
  const { hasPermission } = usePermission();
  const toast = useToast();

  // Derive candidate from global state
  const [candidate, setCandidate] = useState<Candidate | null>(null);
  const [isLocalLoading, setIsLocalLoading] = useState(true);
  const [fetchError, setFetchError] = useState<string | null>(null);
  const [isExportingReport, setIsExportingReport] = useState(false);

  useEffect(() => {
    const loadCandidate = async () => {
      if (!id) return;

      setIsLocalLoading(true);
      setFetchError(null);

      try {
        // First try to find in context if available
        if (candidates.length > 0) {
          const found = candidates.find(c => c.id === id);
          if (found) {
            setCandidate(found);
            setIsLocalLoading(false);
            return;
          }
        }

        // If not found in context or context is empty, fetch directly from service
        const directCandidate = await CandidateService.getCandidate(id);
        if (directCandidate) {
          setCandidate(directCandidate);
        } else {
          setFetchError('Personnel records not found for this identifier.');
        }
      } catch (err) {
        console.error('Error in direct candidate fetch:', err);
        setFetchError('Failed to establish connection to workforce registry.');
      } finally {
        setIsLocalLoading(false);
      }
    };

    loadCandidate();
  }, [id, candidates]);

  // Log profile view once when candidate is loaded
  useEffect(() => {
    if (candidate && candidate.id) {
      AuditService.log('PROFILE_VIEW', { candidateId: candidate.id, candidateName: candidate.name });
    }
  }, [candidate?.id]);

  const [activeTab, setActiveTab] = useState<'profile' | 'documents' | 'timeline' | 'audit'>('profile');

  // Handles profile fields editing
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [editedProfile, setEditedProfile] = useState<Partial<Candidate>>({});

  // Custom payment type input state (replaces window.prompt)
  const [newCustomPaymentType, setNewCustomPaymentType] = useState('');

  // Matched Jobs & Employers State
  const [matchedJobs, setMatchedJobs] = useState<Job[]>([]);
  const [employersMap, setEmployersMap] = useState<Record<string, Employer>>({});

  useEffect(() => {
    const loadLinkedData = async () => {
      if (!candidate || !hasPermission('candidates.view')) return;
      try {
        const allJobs = await JobService.getJobs();
        const allEmployers = await PartnerService.getEmployers();

        const matches = allJobs.filter(j => j.matchedCandidateIds?.includes(candidate.id));
        setMatchedJobs(matches);

        const map: Record<string, Employer> = {};
        allEmployers.forEach(e => { map[e.id] = e; });
        setEmployersMap(map);
      } catch (error) {
        console.error("Error loading linked data", error);
      }
    };
    loadLinkedData();
  }, [candidate, hasPermission]);

  const startEditing = () => {
    if (!candidate) return;

    // Ensure data is synchronized before editing
    const syncedCandidate = DataSyncService.fullSync(candidate);

    setEditedProfile(syncedCandidate);
    setIsEditingProfile(true);
  };
  const saveProfile = async () => {
    if (!candidate || !editedProfile) return;

    try {
      // Clean passports array to prevent empty/duplicate entries
      const cleanedPassports = (editedProfile.passports || []).filter(
        p => p && (p.passportNumber?.trim() || p.issuedDate?.trim() || p.expiryDate?.trim())
      );

      // Use DataSyncService to ensure bidirectional parity
      const updatedCandidate = DataSyncService.fullSync({
        ...candidate,
        ...editedProfile,
        passports: cleanedPassports.length > 0 ? cleanedPassports : [],
        // Special handling for slbfeData specific to this component's logic
        slbfeData: {
          biometricStatus: 'Pending',
          agreementStatus: 'Pending',
          ...(candidate.slbfeData || {}),
          ...(editedProfile.slbfeData || {}),
          // Deep-merge familyConsent to avoid losing nested fields
          familyConsent: {
            isGiven: false,
            ...(candidate.slbfeData?.familyConsent || {}),
            ...((editedProfile.slbfeData as any)?.familyConsent || {})
          }
        } as any,
        // Ensure complex arrays are preserved if missing in editedProfile
        advancePayments: (editedProfile as any).advancePayments ?? [],
        workflowMilestones: {
          ...(candidate.workflowMilestones || {}),
          ...((editedProfile as any).workflowMilestones || {}),
        },
        remarkLog: (editedProfile as any).remarkLog || (candidate as any).remarkLog || [],
      });

      // Recalculate completion
      const finalCandidate = ProfileCompletionService.updateCompletionData(updatedCandidate);

      await CandidateService.updateCandidate(finalCandidate);

      updateCandidateInState(finalCandidate);
      setCandidate(finalCandidate);
      setIsEditingProfile(false);

      await CandidateService.addTimelineEvent(candidate.id, {
        type: 'SYSTEM',
        title: 'Profile Updated',
        description: 'Candidate profile information was updated',
        actor: user?.name || 'Internal Staff',
        userId: user?.id
      });
      toast.success('Profile saved successfully');
    } catch (e) {
      console.error('Error saving profile:', e);
      toast.error('Failed to save profile. Please try again.');
    }
  };

  // Handle compliance update
  const handleComplianceUpdate = async (data: {
    passport: Partial<PassportData>;
    pcc: Partial<PCCData>
  }) => {
    if (!candidate) return;

    let updatedCandidate = { ...candidate };

    // Process Passport
    if (data.passport.passportNumber) {
      const passportData = ComplianceService.evaluatePassport(
        data.passport.expiryDate || '',
        data.passport.passportNumber || '',
        data.passport.country || '',
        data.passport.issuedDate || ''
      );
      updatedCandidate.passportData = passportData;
    }

    // Process PCC
    if (data.pcc.issuedDate) {
      const pccData = ComplianceService.evaluatePCC(
        data.pcc.issuedDate || '',
        data.pcc.expiryDate || ''
      );
      updatedCandidate.pccData = pccData;
    }

    // Fix: Keep passports array in sync if it exists or create it
    if (updatedCandidate.passportData) {
      if (updatedCandidate.passports && updatedCandidate.passports.length > 0) {
        updatedCandidate.passports[0] = updatedCandidate.passportData;
      } else {
        updatedCandidate.passports = [updatedCandidate.passportData];
      }
    }

    // Recalculate profile completion
    updatedCandidate = ProfileCompletionService.updateCompletionData(updatedCandidate);

    updateCandidateInState(updatedCandidate);
    setCandidate(updatedCandidate);

    try {
      await CandidateService.updateCandidate(updatedCandidate);
      await CandidateService.addTimelineEvent(candidate.id, {
        type: 'SYSTEM',
        title: 'Compliance Data Updated',
        description: 'Passport and PCC information has been updated',
        actor: user?.name || 'Internal Staff',
        userId: user?.id
      });
    } catch (err) {
      console.error('Failed to update compliance data', err);
    }
  };

  // Handle interview schedule update
  const handleInterviewUpdate = async (data: { interviews: import('../types').InterviewRecord[] }) => {
    if (!candidate) return;

    const updatedCandidate: Candidate = {
      ...candidate,
      stageData: {
        ...candidate.stageData,
        interviews: data.interviews
      }
    };

    updateCandidateInState(updatedCandidate);
    setCandidate(updatedCandidate);

    try {
      await CandidateService.updateCandidate(updatedCandidate);
      await CandidateService.addTimelineEvent(candidate.id, {
        type: 'SYSTEM',
        title: 'Interview Schedule Updated',
        description: `Interview schedules updated (${data.interviews.length} total)`,
        actor: user?.name || 'Internal Staff',
        userId: user?.id
      });
    } catch (err) {
      console.error('Failed to update interview data', err);
    }
  };

  // Tracking ref to prevent out-of-order execution from overwriting rapid changes
  const latestDocUpdateRef = React.useRef<number>(0);

  // Handle document update safely against rapid clicks by fetching fresh data
  const handleDocumentUpdate = async (updatedDocs: CandidateDocument[]) => {
    if (!candidate) return;
    const currentCallId = ++latestDocUpdateRef.current;

    try {
      // 1. Fetch fresh candidate data so rapid clicks do not overwrite each other's changes
      const freshCandidate = await CandidateService.getCandidate(candidate.id);

      if (latestDocUpdateRef.current !== currentCallId) {
        // A newer update was dispatched while we were waiting for the fetch
        // Abort this save to prevent the older (current) state from overwriting the newer state
        console.warn('Aborting stale document update payload to prevent UI reverting');
        return;
      }

      const safeCandidate = freshCandidate || candidate;

      // Smart merge to protect background updates from other users or concurrent tabs
      // Prevents erasing documents uploaded/updated by others during this fetch window
      const mergedDocs = [...(safeCandidate.documents || [])];

      updatedDocs.forEach(localDoc => {
        const freshIndex = mergedDocs.findIndex(d => d.type === localDoc.type);
        const originalDoc = candidate.documents?.find(d => d.type === localDoc.type);

        if (freshIndex === -1) {
          // New document local action
          mergedDocs.push(localDoc);
        } else {
          // If we actually changed this document locally compared to what we started with, 
          // our local change wins. Otherwise, keep the fresh background state.
          if (JSON.stringify(localDoc) !== JSON.stringify(originalDoc)) {
            mergedDocs[freshIndex] = localDoc;
          }
        }
      });

      const newEvent: TimelineEvent = {
        id: `evt-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
        timestamp: new Date().toISOString(),
        type: 'DOCUMENT',
        title: 'Documents Updated',
        description: 'Candidate documents have been modified',
        actor: user?.name || 'Internal Staff',
        userId: user?.id,
        stage: safeCandidate.stage
      };

      const updatedCandidate: Candidate = {
        ...safeCandidate,
        documents: mergedDocs,
        timelineEvents: [newEvent, ...(safeCandidate.timelineEvents || [])]
      };

      // 2. Optimistic local update
      updateCandidateInState(updatedCandidate);
      setCandidate(updatedCandidate);

      // 3. Persist back to database
      await CandidateService.updateCandidate(updatedCandidate);
    } catch (err) {
      console.error('Failed to update documents', err);
      // Fallback in case of network issue
      const fallbackCandidate = { ...candidate, documents: updatedDocs };
      updateCandidateInState(fallbackCandidate);
      setCandidate(fallbackCandidate);
      await CandidateService.updateCandidate(fallbackCandidate);
    }
  };

  // Strict Workflow Actions
  const handleAdvanceStage = async (forceOverride: boolean = false) => {
    if (!candidate) return;

    const nextStage = WorkflowEngine.getNextStage(candidate.stage);
    if (!nextStage) return;

    // Use WorkflowEngine to perform transition logic
    const transitionResult = await WorkflowEngine.performTransition(candidate, nextStage, user?.name || 'System Admin', undefined, forceOverride);

    if (transitionResult.success) {
      const today = new Date().toISOString().split('T')[0];
      const updatedCandidate = { ...candidate, stage: nextStage };

      // Auto-update workflow milestone dates to bind with workflow progress
      const milestones = { ...(updatedCandidate.workflowMilestones || {}) };
      switch (nextStage) {
        case WorkflowStage.VERIFIED:
          milestones.verifiedDate = today;
          break;
        case WorkflowStage.APPLIED:
          milestones.offerAppliedDate = today;
          break;
        case WorkflowStage.OFFER_RECEIVED:
          milestones.offerReceivedDate = today;
          break;
        case WorkflowStage.WP_RECEIVED:
          milestones.wpReceivedDate = today;
          break;
        case WorkflowStage.EMBASSY_APPLIED:
          milestones.embAppliedDate = today;
          break;
        case WorkflowStage.VISA_RECEIVED:
          milestones.stampRejectDate = today;
          milestones.stampResult = 'Stamped';
          break;
        case WorkflowStage.SLBFE_REGISTRATION:
          milestones.slbfeRegistrationDate = today;
          break;
        case WorkflowStage.TICKET_ISSUED:
          milestones.ticketIssuedDate = today;
          break;
        case WorkflowStage.DEPARTED:
          milestones.departureDate = today;
          updatedCandidate.departureDate = today;
          break;
      }
      updatedCandidate.workflowMilestones = milestones;

      // Update Backend
      await CandidateService.updateCandidate(updatedCandidate);

      // Update Context
      updateCandidateInState(updatedCandidate);

      // Update Local State
      setCandidate(updatedCandidate);

      // Log Event
      await CandidateService.addTimelineEvent(candidate.id, {
        type: 'WORKFLOW',
        title: `Advanced to ${nextStage}`,
        description: `Candidate advanced from ${candidate.stage} to ${nextStage}`,
        actor: user?.name || 'Internal Staff',
        userId: user?.id
      });

    } else {
      toast.warning(`Cannot advance stage: ${transitionResult.error}`);
    }
  };

  const handleStageClick = async (toStage: WorkflowStage) => {
    if (!candidate) return;

    const fromIndex = WORKFLOW_STAGES.indexOf(candidate.stage);
    const toIndex = WORKFLOW_STAGES.indexOf(toStage);

    if (toIndex === fromIndex) return;

    if (toIndex < fromIndex) {
      const reason = prompt(`Reason for rollback to ${toStage}:`);
      if (reason) handleRollback(toStage, reason);
      return;
    }

    const isSequential = toIndex === fromIndex + 1;
    const confirmMsg = isSequential
      ? `Progress workflow to ${toStage}?`
      : `JUMP workflow to ${toStage}? (Bypasses sequential logic)`;

    if (window.confirm(confirmMsg)) {
      // Logic for jump is same as advance but with forceOverride=true if non-sequential
      // Note: WorkflowEngine.performTransition takes forceOverride as last param
      const result = await WorkflowEngine.performTransition(candidate, toStage, user?.name || 'System Admin', undefined, !isSequential);

      if (result.success) {
        const today = new Date().toISOString().split('T')[0];
        const updatedCandidate = { ...candidate, stage: toStage };
        const milestones = { ...(updatedCandidate.workflowMilestones || {}) };

        // Update relevant milestone for the target stage
        switch (toStage) {
          case WorkflowStage.VERIFIED: milestones.verifiedDate = today; break;
          case WorkflowStage.APPLIED: milestones.offerAppliedDate = today; break;
          case WorkflowStage.OFFER_RECEIVED: milestones.offerReceivedDate = today; break;
          case WorkflowStage.WP_RECEIVED: milestones.wpReceivedDate = today; break;
          case WorkflowStage.EMBASSY_APPLIED: milestones.embAppliedDate = today; break;
          case WorkflowStage.VISA_RECEIVED:
            milestones.stampRejectDate = today;
            milestones.stampResult = 'Stamped';
            break;
          case WorkflowStage.SLBFE_REGISTRATION: milestones.slbfeRegistrationDate = today; break;
          case WorkflowStage.TICKET_ISSUED: milestones.ticketIssuedDate = today; break;
          case WorkflowStage.DEPARTED:
            milestones.departureDate = today;
            updatedCandidate.departureDate = today;
            break;
        }

        updatedCandidate.workflowMilestones = milestones;
        await CandidateService.updateCandidate(updatedCandidate);
        updateCandidateInState(updatedCandidate);
        setCandidate(updatedCandidate);

        await CandidateService.addTimelineEvent(candidate.id, {
          type: 'WORKFLOW',
          title: `Moved to ${toStage}`,
          description: `Direct stage transition from ${candidate.stage} to ${toStage}`,
          actor: user?.name || 'Internal Staff',
          timestamp: new Date().toISOString()
        });

        toast.success(`Candidate moved to ${toStage}`);
      } else {
        toast.error(result.error || "Transition failed");
      }
    }
  };

  const handleRollback = async (targetStage: WorkflowStage, reason: string) => {
    if (!candidate) return;

    // Direct rollback logic since WorkflowEngine.performTransition checks strictly for forward movement or specific rules
    // For rollback, we generally allow it with a reason, but we should validate if needed.
    // Assuming implicit allow for admin overrides or generic rollbacks for now.

    // Check if target stage is valid? 
    // Simplified: Just update.

    const updatedCandidate = { ...candidate, stage: targetStage };

    // When rolling back, we might optionally clear later milestones,
    // but the request was specifically to bond the progress and dates.
    // We'll update today's date into the targeted rollback stage just in case
    // it functions as a fresh entry to that stage.

    await CandidateService.updateCandidate(updatedCandidate);
    updateCandidateInState(updatedCandidate);
    setCandidate(updatedCandidate);


    await CandidateService.addTimelineEvent(candidate.id, {
      type: 'WORKFLOW',
      title: `Rolled back to ${targetStage}`,
      description: `Rollback Reason: ${reason}`,
      actor: user?.name || 'Internal Staff',
      userId: user?.id
    });
  };

  // Handle delete
  const handleDelete = async () => {
    if (!candidate) return;

    const policy = WorkflowEngine.canPerformAction(candidate, 'DELETE');
    if (!policy.allowed) {
      toast.warning(`Policy Block: ${policy.reason}`);
      return;
    }

    if (confirm(`Are you sure you want to delete ${candidate.name}?`)) {
      await CandidateService.deleteCandidate(candidate.id);
      removeCandidateFromState(candidate.id);
      if (candidate) {
        await CandidateService.addTimelineEvent(candidate.id, {
          type: 'STATUS_CHANGE',
          title: 'Candidate Profile Deleted',
          description: `Profile permanently removed from system`,
          actor: user?.name || 'System Admin',
          userId: user?.id
        });
      }
      navigate('/candidates');
    }
  };

  // Handle activity log (remarkLog) update from ActivityLogWidget
  const handleRemarkLogUpdate = async (updatedRemarkLog: RemarkEntry[]) => {
    if (!candidate) return;

    const updatedCandidate = {
      ...candidate,
      remarkLog: updatedRemarkLog,
    } as Candidate;

    try {
      await CandidateService.updateCandidate(updatedCandidate);
      updateCandidateInState(updatedCandidate);
      setCandidate(updatedCandidate);

      await CandidateService.addTimelineEvent(candidate.id, {
        type: 'NOTE',
        title: 'Activity Log Updated',
        description: `Activity log updated (${updatedRemarkLog.length} entries)`,
        actor: user?.name || 'Internal Staff',
        userId: user?.id
      });
      toast.success('Activity log saved successfully');
    } catch (err) {
      console.error('Failed to update activity log', err);
      toast.error('Failed to update activity log');
    }
  };

  const handleGenerateReport = async () => {
    if (!candidate) return;

    setIsExportingReport(true);
    try {
      // Dynamically import react-pdf components
      const { pdf } = await import('@react-pdf/renderer');
      const { CandidateReportPDF } = await import('../src/components/reports/CandidateReportPDF');

      // Generate system report first for strategic assessment and risk scoring
      const { ReportService } = await import('../services/reportService');
      const systemReport = await ReportService.generateReport(candidate);

      const blob = await pdf(
        <CandidateReportPDF
          candidate={candidate}
          reportId={`REP-${Date.now()}`}
          generatedBy={user?.name || 'Internal Staff'}
          systemReport={systemReport}
        />
      ).toBlob();

      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `Candidate_Audit_Report_${candidate.name.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.pdf`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);

      CandidateService.addTimelineEvent(candidate.id, {
        type: 'SYSTEM',
        title: 'Report Generated',
        description: 'Candidate Strategic Assessment Report was generated',
        actor: user?.name || 'Internal Staff',
        userId: user?.id
      });
      toast.success('Report successfully generated!');
    } catch (error) {
      console.error('Failed to generate PDF:', error);
      toast.error('Failed to generate report. Please try again.');
    } finally {
      setIsExportingReport(false);
    }
  };

  // Define tabs
  const tabs: Tab[] = [
    { id: 'profile', label: 'Profile', icon: User },
    { id: 'documents', label: 'Documents', icon: FileText, count: candidate?.documents?.length || 0 },
    { id: 'timeline', label: 'Timeline', icon: History, count: candidate?.timelineEvents?.length || 0 },
    { id: 'audit', label: 'System Audit', icon: ShieldCheck }
  ];

  // Loading state
  if (isLocalLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="text-center ">
          <div className="w-16 h-16 bg-blue-100 rounded-lg flex items-center justify-center text-blue-600 mx-auto mb-6 shadow-lg shadow-blue-50/50">
            <RefreshCw size={32} className="animate-spin" />
          </div>
          <p className="text-slate-800 font-bold text-lg mb-1 tracking-tight">Syncing Workforce Data</p>
          <p className="text-slate-400 text-xs font-medium uppercase tracking-[0.2em]">Enterprise Registry Integration</p>
        </div>
      </div>
    );
  }

  // Error/Not Found state
  if (fetchError || !candidate) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-white rounded-xl border border-slate-200 shadow-md p-8 text-center">
          {/* Background Decoration */}
          <div className="absolute top-0 left-0 w-full h-1 bg-red-500" />

          <div className="w-20 h-20 bg-red-50 rounded-lg flex items-center justify-center text-red-500 mx-auto mb-8">
            <ShieldAlert size={40} />
          </div>
          <h2 className="text-xl font-semibold text-slate-900 mb-2">Access Alert</h2>
          <p className="text-slate-500 mb-8 font-medium">
            {fetchError || "The personnel record you are attempting to access is either restricted or does not exist in the current registry."}
          </p>
          <div className="flex flex-col gap-3">
            <button
              onClick={() => navigate('/candidates')}
              className="w-full py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all flex items-center justify-center gap-2"
            >
              Back to Candidates
            </button>
            <button
              onClick={() => window.location.reload()}
              className="w-full py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-bold hover:bg-slate-50 transition-all flex items-center justify-center gap-2"
            >
              <RefreshCw size={16} /> Retry Verification
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Hero Section */}
      <CandidateHero candidate={candidate} />

      {/* Tab Navigation */}
      <TabNavigation activeTab={activeTab} onTabChange={(tab) => setActiveTab(tab as any)} tabs={tabs} />

      {/* Main Content Area */}
      <div className="max-w-7xl mx-auto px-6 py-6" id="main-content-tabs">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Main Content (70%) */}
          <div className="lg:col-span-2 space-y-6">
            {/* Profile Tab */}
            {activeTab === 'profile' && (
              <div className="bg-white rounded-xl border border-slate-200 p-6">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-xl font-bold text-slate-900">Profile Information</h2>
                  {!isEditingProfile ? (
                    <button
                      onClick={startEditing}
                      className="px-4 py-2 bg-blue-50 text-blue-600 rounded-lg text-sm font-semibold hover:bg-blue-100 transition-colors"
                    >
                      Edit Profile
                    </button>
                  ) : (
                    <div className="flex gap-2">
                      <button
                        onClick={() => setIsEditingProfile(false)}
                        className="px-4 py-2 bg-slate-50 text-slate-600 rounded-lg text-sm font-semibold hover:bg-slate-100 transition-colors"
                      >
                        Cancel
                      </button>
                      <button
                        onClick={saveProfile}
                        className="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-semibold hover:bg-blue-700 transition-colors"
                      >
                        Save Changes
                      </button>
                    </div>
                  )}
                </div>

                {/* === REG NO BADGE — PRIMARY IDENTIFIER (Red ink on paper forms) === */}
                <div className="mb-6 bg-gradient-to-r from-red-50 to-orange-50 border-2 border-red-200 rounded-xl p-4 flex flex-wrap items-center justify-between gap-4">
                  <div className="flex items-center gap-4">
                    <div className="bg-red-600 text-white text-xs font-semibold uppercase tracking-wider px-3 py-1 rounded-md shadow-sm">REG NO</div>
                    {isEditingProfile ? (
                      <input
                        type="text"
                        value={editedProfile.regNo ?? ''}
                        onChange={(e) => setEditedProfile({ ...editedProfile, regNo: e.target.value })}
                        placeholder="e.g. SPA 19-260225"
                        className="text-2xl font-black text-red-700 bg-white border-2 border-red-300 rounded-lg px-3 py-1 focus:ring-2 focus:ring-red-500 outline-none tracking-wide"
                        style={{ minWidth: '220px' }}
                      />
                    ) : (
                      <span className="text-2xl font-semibold text-red-700">{candidate.regNo ?? '-'}</span>
                    )}
                  </div>
                  <div className="flex items-center gap-6 text-xs text-slate-500">
                    <div>
                      <span className="font-bold uppercase">Reg Date: </span>
                      {isEditingProfile ? (
                        <input
                          type="date"
                          value={editedProfile.regDate ? editedProfile.regDate.split('T')[0] : ''}
                          onChange={(e) => setEditedProfile({ ...editedProfile, regDate: e.target.value })}
                          className="text-sm border border-slate-300 rounded px-2 py-0.5 ml-1"
                        />
                      ) : (
                        <span className="font-medium text-slate-700 ml-1">{candidate.regDate ? new Date(candidate.regDate).toLocaleDateString() : '-'}</span>
                      )}
                    </div>
                    {isEditingProfile ? (
                      <div className="flex flex-wrap gap-3">
                        <div>
                          <span className="font-bold uppercase">Agent: </span>
                          <input type="text" value={editedProfile.foreignAgent ?? ''} onChange={(e) => setEditedProfile({ ...editedProfile, foreignAgent: e.target.value })} placeholder="Foreign Agent" className="text-sm border border-slate-300 rounded px-2 py-0.5 ml-1 w-28" />
                        </div>
                        <div>
                          <span className="font-bold uppercase">Coordinator: </span>
                          <input type="text" value={editedProfile.coordinatorName ?? ''} onChange={(e) => setEditedProfile({ ...editedProfile, coordinatorName: e.target.value })} placeholder="Name" className="text-sm border border-slate-300 rounded px-2 py-0.5 ml-1 w-28" />
                        </div>
                        <div>
                          <span className="font-bold uppercase">Company: </span>
                          <input type="text" value={(editedProfile as any).companyName || (candidate as any).companyName || ''} onChange={(e) => setEditedProfile({ ...editedProfile, companyName: e.target.value } as any)} placeholder="Company" className="text-sm border border-slate-300 rounded px-2 py-0.5 ml-1 w-28" />
                        </div>
                        <div>
                          <span className="font-bold uppercase">D/H Officer: </span>
                          <input type="text" value={editedProfile.dhOfficer ?? ''} onChange={(e) => setEditedProfile({ ...editedProfile, dhOfficer: e.target.value })} placeholder="Officer" className="text-sm border border-slate-300 rounded px-2 py-0.5 ml-1 w-28" />
                        </div>
                      </div>
                    ) : (
                      <>
                        {candidate.foreignAgent && <div><span className="font-bold uppercase">Agent: </span><span className="font-medium text-slate-700">{candidate.foreignAgent}</span></div>}
                        {candidate.coordinatorName && <div><span className="font-bold uppercase">Coordinator: </span><span className="font-medium text-slate-700">{candidate.coordinatorName}</span></div>}
                        {(candidate as any).companyName && <div><span className="font-bold uppercase">Company: </span><span className="font-medium text-slate-700">{(candidate as any).companyName}</span></div>}
                        {candidate.dhOfficer && <div><span className="font-bold uppercase">D/H Officer: </span><span className="font-medium text-slate-700">{candidate.dhOfficer}</span></div>}
                      </>
