                          <select value={(editedProfile as any).embassyDetails?.stampResult ?? 'Pending'} onChange={(e) => setEditedProfile({ ...editedProfile, embassyDetails: { ...candidate.embassyDetails, ...(editedProfile as any).embassyDetails, stampResult: e.target.value } } as any)} className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-amber-500">
                            <option value="Pending">Pending</option>
                            <option value="Stamped">Stamped</option>
                            <option value="Rejected">Rejected</option>
                          </select>
                        </div>
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-5 pt-2">
                        <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Awareness Program Date</label>
                          <input type="date" value={(editedProfile as any).embassyDetails?.awarenessProgramDate ?? ''} onChange={(e) => setEditedProfile({ ...editedProfile, embassyDetails: { ...candidate.embassyDetails, ...(editedProfile as any).embassyDetails, awarenessProgramDate: e.target.value } } as any)} className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-amber-500" />
                        </div>
                        <div className="flex items-end pb-2">
                          <label className="flex items-center gap-2 cursor-pointer">
                            <input type="checkbox" checked={(editedProfile as any).embassyDetails?.awarenessProgramSigned ?? false} onChange={(e) => setEditedProfile({ ...editedProfile, embassyDetails: { ...candidate.embassyDetails, ...(editedProfile as any).embassyDetails, awarenessProgramSigned: e.target.checked } } as any)} className="w-4 h-4 rounded border-slate-300 text-amber-600" />
                            <span className="text-xs font-bold text-slate-600 uppercase">Awareness Program Signed</span>
                          </label>
                        </div>
                      </div>
                    </div>
                  ) : (
                    <div className="bg-amber-50/30 p-5 rounded-xl border border-amber-100 space-y-4">
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <div>
                          <label className="text-xs font-medium text-slate-500 uppercase">E NO</label>
                          <div className="text-sm font-bold text-slate-900 mt-1 font-mono">{candidate.embassyDetails?.eNo || '-'}</div>
                        </div>
                        <div>
                          <label className="text-xs font-medium text-slate-500 uppercase">SE NO</label>
                          <div className="text-sm font-bold text-slate-900 mt-1 font-mono">{candidate.embassyDetails?.seNo || '-'}</div>
                        </div>
                        <div>
                          <label className="text-xs font-medium text-slate-500 uppercase">Applied Date</label>
                          <div className="text-sm font-medium text-slate-900 mt-1">{candidate.embassyDetails?.appliedDate || '-'}</div>
                        </div>
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 pt-2 border-t border-amber-100">
                        <div>
                          <label className="text-xs font-medium text-slate-500 uppercase">Appointment Date</label>
                          <div className="text-sm font-bold text-amber-700 mt-1">{candidate.embassyDetails?.appointmentDate ? new Date(candidate.embassyDetails.appointmentDate).toLocaleString() : '-'}</div>
                        </div>
                        <div>
                          <label className="text-xs font-medium text-slate-500 uppercase">Stamp Date</label>
                          <div className="text-sm font-medium text-slate-900 mt-1">{candidate.embassyDetails?.stampDate || '-'}</div>
                        </div>
                        <div>
                          <label className="text-xs font-medium text-slate-500 uppercase">Stamp Result</label>
                          <div className="mt-1">
                            <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${candidate.embassyDetails?.stampResult === 'Stamped' ? 'bg-green-100 text-green-700' : candidate.embassyDetails?.stampResult === 'Rejected' ? 'bg-red-100 text-red-700' : 'bg-slate-100 text-slate-600'}`}>
                              {candidate.embassyDetails?.stampResult || 'Pending'}
                            </span>
                          </div>
                        </div>
                      </div>
                      {(candidate.embassyDetails?.awarenessProgramDate || candidate.embassyDetails?.awarenessProgramSigned) && (
                        <div className="grid grid-cols-2 gap-4 pt-2 border-t border-amber-100">
                          <div>
                            <label className="text-xs font-medium text-slate-500 uppercase">Awareness Program</label>
                            <div className="text-sm font-medium text-slate-900 mt-1">{candidate.embassyDetails?.awarenessProgramDate || '-'}</div>
                          </div>
                          <div>
                            <label className="text-xs font-medium text-slate-500 uppercase">Signed</label>
                            <div className="text-sm font-bold mt-1">{candidate.embassyDetails?.awarenessProgramSigned ? '✅ Yes' : '❌ No'}</div>
                          </div>
                        </div>
                      )}
                    </div>
                  )}
                </section>

                {/* SECTION 1.57: FINANCIAL LEDGER & ADVANCE PAYMENTS */}
                <section className="mt-8 pt-8 border-t border-slate-100 mb-6 w-full overflow-hidden">
                  <FinancialLedgerWidget
                    candidate={(isEditingProfile ? editedProfile : candidate) as any}
                    isEditing={isEditingProfile}
                    onUpdate={(payments, usdRateEmb, usdRateFA) => {
                      setEditedProfile({
                        ...editedProfile,
                        advancePayments: payments,
                        ...(usdRateEmb !== undefined ? { usdRateEmb } : {}),
                        ...(usdRateFA !== undefined ? { usdRateFA } : {})
                      } as any);
                    }}
                  />
                </section>

                {/* SECTION 1.575: DATE/REMARK LOG (handwritten notes section on paper forms) */}
                <section className="mt-8 pt-8 border-t border-slate-100 mb-6">
                  <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                    <span className="w-6 h-1 bg-slate-300 rounded-full"></span>
                    Date / Remark Log
                  </h3>
                  <div className="bg-white rounded-xl border border-slate-200 overflow-hidden">
                    {/* Existing remarks */}
                    <div className="px-5 py-2">
                      {((candidate as any).remarkLog && (candidate as any).remarkLog.length > 0) ? (
                        <div className="space-y-0">
                          {((candidate as any).remarkLog).map((entry: any, idx: number) => (
                            <div key={idx} className="flex gap-3 py-2.5 border-b border-slate-100 last:border-0 group items-start">
                              <div className="text-[11px] font-semibold text-slate-500 whitespace-nowrap min-w-[80px] mt-0.5">{entry.date}</div>
                              <div className="text-xs text-slate-700 leading-relaxed flex-1">{entry.remark}</div>
                              <button
                                type="button"
                                onClick={() => {
                                  const existing = (candidate as any).remarkLog || [];
                                  const updated = [...existing];
                                  updated.splice(idx, 1);
                                  handleRemarkLogUpdate(updated);
                                }}
                                className="p-1 text-slate-300 hover:text-red-500 rounded opacity-0 group-hover:opacity-100 transition-opacity"
                                title="Delete Remark"
                              >
                                <Trash2 size={14} />
                              </button>
                            </div>
                          ))}
                        </div>
                      ) : (
                        <div className="text-xs text-slate-400 italic text-center py-3">
                          No remarks recorded yet
                        </div>
                      )}
                    </div>

                    {/* Add new remark */}
                    <div className="px-5 py-3 bg-slate-50 border-t border-slate-200">
                      <div className="flex gap-3 items-end">
                        <div className="flex-shrink-0">
                          <label className="block text-[10px] font-semibold text-slate-500 uppercase mb-1 tracking-wider">Date</label>
                          <input
                            type="date"
                            id="new-remark-date"
                            defaultValue={new Date().toISOString().split('T')[0]}
                            className="px-2 py-1.5 border border-slate-300 rounded-md text-[11px] font-medium text-slate-700 focus:ring-1 focus:ring-slate-300 outline-none"
                          />
                        </div>
                        <div className="flex-1">
                          <label className="block text-[10px] font-semibold text-slate-500 uppercase mb-1 tracking-wider">Remark</label>
                          <input
                            type="text"
                            id="new-remark-text"
                            placeholder="Enter remark... (Press Add)"
                            className="w-full px-3 py-1.5 border border-slate-300 rounded-md text-[11px] text-slate-700 focus:ring-1 focus:ring-slate-300 outline-none"
                            onKeyDown={(e) => {
                              if (e.key === 'Enter') {
                                e.preventDefault();
                                document.getElementById('add-remark-btn')?.click();
                              }
                            }}
                          />
                        </div>
                        <button
                          id="add-remark-btn"
                          onClick={() => {
                            const dateInput = document.getElementById('new-remark-date') as HTMLInputElement;
                            const textInput = document.getElementById('new-remark-text') as HTMLInputElement;
                            if (dateInput?.value && textInput?.value) {
                              const existing = (candidate as any).remarkLog || [];
                              handleRemarkLogUpdate([...existing, { date: dateInput.value, remark: textInput.value }]);
                              textInput.value = '';
                            }
                          }}
                          className="px-3 py-1.5 bg-slate-800 text-white rounded-md text-[11px] font-medium hover:bg-slate-900 transition-colors flex-shrink-0"
                        >
                          Add Entry
                        </button>
                      </div>
                    </div>
                  </div>
                </section>

                {/* SECTION 1.58: CERTIFICATE CHECKLIST */}
                {(() => {
                  const checklistItems = [
                    { num: 1, label: 'PP Size Photo (6)', docType: 'Passport Size Photos (6)' },
                    { num: 2, label: 'Full Photo', docType: 'Full Photo (1)' },
                    { num: 3, label: 'Edu: Certificates (O/L, A/L)', docType: 'O/L Certificate', altDocType: 'A/L Certificate' },
                    { num: 4, label: 'Course Certificates', docType: 'Course Certificates' },
                    { num: 5, label: 'NVQ/Trade Test Certificates', docType: 'NVQ/Trade Test Certificates' },
                    { num: 6, label: 'CDF', docType: 'CDF' },
                    { num: 7, label: 'ID', docType: 'ID' },
                    { num: 8, label: 'Driving Licence', docType: 'Driving licence' },
                    { num: 9, label: 'Police Clearance', docType: 'Police Clearance' },
                    { num: 10, label: 'Offer Letter', docType: 'Offer Letter' },
                    { num: 11, label: 'Work Permit (WP)', docType: 'Work Permit (WP)' },
                    { num: 12, label: 'Experience Letters', docType: 'Experience Letters' },
                    { num: 13, label: 'Medical Report Date', docType: 'Medical Report' },
                    { num: 14, label: 'Application CV', docType: 'Application CV' }
                  ];

                  const checklistStatus = checklistItems.map(item => {
                    let docStatus = 'none';
                    let uploadDate = '';
                    if (item.docType && candidate.documents) {
                      const docs = candidate.documents.filter(d => d.type === item.docType || (item.altDocType && d.type === item.altDocType));
                      if (docs.length > 0) {
                        const sorted = [...docs].sort((a, b) => new Date(b.uploadedAt || 0).getTime() - new Date(a.uploadedAt || 0).getTime());
                        if (sorted[0]?.uploadedAt) uploadDate = new Date(sorted[0].uploadedAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
                        if (docs.some(d => d.status === 'Approved')) docStatus = 'Approved';
                        else if (docs.some(d => d.status === 'Pending Review')) docStatus = 'Pending Review';
                        else if (docs.some(d => d.status === 'Correction Required')) docStatus = 'Correction Required';
                        else if (docs.some(d => d.status === 'Rejected')) docStatus = 'Rejected';
                      }
                    }
                    return { ...item, docStatus, uploadDate };
                  });

                  const collectedCount = checklistStatus.filter(i => i.docStatus !== 'none').length;

                  return (
                    <section className="mt-8 pt-8 border-t border-slate-100 mb-6">
                      <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                        <span className="w-6 h-1 bg-purple-500 rounded-full"></span>
                        Certificates Checklist
                        <span className="ml-auto text-[11px] font-bold text-purple-600 bg-purple-50 px-2 py-0.5 rounded">{collectedCount}/14</span>
                      </h3>
                      <div className="rounded-lg border border-slate-200 overflow-hidden">
                        <div className="grid grid-cols-1 md:grid-cols-2 divide-x divide-slate-100">
                          {[checklistStatus.slice(0, 7), checklistStatus.slice(7, 14)].map((col, colIdx) => (
                            <div key={colIdx} className="divide-y divide-slate-100">
                              {col.map(item => {
                                const has = item.docStatus !== 'none';
                                let statusText = '—';
                                let statusClass = 'text-slate-300';
                                if (item.docStatus === 'Approved') { statusText = '✓ Verified'; statusClass = 'text-emerald-600'; }
                                else if (item.docStatus === 'Pending Review') { statusText = 'Reviewing'; statusClass = 'text-amber-600'; }
                                else if (item.docStatus === 'Correction Required' || item.docStatus === 'Rejected') { statusText = 'Issue'; statusClass = 'text-red-500'; }

                                return (
                                  <div key={item.num} className={`flex items-center gap-2.5 px-4 py-2 text-xs ${has ? 'bg-white' : 'bg-slate-50/50'}`}>
                                    <span className="text-[10px] font-mono text-slate-400 w-4 text-right shrink-0">{item.num}</span>
                                    <span className={`flex-1 truncate ${has ? 'text-slate-800 font-medium' : 'text-slate-400'}`}>{item.label}</span>
                                    {item.uploadDate && <span className="text-[10px] text-slate-400 shrink-0">{item.uploadDate}</span>}
                                    <span className={`text-[10px] font-semibold shrink-0 min-w-[60px] text-right ${statusClass}`}>{statusText}</span>
                                  </div>
                                );
                              })}
                            </div>
                          ))}
                        </div>
                      </div>
                    </section>
                  );
                })()}

                {/* SECTION 1.59: WORKFLOW MILESTONES (bottom tracking row on paper form) */}
                <section className="mt-8 pt-8 border-t border-slate-100 mb-6">
                  <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                    <span className="w-6 h-1 bg-cyan-500 rounded-full"></span>
                    Workflow Milestone Dates
                  </h3>

                  {isEditingProfile ? (
                    <div className="bg-cyan-50/50 p-6 rounded-xl border border-cyan-200 border-dashed">
                      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                        {[
                          { key: 'offerAppliedDate', label: 'Offer Applied' },
                          { key: 'offerReceivedDate', label: 'Offer Received' },
                          { key: 'wpAppliedDate', label: 'WP Applied' },
                          { key: 'wpReceivedDate', label: 'WP Received' },
                          { key: 'embAppliedDate', label: 'EMB Applied' },
                          { key: 'embAppointmentDate', label: 'EMB Appointment' },
                          { key: 'stampRejectDate', label: 'Stamp/Reject' },
                          { key: 'slbfeTrainingDate', label: 'SLBFE Training' },
                          { key: 'slbfeRegistrationDate', label: 'SLBFE Registration' },
                          { key: 'departureDate', label: 'Departure' },
                        ].map(milestone => (
                          <div key={milestone.key}>
                            <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1">{milestone.label}</label>
                            <input
                              type="date"
                              value={((editedProfile as any).workflowMilestones ?? {} as any)[milestone.key] || ''}
                              onChange={(e) => {
                                const existing = (editedProfile as any).workflowMilestones ?? {};
                                setEditedProfile({ ...editedProfile, workflowMilestones: { ...existing, [milestone.key]: e.target.value } } as any);
                              }}
                              className="w-full px-2 py-1.5 border border-slate-300 rounded-lg text-xs focus:ring-2 focus:ring-cyan-500"
                            />
                          </div>
                        ))}
                      </div>
                      <div className="mt-4 pt-3 border-t border-cyan-200">
                        <div>
                          <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1">Stamp Result Notes</label>
                          <input
                            type="text"
                            value={((editedProfile as any).workflowMilestones ?? {} as any).stampResult || ''}
                            onChange={(e) => {
                              const existing = (editedProfile as any).workflowMilestones ?? {};
                              setEditedProfile({ ...editedProfile, workflowMilestones: { ...existing, stampResult: e.target.value } } as any);
                            }}
                            placeholder="e.g. Stamped / Rejected - reason"
                            className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm"
                          />
                        </div>
                      </div>
                    </div>
                  ) : (
                    <div className="bg-cyan-50/30 p-5 rounded-xl border border-cyan-100">
                      {/* Progress bar visualization */}
                      <div className="flex items-center gap-0 overflow-x-auto pb-3">
                        {[
                          { key: 'offerAppliedDate', label: 'Offer\nApplied', icon: '📋' },
                          { key: 'offerReceivedDate', label: 'Offer\nReceived', icon: '📩' },
                          { key: 'wpAppliedDate', label: 'WP\nApplied', icon: '📝' },
                          { key: 'wpReceivedDate', label: 'WP\nReceived', icon: '✅' },
                          { key: 'embAppliedDate', label: 'EMB\nApplied', icon: '🏛️' },
                          { key: 'embAppointmentDate', label: 'EMB\nAppoint.', icon: '📅' },
                          { key: 'stampRejectDate', label: 'Stamp/\nReject', icon: '🔖' },
                          { key: 'slbfeTrainingDate', label: 'SLBFE\nTraining', icon: '🎓' },
                          { key: 'slbfeRegistrationDate', label: 'SLBFE\nReg.', icon: '📑' },
                          { key: 'departureDate', label: 'Departure', icon: '✈️' },
                        ].map((milestone, idx, arr) => {
                          const milestones = candidate.workflowMilestones || {} as any;
                          const date = (milestones as any)[milestone.key];
                          const isCompleted = !!date;
                          const isLast = idx === arr.length - 1;
                          return (
                            <div key={milestone.key} className="flex items-center flex-shrink-0">
                              <div className="flex flex-col items-center" style={{ minWidth: '72px' }}>
                                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm ${isCompleted ? 'bg-cyan-600 text-white shadow-md shadow-cyan-200' : 'bg-white border-2 border-slate-200 text-slate-400'}`}>
                                  {isCompleted ? '✓' : milestone.icon}
                                </div>
                                <span className="text-xs font-bold text-slate-600 mt-1.5 text-center whitespace-pre-line leading-tight">{milestone.label}</span>
                                <span className="text-[8px] font-medium text-cyan-700 mt-0.5">{date || '-'}</span>
                              </div>
                              {!isLast && (
                                <div className={`w-6 h-0.5 flex-shrink-0 ${isCompleted ? 'bg-cyan-400' : 'bg-slate-200'}`}></div>
                              )}
                            </div>
                          );
                        })}
                      </div>
                      {(candidate.workflowMilestones as any)?.stampResult && (
                        <div className="mt-2 pt-2 border-t border-cyan-100 text-xs">
                          <span className="font-bold text-slate-500 uppercase">Stamp Result: </span>
                          <span className="font-medium text-slate-700">{(candidate.workflowMilestones as any).stampResult}</span>
                        </div>
                      )}
                    </div>
                  )}
                </section>

                {/* SECTION 1.6: OFFICE USE ONLY */}
                <section className="mt-8 pt-8 border-t border-slate-100 mb-6">
                  <h3 className="text-base font-bold text-slate-800 tracking-tight mb-5 flex items-center gap-2">
                    <Briefcase size={18} className="text-violet-500" />
                    Office Use Only
                  </h3>

                  {isEditingProfile ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 bg-slate-50 p-6 rounded-xl border border-slate-200 border-dashed">
                      <div>
                        <label className="text-xs font-bold text-slate-500 uppercase">Customer Care Officer</label>
                        <input
                          type="text"
                          value={editedProfile.officeUseOnly?.customerCareOfficer || ''}
                          onChange={(e) => setEditedProfile({
                            ...editedProfile,
                            officeUseOnly: { ...(editedProfile.officeUseOnly || { customerCareOfficer: '', fileHandlingOfficer: '', date: '', charges: '' }), customerCareOfficer: e.target.value }
                          })}
                          className="w-full mt-1 p-2 text-sm border rounded-lg focus:ring-2 focus:ring-violet-500"
                        />
                      </div>
                      <div>
                        <label className="text-xs font-bold text-slate-500 uppercase">File Handling Officer</label>
                        <input
                          type="text"
                          value={editedProfile.officeUseOnly?.fileHandlingOfficer || ''}
                          onChange={(e) => setEditedProfile({
                            ...editedProfile,
                            officeUseOnly: { ...(editedProfile.officeUseOnly || { customerCareOfficer: '', fileHandlingOfficer: '', date: '', charges: '' }), fileHandlingOfficer: e.target.value }
                          })}
                          className="w-full mt-1 p-2 text-sm border rounded-lg focus:ring-2 focus:ring-violet-500"
                        />
                      </div>
                      <div>
                        <label className="text-xs font-bold text-slate-500 uppercase">Date</label>
                        <input
                          type="date"
                          value={editedProfile.officeUseOnly?.date || ''}
                          onChange={(e) => setEditedProfile({
                            ...editedProfile,
                            officeUseOnly: { ...(editedProfile.officeUseOnly || { customerCareOfficer: '', fileHandlingOfficer: '', date: '', charges: '' }), date: e.target.value }
                          })}
                          className="w-full mt-1 p-2 text-sm border rounded-lg focus:ring-2 focus:ring-violet-500"
                        />
                      </div>
                      <div>
                        <label className="text-xs font-bold text-slate-500 uppercase">Charges</label>
                        <input
                          type="text"
                          value={editedProfile.officeUseOnly?.charges || ''}
                          onChange={(e) => setEditedProfile({
                            ...editedProfile,
                            officeUseOnly: { ...(editedProfile.officeUseOnly || { customerCareOfficer: '', fileHandlingOfficer: '', date: '', charges: '' }), charges: e.target.value }
                          })}
                          placeholder="e.g. 1350000 + Ticket + Medical"
                          className="w-full mt-1 p-2 text-sm border rounded-lg focus:ring-2 focus:ring-violet-500"
                        />
                      </div>
                    </div>
                  ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 bg-slate-50 p-6 rounded-xl border border-slate-200 border-dashed">
                      <div>
                        <label className="text-xs font-bold text-slate-500 uppercase">Customer Care Officer</label>
                        <div className="text-sm font-medium text-slate-900 mt-1">{candidate?.officeUseOnly?.customerCareOfficer || '-'}</div>
                      </div>
                      <div>
                        <label className="text-xs font-bold text-slate-500 uppercase">File Handling Officer</label>
                        <div className="text-sm font-medium text-slate-900 mt-1">{candidate?.officeUseOnly?.fileHandlingOfficer || '-'}</div>
                      </div>
                      <div>
                        <label className="text-xs font-bold text-slate-500 uppercase">Date</label>
                        <div className="text-sm font-medium text-slate-900 mt-1">{candidate?.officeUseOnly?.date || '-'}</div>
                      </div>
                      <div>
                        <label className="text-xs font-bold text-slate-500 uppercase">Charges</label>
                        <div className="text-sm font-bold text-indigo-600 mt-1">{candidate?.officeUseOnly?.charges || '-'}</div>
                      </div>
                    </div>
                  )}
                </section>
              </div>
            )
            }

            {/* Documents Tab */}
            {
              activeTab === 'documents' && (
                <div className="bg-white rounded-xl border border-slate-200 p-6">
                  <DocumentManager
                    candidate={candidate}
                    onUpdate={handleDocumentUpdate}
                  />
                </div>
              )
            }


            {/* Timeline Tab */}
            {
              activeTab === 'timeline' && (
                <div className="bg-white rounded-xl border border-slate-200 p-6">
                  <TimelineView events={candidate.timelineEvents || []} />
                </div>
              )
            }

            {/* System Audit Tab */}
            {
              activeTab === 'audit' && (
                <div className="bg-white rounded-xl border border-slate-200 p-6 shadow-sm">
                  <CandidateReport candidate={candidate} />
                </div>
              )
            }

          </div>

          {/* Sidebar (30%) */}
          <div className="space-y-4">
            <QuickActionsWidget
              candidate={candidate}
              onDelete={handleDelete}
              onGenerateReport={handleGenerateReport}
              isGeneratingReport={isExportingReport}
            />
            <InterviewWidget
              candidate={candidate}
              onUpdate={handleInterviewUpdate}
            />
            <ComplianceWidget
              candidate={candidate}
              onUpdate={handleComplianceUpdate}
              onRefresh={refreshCandidates}
            />
            <SLBFEStatusWidget candidate={candidate} />
            <ActivityLogWidget
              candidate={candidate}
              onUpdate={handleRemarkLogUpdate}
              isEditable={true}
            />

            {/* Matched Jobs Widget */}
            {hasPermission('candidates.view') && matchedJobs.length > 0 && (
              <div className="bg-white rounded-xl border border-slate-200 p-5">
                <h4 className="text-sm font-bold text-slate-700 mb-3 flex items-center gap-2">
                  <Briefcase size={14} className="text-blue-500" />
                  Matched Jobs ({matchedJobs.length})
                </h4>
                <div className="space-y-2.5">
                  {matchedJobs.map(job => {
                    const employer = job.employerId ? employersMap[job.employerId] : null;
                    return (
                      <div key={job.id} className="p-3 bg-slate-50 rounded-lg border border-slate-100 hover:border-blue-200 transition-all">
                        <Link to={`/jobs?highlight=${job.id}`} className="text-sm font-bold text-slate-800 hover:text-blue-600 transition-colors">
                          {job.title}
                        </Link>
                        <div className="flex items-center gap-2 mt-1">
                          {employer && (
                            <Link to={`/partners/${employer.id}`} className="text-[10px] text-blue-500 hover:underline font-semibold">
                              {employer.companyName}
                            </Link>
                          )}
                          <span className="text-[10px] text-slate-400">•</span>
                          <span className="text-[10px] text-slate-500">{job.location}</span>
                        </div>
                        <div className="flex items-center justify-between mt-1.5">
                          <span className="text-[10px] text-green-600 font-bold">{job.salaryRange}</span>
                          <span className={`text-xs font-bold px-1.5 py-0.5 rounded ${job.status === 'Open' ? 'bg-green-50 text-green-600' :
                            job.status === 'Filled' ? 'bg-blue-50 text-blue-600' :
                              'bg-slate-100 text-slate-500'
                            }`}>{job.status}</span>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
            <WorkflowProgressWidget
              candidate={candidate}
              onAdvance={handleAdvanceStage}
              onRollback={handleRollback}
              onStageClick={handleStageClick}
            />
            <RecentActivityWidget
              candidate={candidate}
              onViewAll={() => {
                setActiveTab('timeline');
                document.getElementById('main-content-tabs')?.scrollIntoView({ behavior: 'smooth' });
              }}
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default CandidateDetail;

import React, { useState } from 'react';
import { Candidate, StageData, DocumentType, DocumentStatus, PaymentRecord, JobRole, Country, SLBFEData, BiometricStatus, PassportData, PassportStatus } from '../types';
import { TemplateService } from '../services/templateService';
import { DataSyncService } from '../services/dataSyncService';

import PreferredCountriesSelector from './ui/PreferredCountriesSelector';
import { X, Save, User, Briefcase, Globe, Activity, FileText, CreditCard, Plus, Trash2, ChevronDown, Check, ShieldCheck } from 'lucide-react';

interface CandidateFormProps {
  initialData?: Partial<Candidate>;
  onSubmit: (data: Partial<Candidate>) => void;
  onClose: () => void;
  title: string;
}

const CandidateForm: React.FC<CandidateFormProps> = ({ initialData, onSubmit, onClose, title }) => {
  // Normalize initial data using DataSyncService
  const initialSyncedData = initialData ? DataSyncService.fullSync(initialData) : null;

  // Document Status Defaults
  const passportPhotosDoc = initialData?.documents?.find(d => d.type === DocumentType.PASSPORT_PHOTOS);
  const fullPhotoDoc = initialData?.documents?.find(d => d.type === DocumentType.FULL_PHOTO);

  // Form State
  const [formData, setFormData] = useState({
    regNo: initialSyncedData?.regNo || '',
    surname: initialSyncedData?.surname || '',
    otherNames: initialSyncedData?.otherNames || '',
    nic: initialSyncedData?.nic || '',
    dob: initialSyncedData?.dob || '',
    gender: initialSyncedData?.gender || '',
    phone: initialSyncedData?.phone || '',
    secondaryPhone: initialSyncedData?.secondaryPhone || '',
    whatsapp: initialSyncedData?.whatsapp || initialSyncedData?.phone || '',
    email: initialSyncedData?.email || '',
    address: initialSyncedData?.address || '',
    city: initialSyncedData?.city || '',
    education: initialSyncedData?.education || [],
    nationality: initialSyncedData?.nationality || 'Sri Lankan',
    placeOfBirth: initialSyncedData?.placeOfBirth || '',
    passportProfession: initialSyncedData?.passportProfession || '',

    // Professional & Operational
    role: initialSyncedData?.role || '',
    location: initialSyncedData?.location || initialSyncedData?.city || '',
    experienceYears: initialSyncedData?.experienceYears,
    skills: initialSyncedData?.skills?.join(', ') || '',
    preferredCountries: initialSyncedData?.preferredCountries || [],
    jobRoles: initialSyncedData?.jobRoles || [],

    // Stage Data
    employerStatus: initialSyncedData?.stageData?.employerStatus || 'Pending',
    medicalStatus: initialSyncedData?.stageData?.medicalStatus || 'Pending',
    medicalScheduledDate: initialSyncedData?.stageData?.medicalScheduledDate || '',
    policeStatus: initialSyncedData?.stageData?.policeStatus || 'Pending',
    visaStatus: initialSyncedData?.stageData?.visaStatus || 'Pending',
    paymentStatus: initialSyncedData?.stageData?.paymentStatus || 'Pending',
    paymentNotes: initialSyncedData?.stageData?.paymentNotes || '',

    // photo docs status
    passportPhotosStatus: passportPhotosDoc?.status || DocumentStatus.PENDING,
    fullPhotoStatus: fullPhotoDoc?.status || DocumentStatus.PENDING,
    targetCountry: initialSyncedData?.targetCountry || initialSyncedData?.country || Country.SAUDI_ARABIA,

    // SLBFE Data
    slbfeRegNo: initialSyncedData?.slbfeData?.registrationNumber || '',
    slbfeRegDate: initialSyncedData?.slbfeData?.registrationDate || '',
    trainingDate: initialSyncedData?.slbfeData?.trainingDate || '',
    insurancePolicyNo: initialSyncedData?.slbfeData?.insurancePolicyNumber || '',
    insuranceExpiryDate: initialSyncedData?.slbfeData?.insuranceExpiryDate || '',
    biometricStatus: initialSyncedData?.slbfeData?.biometricStatus || BiometricStatus.PENDING,
    familyConsentGiven: initialSyncedData?.slbfeData?.familyConsent?.isGiven || false,
    agreementStatus: initialSyncedData?.slbfeData?.agreementStatus || 'Pending',
    spouseName: initialSyncedData?.spouseName || '',
    passports: initialSyncedData?.passports || [],
    officeUseOnly: initialSyncedData?.officeUseOnly || { customerCareOfficer: '', fileHandlingOfficer: '', date: '', charges: '' },

    // Phase 4-6 System Data
    wpReferenceNumber: initialSyncedData?.stageData?.wpReferenceNumber || '',
    travelInsurancePolicyNumber: initialSyncedData?.stageData?.travelInsurancePolicyNumber || '',
    travelInsuranceCoverageEndDate: initialSyncedData?.stageData?.travelInsuranceCoverageEndDate || '',
    flightNumber: initialSyncedData?.stageData?.flightNumber || '',
    flightPNR: initialSyncedData?.stageData?.flightPNR || '',
    flightDepartureTime: initialSyncedData?.stageData?.flightDepartureTime || '',
    workingVideoLink: initialSyncedData?.stageData?.workingVideoLink || '',
    selfIntroductionVideoLink: initialSyncedData?.stageData?.selfIntroductionVideoLink || '',
  });

  const [additionalVideoLinks, setAdditionalVideoLinks] = useState<string[]>(initialData?.stageData?.additionalVideoLinks || []);

  // Re-added missing states for JSX compatibility
  const [paymentHistory, setPaymentHistory] = useState<PaymentRecord[]>(initialData?.stageData?.paymentHistory || []);
  const [newPayment, setNewPayment] = useState({ date: '', amount: '', notes: '' });
  const [showSecondaryPhone, setShowSecondaryPhone] = useState(!!initialData?.secondaryPhone);
  const [jobRoles, setJobRoles] = useState<JobRole[]>(
    (initialData?.jobRoles || []).map(r => typeof r === 'string' ? { title: r, experienceYears: undefined as any, skillLevel: 'Skilled' } : r)
  );
  const [newJobRole, setNewJobRole] = useState<JobRole>({ title: '', experienceYears: undefined as any, skillLevel: 'Skilled', notes: '' });
  const [countrySearch, setCountrySearch] = useState('');
  const [showCountryDropdown, setShowCountryDropdown] = useState(false);
  const [showEducationDropdown, setShowEducationDropdown] = useState(false);

  const age = React.useMemo(() => {
    if (!formData.dob) return '';
    const birthDate = new Date(formData.dob);
    const today = new Date();
    let calculatedAge = today.getFullYear() - birthDate.getFullYear();
    const m = today.getMonth() - birthDate.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
      calculatedAge--;
    }
    return calculatedAge.toString();
  }, [formData.dob]);

  const handleAddPayment = () => {
    if (!newPayment.amount || !newPayment.date) return;
    const record: PaymentRecord = {
      id: `pay-${Date.now()}`,
      date: newPayment.date,
      amount: newPayment.amount,
      notes: newPayment.notes
    };
    setPaymentHistory([...paymentHistory, record]);
    setNewPayment({ date: '', amount: '', notes: '' });
  };

  const handleRemovePayment = (id: string) => {
    setPaymentHistory(paymentHistory.filter(p => p.id !== id));
  };

  const handleAddPassport = () => {
    setFormData(prev => ({
      ...prev,
      passports: [
        ...prev.passports,
        {
          passportNumber: '',
          country: Country.SAUDI_ARABIA, // Default
          issuedDate: '',
          expiryDate: '',
          status: PassportStatus.VALID,
          validityDays: 0
        }
      ]
    }));
  };

  const handleAddVideoLink = () => {
    setAdditionalVideoLinks(prev => [...prev, '']);
  };

  const handleUpdateVideoLink = (index: number, value: string) => {
    setAdditionalVideoLinks(prev => {
      const updated = [...prev];
      updated[index] = value;
      return updated;
    });
  };

  const handleRemoveVideoLink = (index: number) => {
    setAdditionalVideoLinks(prev => prev.filter((_, i) => i !== index));
  };

  const handleRemovePassport = (index: number) => {
    setFormData(prev => ({
      ...prev,
      passports: prev.passports.filter((_, i) => i !== index)
    }));
  };

  const handlePassportChange = (index: number, field: keyof PassportData, value: any) => {
    setFormData(prev => {
      const updatedPassports = [...prev.passports];
      updatedPassports[index] = { ...updatedPassports[index], [field]: value };
      return { ...prev, passports: updatedPassports };
    });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const stageDataUpdate: StageData = {
      ...initialData?.stageData,
      employerStatus: formData.employerStatus as StageData['employerStatus'],
      medicalStatus: formData.medicalStatus as StageData['medicalStatus'],
      medicalScheduledDate: formData.medicalStatus === 'Scheduled' ? formData.medicalScheduledDate : undefined,
      policeStatus: formData.policeStatus as StageData['policeStatus'],
      visaStatus: formData.visaStatus as StageData['visaStatus'],
      paymentStatus: formData.paymentStatus as StageData['paymentStatus'],
      paymentNotes: formData.paymentNotes,
      paymentHistory: paymentHistory,
      // Phase 4-6 tracking data
      wpReferenceNumber: formData.wpReferenceNumber,
      travelInsurancePolicyNumber: formData.travelInsurancePolicyNumber,
      travelInsuranceCoverageEndDate: formData.travelInsuranceCoverageEndDate,
      flightNumber: formData.flightNumber,
      flightPNR: formData.flightPNR,
      flightDepartureTime: formData.flightDepartureTime,
      workingVideoLink: formData.workingVideoLink,
      selfIntroductionVideoLink: formData.selfIntroductionVideoLink,
      additionalVideoLinks: additionalVideoLinks.filter(link => link.trim() !== ''),
    };

    // Update documents if in Edit Mode (initialData.documents exists)
    let updatedDocuments = initialData?.documents;
    if (updatedDocuments) {
      updatedDocuments = updatedDocuments.map(doc => {
        if (doc.type === DocumentType.PASSPORT_PHOTOS) {
          return { ...doc, status: formData.passportPhotosStatus as DocumentStatus };
        }
        if (doc.type === DocumentType.FULL_PHOTO) {
          return { ...doc, status: formData.fullPhotoStatus as DocumentStatus };
        }
        return doc;
      });
    }

    const slbfeDataUpdate: SLBFEData = {
      ...initialData?.slbfeData,
      registrationNumber: formData.slbfeRegNo,
      registrationDate: formData.slbfeRegDate,
      trainingDate: formData.trainingDate,
      insurancePolicyNumber: formData.insurancePolicyNo,
      insuranceExpiryDate: formData.insuranceExpiryDate,
      biometricStatus: formData.biometricStatus as BiometricStatus,
      familyConsent: {
        ...initialData?.slbfeData?.familyConsent,
        isGiven: formData.familyConsentGiven
      },
      agreementStatus: formData.agreementStatus as any
    };

    const constructedName = `${formData.otherNames} ${formData.surname}`.trim();
    const skillsArray = formData.skills.split(',').map((s: string) => s.trim()).filter((s: string) => s);

    const processedData = DataSyncService.fullSync({
      ...initialData,
      ...formData,
      name: constructedName,
      location: formData.city ? `${formData.city}, ${formData.address}` : formData.address,
      skills: skillsArray,
      preferredCountries: formData.preferredCountries,
      jobRoles: jobRoles,
      slbfeData: slbfeDataUpdate,
      stageData: stageDataUpdate,
      passports: formData.passports,
      documents: updatedDocuments,
      officeUseOnly: formData.officeUseOnly,
      secondaryPhone: formData.secondaryPhone,
    });

    onSubmit(processedData);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-[100] p-4 backdrop-blur-sm">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-3xl max-h-[90vh] overflow-y-auto border border-slate-200">
        <div className="sticky top-0 bg-white z-10 flex justify-between items-center p-6 border-b border-slate-100">
          <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <User className="text-blue-600" /> {title}
          </h3>
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors">
            <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-8">

          {/* PERSONAL INFORMATION */}
          <div className="space-y-6">
            <h4 className="font-bold text-slate-400 uppercase tracking-wider text-xs border-b border-slate-100 pb-2 mb-4">
              Personal Information
            </h4>

            {/* Row 0: Reg No */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
              <div className="space-y-1 md:col-span-2">
                <label className="text-sm font-semibold text-slate-700">Registration Number</label>
                <input
                  name="regNo"
                  value={formData.regNo}
                  onChange={handleChange}
                  placeholder="e.g. SC 126"
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all font-bold text-red-700 max-w-sm"
                />
              </div>
            </div>

            {/* Row 1: Name */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1">
                <label className="text-sm font-semibold text-slate-700">Surname <span className="text-red-500">*</span></label>
                <input
                  name="surname"
                  value={formData.surname}
                  // FRICTIONLESS: required removed
                  onChange={handleChange}
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                />
              </div>
              <div className="space-y-1">
                <label className="text-sm font-semibold text-slate-700">Other Names <span className="text-red-500">*</span></label>
                <input
                  name="otherNames"
                  value={formData.otherNames}
                  onChange={handleChange}
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                />
              </div>
            </div>

            {/* Row 2: NIC & DOB */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1">
                <label className="text-sm font-semibold text-slate-700">NIC <span className="text-red-500">*</span></label>
                <input
                  name="nic"
                  value={formData.nic}
                  // FRICTIONLESS: required removed
                  onChange={handleChange}
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                />
              </div>
              <div className="space-y-1">
                <label className="text-sm font-semibold text-slate-700">Date of Birth <span className="text-red-500">*</span></label>
                <div className="relative">
                  <input
                    name="dob"
                    type="date"
                    value={formData.dob}
                    onChange={handleChange}
                    className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                  />
                </div>
              </div>
            </div>

            {/* Row 3: Age & Gender */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1">
                <label className="text-sm font-semibold text-slate-700">Age</label>
                <input
                  value={age}
                  disabled
                  className="w-full px-4 py-2.5 bg-slate-100 border border-slate-200 rounded-lg text-slate-500 cursor-not-allowed"
                />
              </div>
              <div className="space-y-1">
                <label className="text-sm font-semibold text-slate-700">Gender <span className="text-red-500">*</span></label>
                <select
                  name="gender"
                  value={formData.gender}
                  onChange={handleChange}
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                >
                  <option value="">Select Gender</option>
                  <option value="Male">Male</option>
                  <option value="Female">Female</option>
                </select>
              </div>
            </div>

            {/* Row 4: Passport Info */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-1">
                <label className="text-sm font-semibold text-slate-700">Place of Birth</label>
                <input
                  name="placeOfBirth"
                  value={formData.placeOfBirth}
                  onChange={handleChange}
                  placeholder="e.g. KEGALLA"
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                />
              </div>
              <div className="space-y-1">
                <label className="text-sm font-semibold text-slate-700">National Status</label>
                <input
                  name="nationality"
                  value={formData.nationality}
                  onChange={handleChange}
                  placeholder="SRI LANKAN"
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                />
              </div>
              <div className="space-y-1">
                <label className="text-sm font-semibold text-slate-700">Profession (Passport)</label>
                <input
                  name="passportProfession"
                  value={formData.passportProfession}
                  onChange={handleChange}
                  placeholder="e.g. HEAVY VEHICLE DRIVER"
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                />
              </div>
            </div>


            {/* Row 4: Phones */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1">
                <label className="text-sm font-semibold text-slate-700">Telephone Number <span className="text-red-500">*</span></label>
                <div className="flex gap-2">
                  <input
                    name="phone"
                    value={formData.phone}
                    // FRICTIONLESS: required removed
                    onChange={(e) => {
                      const val = e.target.value;
                      setFormData(prev => ({ ...prev, phone: val }));
                      // Auto-sync WhatsApp if it was matching phone
                      if (formData.whatsapp === formData.phone) {
                        setFormData(prev => ({ ...prev, whatsapp: val }));
                      }
                    }}
                    className="flex-1 px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                  />
                  {!showSecondaryPhone && (
                    <button
                      type="button"
                      onClick={() => setShowSecondaryPhone(true)}
                      className="px-3 py-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-100 transition-colors"
                      title="Add Secondary Phone"
                    >
                      <Plus size={20} />
                    </button>
                  )}
                </div>
                {showSecondaryPhone && (
                  <div className="flex gap-2 mt-2 animate-in slide-in-from-top-2 fade-in">
                    <input
                      name="secondaryPhone"
                      placeholder="Secondary Phone (Optional)"
                      value={formData.secondaryPhone}
                      onChange={handleChange}
                      className="flex-1 px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                    />
                    <button
                      type="button"
                      onClick={() => {
                        setShowSecondaryPhone(false);
                        setFormData(prev => ({ ...prev, secondaryPhone: '' }));
                      }}
                      className="px-3 py-2 bg-red-50 text-red-500 rounded-lg hover:bg-red-100 transition-colors"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                )}
              </div>
              <div className="space-y-1">
                <label className="text-sm font-semibold text-slate-700">WhatsApp Number <span className="text-red-500">*</span></label>
                <input
                  name="whatsapp"
                  value={formData.whatsapp}
                  // FRICTIONLESS: required removed
                  onChange={handleChange}
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                />
              </div>
            </div>

            {/* Row 5: Email */}
            <div className="space-y-1">
              <label className="text-sm font-semibold text-slate-700">Email</label>
              <input
                name="email"
                type="email"
                value={formData.email}
                onChange={handleChange}
                className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
              />
            </div>

            {/* Row 6: Address */}
            <div className="space-y-1">
              <label className="text-sm font-semibold text-slate-700">Address Line <span className="text-red-500">*</span></label>
              <input
                name="address"
                value={formData.address}
                onChange={handleChange}
                className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
              />
            </div>

            {/* Row 7: City */}
            <div className="space-y-1">
              <label className="text-sm font-semibold text-slate-700">City <span className="text-red-500">*</span></label>
              <input
                name="city"
                value={formData.city}
                onChange={handleChange}
                className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
              />
            </div>

            {/* Row 8: Education */}
            {/* Row 8: Education (Multi-Select) */}
            <div className="space-y-1 relative">
              <label className="text-sm font-semibold text-slate-700">Highest Education <span className="text-red-500">*</span></label>

              <div className="flex flex-wrap gap-2 mb-2">
                {Array.isArray(formData.education) && formData.education.map((edu: string) => (
                  <span key={edu} className="bg-emerald-100 text-emerald-800 text-xs font-semibold px-2.5 py-1 rounded-full flex items-center gap-1">
                    {edu}
                    <button type="button" onClick={() => setFormData(p => ({ ...p, education: (p.education as string[]).filter(e => e !== edu) }))}>
                      <X size={12} className="hover:text-red-600" />
                    </button>
                  </span>
                ))}
              </div>

              <div className="relative">
                <button
                  type="button"
                  onClick={() => setShowEducationDropdown(!showEducationDropdown)}
                  className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-left flex justify-between items-center text-sm"
                >
                  <span className={!formData.education || formData.education.length === 0 ? 'text-slate-400' : 'text-slate-800'}>
                    {!formData.education || formData.education.length === 0 ? 'Select Qualifications...' : 'Add more...'}
                  </span>
                  <ChevronDown size={16} className="text-slate-400" />
                </button>

                {showEducationDropdown && (
                  <div className="absolute z-30 w-full mt-1 bg-white border border-slate-200 rounded-lg shadow-lg max-h-48 overflow-y-auto">
                    {['G.C.E O/L', 'G.C.E A/L', 'Diploma', 'NVQ 3', 'NVQ 4', 'HND', 'Bachelor\'s Degree', 'Master\'s Degree', 'PhD', 'Other']
                      .filter(e => !formData.education?.includes(e))
                      .map(edu => (
                        <div
                          key={edu}
                          onClick={() => {
                            const current = Array.isArray(formData.education) ? formData.education : [];
                            setFormData(p => ({ ...p, education: [...current, edu] }));
                            setShowEducationDropdown(false);
                          }}
                          className="px-4 py-2 hover:bg-emerald-50 cursor-pointer text-sm text-slate-700 group flex items-center justify-between"
                        >
                          {edu}
                          <Check size={14} className="opacity-0 group-hover:opacity-100 text-emerald-600" />
                        </div>
                      ))}
                  </div>
                )}
              </div>
            </div>
          </div >

          {/* PROFESSIONAL DETAILS (Preserving necessary system fields) */}
          < div className="space-y-6" >
            <h4 className="font-bold text-slate-400 uppercase tracking-wider text-xs border-b border-slate-100 pb-2 mb-4">
              Professional Details
            </h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1">
                <label className="text-sm font-semibold text-slate-700">Job Role</label>
                <input
                  name="role"
                  value={formData.role}
                  onChange={handleChange}
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                  placeholder="e.g. Civil Engineer"
                />
              </div>
              <div className="space-y-1">
                <label className="text-sm font-semibold text-slate-700">Experience (Years)</label>
                <input
                  name="experienceYears"
                  type="number"
                  min="0"
                  value={formData.experienceYears || ''}
                  onChange={handleChange}
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                />
              </div>
            </div>
            <div className="space-y-1">
              <label className="text-sm font-semibold text-slate-700">Skills (Comma separated)</label>
              <input
                name="skills"
                value={formData.skills}
                onChange={handleChange}
                className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
              />
            </div>
            <h4 className="font-bold text-slate-400 uppercase tracking-wider text-xs border-b border-slate-100 pb-2 mb-4">
              Job & Preferences
            </h4>

            {/* Preferred Countries - Split Region */}
            <div className="space-y-4 mb-6">
              <div className="bg-slate-50 border border-slate-200 rounded-lg p-3">
                <h5 className="text-sm font-bold text-slate-700 mb-2 flex items-center gap-2">
                  <Globe size={14} className="text-purple-600" /> Europe Preferences
                </h5>
                <PreferredCountriesSelector
                  label=""
                  allowedRegions={['Europe']}
                  selectedCountries={formData.preferredCountries}
                  onChange={(countries) => setFormData(p => ({ ...p, preferredCountries: countries }))}
                />
              </div>

              <div className="bg-slate-50 border border-slate-200 rounded-lg p-3">
                <h5 className="text-sm font-bold text-slate-700 mb-2 flex items-center gap-2">
                  <Globe size={14} className="text-amber-600" /> Middle East Preferences
                </h5>
                <PreferredCountriesSelector
                  label=""
                  allowedRegions={['Middle East']}
                  selectedCountries={formData.preferredCountries}
                  onChange={(countries) => setFormData(p => ({ ...p, preferredCountries: countries }))}
                />
              </div>

              <div className="bg-slate-50 border border-slate-200 rounded-lg p-3">
                <h5 className="text-sm font-bold text-slate-700 mb-2 flex items-center gap-2">
                  <Globe size={14} className="text-blue-600" /> Southeast Asia Preferences
                </h5>
                <PreferredCountriesSelector
                  label=""
                  allowedRegions={['Southeast Asia']}
                  selectedCountries={formData.preferredCountries}
                  onChange={(countries) => setFormData(p => ({ ...p, preferredCountries: countries }))}
                />
              </div>
            </div>

            {/* DYNAMIC JOB ROLES */}
            <div className="space-y-4 pt-4 border-t border-slate-100">
              <h5 className="font-bold text-slate-700 text-sm flex items-center gap-2">
                Job Roles & Experience <Briefcase size={14} className="text-blue-600" />
              </h5>

              {jobRoles.map((role, idx) => (
                <div key={idx} className="flex gap-2 items-start bg-slate-50 p-3 rounded-lg border border-slate-200">
                  <div className="grid grid-cols-12 gap-2 flex-1">
                    <div className="col-span-4">
                      <span className="text-xs font-semibold text-slate-500 block">Title</span>
                      <span className="text-sm font-medium text-slate-800">{role.title}</span>
                    </div>
                    <div className="col-span-2">
                      <span className="text-xs font-semibold text-slate-500 block">Exp</span>
                      <span className="text-sm text-slate-800">{role.experienceYears}y</span>
                    </div>
                    <div className="col-span-3">
                      <span className="text-xs font-semibold text-slate-500 block">Level</span>
                      <span className="text-xs bg-blue-100 text-blue-800 px-2 py-0.5 rounded-full">{role.skillLevel}</span>
                    </div>
                    <div className="col-span-3">
                      <span className="text-xs font-semibold text-slate-500 block">Notes</span>
                      <span className="text-xs text-slate-600 truncate">{role.notes || '-'}</span>
                    </div>
                  </div>
                  <button type="button" onClick={() => setJobRoles(prev => prev.filter((_, i) => i !== idx))} className="text-red-400 hover:text-red-600 p-1">
                    <Trash2 size={16} />
                  </button>
                </div>
              ))}

              <div className="flex gap-2 items-end bg-blue-50/50 p-3 rounded-lg border border-blue-100 border-dashed">
                <div className="flex-1 grid grid-cols-12 gap-2">
                  <div className="col-span-4 space-y-1">
                    <label className="text-[10px] uppercase font-bold text-slate-400">Title</label>
                    <input
                      value={newJobRole.title}
                      onChange={e => setNewJobRole(p => ({ ...p, title: e.target.value }))}
                      className="w-full px-2 py-1.5 text-sm border border-slate-300 rounded outline-none"
                      placeholder="Job Title"
                    />
                  </div>
                  <div className="col-span-2 space-y-1">
                    <label className="text-[10px] uppercase font-bold text-slate-400">Yrs</label>
                    <input
                      type="number"
                      placeholder="e.g. 5"
                      value={newJobRole.experienceYears || ''}
                      onChange={e => setNewJobRole(p => ({ ...p, experienceYears: e.target.value ? parseInt(e.target.value) : '' as any }))}
                      className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    />
                  </div>
                  <div className="col-span-3 space-y-1">
                    <label className="text-[10px] uppercase font-bold text-slate-400">Level</label>
                    <select
                      value={newJobRole.skillLevel}
                      onChange={e => setNewJobRole(p => ({ ...p, skillLevel: e.target.value as JobRole['skillLevel'] }))}
                      className="w-full px-2 py-1.5 text-sm border border-slate-300 rounded outline-none"
                    >
                      <option>Beginner</option>
                      <option>Intermediate</option>
                      <option>Skilled</option>
                      <option>Expert</option>
                    </select>
                  </div>
                  <div className="col-span-3 space-y-1">
                    <label className="text-[10px] uppercase font-bold text-slate-400">Notes</label>
                    <input
                      value={newJobRole.notes}
                      onChange={e => setNewJobRole(p => ({ ...p, notes: e.target.value }))}
                      className="w-full px-2 py-1.5 text-sm border border-slate-300 rounded outline-none"
                      placeholder="Opt..."
                    />
                  </div>
                </div>
                <button
                  type="button"
                  onClick={() => {
                    if (newJobRole.title) {
                      setJobRoles([...jobRoles, newJobRole]);
                      setNewJobRole({ title: '', experienceYears: undefined as any, skillLevel: 'Skilled', notes: '' });
                    }
                  }}
                  className="bg-blue-600 text-white p-2 rounded hover:bg-blue-700 transition-colors"
                >
                  <Plus size={16} />
                </button>
              </div>
            </div>
            <div className="space-y-1">
              <label className="text-sm font-semibold text-slate-700">Target Country <span className="text-red-500">*</span></label>
              <select
                name="targetCountry"
                value={formData.targetCountry}
                onChange={handleChange}
                className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              >
                {TemplateService.getCountries().map(country => (
                  <option key={country} value={country}>{country}</option>
                ))}
              </select>
              <p className="text-[10px] text-slate-400 mt-1">This will automatically generate the required document checklist for this region.</p>
            </div>
          </div >

          {/* REGISTRATION DOCUMENTS */}
          < div className="pt-2" >
            <h4 className="font-bold text-slate-400 uppercase tracking-wider text-xs border-b border-slate-100 pb-2 mb-4 flex items-center gap-2">
              Registration Documents <FileText size={12} />
            </h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-slate-50 p-6 rounded-xl border border-slate-100">
              <div className="space-y-2">
                <label className="text-sm font-semibold text-slate-700">Passport Photos (6)</label>
                <select
                  name="passportPhotosStatus"
                  value={formData.passportPhotosStatus}
                  onChange={handleChange}
                  className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer"
                >
                  {Object.values(DocumentStatus).map(status => (
                    <option key={status} value={status}>{status}</option>
                  ))}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-semibold text-slate-700">Full Photo (1)</label>
                <select
                  name="fullPhotoStatus"
                  value={formData.fullPhotoStatus}
                  onChange={handleChange}
                  className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer"
                >
                  {Object.values(DocumentStatus).map(status => (
                    <option key={status} value={status}>{status}</option>
                  ))}
                </select>
              </div>
            </div>

            {/* Passports Section */}
            <div className="mt-6 pt-4 border-t border-slate-100">
              <div className="flex justify-between items-center mb-3">
                <label className="text-sm font-bold text-slate-700 flex items-center gap-2">
                  Valid Passports <ShieldCheck size={14} className="text-emerald-600" />
                </label>
                <button
                  type="button"
                  onClick={handleAddPassport}
                  className="text-white bg-blue-600 hover:bg-blue-700 text-xs px-3 py-1.5 rounded-lg flex items-center gap-1 font-bold transition-colors"
                >
                  <Plus size={14} /> Add Passport
                </button>
              </div>

              <div className="space-y-3">
                {formData.passports && formData.passports.length > 0 ? (
                  formData.passports.map((passport, idx) => (
                    <div key={idx} className="bg-slate-50 p-3 rounded-lg border border-slate-200 relative group">
                      <button
                        type="button"
                        onClick={() => handleRemovePassport(idx)}
                        className="absolute top-2 right-2 text-slate-400 hover:text-red-500 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <Trash2 size={14} />
                      </button>

                      <div className="grid grid-cols-1 md:grid-cols-12 gap-3">
                        <div className="md:col-span-3">
                          <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Passport No</label>
                          <input
                            value={passport.passportNumber}
                            onChange={(e) => handlePassportChange(idx, 'passportNumber', e.target.value)}
                            placeholder="N/A"
                            className="w-full px-2 py-1.5 text-sm bg-white border border-slate-200 rounded outline-none focus:border-blue-500"
                          />
                        </div>
                        <div className="md:col-span-3">
                          <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Country</label>
                          <select
                            value={passport.country}
                            onChange={(e) => handlePassportChange(idx, 'country', e.target.value)}
                            className="w-full px-2 py-1.5 text-sm bg-white border border-slate-200 rounded outline-none focus:border-blue-500"
                          >
                            {TemplateService.getCountries().map(c => (
                              <option key={c} value={c}>{c}</option>
                            ))}
                          </select>
                        </div>
                        <div className="md:col-span-3">
                          <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Issued Date</label>
                          <input
                            type="date"
                            value={passport.issuedDate ? new Date(passport.issuedDate).toISOString().split('T')[0] : ''}
                            onChange={(e) => handlePassportChange(idx, 'issuedDate', e.target.value)}
                            className="w-full px-2 py-1.5 text-sm bg-white border border-slate-200 rounded outline-none focus:border-blue-500"
                          />
                        </div>
                        <div className="md:col-span-3">
                          <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Expiry Date</label>
                          <input
                            type="date"
                            value={passport.expiryDate ? new Date(passport.expiryDate).toISOString().split('T')[0] : ''}
                            onChange={(e) => handlePassportChange(idx, 'expiryDate', e.target.value)}
                            className="w-full px-2 py-1.5 text-sm bg-white border border-slate-200 rounded outline-none focus:border-blue-500"
                          />
                        </div>
                      </div>
                    </div>
                  ))
                ) : (
                  <div className="text-center p-6 bg-slate-50 rounded-lg border border-dashed border-slate-300">
                    <Globe size={24} className="mx-auto text-slate-300 mb-2" />
                    <p className="text-xs text-slate-500 mb-3">No passport details added.</p>
                    <button type="button" onClick={handleAddPassport} className="text-blue-600 font-semibold text-xs hover:underline">
                      Add Primary Passport
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div >

          {/* OPERATIONAL STATUS */}
          < div className="pt-2" >
            <h4 className="font-bold text-slate-400 uppercase tracking-wider text-xs border-b border-slate-100 pb-2 mb-4 flex items-center gap-2">
              Operational Statuses <Activity size={12} />
            </h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-slate-50 p-6 rounded-xl border border-slate-100">
              <div className="space-y-2">
                <label className="text-sm font-semibold text-slate-700">Employer Selection</label>
                <select
                  name="employerStatus"
                  value={formData.employerStatus}
                  onChange={handleChange}
                  className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer"
                >
                  <option value="Pending">Pending</option>
                  <option value="Selected">Selected</option>
                  <option value="Rejected">Rejected</option>
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-semibold text-slate-700">Medical Status</label>
                <select
                  name="medicalStatus"
                  value={formData.medicalStatus}
                  onChange={handleChange}
                  className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer"
                >
                  <option value="Pending">Pending</option>
                  <option value="Scheduled">Scheduled</option>
                  <option value="Cleared">Cleared</option>
                  <option value="Failed">Failed</option>
                </select>

                {formData.medicalStatus === 'Scheduled' && (
                  <div className="animate-in fade-in slide-in-from-top-2">
                    <label className="text-[11px] font-bold text-blue-600 uppercase tracking-wider mb-1 block">Appointment Date <span className="text-red-500">*</span></label>
                    <input
                      type="date"
                      name="medicalScheduledDate"
                      value={formData.medicalScheduledDate}
                      onChange={handleChange}
                      // FRICTIONLESS: required removed
                      className="w-full px-4 py-2 bg-blue-50 border border-blue-200 rounded-lg text-blue-800 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                    />
                  </div>
                )}
              </div>

              <div className="space-y-2">
                <label className="text-sm font-semibold text-slate-700">Police Clearance</label>
                <select
                  name="policeStatus"
                  value={formData.policeStatus}
                  onChange={handleChange}
                  className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer"
                >
                  <option value="Pending">Pending</option>
                  <option value="Applied">Applied</option>
                  <option value="Issued">Issued</option>
                  <option value="Rejected">Rejected</option>
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-semibold text-slate-700">Visa Status</label>
                <select
                  name="visaStatus"
                  value={formData.visaStatus}
                  onChange={handleChange}
                  className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer"
                >
                  <option value="Pending">Pending</option>
                  <option value="Submitted">Submitted</option>
                  <option value="Approved">Approved</option>
                  <option value="Rejected">Rejected</option>
                </select>
              </div>
            </div>
          </div >

          {/* PAYMENT DETAILS SECTION */}
          < div className="pt-2" >
            <h4 className="font-bold text-slate-400 uppercase tracking-wider text-xs border-b border-slate-100 pb-2 mb-4 flex items-center gap-2">
              Payment Details <CreditCard size={12} />
            </h4>
            <div className="bg-slate-50 p-6 rounded-xl border border-slate-100 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700">Overall Payment Status</label>
                  <select
                    name="paymentStatus"
                    value={formData.paymentStatus}
                    onChange={handleChange}
                    className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer"
                  >
                    <option value="Pending">Pending</option>
                    <option value="Partial">Partial</option>
                    <option value="Completed">Completed</option>
                  </select>
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700">General Notes</label>
                  <input
                    name="paymentNotes"
                    value={formData.paymentNotes}
                    onChange={handleChange}
                    placeholder="Overall payment remarks..."
                    className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  />
                </div>
              </div>

              {/* Payment History Table */}
              <div className="bg-white rounded-lg border border-slate-200 overflow-hidden">
                <div className="p-3 bg-slate-50 border-b border-slate-200 font-semibold text-xs text-slate-500 uppercase flex justify-between items-center">
                  <span>Payment History</span>
                  <span className="text-[10px] bg-blue-100 text-blue-700 px-2 py-0.5 rounded-full">{paymentHistory.length} Records</span>
                </div>

                {/* List */}
                <div className="max-h-48 overflow-y-auto">
                  {paymentHistory.length > 0 ? (
                    <table className="w-full text-left text-sm">
                      <thead className="bg-slate-50 text-slate-500 text-xs">
                        <tr>
                          <th className="px-4 py-2">Date</th>
                          <th className="px-4 py-2">Amount</th>
                          <th className="px-4 py-2">Notes</th>
                          <th className="px-4 py-2 text-right">Action</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                        {paymentHistory.map(record => (
                          <tr key={record.id}>
                            <td className="px-4 py-2 text-slate-700">{record.date}</td>
                            <td className="px-4 py-2 font-mono font-medium text-slate-800">{record.amount}</td>
                            <td className="px-4 py-2 text-slate-500 text-xs truncate max-w-[150px]">{record.notes}</td>
                            <td className="px-4 py-2 text-right">
                              <button onClick={() => handleRemovePayment(record.id)} className="text-red-400 hover:text-red-600 transition-colors">
                                <Trash2 size={14} />
                              </button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  ) : (
                    <div className="p-4 text-center text-sm text-slate-400 italic">No payments recorded yet.</div>
                  )}
                </div>

                {/* Add New Record */}
                <div className="p-3 bg-slate-50 border-t border-slate-200 grid grid-cols-12 gap-3 items-end">
                  <div className="col-span-3">
                    <label className="block text-xs font-semibold text-slate-500 mb-1">Date</label>
                    <input
                      type="date"
                      value={newPayment.date}
                      onChange={(e) => setNewPayment({ ...newPayment, date: e.target.value })}
                      className="w-full px-2 py-1.5 text-sm border border-slate-200 rounded focus:ring-1 focus:ring-blue-500 outline-none"
                    />
                  </div>
                  <div className="col-span-3">
                    <label className="block text-xs font-semibold text-slate-500 mb-1">Amount</label>
                    <input
                      type="text"
                      placeholder="0.00"
                      value={newPayment.amount}
                      onChange={(e) => setNewPayment({ ...newPayment, amount: e.target.value })}
                      className="w-full px-2 py-1.5 text-sm border border-slate-200 rounded focus:ring-1 focus:ring-blue-500 outline-none"
                    />
                  </div>
                  <div className="col-span-5">
                    <label className="block text-xs font-semibold text-slate-500 mb-1">Notes</label>
                    <input
                      type="text"
                      placeholder="e.g. Initial deposit"
                      value={newPayment.notes}
                      onChange={(e) => setNewPayment({ ...newPayment, notes: e.target.value })}
                      className="w-full px-2 py-1.5 text-sm border border-slate-200 rounded focus:ring-1 focus:ring-blue-500 outline-none"
                    />
                  </div>
                  <div className="col-span-1">
                    <button
                      type="button"
                      onClick={handleAddPayment}
                      className="w-full flex items-center justify-center h-[34px] bg-blue-600 text-white rounded hover:bg-blue-700 transition-colors"
                      title="Add Payment"
                    >
                      <Plus size={16} />
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div >

          {/* SLBFE COMPLIANCE SECTION */}
          < div className="pt-2" >
            <h4 className="font-bold text-slate-400 uppercase tracking-wider text-xs border-b border-slate-100 pb-2 mb-4 flex items-center gap-2">
              SLBFE Compliance <ShieldCheck size={12} />
