import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { List } from 'react-window';
import { useCandidates } from '../context/CandidateContext';
import { Candidate, ProfileCompletionStatus, WorkflowStage } from '../types';
import { AuditService } from '../services/auditService';
import { Download, Users, X, ArrowRight, Loader2 } from 'lucide-react';
import { Link, useSearchParams, useNavigate } from 'react-router-dom';
import FilterBar from './FilterBar';
import Skeleton from './ui/Skeleton';
import { convertToCSV } from '../services/csvExportService';
import { useDebounce } from '../hooks/useDebounce';
import { CandidateService } from '../services/candidateService';
import { supabase } from '../services/supabase';
import { useAuth } from '../context/AuthContext';

const PAGE_SIZE = 50;

const areEqual = (prevProps: any, nextProps: any) => {
  const index = prevProps.rowIndex ?? prevProps.index;
  const nextIndex = nextProps.rowIndex ?? nextProps.index;

  const prevCand = prevProps.candidates?.[index];
  const nextCand = nextProps.candidates?.[nextIndex];

  if (prevCand?.id !== nextCand?.id || prevCand?.stage !== nextCand?.stage || prevCand?.profileCompletionStatus !== nextCand?.profileCompletionStatus) {
    return false;
  }

  const wasSelected = prevProps.selectedIds?.includes(prevCand?.id);
  const isSelected = nextProps.selectedIds?.includes(nextCand?.id);

  return wasSelected === isSelected && prevProps.style === nextProps.style;
};

const CandidateRow = React.memo(({ index, style, candidates, selectedIds, onSelect, adminCheck }: any) => {
  const candidate = candidates[index];

  if (!candidate) {
    return (
      <div style={style} className="px-4 md:px-6">
        <div className="bg-white border border-slate-200 rounded-lg shadow-sm mb-3 p-4 flex items-center justify-center">
          <div className="flex items-center gap-2 text-slate-400">
            <Loader2 size={16} className="animate-spin" />
            <span className="text-sm font-medium">Loading candidates...</span>
          </div>
        </div>
      </div>
    );
  }

  const isSelected = selectedIds.includes(candidate.id);

  return (
    <div style={style} className="px-4 md:px-6">
      <div className={`bg-white border border-slate-200 rounded-lg shadow-sm mb-3 p-4 hover:border-blue-300 transition-colors flex flex-col md:flex-row md:items-center gap-4 ${isSelected ? 'ring-2 ring-blue-500 bg-blue-50/50' : ''
        }`}>
        {/* Mobile Header: Checkbox + Avatar + Basic Info */}
        <div className="flex items-center gap-3 md:w-1/3 min-w-0">
          {adminCheck && (
            <input
              type="checkbox"
              checked={isSelected}
              onChange={() => onSelect(candidate.id)}
              className="w-5 h-5 rounded-lg border-slate-300 text-blue-600 focus:ring-blue-500 transition-premium cursor-pointer shrink-0"
            />
          )}
          <div className="relative flex-shrink-0">
            <img
              src={candidate.avatarUrl || `https://ui-avatars.com/api/?name=${encodeURIComponent(candidate.name)}`}
              className="w-12 h-12 rounded-xl border border-slate-200 shadow-sm"
              alt=""
            />
            <div className={`absolute -bottom-1 -right-1 w-4 h-4 rounded-full border-2 border-white shadow-sm ${candidate.profileCompletionStatus === ProfileCompletionStatus.COMPLETE || candidate.profileCompletionPercentage >= 75 ? 'bg-emerald-500' : 'bg-amber-500'
              }`} />
          </div>
          <div className="truncate flex-1">
            <Link to={`/candidates/${candidate.id}`} className="font-semibold text-slate-900 hover:text-blue-600 truncate block text-base">
              {candidate.regNo || candidate.candidateCode || 'NO REG'}
            </Link>
            <div className="flex flex-wrap items-center gap-2 mt-1">
              {(candidate.preferredCountries && candidate.preferredCountries.length > 0) ? (
                candidate.preferredCountries.map((country: string) => (
                  <span key={country} className="text-xs bg-slate-100 text-slate-700 font-medium px-2 py-0.5 rounded border border-slate-200">
                    {country}
                  </span>
                ))
              ) : candidate.targetCountry ? (
                <span className="text-xs bg-slate-100 text-slate-700 font-medium px-2 py-0.5 rounded border border-slate-200">
                  {candidate.targetCountry}
                </span>
              ) : candidate.country ? (
                <span className="text-xs bg-slate-100 text-slate-700 font-medium px-2 py-0.5 rounded border border-slate-200">
                  {candidate.country}
                </span>
              ) : (
                <span className="text-xs bg-slate-50 text-slate-500 font-medium px-2 py-0.5 rounded border border-slate-200">
                  No Destination
                </span>
              )}
              <span className="text-[10px] text-slate-400 font-bold uppercase truncate ml-1">
                • {candidate.role || 'Personnel'}
              </span>
            </div>
          </div>
        </div>

        {/* Desktop/Mobile Detail Wrapper */}
        <div className="flex items-center justify-between md:contents">
          <div className="md:w-1/4 text-xs font-bold text-slate-500 flex items-center gap-2">
            <div className="w-1.5 h-1.5 rounded-full bg-blue-400 md:hidden" />
            {candidate.phone || 'No Contact'}
          </div>

          <div className="md:w-1/4">
            <span className={`badge ${candidate.stage === WorkflowStage.DEPARTED ? 'badge-green' :
              [WorkflowStage.VISA_RECEIVED, WorkflowStage.TICKET_ISSUED, WorkflowStage.SLBFE_REGISTRATION].includes(candidate.stage) ? 'badge-blue' :
                [WorkflowStage.REGISTERED, WorkflowStage.VERIFIED].includes(candidate.stage) ? 'badge-slate' :
                  [WorkflowStage.APPLIED, WorkflowStage.OFFER_RECEIVED, WorkflowStage.WP_RECEIVED, WorkflowStage.EMBASSY_APPLIED].includes(candidate.stage) ? 'badge-purple' :
                    'badge-amber'
              }`}>
              {candidate.stage}
            </span>
          </div>

          <div className="flex justify-end md:flex-1">
            <Link
              to={`/candidates/${candidate.id}`}
              className="w-10 h-10 flex items-center justify-center bg-slate-50 hover:bg-blue-600 hover:text-white rounded-xl text-slate-400 transition-premium shadow-sm"
            >
              <ArrowRight size={20} />
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
}, areEqual);


const CandidateList: React.FC = () => {
  const { candidates: contextCandidates } = useCandidates(); // Keeps the top-level stats alive
  const { user } = useAuth();
  const isAdmin = user?.role === 'Admin';

  const [paginatedCandidates, setPaginatedCandidates] = useState<Candidate[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [page, setPage] = useState(0);
  const [isLoading, setIsLoading] = useState(true);
  const [isFetchingMore, setIsFetchingMore] = useState(false);
  const [hasMoreItems, setHasMoreItems] = useState(true);

  const [searchQuery, setSearchQuery] = useState('');
  const debouncedSearchQuery = useDebounce(searchQuery, 300);
  const [activeStatus, setActiveStatus] = useState<ProfileCompletionStatus | 'ALL'>('ALL');
  const [activeStage, setActiveStage] = useState<WorkflowStage | 'ALL'>('ALL');
  const [activeCountries, setActiveCountries] = useState<string[]>([]);
  const [selectedCandidateIds, setSelectedCandidateIds] = useState<string[]>([]);
  const [isIntegrityScanActive, setIsIntegrityScanActive] = useState(false);
  const [listHeight, setListHeight] = useState(600);
  const [isScanning, setIsScanning] = useState(false);

  const [searchParams] = useSearchParams();
  const navigate = useNavigate();

  // Initialize filters from URL
  useEffect(() => {
    const statusParam = searchParams.get('status');
    if (statusParam) {
      const status = statusParam.toUpperCase() as ProfileCompletionStatus;
      if (Object.values(ProfileCompletionStatus).includes(status)) {
        setActiveStatus(status);
      }
    }

    const stageParam = searchParams.get('stage');
    if (stageParam) {
      const stage = stageParam.toUpperCase() as WorkflowStage;
      if (Object.values(WorkflowStage).includes(stage)) {
        setActiveStage(stage);
      }
    }

    const countriesParam = searchParams.get('countries');
    if (countriesParam) {
      setActiveCountries(countriesParam.split(','));
    }
  }, [searchParams]);

  // Load Initial Data or Filter Change
  const loadData = useCallback(async (pageNum: number, isRefresh: boolean = false, isQuiet: boolean = false) => {
    if (isRefresh && !isQuiet) setIsLoading(true);
    else if (!isQuiet) setIsFetchingMore(true);

    try {
      const { candidates: newBatch, count } = await CandidateService.searchCandidates(
        PAGE_SIZE,
        pageNum * PAGE_SIZE,
        {
          status: activeStatus,
          stage: activeStage,
          query: debouncedSearchQuery,
          countries: activeCountries
        }
      );

      setPaginatedCandidates(prev => isRefresh ? newBatch : [...prev, ...newBatch]);
      setTotalCount(count);
      // Ensure we can fetch more if the current batch is full, regardless of count API bug
      setHasMoreItems(newBatch.length === PAGE_SIZE);
    } catch (err) {
      console.error("Failed to load candidates page", err);
    } finally {
      setIsLoading(false);
      setIsFetchingMore(false);
    }
  }, [activeStatus, activeStage, debouncedSearchQuery, activeCountries]);

  useEffect(() => {
    setPage(0);
    loadData(0, true);
  }, [loadData]);

  useEffect(() => {
    // Connect to realtime for updates directly visible in the local paginated list
    const channel = supabase.channel('public:candidates_list')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'candidates' },
        (payload) => {
          // On any change, softly reload the first page data without showing loading states
          // This keeps the list fresh without jarring the user
          loadData(0, true, true);
        }
      )
      .subscribe();

    return () => { channel.unsubscribe(); };
  }, [loadData]);


  const loadMoreItems = () => {
    if (isFetchingMore || isLoading || !hasMoreItems) return;
    const nextPage = page + 1;
    setPage(nextPage);
    loadData(nextPage, false);
  };

  // Handle resize for virtual list
  useEffect(() => {
    const handleResize = () => {
      const isMobile = window.innerWidth < 768;
      // On mobile, we need more space at the bottom for the fixed nav bar
      setListHeight(window.innerHeight - (isMobile ? 360 : 300));
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Use the context array just for the stats counter on the header
  const candidateCounts = useMemo(() => ({
    all: contextCandidates.length,
    quick: contextCandidates.filter(c => c.profileCompletionStatus === ProfileCompletionStatus.QUICK).length,
    partial: contextCandidates.filter(c => c.profileCompletionStatus === ProfileCompletionStatus.PARTIAL && (c.profileCompletionPercentage || 0) < 75).length,
    complete: contextCandidates.filter(c => c.profileCompletionStatus === ProfileCompletionStatus.COMPLETE || (c.profileCompletionPercentage || 0) >= 75).length
  }), [contextCandidates]);

  const handleStatusChange = (status: ProfileCompletionStatus | 'ALL') => {
    setActiveStatus(status);
    updateURL(status, activeStage, activeCountries);
  };

  const handleStageChange = (stage: WorkflowStage | 'ALL') => {
    setActiveStage(stage);
    updateURL(activeStatus, stage, activeCountries);
  };

  const handleCountryChange = (countries: string[]) => {
    setActiveCountries(countries);
    updateURL(activeStatus, activeStage, countries);
  };

  const updateURL = (status: ProfileCompletionStatus | 'ALL', stage: WorkflowStage | 'ALL', countries: string[]) => {
    const params = new URLSearchParams();
    if (status !== 'ALL') params.set('status', status.toLowerCase());
    if (stage !== 'ALL') params.set('stage', stage.toLowerCase());
    if (countries.length > 0) params.set('countries', countries.join(','));
    navigate(`?${params.toString()}`, { replace: true });
  };

  const handleClearFilters = () => {
    setActiveStatus('ALL');
    setActiveStage('ALL');
    setActiveCountries([]);
    setSearchQuery('');
    navigate('', { replace: true });
  };

  const hasActiveFilters = activeStatus !== 'ALL' || activeStage !== 'ALL' || searchQuery !== '' || activeCountries.length > 0;

  const handleSelectCandidate = (id: string) => {
    setSelectedCandidateIds(prev =>
      prev.includes(id) ? prev.filter(cid => cid !== id) : [...prev, id]
    );
  };

  const handleSelectAll = () => {
    if (selectedCandidateIds.length === paginatedCandidates.length) {
      setSelectedCandidateIds([]);
    } else {
      setSelectedCandidateIds(paginatedCandidates.map(c => c.id));
    }
  };

  const handleBulkExport = (format: 'json' | 'csv' = 'csv') => {
    const selectedCandidates = contextCandidates.filter(c => selectedCandidateIds.includes(c.id));
    let dataBlob: Blob;
    let extension: string;

    if (format === 'csv') {
      const csvStr = convertToCSV(selectedCandidates);
      dataBlob = new Blob([csvStr], { type: 'text/csv' });
      extension = 'csv';
    } else {
      const dataStr = JSON.stringify(selectedCandidates, null, 2);
      dataBlob = new Blob([dataStr], { type: 'application/json' });
      extension = 'json';
    }

    const url = URL.createObjectURL(dataBlob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `candidates-bulk-${new Date().toISOString().split('T')[0]}.${extension}`;
    link.click();
    URL.revokeObjectURL(url);

    AuditService.log('BULK_CANDIDATE_EXPORTED', {
      format,
      recordCount: selectedCandidates.length,
      candidateIds: selectedCandidates.map(c => c.id)
    });
  };

  const toggleIntegrityScan = () => {
    setIsIntegrityScanActive(!isIntegrityScanActive);
  };




  return (
    <div className="min-h-screen bg-slate-50 relative overflow-hidden">
      <div className="bg-white border-b border-slate-200 px-4 md:px-6 py-4">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-2xl font-semibold text-slate-900">Candidates</h1>
            <div className="flex items-center gap-2 text-sm text-slate-500 mt-1">
              <Users size={12} className="text-blue-500" />
              <span>{Math.max(totalCount, candidateCounts.all)} Total Candidates</span>
            </div>
          </div>
          <div className="flex items-center gap-2 overflow-x-auto pb-2 md:pb-0 scrollbar-hide">
            <button
              onClick={toggleIntegrityScan}
              className={`flex items-center gap-2 px-3 py-2 border rounded-xl transition-premium text-sm font-medium shrink-0 ${isIntegrityScanActive
                ? 'bg-red-50 border-red-200 text-red-700'
                : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                }`}
            >
              <div className={`w-1.5 h-1.5 rounded-full ${isIntegrityScanActive ? 'bg-red-500 animate-ping' : 'bg-slate-300'}`} />
              {isIntegrityScanActive ? 'Checking...' : 'Data Check'}
            </button>
            <div className="hidden md:block h-6 w-px bg-slate-200 mx-1" />
            <Link
              to="/candidates/quick-add"
              className="hidden md:block px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-md shadow-sm hover:bg-slate-50 transition-colors text-sm font-medium"
            >
              Quick Create
            </Link>
            <Link
              to="/applications/new"
              className="px-4 py-2 bg-blue-600 text-white rounded-md shadow-sm hover:bg-blue-700 transition-colors text-sm font-medium"
            >
              Full Form
            </Link>
          </div>
        </div>
      </div>

      {/* Filter Bar */}
      <FilterBar
        activeStatus={activeStatus}
        onStatusChange={handleStatusChange}
        activeStage={activeStage}
        onStageChange={handleStageChange}
        activeCountries={activeCountries}
        onCountryChange={handleCountryChange}
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        candidateCounts={candidateCounts}
        onClearFilters={handleClearFilters}
        hasActiveFilters={hasActiveFilters}
      />

      {/* Bulk Actions Bar (Admin Only) */}
      {isAdmin && selectedCandidateIds.length > 0 && (
        <div className="fixed bottom-[calc(var(--bottom-nav-height)+0.5rem)] md:bottom-6 left-3 right-3 sm:left-4 sm:right-4 md:left-1/2 md:-translate-x-1/2 z-50 transition-premium scale-in">
          <div className="bg-slate-900/95 backdrop-blur-xl text-white border border-slate-800 shadow-2xl rounded-2xl px-4 py-3 flex items-center justify-between md:justify-start md:gap-4 max-w-lg mx-auto md:max-w-none">
            <div className="flex items-center gap-2 pr-4 md:border-r border-slate-800">
              <span className="bg-blue-600 text-white text-[10px] font-black px-2 py-0.5 rounded shadow-lg shadow-blue-500/20 animate-pulse">
                {selectedCandidateIds.length}
              </span>
              <span className="hidden md:inline text-xs font-black uppercase tracking-widest text-slate-400">Candidates Selected</span>
            </div>
            <button
              onClick={() => handleBulkExport('csv')}
              className="flex items-center gap-2 px-4 py-2 bg-white text-slate-900 rounded-xl hover:bg-slate-100 transition-premium text-xs font-black uppercase tracking-tight shadow-xl"
            >
              <Download size={14} />
              <span className="hidden md:inline">Export CSV</span>
              <span className="md:hidden">Export</span>
            </button>
            <div className="flex items-center gap-3 pl-4 border-l border-slate-800">
              <button
                onClick={handleSelectAll}
                className="text-[10px] font-black text-slate-400 hover:text-white uppercase tracking-tighter transition-premium"
              >
                {selectedCandidateIds.length === paginatedCandidates.length ? 'Reset' : 'Select All'}
              </button>
              <button onClick={() => setSelectedCandidateIds([])} className="p-1 hover:bg-white/10 rounded-lg text-slate-500 hover:text-red-400 transition-premium">
                <X size={16} />
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Main Content */}
      <div className="px-3 sm:px-4 md:px-6 py-3 sm:py-4">
        {/* Results Header */}
        <div className="flex items-center justify-between mb-3 px-2">
          <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase tracking-wider">
            <Users size={12} />
            <span>Showing {paginatedCandidates.length} of {
              hasActiveFilters ? Math.max(totalCount, paginatedCandidates.length) + (hasMoreItems ? '+' : '') : Math.max(totalCount, candidateCounts.all, paginatedCandidates.length)
            } Candidates</span>
          </div>
        </div>

        {/* Loading State */}
        {(isLoading || isScanning) && (
          <div className="space-y-3">
            {[1, 2, 3, 4, 5].map(i => (
              <div key={i} className="bg-white border border-slate-200 rounded-xl p-4">
                <div className="flex items-center gap-4">
                  <Skeleton className="w-10 h-10 rounded-full" />
                  <div className="flex-1 space-y-2">
                    <Skeleton className="h-4 w-48" />
                    <Skeleton className="h-3 w-96" />
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {!isLoading && paginatedCandidates.length === 0 && (
          <div className="bg-white border-2 border-dashed border-slate-200 rounded-2xl p-16 text-center">
            <Users size={48} className="mx-auto text-slate-200 mb-4" />
            <h3 className="text-lg font-bold text-slate-900 mb-2">
              {hasActiveFilters ? 'No matches in registry' : 'Registry Empty'}
            </h3>
            <p className="text-slate-500 mb-6 max-w-xs mx-auto text-sm">
              {hasActiveFilters
                ? 'Adjust your high-precision filters to locate personnel.'
                : 'Initialize the workforce by enrolling new personnel.'}
            </p>
            <button onClick={handleClearFilters} className="px-6 py-2 bg-slate-900 text-white rounded-xl text-sm font-bold">
              Reset Filters
            </button>
          </div>
        )}

        {/* Virtualized Registry */}
        {!isLoading && paginatedCandidates.length > 0 && (
          <div className="glass-card overflow-hidden bg-white/50 touch-pan-y" style={{ height: listHeight }}>
            <div className="hidden md:flex items-center px-6 py-3 border-b border-slate-200 bg-slate-50/50 text-[10px] font-black uppercase tracking-widest text-slate-400 sticky top-0 z-10 backdrop-blur-sm">
              <div className="w-1/3">Candidate</div>
              <div className="w-1/4">Contact</div>
              <div className="w-1/4">Status</div>
              <div className="flex-1 text-right italic normal-case font-bold text-slate-300">Synced</div>
            </div>

            <List
              defaultHeight={listHeight - 40}
              rowCount={paginatedCandidates.length + (hasMoreItems ? 1 : 0)}
              rowHeight={window.innerWidth < 768 ? 160 : 72}
              rowComponent={CandidateRow as any}
              onRowsRendered={({ stopIndex }: { stopIndex: number }) => {
                if (stopIndex >= paginatedCandidates.length - 5) {
                  loadMoreItems();
                }
              }}
              rowProps={{
                candidates: paginatedCandidates,
                selectedIds: selectedCandidateIds,
                onSelect: handleSelectCandidate,
                adminCheck: isAdmin
              }}
              className="custom-scrollbar"
            />
          </div>
        )}
        {/* Mobile FAB */}
        <div className="lg:hidden fixed bottom-[calc(var(--bottom-nav-height)+0.5rem)] right-4 sm:right-6 z-40">
          <Link
            to="/candidates/quick-add"
            className="w-14 h-14 bg-slate-900 text-white rounded-2xl flex items-center justify-center shadow-lg hover:bg-slate-800 transition-colors"
          >
            <Users size={24} />
            <div className="absolute -top-1 -right-1 w-5 h-5 bg-blue-600 rounded-full flex items-center justify-center text-[10px] font-black border-2 border-white">+</div>
          </Link>
        </div>
      </div>
    </div>
  );
};

export default CandidateList;

import React, { useEffect, useState } from 'react';
import { ShieldCheck, Printer, RefreshCw, AlertCircle, AlertTriangle, FileText, User, Info, CheckCircle } from 'lucide-react';
import { Candidate } from '../types';
import type { SystemReport } from '../services/reportService';
import { useCandidateReport } from '../src/hooks/useCandidateReport';

interface CandidateReportProps {
    candidate: Candidate;
}

const CandidateReport: React.FC<CandidateReportProps> = ({ candidate }) => {
    const [report, setReport] = useState<SystemReport | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [isExporting, setIsExporting] = useState(false);

    const { reportId, generatedBy } = useCandidateReport(candidate);

    const generate = React.useCallback(async () => {
        setIsLoading(true);
        try {
            const { ReportService } = await import('../services/reportService');
            const data = await ReportService.generateReport(candidate);
            setReport(data);
        } catch (error) {
            console.error('Failed to generate report:', error);
        } finally {
            setIsLoading(false);
        }
    }, [candidate]);

    const handleExportPDF = async () => {
        if (!report) return;
        setIsExporting(true);
        try {
            const { pdf } = await import('@react-pdf/renderer');
            const { CandidateReportPDF } = await import('../src/components/reports/CandidateReportPDF');

            const blob = await pdf(
                <CandidateReportPDF
                    candidate={candidate}
                    reportId={reportId}
                    generatedBy={generatedBy}
                    systemReport={report}
                />
            ).toBlob();

            const url = URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = `${candidate.regNo || candidate.candidateCode}_${new Date().toISOString().split('T')[0]}.pdf`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            URL.revokeObjectURL(url);
        } catch (error) {
            console.error('Failed to export PDF:', error);
            alert('Failed to generate PDF.');
        } finally {
            setIsExporting(false);
        }
    };

    useEffect(() => {
        generate();
    }, [generate]);

    if (isLoading) {
        return (
            <div className="flex flex-col items-center justify-center p-12 space-y-4">
                <RefreshCw size={24} className="text-slate-400 animate-spin" />
                <p className="text-xs font-semibold text-slate-500 uppercase tracking-widest">Compiling System Audit Matrix...</p>
            </div>
        );
    }

    if (!report) return null;

    const totalFlags = report.missingInfo.length + report.documentGaps.missing.length + report.documentGaps.rejected.length + report.dataQuality.length;

    return (
        <div className="animate-in fade-in duration-300 font-sans text-slate-900">
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 pb-4 border-b-2 border-slate-800">
                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <ShieldCheck size={20} className="text-slate-900" />
                        <h2 className="text-lg font-bold uppercase tracking-tight">System Audit & Integrity Matrix</h2>
                    </div>
                    <div className="flex gap-4 text-xs font-medium text-slate-600 uppercase tracking-wider">
                        <span>Report ID: <span className="text-slate-900">{reportId}</span></span>
                        <span>Generated: <span className="text-slate-900">{new Date().toLocaleString()}</span></span>
                    </div>
                </div>
                <div className="flex items-center gap-3 mt-4 md:mt-0">
                    <button onClick={generate} className="px-3 py-1.5 border border-slate-300 hover:bg-slate-50 text-slate-700 text-xs font-bold uppercase transition-colors flex items-center gap-1.5">
                        <RefreshCw size={14} /> Refresh
                    </button>
                    <button onClick={handleExportPDF} disabled={isExporting} className="px-3 py-1.5 bg-slate-900 hover:bg-slate-800 text-white text-xs font-bold uppercase transition-colors flex items-center gap-1.5 disabled:opacity-50">
                        {isExporting ? <RefreshCw size={14} className="animate-spin" /> : <Printer size={14} />}
                        {isExporting ? 'Exporting...' : 'Export PDF'}
                    </button>
                </div>
            </div>

            {/* Core Metrics Summary */}
            <div className="grid grid-cols-2 md:grid-cols-4 border border-slate-300 mb-8 max-w-full overflow-hidden">
                <div className="p-3 border-b md:border-b-0 md:border-r border-slate-300 bg-slate-50">
                    <p className="text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-1">Data Completion</p>
                    <p className={`text-xl font-bold ${report.completionPercentage === 100 ? 'text-emerald-700' : report.completionPercentage >= 80 ? 'text-slate-800' : 'text-red-700'}`}>
                        {report.completionPercentage}%
                    </p>
                </div>
                <div className="p-3 border-b md:border-b-0 md:border-r border-slate-300 bg-slate-50">
                    <p className="text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-1">Integrity Flags</p>
                    <p className={`text-xl font-bold ${totalFlags === 0 ? 'text-emerald-700' : 'text-red-700'}`}>
                        {totalFlags} Detect{totalFlags === 1 ? 'ed' : 's'}
                    </p>
                </div>
                <div className="p-3 border-r border-slate-300 bg-slate-50">
                    <p className="text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-1">SLA Velocity</p>
                    <p className="text-xl font-bold text-slate-800 capitalize truncate">
                        {report.slaStatus.status.toLowerCase().replace('_', ' ')}
                    </p>
                </div>
                <div className="p-3 bg-slate-50">
                    <p className="text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-1">System Status</p>
                    <p className="text-xl font-bold text-slate-800 truncate" title={report.overallStatus}>
                        {report.overallStatus}
                    </p>
                </div>
            </div>

            {/* Matrix Data Sections */}
            <div className="space-y-8">

                {/* Identity & Traceability */}
                <section>
                    <h3 className="text-xs font-bold uppercase text-slate-800 mb-2 tracking-widest pl-1 border-l-2 border-slate-800">Identity & Traceability Validation</h3>
                    <div className="overflow-x-auto">
                        <table className="w-full text-xs text-left border border-slate-300">
                            <thead className="bg-slate-100 border-b border-slate-300 text-slate-600 font-bold uppercase tracking-wider">
                                <tr>
                                    <th className="p-2 border-r border-slate-300 w-1/3">Verification Entity</th>
                                    <th className="p-2 border-r border-slate-300 w-1/3">System Value</th>
                                    <th className="p-2 w-1/3">Validation Status</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-200">
                                {[
                                    { entity: 'Primary Subject Name', value: candidate.name, status: 'Active', valid: true },
                                    { entity: 'System Identifier (Reg No)', value: candidate.candidateCode, status: 'Registered', valid: true },
                                    { entity: 'National Identity Structure', value: candidate.nic || '-', status: candidate.nic ? 'Verified' : 'Unverified (Missing)', valid: !!candidate.nic },
                                    { entity: 'Date of Birth Trace', value: candidate.dob || '-', status: candidate.dob ? 'Valid Format' : 'Unverified (Missing)', valid: !!candidate.dob },
                                    { entity: 'Contact Channel Integrity', value: candidate.phone, status: 'Active', valid: !!candidate.phone },
                                    { entity: 'Geospatial Location', value: candidate.city || '-', status: candidate.city ? 'Mapped' : 'Unmapped', valid: !!candidate.city },
                                    { entity: 'Passport Documentation', value: candidate.passportData?.passportNumber ? `No: ${candidate.passportData.passportNumber}` : '-', status: candidate.passportData?.passportNumber ? 'Document Verified' : 'No Data Present', valid: !!candidate.passportData?.passportNumber }
                                ].map((row, i) => (
                                    <tr key={i} className="hover:bg-slate-50">
                                        <td className="p-2 border-r border-slate-300 font-medium text-slate-700">{row.entity}</td>
                                        <td className="p-2 border-r border-slate-300 text-slate-900">{row.value}</td>
                                        <td className="p-2">
                                            <span className={`flex items-center gap-1.5 font-bold ${row.valid ? 'text-emerald-700' : 'text-red-600'}`}>
                                                {row.valid ? <CheckCircle size={14} /> : <AlertCircle size={14} />}
                                                {row.status}
                                            </span>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </section>

                {/* Chronological State Processing */}
                <section>
                    <h3 className="text-xs font-bold uppercase text-slate-800 mb-2 tracking-widest pl-1 border-l-2 border-slate-800">Chronological State Processing</h3>
                    <div className="overflow-x-auto">
                        <table className="w-full text-xs text-left border border-slate-300">
                            <thead className="bg-slate-100 border-b border-slate-300 text-slate-600 font-bold uppercase tracking-wider">
                                <tr>
                                    <th className="p-2 border-r border-slate-300 w-1/3">Event Descriptor</th>
                                    <th className="p-2 border-r border-slate-300 w-1/3">Timestamp Vector</th>
                                    <th className="p-2 w-1/3">Delta / Constraint</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-200">
                                <tr>
                                    <td className="p-2 border-r border-slate-300 font-medium text-slate-700">Initial Entity Creation</td>
                                    <td className="p-2 border-r border-slate-300 text-slate-900">{new Date(candidate.audit.createdAt).toLocaleString()}</td>
                                    <td className="p-2 text-slate-600">-</td>
                                </tr>
                                <tr>
                                    <td className="p-2 border-r border-slate-300 font-medium text-slate-700">Last Modified Checksum</td>
                                    <td className="p-2 border-r border-slate-300 text-slate-900">{new Date(candidate.audit.updatedAt).toLocaleString()}</td>
                                    <td className="p-2 text-slate-600">Updated by System</td>
                                </tr>
                                <tr>
                                    <td className="p-2 border-r border-slate-300 font-medium text-slate-700">Current Workflow Stage Entry</td>
                                    <td className="p-2 border-r border-slate-300 text-slate-900">{candidate.stageEnteredAt ? new Date(candidate.stageEnteredAt).toLocaleString() : 'N/A'}</td>
                                    <td className="p-2 font-medium">
                                        {report.comparativeMetrics && (
                                            <span className={report.comparativeMetrics.candidateDays > report.comparativeMetrics.companyAvgDays ? "text-amber-600" : "text-emerald-700"}>
                                                {report.comparativeMetrics.candidateDays} days (SLA Benchmark: {report.comparativeMetrics.companyAvgDays})
                                            </span>
                                        )}
                                    </td>
                                </tr>
                            </tbody>
                        </table>
                    </div>
                </section>

                {/* Exception and Deficit Logs */}
                <section>
                    <h3 className="text-xs font-bold uppercase text-slate-800 mb-2 tracking-widest pl-1 border-l-2 border-slate-800">Exception & Integrity Log</h3>

                    {totalFlags === 0 ? (
                        <div className="p-4 border border-emerald-300 bg-emerald-50 text-emerald-800 flex items-center gap-3">
                            <CheckCircle size={18} />
                            <span className="text-sm font-bold uppercase">No Exceptions Detected. Integrity is Optimal.</span>
                        </div>
                    ) : (
                        <div className="overflow-x-auto">
                            <table className="w-full text-xs text-left border border-slate-300">
                                <thead className="bg-slate-100 border-b border-slate-300 text-slate-600 font-bold uppercase tracking-wider">
                                    <tr>
                                        <th className="p-2 border-r border-slate-300 w-24">Severity</th>
                                        <th className="p-2 border-r border-slate-300 w-48">Category Type</th>
                                        <th className="p-2 border-r border-slate-300 w-48">Entity Field / Document</th>
                                        <th className="p-2">Exception Detail</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-200">
                                    {/* Data Quality */}
                                    {report.dataQuality.map((issue, idx) => (
                                        <tr key={`dq-${idx}`} className="hover:bg-slate-50">
                                            <td className="p-2 border-r border-slate-300 font-bold text-red-600">HIGH</td>
                                            <td className="p-2 border-r border-slate-300 text-slate-700">Data Quality Incident</td>
                                            <td className="p-2 border-r border-slate-300 font-medium">{issue.field}</td>
                                            <td className="p-2 text-slate-900">{issue.issue}</td>
                                        </tr>
                                    ))}
                                    {/* Rejected Docs */}
                                    {report.documentGaps.rejected.map((doc, idx) => (
                                        <tr key={`dr-${idx}`} className="hover:bg-slate-50">
                                            <td className="p-2 border-r border-slate-300 font-bold text-red-600">HIGH</td>
                                            <td className="p-2 border-r border-slate-300 text-slate-700">Document Rejection</td>
                                            <td className="p-2 border-r border-slate-300 font-medium">{doc.type}</td>
                                            <td className="p-2 text-slate-900">{doc.reason}</td>
                                        </tr>
                                    ))}
                                    {/* Missing Docs */}
                                    {report.documentGaps.missing.map((doc, idx) => (
                                        <tr key={`dm-${idx}`} className="hover:bg-slate-50">
                                            <td className="p-2 border-r border-slate-300 font-bold text-amber-600">ELEVATED</td>
                                            <td className="p-2 border-r border-slate-300 text-slate-700">Missing Core Requirement</td>
                                            <td className="p-2 border-r border-slate-300 font-medium">{doc}</td>
                                            <td className="p-2 text-slate-900">Required document is absent from vault.</td>
                                        </tr>
                                    ))}
                                    {/* Missing Info */}
                                    {report.missingInfo.map((info, idx) => (
                                        <tr key={`mi-${idx}`} className="hover:bg-slate-50">
                                            <td className="p-2 border-r border-slate-300 font-bold text-slate-500">MODERATE</td>
                                            <td className="p-2 border-r border-slate-300 text-slate-700">Data Void / Null Output</td>
                                            <td className="p-2 border-r border-slate-300 font-medium">{info}</td>
                                            <td className="p-2 text-slate-900">Field has not been populated.</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </section>
            </div>
        </div>
    );
};

export default CandidateReport;

import React from 'react';
import { Candidate, PassportData, PCCData, MedicalStatus, ComplianceFlag } from '../types';
import { CheckCircle2, AlertTriangle, XCircle, ShieldCheck, Calendar, Activity, AlertOctagon, Flag, Plus, Trash2 } from 'lucide-react';
import { ComplianceEngine } from '../services/compliance/ComplianceEngine';
import { ComplianceSeverity } from '../services/compliance/ComplianceTypes';
import { CandidateService } from '../services/candidateService';
import { ComplianceService } from '../services/complianceService';

interface ComplianceWidgetProps {
    candidate: Candidate;
    onUpdate?: (data: any) => void; // General update trigger
    onRefresh?: () => void; // Trigger reload
}

const ComplianceWidget: React.FC<ComplianceWidgetProps> = ({ candidate, onUpdate, onRefresh }) => {
    const passport = candidate.passportData;
    const pcc = candidate.pccData;
    const stageData = candidate.stageData;

    // Report
    const report = ComplianceEngine.evaluateCandidate(candidate);
    const score = report.scoreCard.overallScore;
    const criticalIssues = report.results.filter(r => r.issue?.severity === ComplianceSeverity.CRITICAL);
    const warningIssues = report.results.filter(r => r.issue?.severity === ComplianceSeverity.WARNING);

    // State
    const [isEditing, setIsEditing] = React.useState(false);
    const [showAddFlag, setShowAddFlag] = React.useState(false);
    const [flagForm, setFlagForm] = React.useState({
        type: 'BEHAVIORAL' as ComplianceFlag['type'],
        severity: 'WARNING' as ComplianceFlag['severity'],
        reason: ''
    });

    // Form State for Docs
    const [formData, setFormData] = React.useState({
        passportNumber: passport?.passportNumber || '',
        passportCountry: passport?.country || '',
        passportIssued: passport?.issuedDate || '',
        passportExpiry: passport?.expiryDate || '',
        pccIssued: pcc?.issuedDate || '',
        pccExpiry: pcc?.expiryDate || ''
    });

    const handleSave = () => {
        if (onUpdate) {
            onUpdate({
                passport: {
                    passportNumber: formData.passportNumber,
                    country: formData.passportCountry,
                    issuedDate: formData.passportIssued,
                    expiryDate: formData.passportExpiry
                },
                pcc: {
                    issuedDate: formData.pccIssued,
                    expiryDate: formData.pccExpiry
                }
            });
        }
        setIsEditing(false);
    };

    const handleAddFlag = async () => {
        if (!flagForm.reason) return;
        await CandidateService.addComplianceFlag(candidate.id, {
            type: flagForm.type,
            severity: flagForm.severity,
            reason: flagForm.reason,
            createdBy: 'User' // In real app, get current user
        });
        setShowAddFlag(false);
        setFlagForm({ type: 'BEHAVIORAL', severity: 'WARNING', reason: '' });
        if (onRefresh) onRefresh();
        else if (onUpdate) onUpdate({});
    };

    const handleResolveFlag = async (flagId: string) => {
        const notes = prompt("Enter resolution notes:");
        if (notes) {
            await CandidateService.resolveComplianceFlag(candidate.id, flagId, notes, 'User');
            if (onRefresh) onRefresh();
            else if (onUpdate) onUpdate({});
        }
    };

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'VALID': return 'bg-green-50 text-green-700 border-green-200';
            case 'EXPIRING': return 'bg-amber-50 text-amber-700 border-amber-200';
            case 'EXPIRED': return 'bg-red-50 text-red-700 border-red-200';
            default: return 'bg-slate-50 text-slate-700 border-slate-200';
        }
    };

    const getStatusIcon = (status: string) => {
        switch (status) {
            case 'VALID': return <CheckCircle2 size={16} className="text-green-600" />;
            case 'EXPIRING': return <AlertTriangle size={16} className="text-amber-600" />;
            case 'EXPIRED': return <XCircle size={16} className="text-red-600" />;
            default: return <AlertTriangle size={16} className="text-slate-400" />;
        }
    };

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-5">
            <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                    <ShieldCheck className={score === 100 ? "text-green-600" : "text-blue-600"} size={20} />
                    <h3 className="font-bold text-slate-800">Compliance & Travel Docs</h3>
                </div>
                <div className="flex items-center gap-3">
                    <div className="flex flex-col items-end">
                        <span className="text-[10px] font-bold uppercase text-slate-400">Score</span>
                        <span className={`text-lg font-black ${score === 100 ? 'text-green-600' : score < 50 ? 'text-red-600' : 'text-amber-600'}`}>
                            {score}%
                        </span>
                    </div>
                    <button
                        onClick={() => isEditing ? handleSave() : setIsEditing(true)}
                        className="text-xs font-bold text-blue-600 hover:bg-blue-50 px-3 py-1.5 rounded-lg transition-colors"
                    >
                        {isEditing ? 'Save' : 'Edit'}
                    </button>
                    <button
                        onClick={() => setShowAddFlag(!showAddFlag)}
                        className="text-xs font-bold text-red-600 hover:bg-red-50 px-3 py-1.5 rounded-lg transition-colors flex items-center gap-1"
                    >
                        <Flag size={12} /> Flag
                    </button>
                </div>
            </div>

            {/* Flag Form */}
            {showAddFlag && (
                <div className="mb-4 bg-red-50 p-3 rounded-lg border border-red-100 animate-in fade-in slide-in-from-top-2">
                    <h4 className="text-xs font-bold text-red-800 mb-2">Add Compliance Flag</h4>
                    <div className="grid grid-cols-2 gap-2 mb-2">
                        <select
                            value={flagForm.type}
                            onChange={(e) => setFlagForm({ ...flagForm, type: e.target.value as any })}
                            className="text-xs border-red-200 rounded"
                        >
                            <option value="LEGAL">Legal</option>
                            <option value="MEDICAL">Medical</option>
                            <option value="DOCUMENT">Document</option>
                            <option value="BEHAVIORAL">Behavioral</option>
                            <option value="OTHER">Other</option>
                        </select>
                        <select
                            value={flagForm.severity}
                            onChange={(e) => setFlagForm({ ...flagForm, severity: e.target.value as any })}
                            className="text-xs border-red-200 rounded"
                        >
                            <option value="WARNING">Warning</option>
                            <option value="CRITICAL">Critical (Blocker)</option>
                        </select>
                    </div>
                    <textarea
                        value={flagForm.reason}
                        onChange={(e) => setFlagForm({ ...flagForm, reason: e.target.value })}
                        placeholder="Reason for flagging..."
                        className="w-full text-xs border-red-200 rounded mb-2 h-16"
                    />
                    <div className="flex justify-end gap-2">
                        <button onClick={() => setShowAddFlag(false)} className="text-xs text-slate-500">Cancel</button>
                        <button onClick={handleAddFlag} className="text-xs bg-red-600 text-white px-3 py-1 rounded font-bold">Add Flag</button>
                    </div>
                </div>
            )}

            {/* Active Flags List */}
            {candidate.complianceFlags && candidate.complianceFlags.some(f => !f.isResolved) && (
                <div className="mb-4 space-y-2">
                    {candidate.complianceFlags.filter(f => !f.isResolved).map(flag => (
                        <div key={flag.id} className={`p-2 rounded-md border flex justify-between items-start ${flag.severity === 'CRITICAL' ? 'bg-red-50 border-red-200' : 'bg-amber-50 border-amber-200'}`}>
                            <div className="flex gap-2">
                                <Flag size={14} className={flag.severity === 'CRITICAL' ? 'text-red-600' : 'text-amber-600'} />
                                <div>
                                    <p className={`text-xs font-bold ${flag.severity === 'CRITICAL' ? 'text-red-800' : 'text-amber-800'}`}>
                                        {flag.type} - {flag.severity}
                                    </p>
                                    <p className="text-xs text-slate-700">{flag.reason}</p>
                                    <p className="text-[10px] text-slate-400 mt-1">By {flag.createdBy} on {new Date(flag.createdAt).toLocaleDateString()}</p>
                                </div>
                            </div>
                            <button
                                onClick={() => handleResolveFlag(flag.id)}
                                className="text-[10px] text-blue-600 hover:underline bg-white/50 px-2 py-1 rounded border border-blue-100"
                            >
                                Resolve
                            </button>
                        </div>
                    ))}
                </div>
            )}

            {/* Compliance Issues Summary */}
            {(criticalIssues.length > 0 || warningIssues.length > 0) && (
                <div className="mb-4 space-y-2">
                    {criticalIssues.map((item, idx) => (
                        <div key={`crit-${idx}`} className="bg-red-50 border border-red-100 p-2 rounded-md flex gap-2 items-start">
                            <AlertOctagon size={14} className="text-red-600 mt-0.5" />
                            <div>
                                <p className="text-xs font-bold text-red-700">{item.issue?.message}</p>
                                <p className="text-[10px] text-red-500">{item.issue?.remedy}</p>
                            </div>
                        </div>
                    ))}
                    {warningIssues.map((item, idx) => (
                        <div key={`warn-${idx}`} className="bg-amber-50 border border-amber-100 p-2 rounded-md flex gap-2 items-start">
                            <AlertTriangle size={14} className="text-amber-600 mt-0.5" />
                            <p className="text-xs font-medium text-amber-700">{item.issue?.message}</p>
                        </div>
                    ))}
                </div>
            )}

            {/* ... Existing Passport/PCC/Medical Sections ... */}
            <div className="space-y-4">
                {/* Passport Section */}
                {/* Check for multiple passports or single legacy passport */}
                {(candidate.passports && candidate.passports.length > 0 ? candidate.passports : (passport ? [passport] : [])).map((ppt, idx) => (
                    <div key={idx} className={`p-4 rounded-lg border mb-3 ${ppt ? getStatusColor(ppt.status) : 'bg-slate-50 border-slate-200 border-dashed'}`}>
                        <div className="flex justify-between items-start mb-2">
                            <div className="flex items-center gap-2">
                                <span className="font-bold text-sm uppercase tracking-wide">Passport {candidate.passports && candidate.passports.length > 1 ? `#${idx + 1}` : ''}</span>
                                {ppt && !isEditing && getStatusIcon(ppt.status)}
                            </div>
                            {ppt && !isEditing && (
                                <span className="text-xs font-bold px-2 py-0.5 bg-white/50 rounded-full border border-black/5">
                                    {ppt.status}
                                </span>
                            )}
                        </div>

                        {isEditing ? (
                            <div className="space-y-3 mt-2">
                                {/* Simple single-edit mode for primary passport only (idx 0) for now to avoid complexity in widget */}
                                {idx === 0 && (
                                    <>
                                        <div>
                                            <label className="block text-xs font-bold text-slate-500 mb-1">Passport Number</label>
                                            <input
                                                type="text"
                                                value={formData.passportNumber}
                                                onChange={e => setFormData({ ...formData, passportNumber: e.target.value })}
                                                className="w-full text-sm border-slate-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                                                placeholder="Enter Passport No."
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-xs font-bold text-slate-500 mb-1">Country</label>
                                            <input
                                                type="text"
                                                value={formData.passportCountry}
                                                onChange={e => setFormData({ ...formData, passportCountry: e.target.value })}
                                                className="w-full text-sm border-slate-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                                            />
                                        </div>
                                        <div className="grid grid-cols-2 gap-2">
                                            <div>
                                                <label className="block text-xs font-bold text-slate-500 mb-1">Issued Date</label>
                                                <input
                                                    type="date"
                                                    value={formData.passportIssued}
                                                    onChange={e => setFormData({ ...formData, passportIssued: e.target.value })}
                                                    className="w-full text-sm border-slate-300 rounded-md"
                                                />
                                            </div>
                                            <div>
                                                <label className="block text-xs font-bold text-slate-500 mb-1">Expiry Date</label>
                                                <input
                                                    type="date"
                                                    value={formData.passportExpiry}
                                                    onChange={e => setFormData({ ...formData, passportExpiry: e.target.value })}
                                                    className="w-full text-sm border-slate-300 rounded-md"
                                                />
                                            </div>
                                        </div>
                                    </>
                                )}
                                {idx > 0 && <div className="text-xs text-slate-400 italic">Editing secondary passports is only available in full profile edit.</div>}
                            </div>
                        ) : (
                            ppt ? (
                                <div className="text-sm space-y-1">
                                    <div className="flex justify-between">
                                        <span className="opacity-75">Number:</span>
                                        <span className="font-mono font-bold">{ppt.passportNumber}</span>
                                    </div>
                                    <div className="flex justify-between">
                                        <span className="opacity-75">Country:</span>
                                        <span>{ppt.country}</span>
                                    </div>
                                    {ppt.expiryDate ? (
                                        <>
                                            <div className="flex justify-between">
                                                <span className="opacity-75">Expiry:</span>
                                                <span>{ppt.expiryDate}</span>
                                            </div>
                                            <div className="flex justify-between items-center mt-2 pt-2 border-t border-black/5">
                                                <span className="text-xs opacity-75">Validity:</span>
                                                <span className={`font-bold ${ppt.validityDays < 180 ? 'text-red-600' : 'text-green-700'}`}>
                                                    {ppt.validityDays} days remaining
                                                </span>
                                            </div>
                                        </>
                                    ) : (
                                        <div className="flex justify-between items-center mt-2 pt-2 border-t border-black/5 text-red-600">
                                            <span className="text-xs opacity-75">Expiry:</span>
                                            <span className="font-bold">Missing</span>
                                        </div>
                                    )}
                                </div>
                            ) : (
                                <div className="text-center py-2 text-slate-400 text-sm">
                                    No Passport Data Linked
                                </div>
                            )
                        )}
                    </div>
                ))}

                {(!candidate.passports || candidate.passports.length === 0) && !passport && (
                    <div className="p-4 rounded-lg border bg-slate-50 border-slate-200 border-dashed text-center py-4 text-slate-400 text-sm">
                        No Passport Data Linked
                    </div>
                )}

                {/* PCC Section */}
                <div className={`p-4 rounded-lg border ${pcc ? getStatusColor(pcc.status) : 'bg-slate-50 border-slate-200 border-dashed'}`}>
                    <div className="flex justify-between items-start mb-2">
                        <div className="flex items-center gap-2">
                            <span className="font-bold text-sm uppercase tracking-wide">Police Clearance</span>
                            {pcc && !isEditing && getStatusIcon(pcc.status)}
                        </div>
                        {pcc && !isEditing && (
                            <span className="text-xs font-bold px-2 py-0.5 bg-white/50 rounded-full border border-black/5">
                                {pcc.status}
                            </span>
                        )}
                    </div>

                    {isEditing ? (
                        <div className="space-y-3 mt-2">
                            <div className="grid grid-cols-2 gap-2">
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 mb-1">PCC Issued Date</label>
                                    <input
                                        type="date"
                                        value={formData.pccIssued}
                                        onChange={e => setFormData({ ...formData, pccIssued: e.target.value })}
                                        className="w-full text-sm border-slate-300 rounded-md"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 mb-1">Expiry Date (Auto)</label>
                                    <input
                                        type="date"
                                        value={formData.pccExpiry || (formData.pccIssued ? ComplianceService.evaluatePCC(formData.pccIssued).expiryDate : '') || ''}
                                        onChange={e => setFormData({ ...formData, pccExpiry: e.target.value })}
                                        className="w-full text-sm border-slate-300 rounded-md transition-all focus:ring-2 focus:ring-blue-500"
                                    />
                                </div>
                            </div>
                        </div>
                    ) : (
                        pcc ? (
                            <div className="text-sm space-y-1">
                                <div className="flex justify-between">
                                    <span className="opacity-75">Issued:</span>
                                    <span>{pcc.issuedDate}</span>
                                </div>
                                {pcc.expiryDate && (
                                    <div className="flex justify-between">
                                        <span className="opacity-75">Expiry Date:</span>
                                        <span className="font-medium text-blue-600">{pcc.expiryDate}</span>
                                    </div>
                                )}
                                <div className="flex justify-between items-center mt-2 pt-2 border-t border-black/5">
                                    <span className="text-xs opacity-75">Age:</span>
                                    <span className={`font-bold ${pcc.ageDays > 150 ? 'text-red-600' : 'text-green-700'}`}>
                                        {pcc.ageDays} days old
                                    </span>
                                </div>
                            </div>
                        ) : (
                            <div className="text-center py-2 text-slate-400 text-sm">
                                No PCC Data Linked
                            </div>
                        )
                    )}
                </div>

                {/* Medical Status Section */}
                {(stageData?.medicalStatus || candidate.medicalData?.status) && (
                    <div className={`p-4 rounded-lg border ${(stageData?.medicalStatus || candidate.medicalData?.status) === MedicalStatus.COMPLETED ? 'bg-green-50 border-green-200' :
                        (stageData?.medicalStatus || candidate.medicalData?.status) === MedicalStatus.FAILED ? 'bg-red-50 border-red-200' :
                            (stageData?.medicalStatus || candidate.medicalData?.status) === MedicalStatus.SCHEDULED ? 'bg-blue-50 border-blue-200' :
                                'bg-slate-50 border-slate-200'
                        }`}>
                        <div className="flex justify-between items-start mb-2">
                            <div className="flex items-center gap-2">
                                <Activity size={16} className={
                                    (stageData?.medicalStatus || candidate.medicalData?.status) === MedicalStatus.COMPLETED ? 'text-green-600' :
                                        (stageData?.medicalStatus || candidate.medicalData?.status) === MedicalStatus.FAILED ? 'text-red-600' :
                                            (stageData?.medicalStatus || candidate.medicalData?.status) === MedicalStatus.SCHEDULED ? 'text-blue-600' :
                                                'text-slate-400'
                                } />
                                <span className="font-bold text-sm uppercase tracking-wide">Medical Status</span>
                            </div>
                            <span className={`text-xs font-bold px-2 py-0.5 rounded-full border ${(stageData?.medicalStatus || candidate.medicalData?.status) === MedicalStatus.COMPLETED ? 'bg-green-100 text-green-700 border-green-300' :
                                (stageData?.medicalStatus || candidate.medicalData?.status) === MedicalStatus.FAILED ? 'bg-red-100 text-red-700 border-red-300' :
                                    (stageData?.medicalStatus || candidate.medicalData?.status) === MedicalStatus.SCHEDULED ? 'bg-blue-100 text-blue-700 border-blue-300' :
                                        'bg-slate-100 text-slate-600 border-slate-300'
                                }`}>
                                {(stageData?.medicalStatus || candidate.medicalData?.status)}
                            </span>
                        </div>

                        <div className="text-sm space-y-1">
                            {(stageData?.medicalScheduledDate || candidate.medicalData?.scheduledDate) && (
                                <div className="flex justify-between items-center">
                                    <span className="opacity-75 flex items-center gap-1">
                                        <Calendar size={14} />
                                        Scheduled:
                                    </span>
                                    <span className="font-medium text-blue-600">{stageData?.medicalScheduledDate || candidate.medicalData?.scheduledDate}</span>
                                </div>
                            )}
                            {(stageData?.medicalCompletedDate || candidate.medicalData?.completedDate) && (
                                <div className="flex justify-between">
                                    <span className="opacity-75">Completed:</span>
                                    <span className="font-medium text-green-600">{stageData?.medicalCompletedDate || candidate.medicalData?.completedDate}</span>
                                </div>
                            )}
                            {(stageData?.medicalNotes || candidate.medicalData?.notes) && (
                                <div className="mt-2 pt-2 border-t border-black/5">
                                    <span className="text-xs opacity-75 block mb-1">Notes:</span>
                                    <p className="text-xs italic">{stageData?.medicalNotes || candidate.medicalData?.notes}</p>
                                </div>
                            )}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default ComplianceWidget;

import React, { useState, useEffect } from 'react';
import { TaskEngine } from '../services/taskEngine';
import { CandidateService } from '../services/candidateService';
import { NotificationService } from '../services/notificationService';
import { FinanceService } from '../services/financeService';
import { PartnerService } from '../services/partnerService';
import { JobService } from '../services/jobService';
import { DemandOrderService } from '../services/demandOrderService';
import { WorkTask, SystemAlert, Candidate, WorkflowStage, ProfileCompletionStatus, JobStatus, DemandOrderStatus } from '../types';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import {
   CheckCircle, AlertTriangle, Clock, Activity, ArrowRight,
   Calendar, Zap, Bell, FileText, UserPlus,
   Briefcase, TrendingUp, MessageCircle, Layout, Settings as SettingsIcon, FilePlus,
   Package, Building2
} from 'lucide-react';
import Skeleton from './ui/Skeleton';
import WidgetErrorBoundary from './ui/WidgetErrorBoundary';

const Dashboard: React.FC = () => {
   const [candidates, setCandidates] = useState<Candidate[]>([]);
   const [tasks, setTasks] = useState<WorkTask[]>([]);
   const [alerts, setAlerts] = useState<SystemAlert[]>([]);
   const [projectedRevenue, setProjectedRevenue] = useState(0);
   const [openJobsCount, setOpenJobsCount] = useState(0);
   const [activeDemands, setActiveDemands] = useState(0);
   const [isLoading, setIsLoading] = useState(true);
   const [activeTaskTab, setActiveTaskTab] = useState<'priority' | 'alerts' | 'compliance'>('priority');
   const navigate = useNavigate();
   const { user } = useAuth();
   const isAdmin = user?.role === 'Admin';

   useEffect(() => {
      const loadDashboardData = async () => {
         try {
            // FRICTIONLESS MODE: Parallel Fetching to eliminate network waterfalls.
            // Only fetch restricted data if user is an Admin.
            const [data, employers, jobs, orders] = await Promise.all([
               CandidateService.getCandidates().then(res => res || []),
               isAdmin ? PartnerService.getEmployers().then(res => res || []) : Promise.resolve([]),
               isAdmin ? JobService.getJobs().then(res => res || []) : Promise.resolve([]),
               isAdmin ? DemandOrderService.getAll().then(res => res || []) : Promise.resolve([])
            ]);

            // OFFLINE MODE: Cache latest data
            if (data.length > 0) localStorage.setItem('caditare_dash_data', JSON.stringify(data));
            if (isAdmin) {
               if (employers.length > 0) localStorage.setItem('caditare_dash_employers', JSON.stringify(employers));
               if (jobs.length > 0) localStorage.setItem('caditare_dash_jobs', JSON.stringify(jobs));
               if (orders.length > 0) localStorage.setItem('caditare_dash_orders', JSON.stringify(orders));
            }

            setCandidates(data);
            const generatedTasks = TaskEngine.generateWorkQueue(data);
            const generatedAlerts = TaskEngine.generateAlerts(data);
            setTasks(generatedTasks);
            setAlerts(generatedAlerts);

            if (isAdmin) {
               setProjectedRevenue(FinanceService.getProjectedRevenue(data, employers));
               setOpenJobsCount(jobs.filter(j => j.status === JobStatus.OPEN).length);
               setActiveDemands(orders.filter(o => o.status === DemandOrderStatus.OPEN || o.status === DemandOrderStatus.PARTIALLY_FILLED).length);
            }
         } catch (error) {
            console.error('Failed to load dashboard data:', error);
            // OFFLINE MODE: Fallback to cached data if network fails
            const cData = localStorage.getItem('caditare_dash_data');
            const cEmpl = localStorage.getItem('caditare_dash_employers');
            const cJobs = localStorage.getItem('caditare_dash_jobs');
            const cOrders = localStorage.getItem('caditare_dash_orders');

            if (cData && cEmpl && cJobs && cOrders) {
               console.log('Network offline. Serving dashboard from local cache.');
               const data = JSON.parse(cData);
               const employers = JSON.parse(cEmpl);
               const jobs = JSON.parse(cJobs);
               const orders = JSON.parse(cOrders);

               setCandidates(data);
               setTasks(TaskEngine.generateWorkQueue(data));
               setAlerts(TaskEngine.generateAlerts(data));
               setProjectedRevenue(FinanceService.getProjectedRevenue(data, employers));
               setOpenJobsCount(jobs.filter((j: any) => j.status === JobStatus.OPEN).length);
               setActiveDemands(orders.filter((o: any) => o.status === DemandOrderStatus.OPEN || o.status === DemandOrderStatus.PARTIALLY_FILLED).length);
            }
         } finally {
            setIsLoading(false);
         }
      };
      loadDashboardData();
   }, []);

   const activeCandidates = candidates.length;
   const criticalIssues = tasks.filter(t => t.priority === 'Critical').length;

   // Profile Completion Stats
   const quickProfiles = candidates.filter(c => c.profileCompletionStatus === ProfileCompletionStatus.QUICK).length;
   const partialProfiles = candidates.filter(c => c.profileCompletionStatus === ProfileCompletionStatus.PARTIAL && (c.profileCompletionPercentage || 0) < 75).length;
   const completeProfiles = candidates.filter(c => c.profileCompletionStatus === ProfileCompletionStatus.COMPLETE || (c.profileCompletionPercentage || 0) >= 75).length;

   const verificationPercent = activeCandidates > 0 ? Math.round((completeProfiles / activeCandidates) * 100) : 0;
   const deployedCount = candidates.filter(c => c.stage === WorkflowStage.DEPARTED).length;
   const deployedPercent = activeCandidates > 0 ? Math.round((deployedCount / activeCandidates) * 100) : 0;

   // Tab-specific filtered data
   const priorityTasks = tasks; // all tasks sorted by priority
   const complianceTasks = tasks.filter(t => t.type === 'ISSUE');
   const alertItems = alerts;

   const getActiveContent = () => {
      if (activeTaskTab === 'alerts') {
         return alertItems.length > 0 ? (
            <div className="divide-y divide-slate-100">
               {alertItems.map((alert) => (
                  <div key={alert.id} className={`p-4 md:p-6 flex items-start gap-4 md:gap-5 border-l-4 transition-all duration-300 ${alert.type === 'DELAY' ? 'border-red-500' :
                     alert.type === 'WARNING' ? 'border-amber-500' : 'border-blue-500'
                     }`}>
                     <div className="pt-1 shrink-0">
                        {alert.type === 'DELAY' ? <AlertTriangle className="text-red-500" size={28} /> :
                           alert.type === 'WARNING' ? <AlertTriangle className="text-amber-500" size={28} /> :
                              <Bell className="text-blue-500" size={28} />}
                     </div>
                     <div className="flex-1 min-w-0">
                        <div className="flex justify-between items-start gap-3 mb-2">
                           <h4 className="font-black text-slate-900 text-lg uppercase tracking-tight">{alert.message}</h4>
                           <span className={`text-xs font-medium px-2 py-0.5 rounded-md shrink-0 ${alert.type === 'DELAY' ? 'bg-red-500 text-white shadow-red-100' :
                              alert.type === 'WARNING' ? 'bg-amber-500 text-white shadow-amber-100' : 'bg-blue-600 text-white shadow-blue-100'
                              }`}>
                              {alert.type}
                           </span>
                        </div>
                        <p className="text-sm text-slate-500 font-medium">
                           {alert.count} candidate{alert.count !== 1 ? 's' : ''} affected
                        </p>
                        <div className="flex items-center gap-4 text-xs mt-3">
                           <span className="text-slate-500 font-medium">
                              <Clock size={12} className="inline mr-1" />
                              {new Date(alert.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                           </span>
                        </div>
                     </div>
                  </div>
               ))}
            </div>
         ) : renderEmpty('No Active Alerts', 'All systems operating normally.');
      }

      if (activeTaskTab === 'compliance') {
         return complianceTasks.length > 0 ? renderTaskList(complianceTasks) : renderEmpty('No Compliance Issues', 'All candidates are compliant.');
      }

      // Default: priority
      return priorityTasks.length > 0 ? renderTaskList(priorityTasks) : renderEmpty('All Caught Up', 'No pending tasks.');
   };

   const renderTaskList = (taskList: WorkTask[]) => (
      <div className="divide-y divide-slate-100">
         {taskList.map((task) => (
            <div key={task.id} onClick={() => navigate(`/candidates/${task.candidateId}`)} className={`p-4 md:p-6 hover:bg-slate-50 transition-colors cursor-pointer group flex items-start gap-4 md:gap-5 border-l-4 transition-all duration-300 ${task.priority === 'Critical' ? 'border-red-500' :
               task.priority === 'High' ? 'border-amber-500' : 'border-blue-500'
               }`}>
               <div className="pt-1 shrink-0 group-hover:scale-110 transition-premium">
                  {task.priority === 'Critical' ? <AlertTriangle className="text-red-500" size={28} /> :
                     task.priority === 'High' ? <Clock className="text-amber-500" size={28} /> :
                        <FileText className="text-blue-500" size={28} />}
               </div>
               <div className="flex-1 min-w-0">
                  <div className="flex justify-between items-start gap-3 mb-2">
                     <h4 className="font-semibold text-slate-900 group-hover:text-blue-600 transition-colors text-base">{task.title}</h4>
                     <span className={`text-xs font-medium px-2 py-0.5 rounded-md shrink-0 ${task.priority === 'Critical' ? 'bg-red-500 text-white shadow-red-100' :
                        task.priority === 'High' ? 'bg-amber-500 text-white shadow-amber-100' : 'bg-blue-600 text-white shadow-blue-100'
                        }`}>
                        {task.priority}
                     </span>
                  </div>
                  <p className="text-sm text-slate-500 mb-4 font-medium leading-relaxed">{task.description}</p>
                  <div className="flex flex-wrap items-center gap-4 text-xs">
                     <span className="flex items-center gap-2 font-medium text-slate-700 bg-slate-100 px-3 py-1.5 rounded-lg border border-slate-200">
                        <UserPlus size={14} className="text-blue-500" /> {task.candidateName}
                     </span>
                     <span className="text-slate-500 font-medium">{task.stage}</span>
                     <span className="ml-auto text-red-600 font-medium flex items-center gap-1.5">
                        <Clock size={12} /> {task.dueDate}
                     </span>
                  </div>
               </div>
               <div className="self-center hidden md:block opacity-0 group-hover:opacity-100 transition-premium shrink-0 translate-x-4 group-hover:translate-x-0">
                  <ArrowRight size={24} className="text-blue-600" />
               </div>
            </div>
         ))}
      </div>
   );

   const renderEmpty = (title: string, subtitle: string) => (
      <div className="flex flex-col items-center justify-center py-24 px-6 text-center">
         <div className="mb-4">
            <CheckCircle size={32} className="text-slate-300" />
         </div>
         <p className="font-semibold text-slate-900 mb-1">{title}</p>
         <p className="text-sm text-slate-500 max-w-[200px]">{subtitle}</p>
      </div>
   );

   return (
      <div className="container-responsive py-4 sm:py-6 md:py-8 space-y-4 sm:space-y-6 md:space-y-8">
         {/* 1. Header Row: High-Level Status (KPIs) */}
         <div className="grid grid-cols-2 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-3 xl:grid-cols-6 gap-3 sm:gap-4">
            {isLoading ? (
               Array.from({ length: 4 }).map((_, i) => (
                  <div key={i} className="bg-white border border-slate-200 rounded-lg p-5 flex items-center justify-between h-[116px]">
                     <div className="space-y-3 w-full">
                        <Skeleton className="h-3 w-24" />
                        <Skeleton className="h-8 w-16" />
                        <Skeleton className="h-3 w-32" />
                     </div>
                     <Skeleton className="h-12 w-12 rounded-xl" />
                  </div>
               ))
            ) : (
               <>
                  <div
                     onClick={() => navigate('/candidates')}
                     className="bg-slate-900 group relative overflow-hidden p-6 rounded-xl shadow-sm hover:shadow-md transition-shadow cursor-pointer"
                  >
                     <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-colors"></div>
                     <div className="flex items-center justify-between relative z-10">
                        <div className="flex-1 min-w-0 pr-2">
                           <p className="text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1 truncate">Total Candidates</p>
                           <h3 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-white mb-1 truncate">{activeCandidates}</h3>
                           <p className="text-xs text-emerald-400 font-bold flex items-center gap-1 uppercase tracking-tight truncate">
                              <Activity size={10} className="shrink-0" /> Online
                           </p>
                        </div>
                        <div className="bg-white/10 backdrop-blur-md p-3 rounded-xl border border-white/10 text-blue-400 group-hover:scale-110 transition-transform shrink-0">
                           <Briefcase size={24} />
                        </div>
                     </div>
                  </div>

                  <div
                     onClick={() => navigate('/pipeline')}
                     className="bg-red-600 group relative overflow-hidden p-6 rounded-xl shadow-sm hover:shadow-md transition-shadow cursor-pointer"
                  >
                     <div className="absolute inset-0 bg-gradient-to-br from-white/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
                     <div className="flex items-center justify-between relative z-10">
                        <div className="flex-1 min-w-0 pr-2">
                           <p className="text-red-100 text-xs font-semibold uppercase tracking-wider mb-1 truncate">Pending Actions</p>
                           <h3 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-white mb-1 truncate">{criticalIssues}</h3>
                           <p className="text-xs text-red-100 font-bold uppercase tracking-tight truncate">Critical</p>
                        </div>
                        <div className="bg-white/20 backdrop-blur-md p-3 rounded-xl border border-white/20 text-yellow-300 group-hover:rotate-12 transition-transform shrink-0">
                           <Zap size={24} />
                        </div>
                     </div>
                  </div>

                  {isAdmin && (
                     <div
                        onClick={() => navigate('/finance')}
                        className="bg-blue-600 group relative overflow-hidden p-6 rounded-xl shadow-sm hover:shadow-md transition-shadow cursor-pointer"
                     >
                        <div className="absolute inset-0 bg-gradient-to-br from-white/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
                        <div className="flex items-center justify-between relative z-10">
                           <div className="flex-1 min-w-0 pr-2">
                              <p className="text-blue-100 text-xs font-semibold uppercase tracking-wider mb-1 truncate">Projected Revenue</p>
                              <h3 className="text-2xl sm:text-2xl lg:text-3xl xl:text-2xl 2xl:text-3xl font-bold text-white mb-1 truncate" title={`$${projectedRevenue.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`}>${projectedRevenue.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</h3>
                              <p className="text-xs text-blue-100 font-bold uppercase tracking-tight truncate">Projected Revenue</p>
                           </div>
                           <div className="bg-white/20 backdrop-blur-md p-3 rounded-xl border border-white/20 text-emerald-300 group-hover:-translate-y-1 transition-transform shrink-0">
                              <TrendingUp size={24} />
                           </div>
                        </div>
                     </div>
                  )}

                  <div
                     onClick={() => navigate('/candidates?stage=Departed')}
                     className="bg-emerald-600 group relative overflow-hidden p-6 rounded-xl shadow-sm hover:shadow-md transition-shadow cursor-pointer"
                  >
                     <div className="absolute inset-0 bg-gradient-to-br from-white/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
                     <div className="flex items-center justify-between relative z-10">
                        <div className="flex-1 min-w-0 pr-2">
                           <p className="text-emerald-100 text-xs font-semibold uppercase tracking-wider mb-1 truncate">Deployed</p>
                           <h3 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-white mb-1 truncate">{candidates.filter(c => c.stage === WorkflowStage.DEPARTED).length}</h3>
                           <p className="text-xs text-emerald-100 font-bold uppercase tracking-tight truncate">Ready for bill</p>
                        </div>
                        <div className="bg-white/20 backdrop-blur-md p-3 rounded-xl border border-white/20 text-yellow-300 group-hover:scale-110 transition-transform shrink-0">
                           <Calendar size={24} />
                        </div>
                     </div>
                  </div>

                  {isAdmin && (
                     <>
                        <div
                           onClick={() => navigate('/jobs')}
                           className="bg-purple-600 group relative overflow-hidden p-6 rounded-xl shadow-sm hover:shadow-md transition-shadow cursor-pointer"
                        >
                           <div className="absolute inset-0 bg-gradient-to-br from-white/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
                           <div className="flex items-center justify-between relative z-10">
                              <div className="flex-1 min-w-0 pr-2">
                                 <p className="text-purple-100 text-xs font-semibold uppercase tracking-wider mb-1 truncate">Open Jobs</p>
                                 <h3 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-white mb-1 truncate">{openJobsCount}</h3>
                                 <p className="text-xs text-purple-100 font-bold uppercase tracking-tight truncate">Hiring Now</p>
                              </div>
                              <div className="bg-white/20 backdrop-blur-md p-3 rounded-xl border border-white/20 text-yellow-300 group-hover:scale-110 transition-transform shrink-0">
                                 <Briefcase size={24} />
                              </div>
                           </div>
                        </div>

                        <div
                           onClick={() => navigate('/partners')}
                           className="bg-indigo-600 group relative overflow-hidden p-6 rounded-xl shadow-sm hover:shadow-md transition-shadow cursor-pointer"
                        >
                           <div className="absolute inset-0 bg-gradient-to-br from-white/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
                           <div className="flex items-center justify-between relative z-10">
                              <div className="flex-1 min-w-0 pr-2">
                                 <p className="text-indigo-100 text-xs font-semibold uppercase tracking-wider mb-1 truncate">Active Demands</p>
                                 <h3 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-white mb-1 truncate">{activeDemands}</h3>
                                 <p className="text-xs text-indigo-100 font-bold uppercase tracking-tight truncate">Orders Open</p>
                              </div>
                              <div className="bg-white/20 backdrop-blur-md p-3 rounded-xl border border-white/20 text-cyan-300 group-hover:rotate-12 transition-transform shrink-0">
                                 <Package size={24} />
                              </div>
                           </div>
                        </div>
                     </>
                  )}
               </>
            )}
         </div>

         {/* Database Health Overview */}
         <div className="bg-white border border-slate-200 rounded-lg p-4 sm:p-6 md:p-8">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 sm:gap-4 mb-6 sm:mb-8">
               <div>
                  <h2 className="text-xl font-semibold text-slate-900 flex items-center gap-3 uppercase tracking-tight">
                     <Activity className="text-blue-600" size={24} />
                     System Status
                  </h2>
                  <p className="text-sm text-slate-500 mt-1">Database Health</p>
               </div>
               <button
                  onClick={() => navigate('/candidates?status=quick')}
                  className="px-6 py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 transition-colors text-sm font-medium"
               >
                  Action Required
               </button>
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-2 md:grid-cols-2 lg:grid-cols-4 gap-3 sm:gap-4 md:gap-6">
               <div className="flex items-center justify-center p-4 bg-slate-50/50 rounded-xl border border-slate-100">
                  <div className="relative w-32 h-32 animate-float">
                     <svg className="transform -rotate-90 w-32 h-32">
