import React, { useState, useMemo, useEffect } from 'react';
import { useParams, Link, useNavigate, useSearchParams } from 'react-router-dom';
import { PartnerService } from '../services/partnerService';
import { CandidateService } from '../services/candidateService';
import { JobService } from '../services/jobService';
import { DemandOrderService } from '../services/demandOrderService';
import { SelectionService } from '../services/selectionService';
import {
    Employer, EmployerStatus, Candidate, DemandOrder,
    DemandOrderStatus, SelectionStage, Job
} from '../types';
import {
    Building2, Users, MapPin, Mail,
    ShieldCheck, AlertTriangle, Clock, Search, Plus,
    ChevronRight, FileText, Star,
    Briefcase, Package, LayoutDashboard, Kanban, Edit2, Trash2
} from 'lucide-react';
import DemandOrderList from './employer/DemandOrderList';
import DemandOrderForm from './employer/DemandOrderForm';
import SelectionBoard from './employer/SelectionBoard';
import CandidateMatchModal from './employer/CandidateMatchModal';
import AddPartnerModal from './employer/AddPartnerModal';

type DetailTab = 'overview' | 'demands' | 'selection';

const PartnerManager: React.FC = () => {
    const { id } = useParams<{ id?: string }>();
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();

    const [employers, setEmployers] = useState<Employer[]>([]);
    const [candidates, setCandidates] = useState<Candidate[]>([]);
    const [allOrders, setAllOrders] = useState<DemandOrder[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [refreshKey, setRefreshKey] = useState(0);

    // Filtered Data State
    const [employerJobs, setEmployerJobs] = useState<Job[]>([]);
    const [employerDemandOrders, setEmployerDemandOrders] = useState<DemandOrder[]>([]);

    // UI State
    const [searchQuery, setSearchQuery] = useState('');
    const [selectedEmployer, setSelectedEmployer] = useState<Employer | null>(null);
    const [activeTab, setActiveTab] = useState<DetailTab>('overview');

    // Modal State
    const [showAddPartner, setShowAddPartner] = useState(false);
    const [showEditPartner, setShowEditPartner] = useState(false);
    const [showDemandForm, setShowDemandForm] = useState(false);
    const [editingOrder, setEditingOrder] = useState<DemandOrder | undefined>();
    const [selectedOrder, setSelectedOrder] = useState<DemandOrder | null>(null);
    const [showMatchModal, setShowMatchModal] = useState(false);

    // Load initial data
    useEffect(() => {
        const loadInitialData = async () => {
            setIsLoading(true);
            try {
                const [employersData, candidatesData, ordersData] = await Promise.all([
                    PartnerService.getEmployers(),
                    CandidateService.getCandidates(),
                    DemandOrderService.getAll()
                ]);

                setEmployers(employersData || []);
                setCandidates(candidatesData || []);
                setAllOrders(ordersData || []);

                if (id) {
                    const emp = employersData.find(e => e.id === id);
                    if (emp) {
                        setSelectedEmployer(emp);
                        // Deep-link: auto-switch to demands tab and select order
                        const tabParam = searchParams.get('tab');
                        if (tabParam === 'demands' || tabParam === 'selection') {
                            setActiveTab(tabParam as DetailTab);
                        }
                        const orderParam = searchParams.get('order');
                        if (orderParam) {
                            // Since we fetched all orders, we can find it here
                            const order = ordersData.find(o => o.id === orderParam);
                            if (order) {
                                setSelectedOrder(order);
                                setActiveTab('demands');
                            }
                        }
                    }
                }
            } catch (error) {
                console.error("Failed to load partner data", error);
            } finally {
                setIsLoading(false);
            }
        };
        loadInitialData();
    }, [id, refreshKey]);

    // Load employer-specific data when selectedEmployer changes
    useEffect(() => {
        const loadEmployerData = async () => {
            if (!selectedEmployer) {
                setEmployerJobs([]);
                setEmployerDemandOrders([]);
                return;
            }

            try {
                const [jobs, orders] = await Promise.all([
                    JobService.getJobsByEmployerId(selectedEmployer.id),
                    DemandOrderService.getByEmployerId(selectedEmployer.id)
                ]);
                setEmployerJobs(jobs || []);
                setEmployerDemandOrders(orders || []);
            } catch (error) {
                console.error("Failed to load employer specific data", error);
            }
        };

        loadEmployerData();
    }, [selectedEmployer, refreshKey]);

    // Sync selectedOrder with latest data from allOrders
    useEffect(() => {
        if (selectedOrder) {
            const updated = allOrders.find(o => o.id === selectedOrder.id);
            if (updated && updated !== selectedOrder) {
                setSelectedOrder(updated);
            }
        }
    }, [allOrders, selectedOrder]);

    const employerCandidates = useMemo(() => {
        if (!selectedEmployer) return [];
        // We rely on employerJobs having been fetched
        const jobIds = employerJobs.map(j => j.id);
        return candidates.filter(c => c.jobId && jobIds.includes(c.jobId));
    }, [selectedEmployer, candidates, employerJobs]);

    const filteredEmployers = employers.filter(e => {
        const query = searchQuery.toLowerCase();
        return (
            (e.companyName || '').toLowerCase().includes(query) ||
            (e.country || '').toLowerCase().includes(query) ||
            (e.contactPerson || '').toLowerCase().includes(query)
        );
    });

    const getStatusColor = (status: EmployerStatus) => {
        switch (status) {
            case EmployerStatus.ACTIVE: return 'bg-green-100 text-green-700';
            case EmployerStatus.INACTIVE: return 'bg-slate-100 text-slate-700';
            case EmployerStatus.PENDING_APPROVAL: return 'bg-amber-100 text-amber-700';
            case EmployerStatus.BLACKLISTED: return 'bg-red-100 text-red-700';
            default: return 'bg-slate-100 text-slate-700';
        }
    };

    const triggerRefresh = () => setRefreshKey(k => k + 1);

    const handleSelectEmployer = (emp: Employer) => {
        setSelectedEmployer(emp);
        setActiveTab('overview');
        setSelectedOrder(null);
    };

    const handleDeletePartner = async (id: string) => {
        if (!window.confirm("Are you sure you want to delete this partner? This action cannot be undone.")) return;
        try {
            await PartnerService.deleteEmployer(id);
            triggerRefresh();
            setSelectedEmployer(null);
        } catch (error) {
            console.error("Failed to delete partner", error);
        }
    };

    const handleEditDemandOrder = (order: DemandOrder) => {
        setEditingOrder(order);
        setShowDemandForm(true);
    };

    const handleDeleteDemandOrder = async (id: string, name: string) => {
        if (!window.confirm(`Are you sure you want to delete the demand order "${name}"? This action cannot be undone.`)) return;
        try {
            await DemandOrderService.delete(id);
            triggerRefresh();
        } catch (error) {
            console.error("Failed to delete demand order", error);
        }
    };

    if (isLoading) return (
        <div className="p-8 text-center text-slate-500 flex flex-col items-center justify-center h-96 gap-4">
            <Building2 size={48} className="text-blue-600 animate-pulse" />
            <p className="font-bold">Loading Employer Dashboard...</p>
        </div>
    );

    // Compute global stats using state data
    const globalStats = {
        totalPartners: employers.length,
        activeAgreements: employers.filter(e => e.status === EmployerStatus.ACTIVE).length,
        openDemands: allOrders.filter(o => o.status === DemandOrderStatus.OPEN || o.status === DemandOrderStatus.PARTIALLY_FILLED).length,
        pendingDocs: employers.filter(e => e.status === EmployerStatus.PENDING_APPROVAL).length,
    };

    return (
        <div className="p-3 sm:p-4 md:p-8 max-w-7xl mx-auto space-y-6 md:space-y-8 animate-in fade-in pb-24 md:pb-8 duration-500">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-3xl font-bold text-slate-900">Employer CRM</h2>
                    <p className="text-slate-500 mt-1">Manage global partners, demand orders, and candidate selections.</p>
                </div>
                <button
                    onClick={() => setShowAddPartner(true)}
                    className="px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg text-sm font-medium flex items-center justify-center gap-2 hover:bg-slate-50 hover:text-blue-600 transition-colors shadow-sm btn-touch"
                >
                    <Plus size={16} /> <span className="hidden sm:inline">Add New Partner</span><span className="sm:hidden">Add</span>
                </button>
            </div>

            {/* STATS OVERVIEW */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
                {[
                    { label: 'Total Partners', value: globalStats.totalPartners, icon: Building2, color: 'text-blue-600', bg: 'bg-blue-50' },
                    { label: 'Active Agreements', value: globalStats.activeAgreements, icon: ShieldCheck, color: 'text-green-600', bg: 'bg-green-50' },
                    { label: 'Open Demands', value: globalStats.openDemands, icon: Package, color: 'text-purple-600', bg: 'bg-purple-50' },
                    { label: 'Pending Approval', value: globalStats.pendingDocs, icon: AlertTriangle, color: 'text-amber-600', bg: 'bg-amber-50' },
                ].map((stat, i) => (
                    <div key={i} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                        <div className="flex items-center gap-4">
                            <div className={`p-2.5 md:p-3 ${stat.bg} ${stat.color} rounded-xl shrink-0`}>
                                <stat.icon size={20} className="md:w-6 md:h-6" />
                            </div>
                            <div className="min-w-0">
                                <p className="text-[10px] md:text-xs font-bold text-slate-400 uppercase tracking-widest truncate">{stat.label}</p>
                                <h4 className="text-xl md:text-2xl font-black text-slate-800">{stat.value}</h4>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="flex flex-col lg:flex-row gap-8">
                {/* PARTNER LIST */}
                <div className="w-full lg:w-[380px] shrink-0 space-y-4">
                    <div className="relative">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input
                            type="text"
                            placeholder="Search by company name, country, or contact..."
                            className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-2xl shadow-sm outline-none focus:ring-2 focus:ring-blue-500 transition-all text-sm"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>

                    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden max-h-[50dvh] lg:max-h-[calc(100dvh-360px)] overflow-y-auto touch-pan-y">
                        {filteredEmployers.map(employer => {
                            const quotaPercent = employer.quotaTotal ? Math.round((employer.quotaUsed || 0) / employer.quotaTotal * 100) : 0;
                            // Need to count orders from allOrders since we can't fetch per employer in list efficiently without N+1
                            // Or we filter appropriately
                            const demandCount = allOrders.filter(o => o.employerId === employer.id).length;
                            const isSelected = selectedEmployer?.id === employer.id;

                            return (
                                <div
                                    key={employer.id}
                                    onClick={() => handleSelectEmployer(employer)}
                                    className={`px-5 py-4 hover:bg-blue-50/30 transition-colors cursor-pointer group border-b border-slate-50 last:border-b-0 ${isSelected ? 'bg-blue-50/50 border-l-4 border-l-blue-600' : ''
                                        }`}
                                >
                                    <div className="flex items-center gap-3">
                                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-bold transition-colors ${isSelected ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-400 group-hover:bg-blue-100 group-hover:text-blue-600'
                                            }`}>
                                            {employer.companyName.charAt(0)}
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <p className="font-bold text-slate-800 text-sm truncate">{employer.companyName}</p>
                                            <div className="flex items-center gap-2 mt-0.5">
                                                <span className="text-[10px] text-slate-500 flex items-center gap-0.5">
                                                    <MapPin size={9} /> {employer.country}
                                                </span>
                                                {demandCount > 0 && (
                                                    <span className="text-[9px] font-bold px-1.5 py-0.5 bg-purple-50 text-purple-600 rounded">
                                                        {demandCount} orders
                                                    </span>
                                                )}
                                            </div>
                                        </div>
                                        <div className="flex flex-col items-end gap-1 shrink-0">
                                            <span className={`px-2 py-0.5 rounded-full text-[9px] font-bold uppercase tracking-wider ${getStatusColor(employer.status)} truncate max-w-[80px] sm:max-w-none`}>
                                                {employer.status}
                                            </span>
                                            <div className="w-16 h-1 bg-slate-100 rounded-full overflow-hidden mt-1">
                                                <div
                                                    className={`h-full transition-all duration-700 ${quotaPercent > 90 ? 'bg-red-500' : quotaPercent > 70 ? 'bg-amber-500' : 'bg-blue-600'}`}
                                                    style={{ width: `${quotaPercent}%` }}
                                                />
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                        {filteredEmployers.length === 0 && (
                            <div className="px-6 py-12 text-center">
                                <Building2 size={32} className="mx-auto text-slate-300 mb-2" />
                                <p className="text-xs text-slate-400 font-bold">No partners found</p>
                            </div>
                        )}
                    </div>
                </div>

                {/* DETAIL AREA */}
                <div className="flex-1 min-w-0">
                    {selectedEmployer ? (
                        <div className="space-y-6">
                            {/* Employer Header */}
                            <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6">
                                <div className="flex items-start justify-between">
                                    <div className="flex items-center gap-4">
                                        <div className="w-16 h-16 bg-blue-600 text-white rounded-2xl flex items-center justify-center text-2xl font-black">
                                            {selectedEmployer.companyName.charAt(0)}
                                        </div>
                                        <div>
                                            <h3 className="text-xl font-bold text-slate-800 break-words line-clamp-2">{selectedEmployer.companyName}</h3>
                                            <p className="text-sm text-slate-500 flex items-center gap-2 mt-0.5 flex-wrap">
                                                <MapPin size={12} className="shrink-0" /> <span className="truncate max-w-[120px]">{selectedEmployer.country}</span>
                                                <span className="text-slate-300">•</span>
                                                {selectedEmployer.regNumber}
                                            </p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2 flex-wrap justify-end">
                                        <span className={`px-2 md:px-3 py-1 rounded-full text-[9px] md:text-[10px] font-bold uppercase tracking-wider ${getStatusColor(selectedEmployer.status)} truncate max-w-[100px] md:max-w-none`}>
                                            {selectedEmployer.status}
                                        </span>
                                        <span className="inline-flex items-center gap-1.5 px-2 py-1 bg-green-50 text-green-700 rounded-lg text-xs font-bold border border-green-100">
                                            <Star size={12} fill="currentColor" /> {selectedEmployer.selectionRatio ? (selectedEmployer.selectionRatio * 10).toFixed(1) : '8.5'}
                                        </span>
                                        <Link
                                            to={`/jobs?employer=${selectedEmployer.id}`}
                                            className="inline-flex items-center gap-1.5 px-3 py-1 bg-white text-slate-700 rounded-lg text-xs font-medium border border-slate-200 hover:text-blue-600 transition-all shrink-0 shadow-sm"
                                        >
                                            <Briefcase size={12} className="hidden sm:block text-slate-400 group-hover:text-blue-500" /> View Jobs ({employerJobs.length})
                                        </Link>
                                        <button onClick={() => setShowEditPartner(true)} className="p-1.5 bg-slate-100 text-slate-600 rounded-lg hover:bg-blue-100 hover:text-blue-600 transition-colors" title="Edit Partner">
                                            <Edit2 size={16} />
                                        </button>
                                        <button onClick={() => handleDeletePartner(selectedEmployer.id)} className="p-1.5 bg-slate-100 text-red-500 rounded-lg hover:bg-red-100 transition-colors" title="Delete Partner">
                                            <Trash2 size={16} />
                                        </button>
                                    </div>
                                </div>

                                {/* Quick Stats */}
                                <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-5 gap-3 mt-5">
                                    <div className="p-3 bg-slate-50 rounded-xl border border-slate-100">
                                        <p className="text-[9px] font-bold text-slate-400 uppercase mb-1">Comms / Hire</p>
                                        <p className="text-lg font-black text-slate-800">${selectedEmployer.commissionPerHire || '450'}</p>
                                    </div>
                                    <div className="p-3 bg-slate-50 rounded-xl border border-slate-100">
                                        <p className="text-[9px] font-bold text-slate-400 uppercase mb-1">Pay Cycle</p>
                                        <p className="text-lg font-black text-slate-800">{selectedEmployer.paymentTermDays || '30'} Days</p>
                                    </div>
                                    <div className="p-3 bg-slate-50 rounded-xl border border-slate-100">
                                        <p className="text-[9px] font-bold text-slate-400 uppercase mb-1">Quota Used</p>
                                        <p className="text-lg font-black text-slate-800">{selectedEmployer.quotaUsed || 0}/{selectedEmployer.quotaTotal || 50}</p>
                                    </div>
                                    <div className="p-3 bg-slate-50 rounded-xl border border-slate-100">
                                        <p className="text-[9px] font-bold text-slate-400 uppercase mb-1">Jobs Posted</p>
                                        <p className="text-lg font-black text-blue-600">{employerJobs.length}</p>
                                    </div>
                                    <div className="p-3 bg-slate-50 rounded-xl border border-slate-100">
                                        <p className="text-[9px] font-bold text-slate-400 uppercase mb-1">Demand Orders</p>
                                        <p className="text-lg font-black text-purple-600">{employerDemandOrders.length}</p>
                                    </div>
                                </div>
                            </div>

                            {/* Tab Navigation */}
                            <div className="flex gap-1 bg-slate-100 p-1 rounded-xl overflow-x-auto scrollbar-none snap-x snap-mandatory shrink-0">
                                {([
                                    { key: 'overview' as DetailTab, label: 'Overview', icon: <LayoutDashboard size={14} /> },
                                    { key: 'demands' as DetailTab, label: 'Demand Orders', icon: <Package size={14} /> },
                                    { key: 'selection' as DetailTab, label: 'Selection Board', icon: <Kanban size={14} /> },
                                ]).map(tab => (
                                    <button
                                        key={tab.key}
                                        onClick={() => {
                                            setActiveTab(tab.key);
                                            if (tab.key !== 'selection') setSelectedOrder(null);
                                        }}
                                        className={`flex-1 shrink-0 px-4 py-3 md:py-2.5 rounded-xl text-sm font-bold flex items-center justify-center gap-2 transition-all whitespace-nowrap btn-touch snap-start ${activeTab === tab.key
                                            ? 'bg-white text-slate-800 shadow-sm'
                                            : 'text-slate-500 hover:text-slate-700'
                                            }`}
                                    >
                                        {tab.icon} {tab.label}
                                    </button>
                                ))}
                            </div>

                            {/* Tab Content */}
                            {activeTab === 'overview' && (
                                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                                    {/* Activity Log */}
                                    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6">
                                        <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center justify-between">
                                            Recent Activity
                                            <button className="text-blue-600 hover:underline">View All</button>
                                        </h4>
                                        <div className="space-y-4">
                                            {(selectedEmployer.activityLog || []).slice(0, 5).map(act => (
                                                <div key={act.id} className="flex gap-3 relative before:absolute before:left-2.5 before:top-8 before:bottom-0 before:w-px before:bg-slate-100 last:before:hidden">
                                                    <div className="w-5 h-5 bg-white border-2 border-slate-100 rounded-full flex-shrink-0 z-10"></div>
                                                    <div>
                                                        <p className="text-xs font-bold text-slate-800 leading-tight">{act.type}: {act.content}</p>
                                                        <p className="text-[10px] text-slate-400 mt-1">{new Date(act.timestamp).toLocaleDateString()} • {act.actor}</p>
                                                    </div>
                                                </div>
                                            ))}
                                            {(!selectedEmployer.activityLog || selectedEmployer.activityLog.length === 0) && (
                                                <p className="text-xs text-slate-400 italic">No activity recorded</p>
                                            )}
                                        </div>
                                    </div>

                                    {/* Active Jobs + Pipeline */}
                                    <div className="space-y-6">
                                        {/* Active Jobs */}
                                        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6">
                                            <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                                                <Briefcase size={12} /> Active Jobs ({employerJobs.length})
                                            </h4>
                                            <div className="space-y-2">
                                                {employerJobs.length > 0 ? employerJobs.map(job => (
                                                    <div key={job.id} className="p-3 bg-white border border-slate-100 rounded-xl hover:border-blue-200 transition-all group">
                                                        <div className="flex items-start justify-between">
                                                            <div className="flex-1">
                                                                <p className="text-xs font-bold text-slate-800 leading-tight">{job.title}</p>
                                                                <p className="text-[10px] text-slate-400 mt-0.5">{job.location}</p>
                                                            </div>
                                                            <span className="text-[9px] font-bold px-2 py-0.5 rounded bg-green-100 text-green-700">
                                                                {job.status}
                                                            </span>
                                                        </div>
                                                        <p className="text-[10px] text-green-600 font-bold mt-1">{job.salaryRange}</p>
                                                    </div>
                                                )) : (
                                                    <p className="text-xs text-slate-400 italic">No active job postings</p>
                                                )}
                                            </div>
                                        </div>

                                        {/* Candidate Pipeline */}
                                        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6">
                                            <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                                                <Users size={12} /> Candidate Pipeline ({employerCandidates.length})
                                            </h4>
                                            <div className="space-y-2">
                                                {employerCandidates.length > 0 ? employerCandidates.slice(0, 5).map(candidate => (
                                                    <Link
                                                        key={candidate.id}
                                                        to={`/candidates/${candidate.id}`}
                                                        className="p-3 bg-white border border-slate-100 rounded-xl hover:border-blue-200 transition-all group flex items-center justify-between"
                                                    >
                                                        <div className="flex items-center gap-3">
                                                            <div className="w-8 h-8 bg-blue-50 rounded-full flex items-center justify-center text-blue-600 font-bold text-xs group-hover:bg-blue-100">
                                                                {candidate.name.charAt(0)}
                                                            </div>
                                                            <div>
                                                                <p className="text-xs font-bold text-slate-800 leading-tight">{candidate.name}</p>
                                                                <p className="text-[10px] text-slate-400">{candidate.stage}</p>
                                                            </div>
                                                        </div>
                                                        <ChevronRight size={14} className="text-slate-300 group-hover:text-blue-600" />
                                                    </Link>
                                                )) : (
                                                    <p className="text-xs text-slate-400 italic">No candidates in pipeline</p>
                                                )}
                                            </div>
                                        </div>
                                    </div>

                                    {/* Legal Documents - Full Width */}
                                    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6 lg:col-span-2">
                                        <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-4">Legal Documents</h4>
                                        <div className="grid grid-cols-2 gap-2">
                                            {selectedEmployer.documents.map(doc => (
                                                <div key={doc.id} className="p-3 bg-white border border-slate-100 rounded-xl flex items-center justify-between group hover:border-blue-100 transition-all">
                                                    <div className="flex items-center gap-3">
                                                        <FileText size={16} className="text-slate-400 group-hover:text-blue-600" />
                                                        <div>
                                                            <p className="text-[11px] font-bold text-slate-800">{doc.title}</p>
                                                            <p className="text-[10px] text-slate-400">Exp: {doc.expiryDate || 'N/A'}</p>
                                                        </div>
                                                    </div>
                                                    <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded ${doc.status === 'Valid' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                                                        {doc.status}
                                                    </span>
                                                </div>
                                            ))}
                                        </div>
                                    </div>

                                    {/* Action Buttons */}
                                    <div className="lg:col-span-2 flex flex-col sm:flex-row gap-3">
                                        <button
                                            onClick={() => navigate(`/jobs?employer=${selectedEmployer.id}`)}
                                            className="flex-1 py-3 sm:py-2.5 bg-white border border-slate-200 text-slate-700 rounded-lg text-sm font-medium hover:bg-slate-50 hover:text-blue-600 transition-colors shadow-sm flex justify-center items-center btn-touch"
                                        >
                                            Manage Jobs
                                        </button>
                                        <button
                                            onClick={() => { setActiveTab('demands'); setShowDemandForm(true); }}
                                            className="flex-1 py-3 sm:py-2.5 bg-white border border-slate-200 text-slate-700 rounded-lg text-sm font-medium hover:bg-slate-50 hover:text-blue-600 transition-colors shadow-sm flex justify-center items-center btn-touch"
                                        >
                                            Create Demand Order
                                        </button>
                                        <a
                                            href={`mailto:${selectedEmployer.email}`}
                                            className="p-3 sm:p-2.5 bg-white text-slate-600 border border-slate-200 rounded-lg hover:bg-slate-50 hover:text-blue-600 transition-colors flex items-center justify-center shadow-sm shrink-0 btn-touch"
                                        >
                                            <Mail size={18} />
                                        </a>
                                    </div>
                                </div>
                            )}

                            {activeTab === 'demands' && (
                                <DemandOrderList
                                    key={refreshKey}
                                    employerId={selectedEmployer.id}
                                    onSelectOrder={(order) => {
                                        setSelectedOrder(order);
                                        setActiveTab('selection');
                                    }}
                                    onEditOrder={handleEditDemandOrder}
                                    onDeleteOrder={handleDeleteDemandOrder}
                                    selectedOrderId={selectedOrder?.id}
                                    onCreateNew={() => {
                                        setEditingOrder(undefined);
                                        setShowDemandForm(true);
                                    }}
                                />
                            )}

                            {activeTab === 'selection' && (
                                selectedOrder ? (
                                    <SelectionBoard
                                        key={refreshKey}
                                        demandOrder={selectedOrder}
                                        onBack={() => {
                                            setSelectedOrder(null);
                                            setActiveTab('demands');
                                        }}
                                        onMatchCandidates={() => setShowMatchModal(true)}
                                        onRefresh={triggerRefresh}
                                    />
                                ) : (
                                    <div className="bg-white rounded-2xl border border-dashed border-slate-200 p-12 text-center">
                                        <Kanban size={48} className="mx-auto text-slate-300 mb-4" />
                                        <h4 className="text-sm font-bold text-slate-500">No Demand Order Selected</h4>
                                        <p className="text-xs text-slate-400 mt-2 max-w-sm mx-auto">
                                            Go to the <button onClick={() => setActiveTab('demands')} className="text-blue-600 hover:underline font-bold">Demand Orders</button> tab and select an order to view its selection board.
                                        </p>
                                    </div>
                                )
                            )}
                        </div>
                    ) : (
                        <div className="bg-slate-50 rounded-2xl border border-dashed border-slate-200 p-8 text-center h-[600px] flex flex-col items-center justify-center">
                            <div className="p-4 bg-white rounded-full text-slate-300 mb-4 shadow-sm">
                                <Building2 size={48} />
                            </div>
                            <h4 className="font-bold text-slate-400">No Partner Selected</h4>
                            <p className="text-xs text-slate-400 mt-2 max-w-xs">Select a company from the list to view their full profile, demand orders, and candidate selection board.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* MODALS */}
            {showAddPartner && (
                <AddPartnerModal
                    onClose={() => setShowAddPartner(false)}
                    onSaved={(emp) => {
                        setShowAddPartner(false);
                        setSelectedEmployer(emp);
                        triggerRefresh();
                    }}
                />
            )}

            {showEditPartner && selectedEmployer && (
                <AddPartnerModal
                    existingEmployer={selectedEmployer}
                    onClose={() => setShowEditPartner(false)}
                    onSaved={(emp) => {
                        setShowEditPartner(false);
                        setSelectedEmployer(emp);
                        triggerRefresh();
                    }}
                />
            )}

            {showDemandForm && selectedEmployer && (
                <DemandOrderForm
                    employerId={selectedEmployer.id}
                    existingOrder={editingOrder}
                    onClose={() => { setShowDemandForm(false); setEditingOrder(undefined); }}
                    onSaved={() => {
                        setShowDemandForm(false);
                        setEditingOrder(undefined);
                        triggerRefresh();
                    }}
                />
            )}

            {showMatchModal && selectedOrder && (
                <CandidateMatchModal
                    demandOrder={selectedOrder}
                    onClose={() => setShowMatchModal(false)}
                    onMatched={() => {
                        setShowMatchModal(false);
                        triggerRefresh();
                    }}
                />
            )}
        </div>
    );
};

export default PartnerManager;

import React, { useState, useEffect } from 'react';
import {
    DndContext,
    DragOverlay,
    PointerSensor,
    TouchSensor,
    KeyboardSensor,
    useSensor,
    useSensors,
    closestCorners,
    DragStartEvent,
    DragEndEvent,
    useDroppable
} from '@dnd-kit/core';
import { useCandidates } from '../context/CandidateContext';
import {
    SortableContext,
    verticalListSortingStrategy,
    useSortable,
    sortableKeyboardCoordinates
} from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { CandidateService } from '../services/candidateService';
import { WorkflowStage, Candidate, StageStatus } from '../types';
import { STAGE_ORDER, WorkflowEngine } from '../services/workflowEngine';
import {
    Users,
    Search,
    Filter,
    AlertCircle
} from 'lucide-react';
import { useToast } from '../context/ToastContext';

// --- Types ---
interface Column {
    id: WorkflowStage;
    title: string;
    candidates: Candidate[];
}

// --- Sortable Card Component ---
const PipelineCard = ({ candidate, isDragging }: { candidate: Candidate; isDragging?: boolean }) => {
    const {
        attributes,
        listeners,
        setNodeRef,
        transform,
        transition,
    } = useSortable({ id: candidate.id });

    const style = {
        transform: CSS.Transform.toString(transform),
        transition,
    };

    const sla = WorkflowEngine.calculateSLAStatus(candidate);

    return (
        <div
            ref={setNodeRef}
            style={style}
            {...attributes}
            {...listeners}
            className={`slate-card-interactive p-3 flex flex-col gap-2 ${isDragging ? 'opacity-50 grayscale scale-105 rotate-2' : ''
                }`}
        >
            <div className="flex items-center gap-3">
                <img
                    src={candidate.avatarUrl || `https://ui-avatars.com/api/?name=${encodeURIComponent(candidate.name)}`}
                    className="w-8 h-8 rounded-full border border-slate-200"
                    alt=""
                />
                <div className="min-w-0">
                    <div className="text-sm font-bold text-slate-900 truncate">{candidate.name}</div>
                    <div className="text-[10px] text-slate-500 font-medium uppercase truncate">
                        {candidate.role || 'GENERAL'}
                    </div>
                </div>
            </div>

            <div className="flex items-center justify-between text-[10px] mt-1 pt-2 border-t border-slate-100">
                <span className={`px-2 py-0.5 rounded-full font-bold uppercase tracking-wider ${candidate.stageStatus === StageStatus.IN_PROGRESS ? 'bg-blue-50 text-blue-700' :
                    candidate.stageStatus === StageStatus.ON_HOLD ? 'bg-orange-50 text-orange-700' :
                        'bg-slate-100 text-slate-600'
                    }`}>
                    {candidate.stageStatus}
                </span>

                {sla.status === 'OVERDUE' && (
                    <div className="flex items-center gap-1 text-red-600 font-bold">
                        <AlertCircle size={10} />
                        <span>{sla.daysElapsed}d</span>
                    </div>
                )}
            </div>
        </div>
    );
};

// --- Column Component ---
const PipelineColumn = ({ column }: { column: Column }) => {
    const { setNodeRef, isOver } = useDroppable({
        id: `column-${column.id}`,
        data: { type: 'column', columnId: column.id }
    });

    return (
        <div className={`flex-shrink-0 w-72 md:w-80 flex flex-col rounded-2xl border overflow-hidden shadow-sm transition-colors duration-200 ${isOver ? 'bg-blue-50/70 border-blue-300 ring-2 ring-blue-200' : 'bg-slate-100/50 border-slate-200'
            }`}>
            <div className="p-4 border-b border-slate-200 bg-white flex justify-between items-center">
                <div className="flex items-center gap-2">
                    <div className={`w-2 h-2 rounded-full ${column.id === WorkflowStage.DEPARTED ? 'bg-emerald-500 animate-pulse' :
                        column.id === WorkflowStage.VISA_RECEIVED ? 'bg-green-500' :
                            'bg-blue-600'
                        }`} />
                    <h3 className="text-[11px] font-black text-slate-900 uppercase tracking-widest">{column.title}</h3>
                </div>
                <span className="text-[10px] font-black text-slate-400 bg-slate-50 border border-slate-100 px-2.5 py-1 rounded-lg">
                    {column.candidates.length}
                </span>
            </div>

            <div ref={setNodeRef} className="flex-1 p-3 flex flex-col gap-3 overflow-y-auto custom-scrollbar min-h-[500px]">
                <SortableContext
                    items={column.candidates.map(c => c.id)}
                    strategy={verticalListSortingStrategy}
                >
                    {column.candidates.map(candidate => (
                        <PipelineCard key={candidate.id} candidate={candidate} />
                    ))}
                </SortableContext>

                {column.candidates.length === 0 && (
                    <div className="h-24 rounded-xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-400 gap-1">
                        <Users size={16} />
                        <span className="text-[10px] uppercase font-bold tracking-widest">Entry Empty</span>
                    </div>
                )}
            </div>
        </div>
    );
};

// --- Main Board Component ---
const PipelineBoard: React.FC = () => {
    const { candidates, updateCandidateInState, refreshCandidates } = useCandidates();
    // Local state for optimistic UI updates if needed, but context handles it.
    // However, dnd-kit needs stable items. Context updates might be fast enough.
    // Let's use context stats directly but we might need local state for immediate feedback if context is slow?
    // Actually, updateCandidateInState updates context state immediately.

    // We can remove local candidates state if we use context directly.
    // But wait, the original code had:
    // const [candidates, setCandidates] = useState<Candidate[]>([]);

    // Let's rely on context.
    const [activeCandidate, setActiveCandidate] = useState<Candidate | null>(null);
    const [searchQuery, setSearchQuery] = useState('');
    const toast = useToast();

    // FRICTIONLESS: Removed activationConstraint (distance: 8) so drag starts instantly without requiring initial movement.
    const sensors = useSensors(
        useSensor(PointerSensor, { activationConstraint: { distance: 5 } }),
        useSensor(TouchSensor, { activationConstraint: { delay: 250, tolerance: 5 } }),
        useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
    );

    // Initial load handled by context
    useEffect(() => {
        refreshCandidates();
    }, []);

    const filteredCandidates = candidates.filter(c =>
        c.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        c.nic?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const columns: Column[] = STAGE_ORDER.map(stage => ({
        id: stage,
        title: stage,
        candidates: filteredCandidates.filter(c => c.stage === stage)
    }));

    const onDragStart = (event: DragStartEvent) => {
        const { active } = event;
        const candidate = candidates.find(c => c.id === active.id);
        if (candidate) setActiveCandidate(candidate);
    };

    const onDragEnd = async (event: DragEndEvent) => {
        setActiveCandidate(null);
        const { active, over } = event;

        if (!over) return;

        const activeId = active.id as string;
        const overId = over.id as string;

        // Determine the target column
        let targetColumnId: WorkflowStage | null = null;

        // Check if dropped directly on a column droppable (id = "column-STAGE_NAME")
        if (overId.startsWith('column-')) {
            targetColumnId = overId.replace('column-', '') as WorkflowStage;
        } else {
            // Check if dropped on a card — find which column that card belongs to
            const overColumn = columns.find(col => col.candidates.some(c => c.id === overId));
            if (overColumn) {
                targetColumnId = overColumn.id;
            }
        }

        if (targetColumnId) {
            const candidate = candidates.find(c => c.id === activeId);
            if (candidate && candidate.stage !== targetColumnId) {
                // Update stage in database
                try {
                    const updatedCandidate = { ...candidate, stage: targetColumnId };

                    // Optimistic update via Context
                    updateCandidateInState(updatedCandidate);

                    // API Call
                    await CandidateService.updateCandidate(updatedCandidate);
                    toast.success(`Moved to ${targetColumnId}`);
                } catch (error) {
                    console.error('Failed to update stage:', error);
                    toast.error('Failed to move candidate. Reverting...');
                    refreshCandidates(); // Revert on failure
                }
            }
        }
    };

    return (
        <div className="flex flex-col h-[calc(100dvh-4rem)] h-[calc(100vh-4rem)] bg-slate-50">
            {/* Search & Header */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between px-4 sm:px-6 md:px-8 py-3 sm:py-4 bg-white border-b border-slate-200 gap-3 sm:gap-4 shrink-0">
                <div className="flex items-center gap-4">
                    <div className="flex flex-col">
                        <h1 className="slate-header text-lg md:text-xl">Visual Pipeline</h1>
                        <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold uppercase tracking-[0.2em] mt-1">
                            <Users size={12} className="text-blue-600" />
                            <span>Batch: {candidates.length} Operations</span>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <div className="relative group flex-1 sm:flex-none">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={14} />
                        <input
                            type="text"
                            placeholder="Locate Identity..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all sm:w-48 md:w-64 uppercase tracking-tighter btn-touch"
                        />
                    </div>
                    <button className="slate-card-interactive flex items-center gap-2 px-3 py-2 text-slate-600 hover:bg-slate-50 transition-premium active:scale-95 shadow-sm btn-touch">
                        <Filter size={14} />
                        <span className="hidden sm:block text-[10px] font-black uppercase tracking-widest">Filters</span>
                    </button>
                </div>
            </div>

            {/* Board Container */}
            <div className="flex-1 overflow-x-auto overflow-y-hidden p-3 sm:p-4 md:p-8 custom-scrollbar touch-pan-x pb-[calc(var(--bottom-nav-height)+1rem)] lg:pb-8">
                <div className="flex h-full gap-4 sm:gap-6 min-w-max">
                    <DndContext
                        sensors={sensors}
                        collisionDetection={closestCorners}
                        onDragStart={onDragStart}
                        onDragEnd={onDragEnd}
                    >
                        {columns.map(column => (
                            <PipelineColumn key={column.id} column={column} />
                        ))}

                        <DragOverlay>
                            {activeCandidate ? (
                                <div className="w-72">
                                    <PipelineCard candidate={activeCandidate} isDragging />
                                </div>
                            ) : null}
                        </DragOverlay>
                    </DndContext>
                </div>
            </div>
        </div>
    );
};

export default PipelineBoard;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { CandidateService } from '../services/candidateService';
import { DuplicateDetectionService } from '../services/duplicateDetectionService';
import { ProfileCompletionService } from '../services/profileCompletionService';
import { NICService } from '../services/nicService';
import { Save, AlertCircle, UserPlus, TrendingUp, ArrowLeft, CheckCircle2 } from 'lucide-react';
import PreferredCountriesSelector from './ui/PreferredCountriesSelector';
import MultiPhoneInput from './ui/MultiPhoneInput';
import { useCandidates } from '../context/CandidateContext';
import { useToast } from '../context/ToastContext';

const QuickAddForm: React.FC = () => {
    const navigate = useNavigate();
    const { candidates } = useCandidates();
    const { showToast } = useToast();
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [showConfirmation, setShowConfirmation] = useState(false);

    const [duplicateMatches, setDuplicateMatches] = useState<any[]>([]);
    const [duplicateFields, setDuplicateFields] = useState<string[]>([]);

    const [formData, setFormData] = useState({
        regNo: '',
        surname: '',
        otherNames: '',
        fullName: '',
        nic: '',
        dob: '',
        gender: '' as 'Male' | 'Female' | '',
        phone: '',
        whatsapp: '',
        email: '',
        address: '',
        role: '',
        preferredCountries: [] as string[],
        additionalContactNumbers: [] as string[],
        notes: ''
    });

    const [errors, setErrors] = useState<Record<string, string>>({});

    // Handle input changes
    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value } = e.target;

        setFormData(prev => {
            const updated = { ...prev, [name]: value };

            // Auto-generate Full Name from Surname and Other Names
            if (name === 'surname' || name === 'otherNames') {
                const s = name === 'surname' ? value : prev.surname;
                const o = name === 'otherNames' ? value : prev.otherNames;
                updated.fullName = `${s} ${o}`.trim();
            }

            // Smart NIC Parsing
            if (name === 'nic') {
                const parsed = NICService.parseNIC(value);
                if (parsed) {
                    updated.dob = parsed.dob;
                    updated.gender = parsed.gender;
                }
            }

            return updated;
        });

        // Clear error when user starts typing
        if (errors[name]) {
            setErrors(prev => ({ ...prev, [name]: '' }));
        }
    };

    // Handle duplicate check on blur
    const handleBlur = (field: 'regNo' | 'nic' | 'phone' | 'whatsapp') => {
        const value = formData[field];
        if (!value) return;

        const checkData: any = {};
        if (field === 'regNo') checkData.regNo = value;
        if (field === 'nic') checkData.nic = value;
        if (field === 'phone') checkData.phone = value;
        if (field === 'whatsapp') checkData.whatsapp = value;

        const { isDuplicate, matches, matchedFields } = DuplicateDetectionService.isDuplicate(checkData, candidates);

        if (isDuplicate) {
            setDuplicateMatches(matches);
            setDuplicateFields(matchedFields);
            console.log('Duplicate detected:', matchedFields);
        }
    };

    const validate = (): boolean => {
        const newErrors: Record<string, string> = {};
        if (!formData.surname) newErrors.surname = 'Surname is required';
        if (!formData.fullName) newErrors.fullName = 'Full legal name is required';
        if (!formData.nic) newErrors.nic = 'NIC is required';
        if (!formData.phone) newErrors.phone = 'Phone number is required';

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    // Handle form submission
    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!validate()) {
            showToast('Please fill in required fields', 'error');
            return;
        }

        if (!showConfirmation) {
            setShowConfirmation(true);
            return;
        }

        setIsSubmitting(true);

        try {
            const candidate = await CandidateService.createCandidate({
                regNo: (formData.regNo || '').trim(),
                name: (formData.fullName || '').trim() || 'Unknown Candidate',
                firstName: (formData.otherNames || '').trim(),
                surname: (formData.surname || '').trim(),
                nic: (formData.nic || '').trim().toUpperCase(),
                phone: (formData.phone || '').trim(),
                whatsapp: (formData.whatsapp || '').trim() || (formData.phone || '').trim(),
                email: (formData.email || '').trim(),
                address: (formData.address || '').trim(),
                role: (formData.role || '').trim(),
                preferredCountries: formData.preferredCountries || [],
                additionalContactNumbers: (formData.additionalContactNumbers || []).filter(n => n && n.trim()),
                dob: formData.dob || undefined,
                gender: formData.gender || undefined,
                notes: formData.notes
            });

            if (candidate) {
                showToast('Candidate added successfully', 'success');
                navigate(`/candidates/${candidate.id}`);
            }
        } catch (error) {
            console.error('Error creating candidate:', error);
            showToast('Failed to create candidate', 'error');
        } finally {
            setIsSubmitting(false);
            setShowConfirmation(false);
        }
    };

    if (showConfirmation) {
        return (
            <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                <div className="bg-white rounded-xl shadow-lg max-w-sm w-full p-6 text-center">
                    <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
                        <UserPlus size={32} />
                    </div>
                    <h3 className="text-lg font-semibold text-slate-900 mb-2">Confirm Registration</h3>
                    <p className="text-slate-500 text-sm mb-6">
                        Are you sure you want to add <strong>{formData.fullName}</strong>?
                    </p>
                    <div className="flex gap-3">
                        <button
                            onClick={() => setShowConfirmation(false)}
                            className="flex-1 py-2.5 px-4 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium"
                        >
                            Review
                        </button>
                        <button
                            onClick={handleSubmit}
                            disabled={isSubmitting}
                            className="flex-1 py-2.5 px-4 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium disabled:opacity-50"
                        >
                            {isSubmitting ? 'Saving...' : 'Confirm'}
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    const completionPercentage = ProfileCompletionService.calculateCompletionPercentage({
        ...formData,
        name: formData.fullName
    });

    return (
        <div className="min-h-screen bg-slate-50 pb-12">
            {/* Header / Navigation */}
            <div className="bg-white border-b border-slate-200 sticky top-0 z-30 px-4 md:px-8 py-4 shadow-sm">
                <div className="max-w-6xl mx-auto flex items-center gap-4">
                    <button
                        onClick={() => navigate(-1)}
                        className="p-2 hover:bg-slate-100 rounded-lg transition-colors text-slate-600"
                    >
                        <ArrowLeft size={20} />
                    </button>
                    <div>
                        <h1 className="text-xl font-semibold text-slate-900">New Candidate</h1>
                        <p className="text-sm text-slate-500">Quick Registration Form</p>
                    </div>
                </div>
            </div>

            <div className="max-w-6xl mx-auto px-4 py-8">
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    {/* Main Form Area */}
                    <div className="lg:col-span-2">
                        <form onSubmit={handleSubmit} className="space-y-6">

                            {/* Personal Information */}
                            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                                <div className="px-6 py-4 border-b border-slate-200 bg-slate-50/50">
                                    <h2 className="text-base font-semibold text-slate-800">1. Personal Details</h2>
                                </div>
                                <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div className="md:col-span-2">
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Registration No.</label>
                                        <input
                                            type="text"
                                            name="regNo"
                                            value={formData.regNo}
                                            onChange={handleChange}
                                            onBlur={() => handleBlur('regNo')}
                                            className="w-full max-w-sm px-3 py-2 border border-slate-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500 sm:text-sm"
                                            placeholder="e.g. SPA 14-180125"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Surname</label>
                                        <input
                                            type="text"
                                            name="surname"
                                            value={formData.surname}
                                            onChange={handleChange}
                                            className={`w-full px-3 py-2 border rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 sm:text-sm ${errors.surname ? 'border-red-300' : 'border-slate-300'}`}
                                            placeholder="As in Passport"
                                        />
                                        <p className={`text-xs mt-1 transition-opacity ${errors.surname ? "text-red-600 opacity-100" : "opacity-0"}`}>{errors.surname || "Error placeholder"}</p>
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Other Names</label>
                                        <input
                                            type="text"
                                            name="otherNames"
                                            value={formData.otherNames}
                                            onChange={handleChange}
                                            className="w-full px-3 py-2 border border-slate-300 rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 sm:text-sm"
                                            placeholder="Given names"
                                        />
                                    </div>
                                    <div className="md:col-span-2">
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Full Legal Name</label>
                                        <input
                                            type="text"
                                            name="fullName"
                                            value={formData.fullName}
                                            onChange={handleChange}
                                            className={`w-full px-3 py-2 border rounded-md shadow-sm bg-slate-50 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 sm:text-sm ${errors.fullName ? 'border-red-300' : 'border-slate-300'}`}
                                            placeholder="Auto-generated from above"
                                        />
                                        <p className={`text-xs mt-1 transition-opacity ${errors.fullName ? "text-red-600 opacity-100" : "opacity-0"}`}>{errors.fullName || "Error placeholder"}</p>
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">NIC Number</label>
                                        <input
                                            type="text"
                                            name="nic"
                                            value={formData.nic}
                                            onChange={handleChange}
                                            onBlur={() => handleBlur('nic')}
                                            className={`w-full px-3 py-2 border rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 sm:text-sm ${errors.nic ? 'border-red-300' : 'border-slate-300'}`}
                                            placeholder="NIC number"
                                        />
                                        {formData.dob && (
                                            <div className="flex items-center gap-2 mt-2">
                                                <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-emerald-100 text-emerald-800">
                                                    DOB: {formData.dob}
                                                </span>
                                                <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-blue-100 text-blue-800">
                                                    {formData.gender}
                                                </span>
                                            </div>
                                        )}
                                        <p className={`text-xs mt-1 transition-opacity ${errors.nic ? "text-red-600 opacity-100" : "opacity-0"}`}>{errors.nic || "Error placeholder"}</p>
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Email Address</label>
                                        <input
                                            type="email"
                                            name="email"
                                            value={formData.email}
                                            onChange={handleChange}
                                            className="w-full px-3 py-2 border border-slate-300 rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 sm:text-sm"
                                            placeholder="Email address"
                                        />
                                    </div>

                                    <div className="md:col-span-2">
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Address</label>
                                        <input
                                            type="text"
                                            name="address"
                                            value={formData.address}
                                            onChange={handleChange}
                                            className="w-full px-3 py-2 border border-slate-300 rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 sm:text-sm"
                                            placeholder="Residential address"
                                        />
                                    </div>
                                </div>
                            </div>

                            {/* Contact Details */}
                            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                                <div className="px-6 py-4 border-b border-slate-200 bg-slate-50/50">
                                    <h2 className="text-base font-semibold text-slate-800">2. Contact Numbers</h2>
                                </div>
                                <div className="p-6">
                                    <MultiPhoneInput
                                        primaryPhone={formData.phone}
                                        whatsappPhone={formData.whatsapp}
                                        additionalPhones={formData.additionalContactNumbers}
                                        onPrimaryPhoneChange={(value) => {
                                            setFormData(prev => ({ ...prev, phone: value }));
                                            if (errors.phone) setErrors(prev => ({ ...prev, phone: '' }));
                                            handleBlur('phone');
                                        }}
                                        onWhatsappPhoneChange={(value) => {
                                            setFormData(prev => ({ ...prev, whatsapp: value }));
                                            handleBlur('whatsapp');
                                        }}
                                        onAdditionalPhonesChange={(phones) => setFormData(prev => ({ ...prev, additionalContactNumbers: phones }))}
                                        onDuplicateDetected={(phone, type) => {
                                            console.log(`Duplicate detected: ${phone} (${type})`);
                                        }}
                                    />
                                    <p className={`text-xs mt-1 transition-opacity ${errors.phone ? "text-red-600 opacity-100" : "opacity-0"}`}>{errors.phone || "Error placeholder"}</p>
                                </div>
                            </div>

                            {/* Job Preferences */}
                            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                                <div className="px-6 py-4 border-b border-slate-200 bg-slate-50/50">
                                    <h2 className="text-base font-semibold text-slate-800">3. Job Preferences</h2>
                                </div>
                                <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Job Role</label>
                                        <input
                                            type="text"
                                            name="role"
                                            value={formData.role}
                                            onChange={handleChange}
                                            className={`w-full px-3 py-2 border rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 sm:text-sm ${errors.role ? 'border-red-300' : 'border-slate-300'}`}
                                            placeholder="e.g. Nurse, Driver, Chef"
                                        />
                                        <p className={`text-xs mt-1 transition-opacity ${errors.role ? "text-red-600 opacity-100" : "opacity-0"}`}>{errors.role || "Error placeholder"}</p>
                                    </div>

                                    <div className="md:col-span-2">
                                        <PreferredCountriesSelector
                                            label="Preferred Countries"
                                            selectedCountries={formData.preferredCountries}
                                            onChange={(countries) => {
                                                setFormData(prev => ({ ...prev, preferredCountries: countries }));
                                                if (errors.preferredCountries) {
                                                    setErrors(prev => ({ ...prev, preferredCountries: '' }));
                                                }
                                            }}
                                        />
                                        <p className={`text-xs mt-1 transition-opacity ${errors.preferredCountries ? "text-red-600 opacity-100" : "opacity-0"}`}>{errors.preferredCountries || "Error placeholder"}</p>
                                    </div>
                                </div>
                            </div>

                            {/* Notes */}
                            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                                <div className="px-6 py-4 border-b border-slate-200 bg-slate-50/50">
                                    <h2 className="text-base font-semibold text-slate-800">Notes (Optional)</h2>
                                </div>
                                <div className="p-6">
                                    <textarea
                                        name="notes"
                                        value={formData.notes}
                                        onChange={handleChange}
                                        rows={4}
                                        className="w-full px-3 py-2 border border-slate-300 rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 sm:text-sm resize-y"
                                        placeholder="Add any special notes..."
                                    />
                                </div>
                            </div>

                            {/* Actions Dock */}
                            <div className="flex flex-col sm:flex-row items-center justify-end gap-3 pt-4">
                                <button
                                    type="button"
                                    onClick={() => navigate('/candidates')}
                                    className="w-full sm:w-auto px-6 py-2.5 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors text-sm font-medium focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-slate-500"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    className="w-full sm:w-auto px-6 py-2.5 bg-blue-600 border border-transparent text-white rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 flex items-center justify-center gap-2"
                                >
                                    <Save size={16} />
                                    Save Candidate
                                </button>
                            </div>
                        </form>
                    </div>

                    {/* Right Side Sidebar */}
                    <div className="lg:col-span-1 space-y-6">
                        <div className="lg:sticky lg:top-24 space-y-4">

                            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                                <div className="flex items-center justify-between mb-4">
                                    <div className="flex items-center gap-2">
                                        <TrendingUp size={20} className="text-blue-600" />
                                        <h3 className="font-semibold text-slate-900">Profile Status</h3>
                                    </div>
                                    <span className="text-2xl font-bold text-blue-600">{completionPercentage}%</span>
                                </div>

                                <div className="w-full bg-slate-100 rounded-full h-2 mb-6 overflow-hidden">
                                    <div
                                        className="bg-blue-600 h-2 rounded-full transition-all duration-500"
                                        style={{ width: `${completionPercentage}%` }}
                                    />
                                </div>

                                <div className={`p-3 rounded-lg border text-center transition-colors ${completionPercentage < 40 ? 'bg-amber-50 border-amber-200 text-amber-700' :
                                    completionPercentage < 80 ? 'bg-blue-50 border-blue-200 text-blue-700' :
                                        'bg-emerald-50 border-emerald-200 text-emerald-700'
                                    }`}>
                                    <span className="text-sm font-medium block">
                                        {completionPercentage < 40 ? 'Needs More Info' :
                                            completionPercentage < 80 ? 'Almost Complete' :
                                                'Complete'}
                                    </span>
                                </div>
                            </div>

                            {(duplicateMatches.length > 0) && (
                                <div className="bg-amber-50 rounded-xl shadow-sm border border-amber-200 p-5">
                                    <div className="flex items-start gap-3">
                                        <AlertCircle size={20} className="text-amber-600 shrink-0 mt-0.5" />
                                        <div>
                                            <h4 className="font-medium text-amber-800 text-sm">Potential Duplicate Found</h4>
                                            <p className="text-xs text-amber-700 mt-1 mb-3">
                                                A candidate with similar details ({duplicateFields.join(', ')}) already exists.
                                            </p>
                                            <button
                                                onClick={() => navigate(`/candidates/${duplicateMatches[0].id}`)}
                                                className="text-xs font-semibold text-amber-700 hover:text-amber-900 underline"
                                            >
                                                View existing profile
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            )}

                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default QuickAddForm;

