import React from 'react';
import { NavLink } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import {
  LayoutDashboard,
  Users,
  Briefcase,
  MessageSquare,
  LogOut,
  Settings,
  KanbanSquare,
  Target,
  DollarSign,
  TrendingUp,
  BrainCircuit,
  Activity,
  X
} from 'lucide-react';

interface SidebarProps {
  isOpen: boolean;
  onClose: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ isOpen, onClose }) => {
  const { logout, user } = useAuth();
  const [agencyName, setAgencyName] = React.useState(() => localStorage.getItem('agency_name') || 'Suhara');

  React.useEffect(() => {
    const updateName = () => {
      setAgencyName(localStorage.getItem('agency_name') || 'Suhara');
    };
    window.addEventListener('agency_update', updateName);
    return () => window.removeEventListener('agency_update', updateName);
  }, []);

  const initials = agencyName.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase();
  const linkClass = ({ isActive }: { isActive: boolean }) =>
    `flex items-center gap-3 px-4 py-3 rounded-lg transition-all duration-200 ${isActive
      ? 'bg-blue-600 text-white shadow-md'
      : 'text-slate-400 hover:bg-slate-800 hover:text-white'
    }`;

  const isAdmin = user?.role === 'Admin';

  // Close sidebar on nav link click (mobile)
  const handleNavClick = () => {
    if (window.innerWidth < 1024) {
      onClose();
    }
  };

  return (
    <aside className={`w-[var(--sidebar-width)] h-[100dvh] h-screen bg-slate-900 text-white flex flex-col fixed left-0 top-0 border-r border-slate-800 z-50 transition-transform duration-300 ease-out lg:translate-x-0 ${isOpen ? 'translate-x-0' : '-translate-x-full'
      }`}>
      {/* Header */}
      <div className="p-5 sm:p-6 border-b border-slate-800 shrink-0">
        <div className="flex items-center justify-between mb-2 lg:hidden">
          <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Navigation</span>
          <button
            onClick={onClose}
            className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-lg transition-all btn-touch"
            aria-label="Close navigation"
          >
            <X size={20} />
          </button>
        </div>
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center shrink-0">
            <span className="font-black text-white text-lg">{initials}</span>
          </div>
          <div className="min-w-0">
            <h1 className="text-lg font-black tracking-tight uppercase truncate">{agencyName} ERP CORE</h1>
            <p className="text-[10px] text-blue-400 font-bold uppercase tracking-widest">Dashboard</p>
          </div>
        </div>
      </div>

      {/* Navigation */}
      <nav className="flex-1 px-3 sm:px-4 py-4 sm:py-6 space-y-1 overflow-y-auto custom-scrollbar touch-pan-y">
        <NavLink to="/" className={linkClass} onClick={handleNavClick}>
          <LayoutDashboard size={20} />
          <span>Dashboard</span>
        </NavLink>
        <NavLink to="/analytics" className={linkClass} onClick={handleNavClick}>
          <BrainCircuit size={20} />
          <span>Intelligence</span>
        </NavLink>
        <NavLink to="/pipeline" className={linkClass} onClick={handleNavClick}>
          <KanbanSquare size={20} />
          <span>Pipeline</span>
        </NavLink>
        <NavLink to="/candidates" className={linkClass} onClick={handleNavClick}>
          <Users size={20} />
          <span>Candidates</span>
        </NavLink>

        {isAdmin && (
          <>
            <div className="pt-3 pb-1">
              <p className="text-[9px] font-bold text-slate-600 uppercase tracking-[0.2em] px-4">Admin</p>
            </div>
            <NavLink to="/jobs" className={linkClass} onClick={handleNavClick}>
              <Briefcase size={20} />
              <span>Jobs</span>
            </NavLink>
            <NavLink to="/partners" className={linkClass} onClick={handleNavClick}>
              <Target size={20} />
              <span>Partners</span>
            </NavLink>
            <NavLink to="/finance" className={linkClass} onClick={handleNavClick}>
              <DollarSign size={20} />
              <span>Finance</span>
            </NavLink>
          </>
        )}

        <NavLink to="/team-chat" className={linkClass} onClick={handleNavClick}>
          <MessageSquare size={20} />
          <span>Chat</span>
        </NavLink>
      </nav>

      {/* Footer */}
      <div className="p-3 sm:p-4 border-t border-slate-800 space-y-1 shrink-0 safe-bottom">
        {isAdmin && (
          <>
            <NavLink to="/audit" className={linkClass} onClick={handleNavClick}>
              <Activity size={20} />
              <span>Audit Trails</span>
            </NavLink>
            <NavLink to="/settings" className={linkClass} onClick={handleNavClick}>
              <Settings size={20} />
              <span>Settings</span>
            </NavLink>
          </>
        )}
        <button onClick={logout} className="flex items-center gap-3 px-4 py-3 w-full text-slate-400 hover:text-white hover:bg-slate-800 rounded-lg transition-all">
          <LogOut size={20} />
          <span>Sign Out</span>
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;

import React, { useState } from 'react';
import { StaffPerformanceMetric } from '../types';
import {
    ArrowLeft, Upload, MessageSquare,
    LogIn, ChevronRight, UserPlus, Edit3, Shield,
    Layers, Clock, Activity
} from 'lucide-react';

// ─── Formatting Helpers ──────────────────────────────────────────────────

const fmtDuration = (mins: number): string => {
    if (!mins) return '0m';
    if (mins < 60) return `${mins}m`;
    const h = Math.floor(mins / 60);
    const m = mins % 60;
    return m > 0 ? `${h}h ${m}m` : `${h}h`;
};

const timeAgo = (d: string): string => {
    if (!d) return 'Never';
    const diff = Date.now() - new Date(d).getTime();
    const m = Math.floor(diff / 60000);
    if (m < 2) return 'Just now';
    if (m < 60) return `${m}m ago`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}h ago`;
    const days = Math.floor(h / 24);
    if (days < 30) return `${days}d ago`;
    return new Date(d).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
};

const getRoleStyle = (role: string): string => {
    const styles: Record<string, string> = {
        Admin: 'bg-purple-50 text-purple-700 ring-1 ring-inset ring-purple-500/20',
        Manager: 'bg-blue-50 text-blue-700 ring-1 ring-inset ring-blue-500/20',
        Recruiter: 'bg-emerald-50 text-emerald-700 ring-1 ring-inset ring-emerald-500/20',
        HR: 'bg-rose-50 text-rose-700 ring-1 ring-inset ring-rose-500/20',
        Finance: 'bg-amber-50 text-amber-700 ring-1 ring-inset ring-amber-500/20',
        Viewer: 'bg-slate-50 text-slate-600 ring-1 ring-inset ring-slate-500/20',
    };
    return styles[role] || styles.Viewer;
};

// ─── INDIVIDUAL DETAIL VIEW ──────────────────────────────────────────────

const StaffDetail: React.FC<{ s: StaffPerformanceMetric; onBack: () => void }> = ({ s, onBack }) => {
    const wb = s.workBreakdown;
    const totalWork = wb.candidatesCreated + wb.candidatesUpdated + wb.documentsUploaded + wb.chatMessagesSent + wb.usersManaged + wb.bulkExports + wb.otherActions;

    const workItems = [
        { label: 'Candidates Registered', val: wb.candidatesCreated, icon: UserPlus, color: '#10b981' },
        { label: 'Candidates Updated', val: wb.candidatesUpdated, icon: Edit3, color: '#3b82f6' },
        { label: 'Documents Uploaded', val: wb.documentsUploaded, icon: Upload, color: '#f59e0b' },
        { label: 'Chat Messages', val: wb.chatMessagesSent, icon: MessageSquare, color: '#8b5cf6' },
        { label: 'User Management', val: wb.usersManaged, icon: Shield, color: '#ef4444' },
    ];

    return (
        <div className="space-y-4 sm:space-y-6 animate-in fade-in duration-300">
            <div className="flex items-start sm:items-center gap-3 sm:gap-4 border-b border-slate-100 pb-4">
                <button onClick={onBack} className="p-2 sm:p-2.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 text-slate-600 transition-colors shadow-sm shrink-0 mt-1 sm:mt-0">
                    <ArrowLeft size={18} />
                </button>
                <div className="min-w-0">
                    <h2 className="text-xl sm:text-2xl font-bold text-slate-900 tracking-tight truncate">{s.name}</h2>
                    <div className="flex flex-wrap items-center gap-2 sm:gap-3 mt-1 sm:mt-1.5">
                        <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${getRoleStyle(s.role)}`}>
                            {s.role}
                        </span>
                        <span className="text-xs sm:text-sm text-slate-500 truncate">{s.email}</span>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 sm:gap-4">
                {[
                    { label: 'WORKLOAD SCORE', value: totalWork, icon: Layers },
                    { label: 'TOTAL SESSIONS', value: s.totalSessions, icon: LogIn },
                    { label: 'UPTIME LOGGED', value: fmtDuration(s.totalUptimeMinutes), icon: Clock },
                    { label: 'AVG SESSION', value: fmtDuration(s.avgSessionMinutes), icon: Clock },
                ].map((k) => (
                    <div key={k.label} className="bg-white border border-slate-200 rounded-xl p-5 shadow-sm">
                        <div className="flex items-center justify-between mb-3">
                            <p className="text-[10px] text-slate-500 font-bold tracking-widest uppercase">{k.label}</p>
                            <k.icon size={16} className="text-slate-400" />
                        </div>
                        <p className="text-2xl sm:text-3xl font-black text-slate-800 tracking-tight truncate">{k.value}</p>
                    </div>
                ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm">
                    <h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider flex items-center gap-2">
                        <Activity className="text-blue-500" size={16} /> History Breakdown
                    </h3>
                    <div className="space-y-5">
                        {workItems.map((w) => {
                            const max = Math.max(...workItems.map(x => x.val), 1);
                            const pct = Math.max((w.val / max) * 100, 2);
                            return (
                                <div key={w.label}>
                                    <div className="flex items-center justify-between mb-1.5">
                                        <div className="flex items-center gap-2">
                                            <w.icon size={14} style={{ color: w.color }} />
                                            <span className="text-xs font-semibold text-slate-700">{w.label}</span>
                                        </div>
                                        <span className="text-sm font-bold text-slate-900">{w.val.toLocaleString()}</span>
