                                                                        <div className="p-2 opacity-0 group-hover/att-card:opacity-100 rounded transition-colors text-slate-400 hover:text-indigo-500">
                                                                            <Maximize2 size={14} />
                                                                        </div>
                                                                    </div>
                                                                )}
                                                            </div>
                                                        ))}
                                                    </div>
