                                                    <button className="p-1 hover:bg-slate-50 rounded text-slate-400 hover:text-slate-600">
                                                        <Smile size={14} />
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )) : (
                        <div className="h-full flex flex-col items-center justify-center p-10 pt-20 text-slate-300 opacity-50">
                            <div className="w-16 h-16 rounded-2xl bg-slate-100 flex items-center justify-center mb-4">
                                <User size={24} />
                            </div>
                            <p className="text-sm font-medium text-slate-400">No messages yet</p>
                            <p className="text-xs mt-1">Start the conversation!</p>
                        </div>
                    )}
                    <div ref={messagesEndRef} />
                </div>
            </div>

            {/* Document Preview Modal */}
            {previewAttachment && (
                <div className="fixed inset-0 z-[200] flex flex-col bg-slate-900/90 backdrop-blur-md animate-in fade-in duration-200">
                    {/* Header */}
                    <div className="h-16 flex items-center justify-between px-6 bg-slate-900/50 border-b border-white/10 shrink-0">
                        <div className="flex items-center gap-4 min-w-0">
                            <div className="w-10 h-10 rounded-lg bg-white/10 flex items-center justify-center text-white shrink-0">
                                {previewAttachment.name.endsWith('.pdf') ? <FileText size={20} /> : <ImageIcon size={20} />}
                            </div>
                            <div className="min-w-0">
                                <h3 className="text-sm font-bold text-white truncate">{previewAttachment.name}</h3>
                                <p className="text-[11px] text-slate-400 uppercase tracking-wider">{previewAttachment.size} • {previewAttachment.mimeType || 'Document'}</p>
                            </div>
                        </div>
                        <div className="flex items-center gap-3">
                            <a
                                href={previewAttachment.url}
                                download={previewAttachment.name}
                                className="flex items-center gap-2 px-4 py-2 bg-white text-slate-900 rounded-lg text-xs font-bold hover:bg-indigo-50 transition-all active:scale-95"
                            >
                                <Download size={14} /> Download
                            </a>
                            <button
                                onClick={() => setPreviewAttachment(null)}
                                className="p-2 text-white hover:bg-white/10 rounded-lg transition-colors"
                            >
                                <X size={20} />
                            </button>
                        </div>
                    </div>

                    {/* Content Body */}
                    <div className="flex-1 overflow-hidden p-6 flex items-center justify-center">
                        <div className="w-full h-full max-w-6xl bg-white rounded-2xl shadow-2xl overflow-hidden relative group/v">
                            {((previewAttachment.name || '').toLowerCase().endsWith('.pdf') || (previewAttachment.mimeType || '').includes('pdf')) ? (
                                <object
                                    data={previewAttachment.url}
                                    type="application/pdf"
                                    className="w-full h-full border-none"
                                >
                                    <iframe
                                        src={previewAttachment.url}
                                        className="w-full h-full border-none"
                                        title={previewAttachment.name}
                                    />
                                </object>
                            ) : (previewAttachment.type === 'image' || (previewAttachment.mimeType || '').startsWith('image/') || /\.(jpg|jpeg|png|gif|webp|svg)$/i.test(previewAttachment.name || '')) ? (
                                <img
                                    src={previewAttachment.url}
                                    className="w-full h-full object-contain"
                                    alt={previewAttachment.name}
                                />
                            ) : (
                                <div className="w-full h-full flex flex-col items-center justify-center bg-slate-50 text-slate-400 p-12 text-center">
                                    <div className="w-24 h-24 rounded-3xl bg-white shadow-sm flex items-center justify-center mb-6">
                                        <FileText size={48} className="text-slate-300" />
                                    </div>
                                    <h4 className="text-lg font-bold text-slate-700 mb-2">No preview available</h4>
                                    <p className="text-sm max-w-xs mb-8">This file type cannot be previewed directly. Please download it to view the full content on your device.</p>
                                    <a
                                        href={previewAttachment.url}
                                        download={previewAttachment.name}
                                        className="inline-flex items-center gap-2 px-6 py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all shadow-lg active:scale-95"
                                    >
                                        <Download size={18} /> Download Now
                                    </a>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useEffect, useState } from 'react';
import { Bell, Check, Trash2, MessageSquare, AtSign } from 'lucide-react';
import { ChatNotification } from '../../types';
import ChatService from '../../services/chatService';
import { formatDistanceToNow } from 'date-fns';

interface ChatNotificationsProps {
    onClose: () => void;
    onNotificationClick: (notification: ChatNotification) => void;
}

export const ChatNotifications: React.FC<ChatNotificationsProps> = ({ onClose, onNotificationClick }) => {
    const [notifications, setNotifications] = useState<ChatNotification[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchNotifications = async () => {
        try {
            setLoading(true);
            const data = await ChatService.getNotifications();
            setNotifications(data);
        } catch (error) {
            console.error('Failed to fetch notifications:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchNotifications();

        // Listen for new notifications
        const handleNewNotification = (notification: ChatNotification) => {
            setNotifications(prev => [notification, ...prev]);
        };

        ChatService.on('notification:new', handleNewNotification);

        return () => {
            ChatService.off('notification:new', handleNewNotification);
        };
    }, []);

    const handleMarkAsRead = async (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        try {
            await ChatService.markNotificationRead(id);
            setNotifications(prev =>
                prev.map(n => n.id === id ? { ...n, isRead: true } : n)
            );
        } catch (error) {
            console.error('Failed to mark as read:', error);
        }
    };

    const handleMarkAllRead = async () => {
        try {
            await ChatService.markAllNotificationsRead();
            setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
        } catch (error) {
            console.error('Failed to mark all as read:', error);
        }
    };

    const getIcon = (type: string) => {
        switch (type) {
            case 'mention': return <AtSign size={16} className="text-blue-500" />;
            case 'reply': return <MessageSquare size={16} className="text-purple-500" />;
            default: return <Bell size={16} className="text-slate-500" />;
        }
    };

    return (
        <div className="absolute right-0 mt-2 w-80 bg-white rounded-lg shadow-xl border border-slate-200 overflow-hidden z-50 animate-in fade-in zoom-in-95 duration-200">
            <div className="bg-slate-50 px-4 py-3 border-b border-slate-100 flex items-center justify-between">
                <h3 className="font-semibold text-slate-800">Notifications</h3>
                <button
                    onClick={handleMarkAllRead}
                    className="text-xs text-blue-600 hover:text-blue-700 font-medium"
                >
                    Mark all read
                </button>
            </div>

            <div className="max-h-96 overflow-y-auto">
                {loading ? (
                    <div className="p-8 text-center text-slate-400">Loading...</div>
                ) : notifications.length === 0 ? (
                    <div className="p-8 text-center text-slate-400">
                        <Bell size={24} className="mx-auto mb-2 opacity-50" />
                        <p className="text-sm">No notifications</p>
                    </div>
                ) : (
                    notifications.map(notification => (
                        <div
                            key={notification.id}
                            onClick={() => onNotificationClick(notification)}
                            className={`p-4 border-b border-slate-50 hover:bg-slate-50 cursor-pointer transition-colors relative group ${notification.isRead ? 'opacity-75' : 'bg-blue-50/50'
                                }`}
                        >
                            <div className="flex gap-3">
                                <div className="mt-1 flex-shrink-0">
                                    {getIcon(notification.type)}
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="text-sm font-medium text-slate-800 mb-0.5">
                                        {notification.title}
                                    </p>
                                    <p className="text-sm text-slate-600 line-clamp-2">
                                        {notification.message}
                                    </p>
                                    <span className="text-xs text-slate-400 mt-1 block">
                                        {formatDistanceToNow(new Date(notification.createdAt), { addSuffix: true })}
                                    </span>
                                </div>
                                {!notification.isRead && (
                                    <div className="flex-shrink-0 self-center">
                                        <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
                                    </div>
                                )}
                            </div>
                            {!notification.isRead && (
                                <button
                                    onClick={(e) => handleMarkAsRead(notification.id, e)}
                                    className="absolute top-2 right-2 p-1 bg-white rounded-full shadow-sm border border-slate-200 opacity-0 group-hover:opacity-100 transition-opacity hover:text-blue-600"
                                    title="Mark as read"
                                >
                                    <Check size={12} />
                                </button>
                            )}
                        </div>
                    ))
                )}
            </div>
        </div>
    );
};

import React, { useEffect, useState } from 'react';
import { User, Shield, Check, Users } from 'lucide-react';
import { ChannelMember } from '../../types';

interface MentionAutocompleteProps {
    members: ChannelMember[];
    query: string;
    onSelect: (userName: string) => void;
    onClose: () => void;
    style?: React.CSSProperties;
}

export const MentionAutocomplete: React.FC<MentionAutocompleteProps> = ({
    members,
    query,
    onSelect,
    onClose,
    style
}) => {
    const [selectedIndex, setSelectedIndex] = useState(0);

    // Extract unique roles from members and filter based on query
    const roles = Array.from(new Set(members.map(m => m.role)))
        .filter((role): role is string => !!role && role.toLowerCase().includes(query.toLowerCase()))
        .map(role => ({ type: 'role' as const, name: role, id: `role-${role}` }));

    const filteredMembers = members
        .filter(member => member.userName.toLowerCase().includes(query.toLowerCase()))
        .map(member => ({ type: 'user' as const, name: member.userName, id: member.userId, avatar: member.userAvatar, role: member.role }));

    const suggestions = [...roles, ...filteredMembers];

    // Reset selection when query changes
    useEffect(() => {
        setSelectedIndex(0);
    }, [query]);

    // Handle keyboard navigation
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (suggestions.length === 0) return;

            if (e.key === 'ArrowDown') {
                e.preventDefault();
                setSelectedIndex(prev => (prev + 1) % suggestions.length);
            } else if (e.key === 'ArrowUp') {
                e.preventDefault();
                setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length);
            } else if (e.key === 'Enter' || e.key === 'Tab') {
                e.preventDefault();
                const selected = suggestions[selectedIndex];
                if (selected) {
                    onSelect(selected.name);
                }
            } else if (e.key === 'Escape') {
                e.preventDefault();
                onClose();
            }
        };

        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [suggestions, selectedIndex, onSelect, onClose]);

    if (suggestions.length === 0) return null;

    return (
        <div
            className="fixed z-50 w-64 bg-white rounded-lg shadow-xl border border-slate-200 overflow-hidden"
            style={style}
        >
            <div className="bg-slate-50 px-3 py-2 border-b border-slate-100 text-xs font-medium text-slate-500">
                Mention user or role
            </div>
            <div className="max-h-48 overflow-y-auto">
                {suggestions.map((item, index) => (
                    <button
                        key={item.id}
                        onClick={() => onSelect(item.name)}
                        className={`w-full px-3 py-2 flex items-center gap-2 text-left transition-colors ${index === selectedIndex ? 'bg-blue-50 text-blue-700' : 'hover:bg-slate-50 text-slate-700'
                            }`}
                    >
                        <div className="w-6 h-6 rounded-full bg-slate-200 flex items-center justify-center overflow-hidden flex-shrink-0">
                            {item.type === 'user' ? (
                                item.avatar ? (
                                    <img src={item.avatar} alt={item.name} className="w-full h-full object-cover" />
                                ) : (
                                    <User size={14} className="text-slate-400" />
                                )
                            ) : (
                                <Users size={14} className="text-indigo-500" />
                            )}
                        </div>
                        <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-1.5">
                                <span className="font-medium truncate text-sm">
                                    {item.name}
                                    {item.type === 'role' && ' (Role)'}
                                </span>
                                {item.type === 'user' && (
                                    <>
                                        {item.role === 'owner' && <Shield size={12} className="text-amber-500" />}
                                        {item.role === 'admin' && <Shield size={12} className="text-blue-500" />}
                                    </>
                                )}
                            </div>
                        </div>
                        {index === selectedIndex && <Check size={14} className="text-blue-600" />}
                    </button>
                ))}
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Employer, EmployerStatus, EmployerDocument, EmployerActivity } from '../../types';
import { PartnerService } from '../../services/partnerService';
import { X, Building2, MapPin, Mail, Phone, DollarSign, FileText, User } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';

interface AddPartnerModalProps {
    onClose: () => void;
    onSaved: (employer: Employer) => void;
    existingEmployer?: Employer;
}

const COUNTRIES = [
    'United Arab Emirates', 'Saudi Arabia', 'Qatar', 'Kuwait', 'Bahrain',
    'Oman', 'Jordan', 'South Korea', 'Japan', 'Malaysia',
    'Singapore', 'Italy', 'Romania', 'Poland', 'Other',
];

const AddPartnerModal: React.FC<AddPartnerModalProps> = ({ onClose, onSaved, existingEmployer }) => {
    const { user } = useAuth();
    const [form, setForm] = useState({
        companyName: existingEmployer?.companyName || '',
        regNumber: existingEmployer?.regNumber || '',
        country: existingEmployer?.country || '',
        address: '', // not directly in Employer type but kept for UI form
        contactPerson: existingEmployer?.contactPerson || '',
        email: existingEmployer?.email || '',
        phone: existingEmployer?.phone || '',
        status: existingEmployer?.status || EmployerStatus.PENDING_APPROVAL,
        commissionPerHire: existingEmployer?.commissionPerHire?.toString() || '',
        paymentTermDays: existingEmployer?.paymentTermDays?.toString() || '30',
        quotaTotal: existingEmployer?.quotaTotal?.toString() || '50',
        notes: existingEmployer?.notes || '',
    });
    const [errors, setErrors] = useState<Record<string, string>>({});

    const validate = (): boolean => {
        const errs: Record<string, string> = {};
        // FRICTIONLESS: Disabled all input validation rules for partner form
        setErrors(errs);
        return true;
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!validate()) return;

        const now = new Date().toISOString();

        let employer: Employer;

        if (existingEmployer) {
            employer = {
                ...existingEmployer,
                companyName: form.companyName,
                regNumber: form.regNumber || existingEmployer.regNumber,
                country: form.country,
                contactPerson: form.contactPerson,
                email: form.email,
                phone: form.phone,
                status: form.status,
                commissionPerHire: form.commissionPerHire ? parseFloat(form.commissionPerHire) : undefined,
                paymentTermDays: parseInt(form.paymentTermDays) || 30,
                quotaTotal: parseInt(form.quotaTotal) || 50,
                notes: form.notes,
            };
            try {
                const updated = await PartnerService.updateEmployer(employer);
                if (updated) onSaved(updated);
            } catch (error) {
                console.error("Failed to update partner:", error);
            }
        } else {
            employer = {
                id: `emp-${Date.now()}`,
                companyName: form.companyName,
                regNumber: form.regNumber || `REG-${Date.now().toString().slice(-6)}`,
                country: form.country,
                contactPerson: form.contactPerson,
                email: form.email,
                phone: form.phone,
                status: form.status,
                commissionPerHire: form.commissionPerHire ? parseFloat(form.commissionPerHire) : undefined,
                paymentTermDays: parseInt(form.paymentTermDays) || 30,
                quotaTotal: parseInt(form.quotaTotal) || 50,
                quotaUsed: 0,
                selectionRatio: 0,
                joinedDate: now,
                documents: [
                    {
                        id: `doc-${Date.now()}-1`,
                        title: 'Trade License',
                        type: 'License',
                        status: 'Pending',
                        expiryDate: '',
                    } as EmployerDocument,
                    {
                        id: `doc-${Date.now()}-2`,
                        title: 'Power of Attorney',
                        type: 'POA',
                        status: 'Pending',
                        expiryDate: '',
                        uploadedAt: now,
                    } as EmployerDocument,
                ],
                activityLog: [
                    {
                        id: `act-${Date.now()}`,
                        type: 'Note',
                        content: 'Partner account created',
                        timestamp: now,
                        actor: user?.name || 'Internal Staff',
                        userId: user?.id,
                    } as EmployerActivity,
                ],
            };
            try {
                const added = await PartnerService.addEmployer(employer);
                if (added) onSaved(added);
            } catch (error) {
                console.error("Failed to add partner:", error);
            }
        }
    };

    const inputClasses = (field: string) =>
        `w-full px-4 py-2.5 bg-white border rounded-xl text-sm outline-none transition-all ${errors[field]
            ? 'border-red-300 focus:ring-2 focus:ring-red-100'
            : 'border-slate-200 focus:ring-2 focus:ring-blue-100 focus:border-blue-400'
        }`;

    return (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-3xl shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto">
                <div className="sticky top-0 bg-white/95 backdrop-blur border-b border-slate-100 px-8 py-5 rounded-t-3xl flex items-center justify-between z-10">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-blue-50 text-blue-600 rounded-xl">
                            <Building2 size={20} />
                        </div>
                        <div>
                            <h3 className="text-lg font-bold text-slate-800">{existingEmployer ? 'Edit Partner' : 'Add New Partner'}</h3>
                            <p className="text-xs text-slate-500">{existingEmployer ? 'Update partner details' : 'Register a new employer / recruitment partner'}</p>
                        </div>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-xl transition-colors">
                        <X size={20} className="text-slate-400" />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="p-8 space-y-6">
                    {/* Company Info Section */}
                    <div>
                        <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                            <Building2 size={12} /> Company Information
                        </h4>
                        <div className="space-y-4">
                            <div>
                                <label className="text-xs font-bold text-slate-600 mb-1.5 block">Company Name</label>
                                <input
                                    type="text"
                                    placeholder="e.g., BuildCorp International"
                                    className={inputClasses('companyName')}
                                    value={form.companyName}
                                    onChange={e => setForm(p => ({ ...p, companyName: e.target.value }))}
                                />
                                {errors.companyName && <p className="text-xs text-red-500 mt-1">{errors.companyName}</p>}
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-xs font-bold text-slate-600 mb-1.5 block">Registration Number</label>
                                    <input
                                        type="text"
                                        placeholder="e.g., REG-123456"
                                        className={inputClasses('regNumber')}
                                        value={form.regNumber}
                                        onChange={e => setForm(p => ({ ...p, regNumber: e.target.value }))}
                                    />
                                </div>
                                <div>
                                    <label className="text-xs font-bold text-slate-600 mb-1.5 block">
                                        <MapPin size={12} className="inline mr-1" /> Country
                                    </label>
                                    <select
                                        className={inputClasses('country')}
                                        value={form.country}
                                        onChange={e => setForm(p => ({ ...p, country: e.target.value }))}
                                    >
                                        <option value="">Select country...</option>
                                        {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
                                    </select>
                                    {errors.country && <p className="text-xs text-red-500 mt-1">{errors.country}</p>}
                                </div>
                            </div>
                            {existingEmployer && (
                                <div>
                                    <label className="text-xs font-bold text-slate-600 mb-1.5 block">Status</label>
                                    <select
                                        className={inputClasses('status')}
                                        value={form.status}
                                        onChange={e => setForm(p => ({ ...p, status: e.target.value as EmployerStatus }))}
                                    >
                                        {Object.values(EmployerStatus).map(s => <option key={s} value={s}>{s}</option>)}
                                    </select>
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="h-px bg-slate-100" />

                    {/* Contact Section */}
                    <div>
                        <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                            <User size={12} /> Contact Details
                        </h4>
                        <div className="space-y-4">
                            <div>
                                <label className="text-xs font-bold text-slate-600 mb-1.5 block">Contact Person</label>
                                <input
                                    type="text"
                                    placeholder="e.g., Ahmed Al Rasheed"
                                    className={inputClasses('contactPerson')}
                                    value={form.contactPerson}
                                    onChange={e => setForm(p => ({ ...p, contactPerson: e.target.value }))}
                                />
                                {errors.contactPerson && <p className="text-xs text-red-500 mt-1">{errors.contactPerson}</p>}
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-xs font-bold text-slate-600 mb-1.5 block">
                                        <Mail size={12} className="inline mr-1" /> Email
                                    </label>
                                    <input
                                        type="email"
                                        placeholder="email@company.com"
                                        className={inputClasses('email')}
                                        value={form.email}
                                        onChange={e => setForm(p => ({ ...p, email: e.target.value }))}
                                    />
                                    {errors.email && <p className="text-xs text-red-500 mt-1">{errors.email}</p>}
                                </div>
                                <div>
                                    <label className="text-xs font-bold text-slate-600 mb-1.5 block">
                                        <Phone size={12} className="inline mr-1" /> Phone
                                    </label>
                                    <input
                                        type="tel"
                                        placeholder="+971 xxx xxxx"
                                        className={inputClasses('phone')}
                                        value={form.phone}
                                        onChange={e => setForm(p => ({ ...p, phone: e.target.value }))}
                                    />
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="h-px bg-slate-100" />

                    {/* Financial Section */}
                    <div>
                        <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                            <DollarSign size={12} /> Financial Terms
                        </h4>
                        <div className="grid grid-cols-3 gap-4">
                            <div>
                                <label className="text-xs font-bold text-slate-600 mb-1.5 block">Commission/Hire ($)</label>
                                <input
                                    type="number"
                                    placeholder="e.g., 450"
                                    className={inputClasses('commissionPerHire')}
                                    value={form.commissionPerHire}
                                    onChange={e => setForm(p => ({ ...p, commissionPerHire: e.target.value }))}
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold text-slate-600 mb-1.5 block">Payment Terms (days)</label>
                                <select
                                    className={inputClasses('paymentTermDays')}
                                    value={form.paymentTermDays}
                                    onChange={e => setForm(p => ({ ...p, paymentTermDays: e.target.value }))}
                                >
                                    <option value="15">15 Days</option>
                                    <option value="30">30 Days</option>
                                    <option value="45">45 Days</option>
                                    <option value="60">60 Days</option>
                                </select>
                            </div>
                            <div>
                                <label className="text-xs font-bold text-slate-600 mb-1.5 block">Quota (Annual)</label>
                                <input
                                    type="number"
                                    min={1}
                                    className={inputClasses('quotaTotal')}
                                    value={form.quotaTotal}
                                    onChange={e => setForm(p => ({ ...p, quotaTotal: e.target.value }))}
                                />
                            </div>
                        </div>
                    </div>

                    {/* Actions */}
                    <div className="flex gap-3 pt-4 border-t border-slate-100">
                        <button
                            type="button"
                            onClick={onClose}
                            className="flex-1 py-3 bg-slate-100 text-slate-700 rounded-xl text-sm font-bold hover:bg-slate-200 transition-all"
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            className="flex-1 py-3 bg-blue-600 text-white rounded-xl text-sm font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100"
                        >
                            {existingEmployer ? 'Update Partner' : 'Create Partner'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default AddPartnerModal;

import React, { useState, useMemo, useEffect } from 'react';
import { DemandOrder, CandidateSelection, SelectionStage, Candidate } from '../../types';
import { CandidateService } from '../../services/candidateService';
import { SelectionService } from '../../services/selectionService';
import { X, Search, UserPlus, Check, Users, Star, MapPin, Briefcase } from 'lucide-react';

interface CandidateMatchModalProps {
    demandOrder: DemandOrder;
    onClose: () => void;
    onMatched: () => void;
}

const CandidateMatchModal: React.FC<CandidateMatchModalProps> = ({
    demandOrder,
    onClose,
    onMatched,
}) => {
    const [searchQuery, setSearchQuery] = useState('');
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [isLoading, setIsLoading] = useState(false);
    const [existingSelections, setExistingSelections] = useState<CandidateSelection[]>([]);

    // Candidates are loaded via useEffect below
    const [candidates, setCandidates] = useState<Candidate[]>([]);

    // Load candidates on mount
    useEffect(() => {
        const load = async () => {
            try {
                const [candidatesData, selectionsData] = await Promise.all([
                    CandidateService.getCandidates(),
                    SelectionService.getByDemandOrderId(demandOrder.id)
                ]);
                setCandidates(candidatesData || []);
                setExistingSelections(selectionsData || []);
            } catch (e) {
                console.error("Failed to load match data", e);
                setCandidates([]);
            }
        };
        load();
    }, [demandOrder.id]);

    const alreadyMatchedIds = useMemo(() => {
        return new Set(existingSelections.map(s => s.candidateId));
    }, [existingSelections]);

    // Calculate match score based on requirement overlap
    const calculateMatchScore = (candidate: Candidate): number => {
        if (!demandOrder.requirements.length) return 50;

        const candidateSkills = [
            ...(candidate.skills || []),
            ...(candidate.preferredCountries || []),
            String(candidate.education || ''),
        ].map(s => String(s).toLowerCase());

        const matches = demandOrder.requirements.filter(req =>
            candidateSkills.some(skill => skill.includes(req.toLowerCase()) || req.toLowerCase().includes(skill))
        );

        return Math.round((matches.length / demandOrder.requirements.length) * 100);
    };

    // Filter and score candidates
    const scoredCandidates = useMemo(() => {
        const query = searchQuery.toLowerCase();
        return candidates
            .filter(c => !alreadyMatchedIds.has(c.id))
            .filter(c => {
                if (!query) return true;
                return (
                    c.name.toLowerCase().includes(query) ||
                    (c.nationality || '').toLowerCase().includes(query) ||
                    (c.skills || []).some(s => s.toLowerCase().includes(query)) ||
                    (c.preferredCountries || []).some(pc => pc.toLowerCase().includes(query))
                );
            })
            .map(c => ({
                candidate: c,
                matchScore: calculateMatchScore(c),
            }))
            .sort((a, b) => b.matchScore - a.matchScore);
    }, [candidates, searchQuery, alreadyMatchedIds]);

    const toggleSelect = (candidateId: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            if (next.has(candidateId)) next.delete(candidateId);
            else next.add(candidateId);
            return next;
        });
    };

    const selectAll = () => {
        const allIds = scoredCandidates.map(sc => sc.candidate.id);
        setSelectedIds(new Set(allIds));
    };

    const handleMatch = async () => {
        setIsLoading(true);
        const now = new Date().toISOString();

        const newSelections: CandidateSelection[] = Array.from(selectedIds).map(candidateId => {
            const scored = scoredCandidates.find(sc => sc.candidate.id === candidateId);
            return {
                id: `sel-${Date.now()}-${candidateId}`,
                demandOrderId: demandOrder.id,
                candidateId,
                candidateName: scored?.candidate.name || 'Unknown',
                stage: SelectionStage.MATCHED,
                matchScore: scored?.matchScore || 50,
                createdAt: now,
                updatedAt: now,
            };
        });

        try {
            await SelectionService.addBatch(newSelections);
            onMatched();
        } catch (error) {
            console.error("Match failed", error);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-3xl shadow-2xl max-w-3xl w-full max-h-[85vh] flex flex-col">
                {/* Header */}
                <div className="sticky top-0 bg-white/95 backdrop-blur border-b border-slate-100 px-8 py-5 rounded-t-3xl flex items-center justify-between z-10">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-purple-50 text-purple-600 rounded-xl">
                            <UserPlus size={20} />
                        </div>
                        <div>
                            <h3 className="text-lg font-bold text-slate-800">Match Candidates</h3>
                            <p className="text-xs text-slate-500">
                                Select candidates to match with: <span className="font-bold text-slate-700">{demandOrder.title}</span>
                            </p>
                        </div>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-xl transition-colors">
                        <X size={20} className="text-slate-400" />
                    </button>
                </div>

                {/* Search + Filters */}
                <div className="px-8 py-4 border-b border-slate-100 flex items-center gap-4">
                    <div className="relative flex-1">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                        <input
                            type="text"
                            placeholder="Search by name, nationality, skills..."
                            className="w-full pl-11 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-2 focus:ring-blue-100 transition-all"
                            value={searchQuery}
                            onChange={e => setSearchQuery(e.target.value)}
                        />
                    </div>
                    <button
                        onClick={selectAll}
                        className="px-3 py-2 text-xs font-bold text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                    >
                        Select All
                    </button>
                    <div className="text-xs text-slate-500">
                        <span className="font-bold text-blue-600">{selectedIds.size}</span> selected
                    </div>
                </div>

                {/* Requirements Reminder */}
                {demandOrder.requirements.length > 0 && (
                    <div className="px-8 py-3 bg-blue-50/50 border-b border-blue-100">
                        <p className="text-[9px] font-bold text-blue-500 uppercase tracking-widest mb-1">Required Skills</p>
                        <div className="flex flex-wrap gap-1.5">
                            {demandOrder.requirements.map((r, i) => (
                                <span key={i} className="px-2 py-0.5 bg-blue-100 text-blue-700 rounded-full text-[10px] font-bold">{r}</span>
                            ))}
                        </div>
                    </div>
                )}

                {/* Candidate List */}
                <div className="flex-1 overflow-y-auto px-8 py-4">
                    {scoredCandidates.length === 0 ? (
                        <div className="text-center py-16">
                            <Users size={40} className="mx-auto text-slate-300 mb-3" />
                            <p className="text-sm font-bold text-slate-400">No unmatched candidates found</p>
                            <p className="text-xs text-slate-400 mt-1">All candidates are already matched to this demand order</p>
                        </div>
                    ) : (
                        <div className="space-y-2">
                            {scoredCandidates.map(({ candidate, matchScore }) => {
                                const isSelected = selectedIds.has(candidate.id);
                                return (
                                    <div
                                        key={candidate.id}
                                        onClick={() => toggleSelect(candidate.id)}
                                        className={`flex items-center gap-4 p-4 rounded-2xl border cursor-pointer transition-all ${isSelected
                                            ? 'bg-blue-50 border-blue-200 ring-1 ring-blue-100'
                                            : 'bg-white border-slate-100 hover:border-blue-200 hover:bg-blue-50/20'
                                            }`}
                                    >
                                        {/* Checkbox */}
                                        <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center flex-shrink-0 transition-all ${isSelected ? 'bg-blue-600 border-blue-600' : 'border-slate-300'
                                            }`}>
                                            {isSelected && <Check size={14} className="text-white" />}
                                        </div>

                                        {/* Avatar */}
                                        <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-500 font-bold text-sm flex-shrink-0">
                                            {candidate.name.charAt(0)}
                                        </div>

                                        {/* Info */}
                                        <div className="flex-1 min-w-0">
                                            <p className="text-sm font-bold text-slate-800 truncate">{candidate.name}</p>
                                            <div className="flex items-center gap-3 mt-0.5">
                                                <span className="text-[10px] text-slate-500 flex items-center gap-1">
                                                    <MapPin size={9} /> {candidate.nationality || 'Unknown'}
                                                </span>
                                                <span className="text-[10px] text-slate-500 flex items-center gap-1">
                                                    <Briefcase size={9} /> {candidate.stage}
                                                </span>
                                            </div>
                                            {candidate.skills && candidate.skills.length > 0 && (
                                                <div className="flex flex-wrap gap-1 mt-1.5">
                                                    {candidate.skills.slice(0, 3).map((s, i) => (
                                                        <span key={i} className="px-1.5 py-0.5 bg-slate-100 text-slate-600 rounded text-[9px] font-bold">{s}</span>
                                                    ))}
                                                    {candidate.skills.length > 3 && (
                                                        <span className="text-[9px] text-slate-400">+{candidate.skills.length - 3} more</span>
                                                    )}
                                                </div>
                                            )}
                                        </div>

                                        {/* Match Score */}
                                        <div className="flex items-center gap-2 flex-shrink-0">
                                            <div className="text-right">
                                                <p className="text-[9px] font-bold text-slate-400 uppercase">Match</p>
                                                <p className={`text-lg font-black ${matchScore >= 80 ? 'text-green-600' :
                                                    matchScore >= 60 ? 'text-amber-600' :
                                                        matchScore >= 40 ? 'text-orange-500' :
                                                            'text-red-500'
                                                    }`}>{matchScore}%</p>
                                            </div>
                                            <Star
                                                size={16}
                                                className={matchScore >= 80 ? 'text-green-400 fill-green-400' : 'text-slate-300'}
                                            />
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className="sticky bottom-0 bg-white/95 backdrop-blur border-t border-slate-100 px-8 py-4 rounded-b-3xl flex items-center justify-between">
                    <p className="text-xs text-slate-500">
                        <span className="font-bold">{scoredCandidates.length}</span> available • <span className="font-bold text-blue-600">{selectedIds.size}</span> selected
                    </p>
                    <div className="flex gap-3">
                        <button
                            onClick={onClose}
                            className="px-5 py-2.5 bg-slate-100 text-slate-700 rounded-xl text-sm font-bold hover:bg-slate-200 transition-all"
                        >
                            Cancel
                        </button>
                        <button
                            onClick={handleMatch}
                            disabled={selectedIds.size === 0 || isLoading}
                            className="px-5 py-2.5 bg-blue-600 text-white rounded-xl text-sm font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                        >
                            <UserPlus size={16} />
                            Match {selectedIds.size} Candidate{selectedIds.size !== 1 ? 's' : ''}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default CandidateMatchModal;

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { DemandOrder, DemandOrderStatus } from '../../types';
import { DemandOrderService } from '../../services/demandOrderService';
import {
    Package, Plus, Calendar, MapPin, Users, Clock,
    ChevronRight, AlertTriangle, CheckCircle2, TrendingUp, Briefcase, ExternalLink, Loader, Edit2, Trash2
} from 'lucide-react';

import { supabase } from '../../services/supabase';

interface DemandOrderListProps {
    employerId: string;
    onSelectOrder: (order: DemandOrder) => void;
    onEditOrder: (order: DemandOrder) => void;
    onDeleteOrder: (id: string, name: string) => void;
    selectedOrderId?: string;
    onCreateNew: () => void;
}

const DemandOrderList: React.FC<DemandOrderListProps> = ({
    employerId,
    onSelectOrder,
    onEditOrder,
    onDeleteOrder,
    selectedOrderId,
    onCreateNew,
}) => {
    const [filter, setFilter] = useState<'all' | 'open' | 'filled' | 'closed'>('all');
    const [orders, setOrders] = useState<DemandOrder[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        let isMounted = true;
        const loadOrders = async () => {
            setIsLoading(true);
            try {
                const data = await DemandOrderService.getByEmployerId(employerId);
                if (isMounted) setOrders(data || []);
            } catch (error) {
                console.error("Failed to load demand orders", error);
            } finally {
                if (isMounted) setIsLoading(false);
            }
        };

        loadOrders();

        // Realtime Data Syncing for Demand Orders
        const subscription = supabase
            .channel(`public:demand_orders:${employerId}`)
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'demand_orders' },
                () => {
                    console.log('Realtime update: demand_orders changed. Refreshing...');
                    loadOrders();
                }
            )
            .subscribe();

        return () => {
            isMounted = false;
            subscription.unsubscribe();
        };
    }, [employerId]);

    const filteredOrders = orders.filter(o => {
        if (filter === 'all') return true;
        if (filter === 'open') return o.status === DemandOrderStatus.OPEN || o.status === DemandOrderStatus.PARTIALLY_FILLED;
        if (filter === 'filled') return o.status === DemandOrderStatus.FILLED;
        if (filter === 'closed') return o.status === DemandOrderStatus.CLOSED || o.status === DemandOrderStatus.CANCELLED;
        return true;
    });

    const getStatusConfig = (status: DemandOrderStatus) => {
        switch (status) {
            case DemandOrderStatus.OPEN:
                return { color: 'bg-blue-100 text-blue-700 border-blue-200', icon: TrendingUp };
            case DemandOrderStatus.PARTIALLY_FILLED:
                return { color: 'bg-amber-100 text-amber-700 border-amber-200', icon: Clock };
            case DemandOrderStatus.FILLED:
                return { color: 'bg-green-100 text-green-700 border-green-200', icon: CheckCircle2 };
            case DemandOrderStatus.CLOSED:
                return { color: 'bg-slate-100 text-slate-600 border-slate-200', icon: CheckCircle2 };
            case DemandOrderStatus.CANCELLED:
                return { color: 'bg-red-100 text-red-700 border-red-200', icon: AlertTriangle };
            default:
                return { color: 'bg-slate-100 text-slate-600 border-slate-200', icon: Package };
        }
    };

    const getDaysUntilDeadline = (deadline?: string) => {
        if (!deadline) return null;
        const days = Math.ceil((new Date(deadline).getTime() - Date.now()) / (1000 * 60 * 60 * 24));
        return days;
    };

    const stats = {
        total: orders.length,
        open: orders.filter(o => o.status === DemandOrderStatus.OPEN || o.status === DemandOrderStatus.PARTIALLY_FILLED).length,
        totalPositions: orders.reduce((sum, o) => sum + o.positionsRequired, 0),
        totalFilled: orders.reduce((sum, o) => sum + o.positionsFilled, 0),
    };

    if (isLoading) return (
        <div className="flex flex-col items-center justify-center p-12 text-slate-400">
            <Loader className="animate-spin mb-2" size={24} />
            <p className="text-xs font-bold">Loading orders...</p>
        </div>
    );

    return (
        <div className="space-y-6">
            {/* Stats Bar */}
            <div className="grid grid-cols-4 gap-3">
                {[
                    { label: 'Total Orders', value: stats.total, color: 'text-slate-800' },
                    { label: 'Active', value: stats.open, color: 'text-blue-600' },
                    { label: 'Positions', value: stats.totalPositions, color: 'text-purple-600' },
                    { label: 'Filled', value: stats.totalFilled, color: 'text-green-600' },
                ].map((s, i) => (
                    <div key={i} className="bg-white/60 backdrop-blur rounded-xl p-3 border border-slate-100">
                        <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{s.label}</p>
                        <p className={`text-xl font-black ${s.color}`}>{s.value}</p>
                    </div>
                ))}
            </div>

            {/* Filters + Create */}
            <div className="flex items-center justify-between">
                <div className="flex gap-1 bg-slate-100 p-1 rounded-xl">
                    {(['all', 'open', 'filled', 'closed'] as const).map(f => (
                        <button
                            key={f}
                            onClick={() => setFilter(f)}
                            className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all capitalize ${filter === f
                                ? 'bg-white text-slate-800 shadow-sm'
                                : 'text-slate-500 hover:text-slate-700'
                                }`}
                        >
                            {f}
                        </button>
                    ))}
                </div>
                <button
                    onClick={onCreateNew}
                    className="px-4 py-2 bg-blue-600 text-white rounded-xl text-xs font-bold flex items-center gap-1.5 hover:bg-blue-700 shadow-lg shadow-blue-100 transition-all"
                >
                    <Plus size={14} /> New Demand Order
                </button>
            </div>

            {/* Order List */}
            <div className="space-y-3">
                {filteredOrders.length === 0 ? (
                    <div className="text-center py-16 bg-white rounded-2xl border border-dashed border-slate-200">
                        <Package size={40} className="mx-auto text-slate-300 mb-3" />
                        <p className="text-sm font-bold text-slate-400">No demand orders found</p>
                        <p className="text-xs text-slate-400 mt-1">Create one to start matching candidates</p>
                    </div>
                ) : (
                    filteredOrders.map(order => {
                        const statusConfig = getStatusConfig(order.status);
                        const fillPercent = order.positionsRequired > 0
                            ? Math.round((order.positionsFilled / order.positionsRequired) * 100)
                            : 0;
                        const daysLeft = getDaysUntilDeadline(order.deadline);
                        const isSelected = selectedOrderId === order.id;

                        return (
                            <div
                                key={order.id}
                                onClick={() => onSelectOrder(order)}
                                className={`bg-white rounded-2xl border p-5 cursor-pointer transition-all hover:shadow-md group ${isSelected
                                    ? 'border-blue-300 ring-2 ring-blue-100 shadow-md'
                                    : 'border-slate-200 hover:border-blue-200'
                                    }`}
                            >
                                <div className="flex items-start justify-between mb-3">
                                    <div className="flex-1">
                                        <h4 className="text-sm font-bold text-slate-800 group-hover:text-blue-700 transition-colors">
                                            {order.title}
                                        </h4>
                                        <div className="flex items-center gap-3 mt-1.5">
                                            <span className="text-[10px] text-slate-500 flex items-center gap-1">
                                                <MapPin size={10} /> {order.location}, {order.country}
                                            </span>
                                            <span className="text-[10px] text-green-600 font-bold">{order.salaryRange}</span>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <Link
                                            to={`/jobs?employer=${order.employerId}`}
                                            onClick={(e) => e.stopPropagation()}
                                            className="p-1.5 bg-blue-50 text-blue-500 rounded-lg border border-blue-100 hover:bg-blue-100 transition-all"
                                            title="View on Job Board"
                                        >
                                            <Briefcase size={12} />
                                        </Link>
                                        <span className={`text-[9px] font-bold px-2 py-1 rounded-lg border ${statusConfig.color}`}>
                                            {order.status}
                                        </span>
                                        <button
                                            onClick={(e) => { e.stopPropagation(); onEditOrder(order); }}
                                            className="p-1.5 bg-slate-50 text-slate-500 rounded-lg border border-slate-100 hover:bg-blue-50 hover:text-blue-600 transition-all"
                                            title="Edit Order"
                                        >
                                            <Edit2 size={12} />
                                        </button>
                                        <button
                                            onClick={(e) => { e.stopPropagation(); onDeleteOrder(order.id, order.title); }}
                                            className="p-1.5 bg-slate-50 text-slate-500 rounded-lg border border-slate-100 hover:bg-red-50 hover:text-red-500 transition-all"
                                            title="Delete Order"
                                        >
                                            <Trash2 size={12} />
                                        </button>
                                        <ChevronRight size={16} className={`text-slate-300 group-hover:text-blue-500 transition-colors ${isSelected ? 'text-blue-500' : ''}`} />
                                    </div>
                                </div>

                                {/* Progress Bar */}
                                <div className="flex items-center gap-3">
                                    <div className="flex-1">
                                        <div className="flex items-center justify-between mb-1">
                                            <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1">
                                                <Users size={10} /> {order.positionsFilled}/{order.positionsRequired} filled
                                            </span>
                                            <span className="text-[9px] font-black text-slate-700">{fillPercent}%</span>
                                        </div>
                                        <div className="h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
                                            <div
                                                className={`h-full rounded-full transition-all duration-700 ${fillPercent >= 100 ? 'bg-green-500' : fillPercent > 50 ? 'bg-blue-500' : 'bg-blue-400'
                                                    }`}
                                                style={{ width: `${fillPercent}%` }}
                                            />
                                        </div>
                                    </div>
                                    {daysLeft !== null && (
                                        <span className={`text-[9px] font-bold px-2 py-1 rounded-lg flex items-center gap-1 whitespace-nowrap ${daysLeft <= 7 ? 'bg-red-50 text-red-600' :
                                            daysLeft <= 30 ? 'bg-amber-50 text-amber-600' :
                                                'bg-slate-50 text-slate-500'
                                            }`}>
                                            <Calendar size={10} />
                                            {daysLeft > 0 ? `${daysLeft}d left` : 'Overdue'}
                                        </span>
                                    )}
                                </div>
                            </div>
                        );
                    })
                )}
            </div>
        </div>
    );
};

export default DemandOrderList;

import React, { useState, useEffect } from 'react';
import { CandidateSelection, SelectionStage, DemandOrder } from '../../types';
import { SelectionService } from '../../services/selectionService';
import { DemandOrderService } from '../../services/demandOrderService';
import {
    Users, UserCheck, Video, Phone, Eye, CheckCircle2,
    FileText, ThumbsUp, XCircle, ChevronLeft, Plus,
    GripVertical, Clock, Star, ArrowRight, MessageSquare,
    Send, X, Loader, Trash2
} from 'lucide-react';

interface SelectionBoardProps {
    demandOrder: DemandOrder;
    onBack: () => void;
    onMatchCandidates: () => void;
    onRefresh: () => void;
}

const STAGE_COLUMNS: { stage: SelectionStage; label: string; icon: React.ReactNode; color: string; bgColor: string }[] = [
    { stage: SelectionStage.MATCHED, label: 'Matched', icon: <Users size={14} />, color: 'text-slate-600', bgColor: 'bg-slate-100' },
    { stage: SelectionStage.CV_SUBMITTED, label: 'CV Sent', icon: <Send size={14} />, color: 'text-blue-600', bgColor: 'bg-blue-50' },
    { stage: SelectionStage.SHORTLISTED, label: 'Shortlisted', icon: <Star size={14} />, color: 'text-purple-600', bgColor: 'bg-purple-50' },
    { stage: SelectionStage.INTERVIEW_SCHEDULED, label: 'Interview', icon: <Video size={14} />, color: 'text-amber-600', bgColor: 'bg-amber-50' },
    { stage: SelectionStage.INTERVIEWED, label: 'Interviewed', icon: <Eye size={14} />, color: 'text-orange-600', bgColor: 'bg-orange-50' },
    { stage: SelectionStage.SELECTED, label: 'Selected', icon: <UserCheck size={14} />, color: 'text-green-600', bgColor: 'bg-green-50' },
    { stage: SelectionStage.OFFER_ISSUED, label: 'Offer Issued', icon: <FileText size={14} />, color: 'text-teal-600', bgColor: 'bg-teal-50' },
    { stage: SelectionStage.OFFER_ACCEPTED, label: 'Accepted', icon: <ThumbsUp size={14} />, color: 'text-emerald-600', bgColor: 'bg-emerald-50' },
];

const SelectionBoard: React.FC<SelectionBoardProps> = ({
    demandOrder,
    onBack,
    onMatchCandidates,
    onRefresh,
}) => {
    const [selections, setSelections] = useState<CandidateSelection[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [detailPanel, setDetailPanel] = useState<CandidateSelection | null>(null);
    const [draggedId, setDraggedId] = useState<string | null>(null);
    const [rejectModal, setRejectModal] = useState<CandidateSelection | null>(null);
    const [rejectReason, setRejectReason] = useState('');

    const loadSelections = async (quiet = false) => {
        if (!quiet) setIsLoading(true);
        try {
            const data = await SelectionService.getByDemandOrderId(demandOrder.id);
            setSelections(data || []);
        } catch (error) {
            console.error("Failed to load selections", error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        loadSelections();
    }, [demandOrder.id]);

    const activeSelections = selections.filter(s => s.stage !== SelectionStage.REJECTED);
    const rejectedSelections = selections.filter(s => s.stage === SelectionStage.REJECTED);

    const handleDragStart = (e: React.DragEvent, selectionId: string) => {
        setDraggedId(selectionId);
        e.dataTransfer.effectAllowed = 'move';
    };

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
    };

    const handleDrop = async (e: React.DragEvent, targetStage: SelectionStage) => {
        e.preventDefault();
        if (!draggedId) return;

        const selection = selections.find(s => s.id === draggedId);
        if (!selection || selection.stage === targetStage) {
            setDraggedId(null);
            return;
        }

        try {
            // Optimistic update
            setSelections(prev => prev.map(s =>
                s.id === draggedId ? { ...s, stage: targetStage } : s
            ));

            await SelectionService.advanceStage(draggedId, targetStage);

            // If candidate reached OFFER_ACCEPTED, increment demand order filled count
            if (targetStage === SelectionStage.OFFER_ACCEPTED) {
                await DemandOrderService.incrementFilled(demandOrder.id);
            }

            // Reload strictly ensuring data consistency
            loadSelections(true);
            onRefresh();
        } catch (error) {
            console.error("Failed to update stage", error);
            // Revert on error would be ideal here
            loadSelections();
        } finally {
            setDraggedId(null);
        }
    };

    const handleAdvance = async (selection: CandidateSelection) => {
        const stageOrder = SelectionService.getStageOrder();
        const currentIndex = stageOrder.indexOf(selection.stage);
        if (currentIndex < stageOrder.length - 1) {
            const nextStage = stageOrder[currentIndex + 1];

            try {
                await SelectionService.advanceStage(selection.id, nextStage);

                if (nextStage === SelectionStage.OFFER_ACCEPTED) {
                    await DemandOrderService.incrementFilled(demandOrder.id);
                }

                if (detailPanel?.id === selection.id) {
                    const updated = await SelectionService.getById(selection.id);
                    setDetailPanel(updated || null);
                }
                loadSelections(true);
                onRefresh();
            } catch (error) {
                console.error("Failed to advance stage", error);
            }
        }
    };

    const handleReject = async () => {
        if (!rejectModal) return;
        try {
            await SelectionService.rejectCandidate(rejectModal.id, rejectReason);
            setRejectModal(null);
            setRejectReason('');
            if (detailPanel?.id === rejectModal.id) setDetailPanel(null);
            loadSelections();
            onRefresh();
        } catch (error) {
            console.error("Failed to reject candidate", error);
        }
    };

    const handleDeleteSelection = async (selection: CandidateSelection) => {
        if (!window.confirm(`Are you sure you want to remove "${selection.candidateName}" from this demand order? This will delete the matching record.`)) return;
        try {
            await SelectionService.delete(selection.id);
            if (detailPanel?.id === selection.id) setDetailPanel(null);
            loadSelections();
            onRefresh();
        } catch (error) {
            console.error("Failed to delete selection", error);
        }
    };

    const fillPercent = demandOrder.positionsRequired > 0
        ? Math.round((demandOrder.positionsFilled / demandOrder.positionsRequired) * 100)
        : 0;

    if (isLoading && selections.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center p-12 text-slate-400">
                <Loader className="animate-spin mb-2" size={24} />
                <p className="text-xs font-bold">Loading selections...</p>
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Header and UI components remain largely same, just ensuring no sync calls */}
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <button
                        onClick={onBack}
                        className="p-2 hover:bg-slate-100 rounded-xl transition-colors"
                    >
                        <ChevronLeft size={20} className="text-slate-500" />
                    </button>
                    <div>
                        <h3 className="text-lg font-bold text-slate-800">{demandOrder.title}</h3>
                        <p className="text-xs text-slate-500 mt-0.5">
                            {demandOrder.location}, {demandOrder.country} • {demandOrder.salaryRange}
                        </p>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    {/* Fill Progress */}
                    <div className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 rounded-xl">
                        <span className="text-[9px] font-bold text-slate-400 uppercase">Filled</span>
                        <span className="text-sm font-black text-slate-800">
                            {demandOrder.positionsFilled}/{demandOrder.positionsRequired}
                        </span>
                        <div className="w-20 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                            <div
                                className={`h-full rounded-full transition-all ${fillPercent >= 100 ? 'bg-green-500' : 'bg-blue-500'}`}
                                style={{ width: `${Math.min(fillPercent, 100)}%` }}
                            />
                        </div>
                    </div>
                    <button
                        onClick={onMatchCandidates}
                        className="px-4 py-2.5 bg-blue-600 text-white rounded-xl text-xs font-bold flex items-center gap-1.5 hover:bg-blue-700 shadow-lg shadow-blue-100 transition-all"
                    >
                        <Plus size={14} /> Match Candidates
                    </button>
                </div>
            </div>

            {/* Kanban Board */}
            <div className="overflow-x-auto pb-4">
                <div className="flex gap-4" style={{ minWidth: `${STAGE_COLUMNS.length * 220}px` }}>
                    {STAGE_COLUMNS.map(col => {
                        const columnSelections = activeSelections.filter(s => s.stage === col.stage);

                        return (
                            <div
                                key={col.stage}
                                className="flex-1 min-w-[200px]"
                                onDragOver={handleDragOver}
                                onDrop={(e) => handleDrop(e, col.stage)}
                            >
                                {/* Column Header */}
                                <div className={`${col.bgColor} rounded-t-2xl px-4 py-3 flex items-center justify-between border border-b-0 border-slate-200/50`}>
                                    <div className="flex items-center gap-2">
                                        <span className={col.color}>{col.icon}</span>
                                        <span className="text-xs font-bold text-slate-700">{col.label}</span>
                                    </div>
                                    <span className="w-6 h-6 bg-white rounded-full flex items-center justify-center text-[10px] font-black text-slate-600 shadow-sm">
                                        {columnSelections.length}
                                    </span>
                                </div>

                                {/* Column Body */}
                                <div className={`bg-slate-50/50 rounded-b-2xl border border-t-0 border-slate-200/50 p-2 space-y-2 min-h-[300px] transition-colors ${draggedId ? 'ring-2 ring-blue-100 ring-inset' : ''
                                    }`}>
                                    {columnSelections.map(sel => (
                                        <div
                                            key={sel.id}
                                            draggable
                                            onDragStart={(e) => handleDragStart(e, sel.id)}
                                            onClick={() => setDetailPanel(sel)}
                                            className={`bg-white rounded-xl border border-slate-100 p-3 cursor-pointer transition-all hover:shadow-md hover:border-blue-200 group ${detailPanel?.id === sel.id ? 'ring-2 ring-blue-200 border-blue-300' : ''
                                                } ${draggedId === sel.id ? 'opacity-50 scale-95' : ''}`}
                                        >
                                            <div className="flex items-start justify-between mb-2">
                                                <div className="flex items-center gap-2">
                                                    <GripVertical size={12} className="text-slate-300 cursor-grab" />
                                                    <div className="w-7 h-7 bg-blue-50 rounded-lg flex items-center justify-center text-blue-600 text-[10px] font-black">
                                                        {sel.candidateName.charAt(0)}
                                                    </div>
                                                </div>
                                                {sel.matchScore && (
                                                    <span className={`text-[8px] font-bold px-1.5 py-0.5 rounded ${sel.matchScore >= 80 ? 'bg-green-100 text-green-700' :
                                                        sel.matchScore >= 60 ? 'bg-amber-100 text-amber-700' :
                                                            'bg-red-100 text-red-700'
                                                        }`}>
                                                        {sel.matchScore}%
                                                    </span>
                                                )}
                                            </div>
                                            <p className="text-xs font-bold text-slate-800 leading-tight">{sel.candidateName}</p>
                                            <div className="flex items-center justify-between mt-2">
                                                <span className="text-[9px] text-slate-400">
                                                    {new Date(sel.updatedAt).toLocaleDateString()}
                                                </span>
                                                <div className="flex items-center gap-1.5 peer opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <button
                                                        onClick={(e) => { e.stopPropagation(); handleDeleteSelection(sel); }}
                                                        className="p-1 bg-red-50 text-red-600 rounded-lg hover:bg-red-100 transition-all"
                                                        title="Remove from board"
                                                    >
                                                        <Trash2 size={12} />
                                                    </button>
                                                    <button
                                                        onClick={(e) => { e.stopPropagation(); handleAdvance(sel); }}
                                                        className="p-1 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-100 transition-all"
                                                        title="Advance to next stage"
                                                    >
                                                        <ArrowRight size={12} />
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Rejected Section */}
            {rejectedSelections.length > 0 && (
                <div className="bg-red-50/50 rounded-2xl border border-red-100 p-4">
                    <h4 className="text-xs font-bold text-red-600 uppercase tracking-widest mb-3 flex items-center gap-2">
                        <XCircle size={14} /> Rejected ({rejectedSelections.length})
                    </h4>
                    <div className="flex flex-wrap gap-2">
                        {rejectedSelections.map(sel => (
                            <div key={sel.id} className="bg-white px-3 py-2 rounded-xl border border-red-100 text-xs">
                                <span className="font-bold text-slate-700">{sel.candidateName}</span>
                                {sel.rejectionReason && (
                                    <span className="text-slate-400 ml-2">— {sel.rejectionReason}</span>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Detail Side Panel - Mostly display, but Advance/Reject uses async handlers now */}
            {detailPanel && (
                <div className="fixed right-0 top-0 h-full w-96 bg-white shadow-2xl border-l border-slate-200 z-50 overflow-y-auto animate-in slide-in-from-right duration-300">
                    <div className="sticky top-0 bg-white/95 backdrop-blur border-b border-slate-100 px-6 py-4 flex items-center justify-between z-10">
                        <h3 className="text-sm font-bold text-slate-800">Candidate Details</h3>
                        <button onClick={() => setDetailPanel(null)} className="p-1 hover:bg-slate-100 rounded-lg transition-colors">
                            <X size={18} className="text-slate-400" />
                        </button>
                    </div>
                    <div className="p-6 space-y-6">
                        {/* Candidate Header */}
                        <div className="flex items-center gap-4">
                            <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-white text-xl font-black">
                                {detailPanel.candidateName.charAt(0)}
                            </div>
                            <div>
                                <p className="text-lg font-bold text-slate-800">{detailPanel.candidateName}</p>
                                <p className="text-xs text-slate-500">ID: {detailPanel.candidateId}</p>
                            </div>
                        </div>

                        {/* Current Stage */}
                        <div className="bg-blue-50 rounded-xl p-4 border border-blue-100">
                            <p className="text-[9px] font-bold text-blue-500 uppercase tracking-widest">Current Stage</p>
                            <p className="text-sm font-bold text-blue-800 mt-1">{detailPanel.stage}</p>
                        </div>

                        {/* Match Score */}
                        {detailPanel.matchScore && (
                            <div className="bg-slate-50 rounded-xl p-4 border border-slate-100">
                                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Match Score</p>
                                <div className="flex items-center gap-3 mt-2">
                                    <div className="flex-1 h-2 bg-slate-200 rounded-full overflow-hidden">
                                        <div
                                            className={`h-full rounded-full ${detailPanel.matchScore >= 80 ? 'bg-green-500' :
                                                detailPanel.matchScore >= 60 ? 'bg-amber-500' :
                                                    'bg-red-500'
                                                }`}
                                            style={{ width: `${detailPanel.matchScore}%` }}
                                        />
                                    </div>
                                    <span className="text-sm font-black text-slate-800">{detailPanel.matchScore}%</span>
                                </div>
                            </div>
                        )}

                        {/* Interview Details */}
                        {detailPanel.interviewDate && (
                            <div className="bg-amber-50 rounded-xl p-4 border border-amber-100">
                                <p className="text-[9px] font-bold text-amber-500 uppercase tracking-widest">Interview</p>
                                <div className="mt-2 space-y-1">
                                    <p className="text-xs text-slate-700 flex items-center gap-2">
                                        <Clock size={12} /> {new Date(detailPanel.interviewDate).toLocaleDateString()}
                                    </p>
                                    {detailPanel.interviewType && (
                                        <p className="text-xs text-slate-700 flex items-center gap-2">
                                            {detailPanel.interviewType === 'Video' ? <Video size={12} /> : <Phone size={12} />}
                                            {detailPanel.interviewType}
                                        </p>
                                    )}
                                </div>
                            </div>
                        )}

                        {/* Interview Notes */}
                        {detailPanel.interviewNotes && (
                            <div>
                                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-2">Interview Notes</p>
                                <p className="text-xs text-slate-600 bg-slate-50 p-3 rounded-xl border border-slate-100">{detailPanel.interviewNotes}</p>
                            </div>
                        )}

                        {/* Employer Feedback */}
                        {detailPanel.employerFeedback && (
                            <div>
                                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-2 flex items-center gap-1">
                                    <MessageSquare size={10} /> Employer Feedback
                                </p>
                                <p className="text-xs text-slate-600 bg-slate-50 p-3 rounded-xl border border-slate-100">{detailPanel.employerFeedback}</p>
                            </div>
                        )}

                        {/* Actions */}
                        <div className="pt-4 border-t border-slate-100 space-y-2">
                            {detailPanel.stage !== SelectionStage.OFFER_ACCEPTED && detailPanel.stage !== SelectionStage.REJECTED && (
                                <>
                                    <button
                                        onClick={() => handleAdvance(detailPanel)}
                                        className="w-full py-3 bg-blue-600 text-white rounded-xl text-sm font-bold hover:bg-blue-700 transition-all flex items-center justify-center gap-2"
                                    >
                                        <ArrowRight size={16} /> Advance Stage
                                    </button>
                                    <button
                                        onClick={() => setRejectModal(detailPanel)}
                                        className="w-full py-3 bg-red-50 text-red-600 rounded-xl text-sm font-bold hover:bg-red-100 transition-all flex items-center justify-center gap-2"
                                    >
                                        <XCircle size={16} /> Reject Candidate
                                    </button>
                                    <button
                                        onClick={() => handleDeleteSelection(detailPanel)}
                                        className="w-full py-3 bg-slate-50 text-slate-400 rounded-xl text-sm font-bold hover:bg-red-50 hover:text-red-500 transition-all flex items-center justify-center gap-2"
                                    >
                                        <Trash2 size={16} /> Delete Selection Record
                                    </button>
                                </>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* Reject Modal - uses async submit */}
            {rejectModal && (
                <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
                    <div className="bg-white rounded-2xl shadow-2xl max-w-md w-full p-6 space-y-4">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-red-50 text-red-600 rounded-xl">
                                <XCircle size={20} />
                            </div>
                            <div>
                                <h3 className="text-sm font-bold text-slate-800">Reject {rejectModal.candidateName}</h3>
                                <p className="text-xs text-slate-500">This removes the candidate from the selection pipeline</p>
                            </div>
                        </div>
                        <textarea
                            rows={3}
                            placeholder="Reason for rejection (optional)..."
                            className="w-full px-4 py-3 border border-slate-200 rounded-xl text-sm outline-none focus:ring-2 focus:ring-red-100"
                            value={rejectReason}
                            onChange={e => setRejectReason(e.target.value)}
                        />
                        <div className="flex gap-3">
                            <button
                                onClick={() => { setRejectModal(null); setRejectReason(''); }}
                                className="flex-1 py-2.5 bg-slate-100 text-slate-700 rounded-xl text-sm font-bold hover:bg-slate-200 transition-all"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={handleReject}
                                className="flex-1 py-2.5 bg-red-600 text-white rounded-xl text-sm font-bold hover:bg-red-700 transition-all"
                            >
                                Confirm Reject
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default SelectionBoard;

/**
 * ProfileAdminSection
 * Extracted from CandidateDetail.tsx — Administrative Details (View + Edit)
 * Handles address, province, district, divisional secretariat, GS division.
 */
import React from 'react';
import { Candidate } from '../../types';
import { MapPin } from 'lucide-react';

interface Props {
    candidate: Candidate;
    isEditing: boolean;
    editedProfile: Partial<Candidate>;
    setEditedProfile: React.Dispatch<React.SetStateAction<Partial<Candidate>>>;
}

const ProfileAdminSection: React.FC<Props> = ({
    candidate,
    isEditing,
    editedProfile,
    setEditedProfile,
}) => {
    const Field = ({ label, value, editValue, onChange, colSpan }: {
        label: string;
        value: string;
        editValue: string;
        onChange: (val: string) => void;
        colSpan?: number;
    }) => (
        <div className={colSpan === 2 ? 'col-span-1 md:col-span-2' : ''}>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">{label}</label>
            {isEditing ? (
                <input
                    type="text"
                    value={editValue}
                    onChange={(e) => onChange(e.target.value)}
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
                />
            ) : (
                <div className="p-2.5 bg-slate-50 rounded-lg text-sm font-medium text-slate-900 border border-slate-200/50">
                    {value || '-'}
                </div>
            )}
        </div>
    );

    return (
        <section className="mt-8 pt-8 border-t border-slate-100">
            <h3 className="text-base font-bold text-slate-800 tracking-tight mb-5 flex items-center gap-2">
                <MapPin size={18} className="text-indigo-500" />
                Administrative Details
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                <Field
                    label="Address"
                    value={candidate?.personalInfo?.address || candidate?.address || '-'}
                    editValue={editedProfile.personalInfo?.address || ''}
                    onChange={(val) => setEditedProfile({
                        ...editedProfile,
                        personalInfo: { ...editedProfile.personalInfo!, address: val }
                    })}
                    colSpan={2}
                />
                <Field
                    label="Province"
                    value={candidate?.personalInfo?.province || candidate?.province || '-'}
                    editValue={editedProfile.personalInfo?.province || ''}
                    onChange={(val) => setEditedProfile({
                        ...editedProfile,
                        personalInfo: { ...editedProfile.personalInfo!, province: val }
                    })}
                />
                <Field
                    label="District"
                    value={candidate?.personalInfo?.district || candidate?.district || '-'}
                    editValue={editedProfile.personalInfo?.district || ''}
                    onChange={(val) => setEditedProfile({
                        ...editedProfile,
                        personalInfo: { ...editedProfile.personalInfo!, district: val }
                    })}
                />
                <Field
                    label="Divisional Secretariat"
                    value={candidate?.personalInfo?.divisionalSecretariat || (candidate as any)?.divisionalSecretariat || '-'}
                    editValue={editedProfile.personalInfo?.divisionalSecretariat || ''}
                    onChange={(val) => setEditedProfile({
                        ...editedProfile,
                        personalInfo: { ...editedProfile.personalInfo!, divisionalSecretariat: val }
                    })}
                />
                <Field
                    label="GS Division"
                    value={candidate?.personalInfo?.gsDivision || (candidate as any)?.gsDivision || '-'}
                    editValue={editedProfile.personalInfo?.gsDivision || ''}
                    onChange={(val) => setEditedProfile({
                        ...editedProfile,
                        personalInfo: { ...editedProfile.personalInfo!, gsDivision: val }
                    })}
                />
            </div>
        </section>
    );
};

export default ProfileAdminSection;

/**
 * ProfilePassportSection
 * Extracted from CandidateDetail.tsx — Passport Bio Page (View + Edit)
 * Handles passport data display in Sri Lankan passport layout format,
 * including MRZ zone rendering, and inline editing of all passport fields.
 */
import React from 'react';
import { Candidate, PassportStatus } from '../../types';
import { ComplianceService } from '../../services/complianceService';
import { generateMRZ } from '../../utils/mrzGenerator';
import { ShieldCheck, ShieldAlert } from 'lucide-react';

interface Props {
    candidate: Candidate;
    isEditing: boolean;
    editedProfile: Partial<Candidate>;
    setEditedProfile: React.Dispatch<React.SetStateAction<Partial<Candidate>>>;
}

const ProfilePassportSection: React.FC<Props> = ({
    candidate,
    isEditing,
    editedProfile,
    setEditedProfile,
}) => {
    return (
        <section>
            <h3 className="text-base font-bold text-slate-800 tracking-tight mb-5 flex items-center gap-2">
                <ShieldCheck size={18} className="text-blue-500" />
                Passport Data
            </h3>

            {isEditing ? (
                <div className="bg-slate-50 p-5 rounded-xl border border-slate-200 space-y-4">
                    {/* Row 1: Type, Country Code, Passport No */}
                    <div className="grid grid-cols-3 gap-4">
                        <div>
                            <label className="block text-xs font-medium text-slate-500 mb-0.5">Type</label>
                            <input type="text" value="PB" disabled className="w-full px-3 py-2 border border-slate-200 rounded-lg text-sm bg-slate-100 text-slate-500 font-mono" />
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-slate-500 mb-0.5">Country Code</label>
                            <input type="text" value="LKA" disabled className="w-full px-3 py-2 border border-slate-200 rounded-lg text-sm bg-slate-100 text-slate-500 font-mono" />
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-slate-500 mb-0.5">Passport No.</label>
                            <input
                                type="text"
                                value={(editedProfile.passports || [])[0]?.passportNumber || ''}
                                onChange={(e) => {
                                    const passports = [...(editedProfile.passports || [{ passportNumber: '', country: 'Sri Lanka', issuedDate: '', expiryDate: '', status: PassportStatus.VALID, validityDays: 0 }])];
                                    passports[0] = { ...passports[0], passportNumber: e.target.value.toUpperCase() };
                                    setEditedProfile({ ...editedProfile, passports });
                                }}
                                className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 font-mono font-bold"
