                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <div className="text-xs text-blue-200 uppercase">Passport No.</div>
                                        <div className="text-sm font-bold text-amber-300 font-mono tracking-wider">{passport.passportNumber || '-'}</div>
                                    </div>
