import React from 'react';
import { Candidate, AdvancePayment, AdvancePaymentType } from '../../types';
import { Trash2, Plus } from 'lucide-react';

interface FinancialLedgerWidgetProps {
    candidate: Candidate;
    isEditing?: boolean;
    onUpdate?: (payments: AdvancePayment[], usdRateEmb?: number, usdRateFA?: number) => void;
}

const DEFAULT_ROWS: string[] = [
    'Register Fee',
    'Offer',
    'Work Permit',
    'Embassy USD',
    'Balance Pay',
    'Ticket',
    'Deposit',
    'Other'
];

const FinancialLedgerWidget: React.FC<FinancialLedgerWidgetProps> = ({
    candidate,
    isEditing = false,
    onUpdate
}) => {
    const payments = candidate.advancePayments || [];
    const customTypes = payments
        .filter(p => !DEFAULT_ROWS.includes(p.type))
        .map(p => p.type);

    const allTypes = Array.from(new Set([...DEFAULT_ROWS, ...customTypes]));

    const totalAmount = payments.reduce((sum, p) => sum + (Number(p.amount) || 0), 0);

    const handleUpdatePayment = (type: string, field: keyof AdvancePayment, value: any) => {
        if (!onUpdate) return;
        const all = [...payments];
        const existIdx = all.findIndex(p => p.type === type);

        const paymentToUpdate = existIdx >= 0 ? { ...all[existIdx] } : { id: `adv-${Date.now()}-${type}`, type: type as AdvancePaymentType };

        // Special mapping for dates vs booleans if needed, but keeping the original string structure
        (paymentToUpdate as any)[field] = value;

        if (field === 'informedDate' && value) {
            paymentToUpdate.informed = true;
        }

        if (existIdx >= 0) {
            all[existIdx] = paymentToUpdate;
        } else {
            all.push(paymentToUpdate);
        }

        onUpdate(all, candidate.usdRateEmb, candidate.usdRateFA);
    };

    const handleDeleteCustom = (type: string) => {
        if (!onUpdate) return;
        const all = payments.filter(p => p.type !== type);
        onUpdate(all, candidate.usdRateEmb, candidate.usdRateFA);
    };

    const handleAddCustom = () => {
        const newType = window.prompt("Enter new custom payment type:");
        if (newType && newType.trim()) {
            const trimmed = newType.trim();
            if (!allTypes.find(t => t.toLowerCase() === trimmed.toLowerCase())) {
                const all = [...payments, { type: trimmed as AdvancePaymentType, id: `adv-${Date.now()}` }];
                if (onUpdate) onUpdate(all, candidate.usdRateEmb, candidate.usdRateFA);
            } else {
                alert('This payment type already exists.');
            }
        }
    };

    const handleUsdRateEmbChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (!onUpdate) return;
        onUpdate(payments, e.target.value ? parseFloat(e.target.value) : undefined, candidate.usdRateFA);
    };

    const handleUsdRateFAChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (!onUpdate) return;
        onUpdate(payments, candidate.usdRateEmb, e.target.value ? parseFloat(e.target.value) : undefined);
    };

    return (
        <div className="w-full">
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider flex items-center gap-2">
                    <span className="w-6 h-1 bg-green-500 rounded-full"></span>
                    Advance Payment Tracking
                </h3>
                <div className="text-xs font-bold text-slate-500 bg-white px-3 py-1.5 rounded-lg border border-slate-200 shadow-sm flex items-center gap-2">
                    Total Paid:
                    <span className="text-green-600 text-sm">
                        Rs. {totalAmount.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                    </span>
                </div>
            </div>

            {isEditing ? (
                <div className="bg-green-50/50 p-6 rounded-xl border border-green-200 border-dashed">
                    <div className="overflow-x-auto">
                        <table className="w-full text-xs">
                            <thead>
                                <tr className="border-b-2 border-green-200">
                                    <th className="text-left py-2 px-2 font-bold text-slate-600 uppercase">#</th>
                                    <th className="text-left py-2 px-2 font-bold text-slate-600 uppercase">Payment Type</th>
                                    <th className="text-left py-2 px-2 font-bold text-slate-600 uppercase">Informed</th>
                                    <th className="text-left py-2 px-2 font-bold text-slate-600 uppercase">Sign Date</th>
                                    <th className="text-left py-2 px-2 font-bold text-slate-600 uppercase">Invoice No</th>
                                    <th className="text-left py-2 px-2 font-bold text-slate-600 uppercase">Amount (Rs)</th>
                                    <th className="text-left py-2 px-2 font-bold text-slate-600 uppercase">Remarks</th>
                                </tr>
                            </thead>
                            <tbody>
                                {allTypes.map((type, idx) => {
                                    const payment = payments.find(p => p.type === type) || {} as Partial<AdvancePayment>;
                                    const isDefault = DEFAULT_ROWS.includes(type);

                                    return (
                                        <tr key={type} className="border-b border-green-100 hover:bg-green-50/50">
                                            <td className="py-2 px-2 font-bold text-slate-500">{idx + 1}</td>
                                            <td className="py-2 px-2 font-bold text-slate-700">{type}</td>
                                            <td className="py-2 px-2">
                                                <input
                                                    type="date"
                                                    value={payment.informedDate || ''}
                                                    onChange={(e) => handleUpdatePayment(type, 'informedDate', e.target.value)}
                                                    className="w-full px-1.5 py-1 border border-slate-300 rounded text-xs focus:outline-none focus:ring-1 focus:ring-green-500"
                                                />
                                            </td>
                                            <td className="py-2 px-2">
                                                <input
                                                    type="date"
                                                    value={payment.signDate || ''}
                                                    onChange={(e) => handleUpdatePayment(type, 'signDate', e.target.value)}
                                                    className="w-full px-1.5 py-1 border border-slate-300 rounded text-xs focus:outline-none focus:ring-1 focus:ring-green-500"
                                                />
                                            </td>
                                            <td className="py-2 px-2">
                                                <input
                                                    type="text"
                                                    value={payment.invoiceNo || ''}
                                                    onChange={(e) => handleUpdatePayment(type, 'invoiceNo', e.target.value)}
                                                    placeholder="Inv#"
                                                    className="w-full px-1.5 py-1 border border-slate-300 rounded text-xs focus:outline-none focus:ring-1 focus:ring-green-500"
                                                />
                                            </td>
                                            <td className="py-2 px-2">
                                                <input
                                                    type="number"
                                                    value={payment.amount || ''}
                                                    onChange={(e) => handleUpdatePayment(type, 'amount', e.target.value ? parseFloat(e.target.value) : undefined)}
                                                    placeholder="0"
                                                    className="w-full px-1.5 py-1 border border-slate-300 rounded text-xs focus:outline-none focus:ring-1 focus:ring-green-500"
                                                />
                                            </td>
                                            <td className="py-2 px-2 flex gap-1 items-center">
                                                <input
                                                    type="text"
                                                    value={payment.remarks || ''}
                                                    onChange={(e) => handleUpdatePayment(type, 'remarks', e.target.value)}
                                                    placeholder="Notes..."
                                                    className="w-full px-1.5 py-1 border border-slate-300 rounded text-xs focus:outline-none focus:ring-1 focus:ring-green-500"
                                                />
                                                {!isDefault && (
                                                    <button
                                                        type="button"
                                                        className="text-red-400 hover:text-red-600 p-1 flex-shrink-0"
                                                        onClick={() => handleDeleteCustom(type)}
                                                        title="Delete custom payment type"
                                                    >
                                                        <Trash2 size={12} />
                                                    </button>
                                                )}
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>

                    <div className="mt-3 flex justify-end">
                        <button
                            type="button"
                            className="flex items-center gap-1.5 text-xs font-bold text-green-700 hover:text-green-800 bg-green-100 hover:bg-green-200 px-3 py-1.5 rounded-lg transition-colors"
                            onClick={handleAddCustom}
                        >
                            <Plus size={14} /> Add Custom Payment
                        </button>
                    </div>

                    <div className="mt-4 grid grid-cols-2 gap-4 pt-3 border-t border-green-200">
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">USD Rate EMB</label>
                            <input
                                type="number"
                                step="0.01"
                                value={candidate.usdRateEmb ?? ''}
                                onChange={handleUsdRateEmbChange}
                                className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm focus:outline-none focus:ring-1 focus:ring-green-500"
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">USD Rate F/A</label>
                            <input
                                type="number"
                                step="0.01"
                                value={candidate.usdRateFA ?? ''}
                                onChange={handleUsdRateFAChange}
                                className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm focus:outline-none focus:ring-1 focus:ring-green-500"
                            />
                        </div>
                    </div>
                </div>
            ) : (
                <div className="bg-green-50/30 p-5 rounded-xl border border-green-100">
                    <div className="overflow-x-auto">
                        <table className="w-full text-xs">
                            <thead>
                                <tr className="border-b-2 border-green-200">
                                    <th className="text-left py-2 px-2 font-bold text-slate-600 uppercase">#</th>
                                    <th className="text-left py-2 px-2 font-bold text-slate-600 uppercase">Type</th>
                                    <th className="text-left py-2 px-2 font-bold text-slate-600 uppercase">Informed</th>
                                    <th className="text-left py-2 px-2 font-bold text-slate-600 uppercase">Sign Date</th>
                                    <th className="text-left py-2 px-2 font-bold text-slate-600 uppercase">Invoice</th>
                                    <th className="text-right py-2 px-2 font-bold text-slate-600 uppercase">Amount</th>
                                    <th className="text-left py-2 px-2 font-bold text-slate-600 uppercase">Remarks</th>
                                </tr>
                            </thead>
                            <tbody>
                                {allTypes.map((type, idx) => {
                                    const payment = payments.find(p => p.type === type);
                                    const hasData = payment && (payment.amount || payment.invoiceNo || payment.informedDate || payment.signDate || payment.remarks);

                                    // Optionally hide purely empty rows in read-only to save space, like the previous iteration.
                                    // But the original component from the screenshot left them all visible to act as an actual checklist/ledger!
                                    // I will leave them visible to match the user's preference for the exact old view.
                                    return (
                                        <tr key={type} className={`border-b border-green-100 ${hasData ? 'bg-green-50/50' : ''}`}>
                                            <td className="py-2 px-2 font-bold text-slate-400">{idx + 1}</td>
                                            <td className="py-2 px-2 font-bold text-slate-700">{type}</td>
                                            <td className="py-2 px-2 text-slate-600">{payment?.informedDate ? new Date(payment.informedDate).toLocaleDateString() : '-'}</td>
                                            <td className="py-2 px-2 text-slate-600">{payment?.signDate ? new Date(payment.signDate).toLocaleDateString() : '-'}</td>
                                            <td className="py-2 px-2 font-mono text-slate-600">{payment?.invoiceNo || '-'}</td>
                                            <td className="py-2 px-2 text-right font-bold text-green-700">{payment?.amount !== undefined ? `Rs. ${payment.amount.toLocaleString()}` : '-'}</td>
                                            <td className="py-2 px-2 text-slate-500 italic">{payment?.remarks || '-'}</td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                    {(candidate.usdRateEmb !== undefined || candidate.usdRateFA !== undefined) && (
                        <div className="mt-3 pt-3 border-t border-green-100 flex gap-6 text-xs">
                            {candidate.usdRateEmb !== undefined && (
                                <div><span className="font-bold text-slate-500 uppercase">USD Rate EMB:</span> <span className="font-bold text-slate-800 ml-1">{candidate.usdRateEmb}</span></div>
                            )}
                            {candidate.usdRateFA !== undefined && (
                                <div><span className="font-bold text-slate-500 uppercase">USD Rate F/A:</span> <span className="font-bold text-slate-800 ml-1">{candidate.usdRateFA}</span></div>
                            )}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default FinancialLedgerWidget;

import React from 'react';
import { FileEdit, Calendar, MessageCircle, Briefcase, FileText, Trash2, RefreshCw, Zap } from 'lucide-react';
import { Candidate, ProfileCompletionStatus } from '../../types';
import { Link } from 'react-router-dom';
import WorkflowEngine from '../../services/workflowEngine';
import { useAuth } from '../../context/AuthContext';

interface QuickActionsWidgetProps {
    candidate: Candidate;
    onDelete?: () => void;
    onGenerateReport?: () => void;
    isGeneratingReport?: boolean;
}

import { usePermission } from '../../hooks/usePermission';

const QuickActionsWidget: React.FC<QuickActionsWidgetProps> = ({
    candidate,
    onDelete,
    onGenerateReport,
    isGeneratingReport = false
}) => {
    const { hasPermission } = usePermission();

    const actions = [];

    // Check policies for common actions
    const schedulePolicy = WorkflowEngine.canPerformAction(candidate, 'SCHEDULE_INTERVIEW');
    const assignPolicy = WorkflowEngine.canPerformAction(candidate, 'ASSIGN_TO_JOB');
    const deletePolicy = WorkflowEngine.canPerformAction(candidate, 'DELETE');

    // Complete Profile action (for incomplete profiles)
    if (candidate.profileCompletionStatus !== ProfileCompletionStatus.COMPLETE) {
        actions.push({
            id: 'complete_profile',
            icon: FileEdit,
            label: 'Complete Profile',
            description: 'Fill in missing information',
            color: 'orange',
            link: `/applications/new?upgrade=${candidate.id}`,
            allowed: true
        });
    }


    // Send Message
    actions.push({
        id: 'send_message',
        icon: MessageCircle,
        label: 'Send Message',
        description: 'Email or SMS to candidate',
        color: 'emerald',
        allowed: true,
        onClick: () => alert('Messaging coming soon!')
    });

    // Assign to Job
    actions.push({
        id: 'assign_job',
        icon: Briefcase,
        label: 'Assign to Job',
        description: assignPolicy.allowed ? 'Match with available position' : assignPolicy.reason,
        color: 'purple',
        allowed: assignPolicy.allowed,
        onClick: () => alert('Job assignment coming soon!')
    });

    // Generate Report
    actions.push({
        id: 'generate_report',
        icon: isGeneratingReport ? RefreshCw : FileText,
        label: isGeneratingReport ? 'Generating...' : 'Generate Report',
        description: isGeneratingReport ? 'Preparing PDF summary...' : 'Create PDF summary',
        color: 'indigo',
        allowed: !isGeneratingReport,
        onClick: onGenerateReport || (() => alert('Report generation coming soon!'))
    });

    const getColorStyle = (color: string, allowed: boolean) => {
        if (!allowed) {
            return {
                button: 'w-full text-left p-2.5 rounded-xl border border-slate-200 bg-slate-50 text-slate-400 cursor-not-allowed opacity-70 flex items-center gap-3',
                icon: 'p-2 rounded-lg bg-slate-100 text-slate-400',
                title: 'text-sm font-semibold text-slate-500',
                subtitle: 'text-xs font-medium text-slate-400 mt-0.5 whitespace-nowrap overflow-hidden text-ellipsis'
            };
        }

        const baseButton = 'w-full text-left p-2.5 rounded-xl border flex items-center gap-3 transition-colors peer hover:z-10 bg-white ring-1 ring-transparent';
        const baseIcon = 'p-2 rounded-lg transition-colors flex-shrink-0';

        switch (color) {
            case 'orange':
                return {
                    button: `${baseButton} border-orange-100 hover:border-orange-300 hover:bg-orange-50/50 hover:ring-orange-100`,
                    icon: `${baseIcon} bg-orange-50 text-orange-600`,
                    title: 'text-sm font-semibold text-orange-900',
                    subtitle: 'text-xs font-medium text-orange-700 mt-0.5 whitespace-nowrap overflow-hidden text-ellipsis'
                };
            case 'blue':
                return {
                    button: `${baseButton} border-blue-100 hover:border-blue-300 hover:bg-blue-50/50 hover:ring-blue-100`,
                    icon: `${baseIcon} bg-blue-50 text-blue-600`,
                    title: 'text-sm font-semibold text-blue-900',
                    subtitle: 'text-xs font-medium text-blue-700 mt-0.5 whitespace-nowrap overflow-hidden text-ellipsis'
                };
            case 'emerald':
                return {
                    button: `${baseButton} border-emerald-100 hover:border-emerald-300 hover:bg-emerald-50/50 hover:ring-emerald-100`,
                    icon: `${baseIcon} bg-emerald-50 text-emerald-600`,
                    title: 'text-sm font-semibold text-emerald-900',
                    subtitle: 'text-xs font-medium text-emerald-700 mt-0.5 whitespace-nowrap overflow-hidden text-ellipsis'
                };
            case 'purple':
                return {
                    button: `${baseButton} border-purple-100 hover:border-purple-300 hover:bg-purple-50/50 hover:ring-purple-100`,
                    icon: `${baseIcon} bg-purple-50 text-purple-600`,
                    title: 'text-sm font-semibold text-purple-900',
                    subtitle: 'text-xs font-medium text-purple-700 mt-0.5 whitespace-nowrap overflow-hidden text-ellipsis'
                };
            case 'indigo':
                return {
                    button: `${baseButton} border-indigo-100 hover:border-indigo-300 hover:bg-indigo-50/50 hover:ring-indigo-100`,
                    icon: `${baseIcon} bg-indigo-50 text-indigo-600`,
                    title: 'text-sm font-semibold text-indigo-900',
                    subtitle: 'text-xs font-medium text-indigo-700 mt-0.5 whitespace-nowrap overflow-hidden text-ellipsis'
                };
            case 'red':
                return {
                    button: `${baseButton} border-red-100 hover:border-red-300 hover:bg-red-50/50 hover:ring-red-100`,
                    icon: `${baseIcon} bg-red-50 text-red-600`,
                    title: 'text-sm font-semibold text-red-900',
                    subtitle: 'text-xs font-medium text-red-700 mt-0.5 whitespace-nowrap overflow-hidden text-ellipsis'
                };
            default:
                return {
                    button: `${baseButton} border-slate-200 hover:border-slate-300 hover:bg-slate-50/50 hover:ring-slate-100`,
                    icon: `${baseIcon} bg-slate-50 text-slate-600`,
                    title: 'text-sm font-semibold text-slate-900',
                    subtitle: 'text-xs font-medium text-slate-500 mt-0.5 whitespace-nowrap overflow-hidden text-ellipsis'
                };
        }
    };

    return (
        <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
            {/* Header */}
            <div className="px-6 py-5 flex items-center justify-between border-b border-slate-100">
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl bg-slate-50 border border-slate-100 flex items-center justify-center">
                        <Zap size={18} className="text-blue-500" />
                    </div>
                    <div>
                        <h3 className="text-base font-bold text-slate-900 tracking-tight">Quick Actions</h3>
                        <p className="text-xs text-slate-500 font-medium mt-0.5">
                            Common operations
                        </p>
                    </div>
                </div>
            </div>

            {/* Content */}
            <div className="px-6 py-5 space-y-3">
                {actions.map((action) => {
                    const style = getColorStyle(action.color, action.allowed);
                    const Icon = action.icon;
                    const isGenerating = isGeneratingReport && action.id === 'generate_report';

                    const content = (
                        <>
                            <div className={style.icon}>
                                <Icon size={18} className={isGenerating ? "animate-spin" : ""} strokeWidth={2.5} />
                            </div>
                            <div className="flex-1 min-w-0">
                                <div className={style.title}>{action.label}</div>
                                <div className={style.subtitle} title={action.description}>{action.description}</div>
                            </div>
                        </>
                    );

                    if (action.link && action.allowed) {
                        return (
                            <Link
                                key={`action-${action.id}`}
                                to={action.link}
                                className={style.button}
                            >
                                {content}
                            </Link>
                        );
                    }

                    return (
                        <button
                            key={`action-${action.id}`}
                            onClick={action.allowed ? action.onClick : undefined}
                            disabled={!action.allowed}
                            className={style.button}
                        >
                            {content}
                        </button>
                    );
                })}

                {/* Delete Action (Admins or those with candidate.delete permission) */}
                {hasPermission('candidates.delete') && onDelete && (() => {
                    const style = getColorStyle('red', deletePolicy.allowed);
                    return (
                        <div className="pt-2"> {/* Tiny separator gap for destructive action */}
                            <button
                                onClick={deletePolicy.allowed ? onDelete : undefined}
                                disabled={!deletePolicy.allowed}
                                className={style.button}
                            >
                                <div className={style.icon}>
                                    <Trash2 size={18} strokeWidth={2.5} />
                                </div>
                                <div className="flex-1 min-w-0 text-left">
                                    <div className={style.title}>Delete Candidate</div>
                                    <div className={style.subtitle} title={deletePolicy.allowed ? 'Permanently remove profile' : deletePolicy.reason}>
                                        {deletePolicy.allowed ? 'Permanently remove' : deletePolicy.reason}
                                    </div>
                                </div>
                            </button>
                        </div>
                    )
                })()}
            </div>
        </div>
    );
};

export default QuickActionsWidget;

import React from 'react';
import { Candidate, WorkflowStage } from '../../types';
import { Check, Circle, AlertCircle, FastForward, RotateCcw } from 'lucide-react';
import WorkflowEngine, { WORKFLOW_STAGES } from '../../services/workflowEngine.v2';

interface WorkflowProgressWidgetProps {
    candidate: Candidate;
    onStageClick?: (stage: WorkflowStage) => void;
    onAdvance?: (forceOverride?: boolean) => void;
    onRollback?: (stage: WorkflowStage, reason: string) => void;
}

const STAGE_LABELS: Record<WorkflowStage, string> = {
    [WorkflowStage.REGISTERED]: 'Registration',
    [WorkflowStage.VERIFIED]: 'Verification',
    [WorkflowStage.APPLIED]: 'Applied',
    [WorkflowStage.OFFER_RECEIVED]: 'Offer Received',
    [WorkflowStage.WP_RECEIVED]: 'WP Received',
    [WorkflowStage.EMBASSY_APPLIED]: 'Embassy Applied',
    [WorkflowStage.VISA_RECEIVED]: 'Visa Received',
    [WorkflowStage.SLBFE_REGISTRATION]: 'SLBFE Registration',
    [WorkflowStage.TICKET_ISSUED]: 'Ticket Issued',
    [WorkflowStage.DEPARTED]: 'Departure'
};

const STAGE_MILESTONE_KEYS: Partial<Record<WorkflowStage, string>> = {
    [WorkflowStage.VERIFIED]: 'verifiedDate',
    [WorkflowStage.APPLIED]: 'offerAppliedDate',
    [WorkflowStage.OFFER_RECEIVED]: 'offerReceivedDate',
    [WorkflowStage.WP_RECEIVED]: 'wpReceivedDate',
    [WorkflowStage.EMBASSY_APPLIED]: 'embAppliedDate',
    [WorkflowStage.VISA_RECEIVED]: 'stampRejectDate',
    [WorkflowStage.SLBFE_REGISTRATION]: 'slbfeRegistrationDate',
    [WorkflowStage.TICKET_ISSUED]: 'ticketIssuedDate',
    [WorkflowStage.DEPARTED]: 'departureDate'
};

const WorkflowProgressWidget: React.FC<WorkflowProgressWidgetProps> = ({ candidate, onStageClick, onAdvance, onRollback }) => {
    const stages = WORKFLOW_STAGES.map(stage => ({
        stage,
        label: STAGE_LABELS[stage]
    }));

    const currentStageIndex = stages.findIndex(s => s.stage === candidate.stage);
    const nextStage = currentStageIndex < stages.length - 1 ? stages[currentStageIndex + 1].stage : null;

    // Live validation for the next stage
    const validation = nextStage ? WorkflowEngine.validateTransition(candidate, nextStage) : null;
    const hasBlockers = !!(validation && !validation.allowed);

    const getStageStatus = (index: number) => {
        if (index < currentStageIndex) return 'completed';
        if (index === currentStageIndex) return 'current';
        return 'upcoming';
    };

    return (
        <div className="bg-white rounded-lg border border-slate-200 shadow-sm">
            {/* Header */}
            <div className="px-4 py-3 flex flex-col gap-3 border-b border-slate-100 bg-slate-50 border-b border-slate-200">
                <div className="flex items-center justify-between">
                    <h3 className="text-sm font-semibold text-slate-800 flex items-center gap-2">
                        <FastForward size={14} className="text-blue-500" />
                        Workflow Progress
                    </h3>
                    {nextStage && (
                        <div className="text-xs font-medium bg-white border border-slate-200 text-slate-600 px-2 py-1 rounded shadow-sm">
                            Next: <span className="text-slate-800">{STAGE_LABELS[nextStage as WorkflowStage]}</span>
                        </div>
                    )}
                </div>

                {/* Compliance Alert */}
                {hasBlockers && (
                    <div className="p-2.5 bg-red-50 rounded-lg border border-red-100 flex items-start gap-2">
                        <AlertCircle size={14} className="text-red-500 shrink-0 mt-0.5" />
                        <div>
                            <div className="text-xs font-semibold text-red-700 mb-0.5">Blockers detected</div>
                            <ul className="space-y-0.5">
                                {validation?.blockers.map((blocker, idx) => (
                                    <li key={idx} className="text-xs text-red-600 flex items-start gap-1.5 leading-tight">
                                        <span className="w-1 h-1 bg-red-400 rounded-full mt-1.5 shrink-0" />
                                        <span>{blocker}</span>
                                    </li>
                                ))}
                            </ul>
                        </div>
                    </div>
                )}

                {/* Actions */}
                {(onAdvance || onRollback) && (
                    <div className="flex gap-2 w-full mt-1">
                        {onRollback && (
                            <button
                                onClick={() => {
                                    const reason = prompt("Reason for rollback:");
                                    const prevStage = WorkflowEngine.getPreviousStage(candidate.stage);
                                    if (reason && prevStage) onRollback(prevStage, reason);
                                }}
                                className="flex-1 py-1.5 text-xs font-medium text-slate-600 bg-white border border-slate-200 rounded hover:bg-slate-50 transition-colors flex justify-center items-center gap-1.5"
                            >
                                <RotateCcw size={12} />
                                Rollback
                            </button>
                        )}
                        {onAdvance && (
                            <button
                                onClick={() => onAdvance(hasBlockers)}
                                className={`flex-1 py-1.5 text-xs font-medium text-white rounded transition-all shadow-sm flex justify-center items-center gap-1.5 ${hasBlockers
                                    ? 'bg-red-500 hover:bg-red-600 shadow-sm'
                                    : 'bg-blue-600 hover:bg-blue-700 shadow-sm'
                                    }`}
                            >
                                {hasBlockers ? 'Override' : 'Advance'}
                                <FastForward size={12} />
                            </button>
                        )}
                    </div>
                )}
            </div>

            {/* Stepper Content */}
            <div className="p-4 py-3">
                <div className="space-y-0 relative">
                    {/* Continuous Line behind */}
                    <div className="absolute left-[11px] top-2 bottom-4 w-0.5 bg-slate-100 z-0"></div>

                    {stages.map((item, index) => {
                        const status = getStageStatus(index);
                        const isClickable = onStageClick && status !== 'current';

                        let milestoneDate = null;
                        if (item.stage === WorkflowStage.REGISTERED) {
                            milestoneDate = candidate.regDate ? new Date(candidate.regDate).toLocaleDateString() : null;
                        } else {
                            const key = STAGE_MILESTONE_KEYS[item.stage];
                            if (key && candidate.workflowMilestones) {
                                const dateStr = (candidate.workflowMilestones as any)[key];
                                if (dateStr) milestoneDate = dateStr;
                            }
                        }

                        return (
                            <div key={item.stage} className="relative z-10 flex items-start gap-3 py-1.5 group">
                                <button
                                    onClick={() => isClickable && onStageClick?.(item.stage)}
                                    disabled={!isClickable}
                                    className={`flex items-center gap-3 w-full focus:outline-none ${isClickable ? 'cursor-pointer' : 'cursor-default'}`}
                                >
                                    {/* Icon */}
                                    <div className="relative flex-shrink-0 w-6 h-6 flex items-center justify-center bg-white">
                                        {status === 'completed' ? (
                                            <div className="w-5 h-5 bg-green-500 rounded-full flex items-center justify-center shadow-sm">
                                                <Check size={10} className="text-white" strokeWidth={3} />
                                            </div>
                                        ) : status === 'current' ? (
                                            <div className="w-5 h-5 bg-blue-100 rounded-full flex items-center justify-center ring-2 ring-white">
                                                <div className="w-2 h-2 bg-blue-600 rounded-full" />
                                            </div>
                                        ) : (
                                            <div className="w-3 h-3 border-2 border-slate-200 bg-white rounded-full group-hover:border-slate-300 transition-colors" />
                                        )}
                                    </div>

                                    {/* Label & Date */}
                                    <div className="flex-1 text-left min-w-0 flex items-center justify-between">
                                        <div className="flex flex-col justify-center">
                                            <span
                                                className={`text-xs font-semibold truncate ${status === 'completed'
                                                    ? 'text-slate-700'
                                                    : status === 'current'
                                                        ? 'text-blue-700'
                                                        : 'text-slate-400 group-hover:text-slate-500 transition-colors'
                                                    }`}
                                            >
                                                {item.label}
                                            </span>
                                            {status === 'current' && (
                                                <span className="text-xs text-blue-600 font-medium inline-block">In Progress</span>
                                            )}
                                        </div>
                                        {milestoneDate && status !== 'current' && (
                                            <span className="text-xs text-slate-500">{milestoneDate}</span>
                                        )}
                                    </div>
                                </button>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
};

export default WorkflowProgressWidget;

import React, { createContext, useContext, useState, ReactNode } from 'react';
import { User, AuthState } from '../types';
import { AuthService } from '../services/authService';
import { AuditService } from '../services/auditService';
import socketService from '../services/socketService';

interface AuthContextType extends AuthState {
    login: (email: string, password: string) => Promise<void>;
    logout: () => Promise<void>;
    updateUser: (user: User) => void;
}

export const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [state, setState] = useState<AuthState>({
        user: null,
        isAuthenticated: false,
        isLoading: true,
    });

    React.useEffect(() => {
        const initAuth = async () => {
            console.log('[Auth] Initializing authentication...');
            try {
                // Check Supabase for existing session
                const user = await AuthService.getCurrentUser();

                if (user) {
                    AuditService.setCurrentUser(user.id);
                    setState({
                        user,
                        isAuthenticated: true,
                        isLoading: false,
                    });
                } else {
                    setState({
                        user: null,
                        isAuthenticated: false,
                        isLoading: false,
                    });
                }
            } catch (error) {
                console.error('[Auth] Initialization error:', error);
                setState({
                    user: null,
                    isAuthenticated: false,
                    isLoading: false,
                });
            }
        };
        initAuth();
    }, []);

    const login = async (email: string, password: string) => {
        setState(prev => ({ ...prev, isLoading: true }));
        try {
            const user = await AuthService.login(email, password);
            AuditService.setCurrentUser(user.id);
            setState({ user, isAuthenticated: true, isLoading: false });
            AuditService.log('USER_LOGIN', { email: user.email }, user.id);
        } catch (error) {
            setState(prev => ({ ...prev, isLoading: false }));
            throw error;
        }
    };

    const logout = async () => {
        if (state.user) {
            AuditService.log('USER_LOGOUT', { email: state.user.email }, state.user.id);
        }
        await AuthService.logout();
        AuditService.setCurrentUser(null);
        setState({ user: null, isAuthenticated: false, isLoading: false });
    };

    const updateUser = (user: User) => {
        setState(prev => ({ ...prev, user }));
    };

    // Auto-Session Timeout (Idle Security) - 2 Hours
    React.useEffect(() => {
        let timeoutId: NodeJS.Timeout;
        const TWO_HOURS_MS = 2 * 60 * 60 * 1000;

        const handleActivity = () => {
            if (timeoutId) {
                clearTimeout(timeoutId);
            }
            if (state.isAuthenticated) {
                timeoutId = setTimeout(() => {
                    console.log('[Auth] Session timed out due to inactivity.');
                    logout();
                    // Hard redirect to clear any sensitive states safely
                    window.location.href = '/login';
                }, TWO_HOURS_MS);
            }
        };

        if (state.isAuthenticated) {
            handleActivity(); // Start timer initially
            window.addEventListener('mousemove', handleActivity);
            window.addEventListener('keydown', handleActivity);
            window.addEventListener('click', handleActivity);
            window.addEventListener('scroll', handleActivity);
        }

        return () => {
            if (timeoutId) {
                clearTimeout(timeoutId);
            }
            window.removeEventListener('mousemove', handleActivity);
            window.removeEventListener('keydown', handleActivity);
            window.removeEventListener('click', handleActivity);
            window.removeEventListener('scroll', handleActivity);
        };
    }, [state.isAuthenticated]);

    // Listen for real-time forced revokes
    React.useEffect(() => {
        if (!state.isAuthenticated) return;

        const handleRevoke = (data: any) => {
            console.error('[Auth] Forcefully revoked via WebSocket:', data?.message);
            // Drop frontend states immediately
            AuthService.logout().then(() => {
                setState({ user: null, isAuthenticated: false, isLoading: false });
                window.location.href = '/login';
            });
        };

        socketService.on('session:revoked', handleRevoke);

        return () => {
            socketService.off('session:revoked', handleRevoke);
        };
    }, [state.isAuthenticated]);

    return (
        <AuthContext.Provider value={{ ...state, login, logout, updateUser }}>
            {children}
        </AuthContext.Provider>
    );
};


export const useAuth = () => {
    const context = useContext(AuthContext);
    if (context === undefined) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Candidate } from '../types';
import { CandidateService } from '../services/candidateService';
import { logger } from '../services/loggerService';
import { supabase } from '../services/supabase';

interface CandidateContextType {
    candidates: Candidate[];
    isLoading: boolean;
    error: string | null;
    refreshCandidates: () => Promise<void>;
    updateCandidateInState: (candidate: Candidate) => void;
    removeCandidateFromState: (id: string) => void;
    addCandidateToState: (candidate: Candidate) => void;
}

const CandidateContext = createContext<CandidateContextType | undefined>(undefined);

export const CandidateProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [candidates, setCandidates] = useState<Candidate[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const refreshCandidates = useCallback(async () => {
        setIsLoading(true);
        setError(null);
        try {
            const data = await CandidateService.getCandidates();
            if (data && data.length > 0) {
                setCandidates(data);
                // OFFLINE MODE: Cache latest data
                localStorage.setItem('caditare_offline_candidates', JSON.stringify(data));
            }
        } catch (err) {
            logger.error('Failed to fetch candidates', err);

            // OFFLINE MODE: Fallback to cached data if network fails
            const cached = localStorage.getItem('caditare_offline_candidates');
            if (cached) {
                console.log('Network offline. Serving candidates from local cache.');
                setCandidates(JSON.parse(cached));
                setError('You are offline. Showing cached data.');
            } else {
                setError('Failed to load candidates. Please try again.');
            }
        } finally {
            setIsLoading(false);
        }
    }, []);

    // OFFLINE MODE: Auto-refresh when internet comes back
    useEffect(() => {
        const handleOnline = () => {
            console.log('Network connection restored. Syncing data...');
            refreshCandidates();
        };
        window.addEventListener('online', handleOnline);
        return () => window.removeEventListener('online', handleOnline);
    }, [refreshCandidates]);

    // Initial load and Real-time subscription setup
    useEffect(() => {
        refreshCandidates();

        // Establish Realtime Collaboration Sync
        const channel = supabase
            .channel('public:candidates')
            .on(
                'postgres_changes',
                { event: 'INSERT', schema: 'public', table: 'candidates' },
                (payload: any) => {
                    logger.debug('Realtime INSERT received:', payload);
                    const newCandidate = CandidateService['mapRowToCandidate'] ?
                        (CandidateService as any).mapRowToCandidate(payload.new) :
                        payload.new.data as Candidate;

                    if (newCandidate && newCandidate.id) {
                        setCandidates(prev => [newCandidate, ...prev.filter(c => c.id !== newCandidate.id)]);
                    } else {
                        refreshCandidates(); // Fallback to full refresh if mapping fails
                    }
                }
            )
            .on(
                'postgres_changes',
                { event: 'UPDATE', schema: 'public', table: 'candidates' },
                (payload: any) => {
                    logger.debug('Realtime UPDATE received:', payload);
                    const updatedCandidate = CandidateService['mapRowToCandidate'] ?
                        (CandidateService as any).mapRowToCandidate(payload.new) :
                        payload.new.data as Candidate;

                    if (updatedCandidate && updatedCandidate.id) {
                        setCandidates(prev => prev.map(c => c.id === updatedCandidate.id ? updatedCandidate : c));
                    } else {
                        refreshCandidates();
                    }
                }
            )
            .on(
                'postgres_changes',
                { event: 'DELETE', schema: 'public', table: 'candidates' },
                (payload: any) => {
                    logger.debug('Realtime DELETE received:', payload);
                    if (payload.old && payload.old.id) {
                        setCandidates(prev => prev.filter(c => c.id !== payload.old.id));
                    }
                }
            )
            .subscribe((status: string) => {
                if (status === 'SUBSCRIBED') {
                    logger.debug('Successfully subscribed to real-time candidate updates');
                }
            });

        // Cleanup subscription on unmount
        return () => {
            supabase.removeChannel(channel);
        };
    }, [refreshCandidates]);

    const updateCandidateInState = useCallback((updatedCandidate: Candidate) => {
        setCandidates(prev => prev.map(c => c.id === updatedCandidate.id ? updatedCandidate : c));
    }, []);

    const removeCandidateFromState = useCallback((id: string) => {
        setCandidates(prev => prev.filter(c => c.id !== id));
    }, []);

    const addCandidateToState = useCallback((newCandidate: Candidate) => {
        setCandidates(prev => [newCandidate, ...prev]);
    }, []);

    return (
        <CandidateContext.Provider value={{
            candidates,
            isLoading,
            error,
            refreshCandidates,
            updateCandidateInState,
            removeCandidateFromState,
            addCandidateToState
        }}>
            {children}
        </CandidateContext.Provider>
    );
};

export const useCandidates = () => {
    const context = useContext(CandidateContext);
    if (context === undefined) {
        throw new Error('useCandidates must be used within a CandidateProvider');
    }
    return context;
};

import React, { createContext, useContext, useState, useEffect, useCallback, ReactNode } from 'react';
import { ChatService } from '../services/chatService';
import { useAuth } from './AuthContext';
import { ChatChannel, ChatMessage, ChatUser, ChatMessageContext, ChatAttachment } from '../types';

interface ChatState {
    channels: ChatChannel[];
    users: ChatUser[];
    activeChannelId: string | null;
    messages: ChatMessage[];
    isTyping: boolean;
    searchQuery: string;
    filterType: 'all' | 'channels' | 'dms';
    isLoading: boolean;
    isMobileSidebarOpen: boolean;
}

interface ChatContextType extends ChatState {
    setActiveChannelId: (id: string | null) => void;
    sendMessage: (text: string, context?: ChatMessageContext, attachments?: ChatAttachment[]) => Promise<void>;
    setSearchQuery: (query: string) => void;
    setFilterType: (type: 'all' | 'channels' | 'dms') => void;
    toggleMobileSidebar: () => void;
    refreshData: () => Promise<void>;
    createChannel: (name: string, type: 'public' | 'private') => Promise<void>;
    deleteChannel: (id: string) => Promise<void>;
    addReaction: (messageId: string, emoji: string) => Promise<void>;
    removeReaction: (messageId: string, emoji: string) => Promise<void>;
}

const ChatContext = createContext<ChatContextType | undefined>(undefined);

export const ChatProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const { user: currentUser } = useAuth();
    const [state, setState] = useState<ChatState>({
        channels: [],
        users: [],
        activeChannelId: 'c1', // Default to General
        messages: [],
        isTyping: false,
        searchQuery: '',
        filterType: 'all',
        isLoading: true,
        isMobileSidebarOpen: true
    });

    const refreshData = useCallback(async () => {
        try {
            const [channelsData, usersData] = await Promise.all([
                ChatService.getChannels(),
                ChatService.getUsers()
            ]);
            setState(prev => ({ ...prev, channels: channelsData, users: usersData, isLoading: false }));
        } catch (error) {
            console.error("Failed to refresh chat data", error);
            setState(prev => ({ ...prev, isLoading: false }));
        }
    }, []);

    // Initial Load
    useEffect(() => {
        refreshData();
    }, [refreshData]);

    // Message Fetching when Active Channel Changes
    useEffect(() => {
        const fetchMessages = async () => {
            if (state.activeChannelId) {
                const data = await ChatService.getMessages(state.activeChannelId);
                setState(prev => ({ ...prev, messages: data.messages }));

                // On mobile, close sidebar when selecting a channel
                if (window.innerWidth < 768) {
                    setState(prev => ({ ...prev, isMobileSidebarOpen: false }));
                }
            }
        };
        fetchMessages();
    }, [state.activeChannelId]);

    // Real-time Listener (Supabase)
    useEffect(() => {
        if (!state.activeChannelId) return;

        console.log(`[Chat] Subscribing to channel: ${state.activeChannelId}`);
        const unsubscribe = ChatService.subscribeToMessages(state.activeChannelId, (newMsg) => {
            const msg: ChatMessage = {
                id: newMsg.id,
                channelId: newMsg.channel_id,
                text: newMsg.text,
                senderId: newMsg.sender_id,
                senderName: newMsg.sender_name,
                timestamp: newMsg.timestamp,
                attachments: newMsg.attachments || [],
                context: newMsg.context,
                isMe: newMsg.sender_id === currentUser?.id,
                isSystem: newMsg.sender_id === 'system'
            };

            setState(prev => {
                // Avoid duplicates
                if (prev.messages.some(m => m.id === msg.id)) return prev;
                return { ...prev, messages: [...prev.messages, msg] };
            });
        });

        return () => {
            console.log(`[Chat] Unsubscribing from channel: ${state.activeChannelId}`);
            unsubscribe();
        };
    }, [state.activeChannelId, currentUser?.id]);

    const sendMessage = async (text: string, context?: ChatMessageContext, attachments?: ChatAttachment[]) => {
        if (!state.activeChannelId || !currentUser) return;

        // 🚀 Optimistic update for zero-delay user experience
        const tempId = `temp_${Date.now()}`;
        const optimisticMsg: ChatMessage = {
            id: tempId,
            channelId: state.activeChannelId,
            text,
            senderId: currentUser.id,
            senderName: currentUser.name || 'Me',
            timestamp: new Date().toISOString(),
            attachments: attachments || [],
            context,
            isMe: true,
            isSystem: false
        };

        // Add to UI immediately before server computes
        setState(prev => ({ ...prev, messages: [...prev.messages, optimisticMsg] }));

        try {
            await ChatService.sendMessage(
                state.activeChannelId,
                text,
                currentUser.id,
                currentUser.name,
                context,
                attachments
            );
            // The real-time listener will pull the verified message, we can optionally clean up tempId here
            // but the listener usually avoids duplicates gracefully.
        } catch (error) {
            console.error("Failed to send message", error);
            // Revert on failure
            setState(prev => ({
                ...prev,
                messages: prev.messages.filter(m => m.id !== tempId)
            }));
        }
    };

    const addReaction = async (messageId: string, emoji: string) => {
        if (!state.activeChannelId) return;
        await ChatService.addReaction(state.activeChannelId, messageId, emoji);
    };

    const removeReaction = async (messageId: string, emoji: string) => {
        if (!state.activeChannelId) return;
        await ChatService.removeReaction(state.activeChannelId, messageId, emoji);
    };

    const createChannel = async (name: string, type: 'public' | 'private') => {
        const newChannel = await ChatService.createChannel(name, type);
        await refreshData();
        setState(prev => ({ ...prev, activeChannelId: newChannel.id }));
    };

    const deleteChannel = async (id: string) => {
        const success = await ChatService.deleteChannel(id);
        if (success) {
            await refreshData();
            if (state.activeChannelId === id) {
                setState(prev => ({ ...prev, activeChannelId: 'c1' }));
            }
        }
    };

    const setActiveChannelId = (id: string | null) => {
        setState(prev => ({ ...prev, activeChannelId: id }));
    };

    const setSearchQuery = (query: string) => {
        setState(prev => ({ ...prev, searchQuery: query }));
    };

    const setFilterType = (type: 'all' | 'channels' | 'dms') => {
        setState(prev => ({ ...prev, filterType: type }));
    };

    const toggleMobileSidebar = () => {
        setState(prev => ({ ...prev, isMobileSidebarOpen: !prev.isMobileSidebarOpen }));
    };

    return (
        <ChatContext.Provider value={{
            ...state,
            setActiveChannelId,
            sendMessage,
            setSearchQuery,
            setFilterType,
            toggleMobileSidebar,
            refreshData,
            createChannel,
            deleteChannel,
            addReaction,
            removeReaction
        }}>
            {children}
        </ChatContext.Provider>
    );
};

export const useChat = () => {
    const context = useContext(ChatContext);
    if (!context) {
        throw new Error('useChat must be used within a ChatProvider');
    }
    return context;
};

