import { Request } from 'express';
// @ts-ignore
import geoip from 'geoip-lite';
import { SessionStore, ActiveSession } from './sessionStore';
import { getIO } from '../socket/chatSocket';
import { query } from '../database';
import { SecurityConfigService } from './securityConfigService';

let activeSessions = SessionStore.loadSessions();
let blacklistedTokens = new Set<string>();

export const SessionService = {
    trackRequest: (req: Request) => {
        if (!req.user) return;

        const userId = req.user.id;
        const userName = req.user.name;
        // Clean up proxy IP formats
        const ip = req.ip?.replace('::ffff:', '') || req.socket?.remoteAddress?.replace('::ffff:', '') || '127.0.0.1';
        const userAgentRaw = req.headers?.['user-agent'] || 'Unknown Browser';

        // Detailed Device Parsing
        let os = 'Unknown OS';
        if (userAgentRaw.includes('Windows')) os = 'Windows';
        else if (userAgentRaw.includes('Macintosh') || userAgentRaw.includes('Mac OS X')) os = 'macOS';
        else if (userAgentRaw.includes('Linux')) os = 'Linux';
        else if (userAgentRaw.includes('iPhone')) os = 'iPhone';
        else if (userAgentRaw.includes('Android')) os = 'Android';

        let browser = 'Unknown Browser';
        if (userAgentRaw.includes('Chrome') && !userAgentRaw.includes('Edg')) browser = 'Chrome';
        else if (userAgentRaw.includes('Safari') && !userAgentRaw.includes('Chrome')) browser = 'Safari';
        else if (userAgentRaw.includes('Firefox')) browser = 'Firefox';
        else if (userAgentRaw.includes('Edg')) browser = 'Edge';

        const userAgent = `${browser} on ${os}`;

        // 3. GeoIP Mapping
        let location = 'Remote Connection';
        const config = SecurityConfigService.getConfig();
        const officeIp = config.officeIp || process.env.OFFICE_ROUTER_IP || '192.168.1.1';

        if (ip === officeIp) {
            location = 'Office Network';
        } else if (ip === '127.0.0.1' || ip === '::1') {
            location = 'Localhost';
        } else {
            const geo = geoip.lookup(ip);
            if (geo) {
                location = `${geo.city || 'Unknown City'}, ${geo.country || 'Unknown Country'}`;
            }
        }

        const sessionId = `${userId}-${ip}-${userAgent}`;

        // Keep session persistent if it's already revoked
        const existingSession = activeSessions.get(sessionId);
        if (existingSession && existingSession.status === 'revoked') {
            return;
        }

        activeSessions.set(sessionId, {
            id: sessionId,
            userId,
            userName,
            ip,
            userAgent,
            location,
            lastActive: Date.now(),
            status: 'active'
        });

        // Save on intervals naturally (we debounce in production, but here we can save direct)
        SessionStore.saveSessions(activeSessions);
    },

    getActiveSessions: () => {
        const now = Date.now();
        // 1. Persistence & Housekeeping
        let changed = false;
        for (const [key, session] of activeSessions.entries()) {
            if (now - session.lastActive > 24 * 60 * 60 * 1000) {
                activeSessions.delete(key);
                changed = true;
            }
        }
        if (changed) SessionStore.saveSessions(activeSessions);

        return Array.from(activeSessions.values()).sort((a, b) => b.lastActive - a.lastActive);
    },

    revokeSession: async (sessionId: string) => {
        const session = activeSessions.get(sessionId);
        if (session) {
            session.status = 'revoked';
            activeSessions.set(sessionId, session);
            SessionStore.saveSessions(activeSessions);

            // 1. JWT Blacklist
            const tokenIdentifier = `blacklisted-${session.userId}`;
            blacklistedTokens.add(tokenIdentifier);

            // 2. Real-Time WebSocket Kick
            const io = getIO();
            if (io) {
                // We emit a special direct event to this user's personal room
                io.to(`user:${session.userId}`).emit('session:revoked', {
                    message: 'Your session has been terminated by an Administrator.'
                });
            }

            // 3. Automated Admin Notification (assuming 'system-admin' is the main admin id, or we log universally)
            try {
                // This alerts the admin interface that a forced revocation occurred.
                await query(`
                    INSERT INTO chat_notifications (id, user_id, type, title, message, is_read, created_at)
                    VALUES (gen_random_uuid(), 'system-admin', 'security_alert', 'Session Revoked', 
                    'A session for ${session.userName} from ${session.ip} was forcefully revoked.', false, NOW())
                `);
            } catch (e) {
                console.error('Pushed security notification to Mock DB (or query failed)');
            }
        }
    },

    // JWT Blacklisting Helper
    blacklistToken: (token: string) => {
        blacklistedTokens.add(token);
    },

    isTokenBlacklisted: (token: string): boolean => {
        return blacklistedTokens.has(token);
    },

    isRevoked: (req: Request): boolean => {
        if (!req.user) return false;
        const ip = req.ip?.replace('::ffff:', '') || req.socket?.remoteAddress?.replace('::ffff:', '') || '127.0.0.1';
        const userAgentRaw = req.headers?.['user-agent'] || '';

        let os = 'Unknown OS';
        if (userAgentRaw.includes('Windows')) os = 'Windows';
        else if (userAgentRaw.includes('Mac OS X') || userAgentRaw.includes('Macintosh')) os = 'macOS';
        else if (userAgentRaw.includes('Linux')) os = 'Linux';
        else if (userAgentRaw.includes('iPhone')) os = 'iPhone';
        else if (userAgentRaw.includes('Android')) os = 'Android';

        let browser = 'Unknown Browser';
        if (userAgentRaw.includes('Chrome') && !userAgentRaw.includes('Edg')) browser = 'Chrome';
        else if (userAgentRaw.includes('Safari') && !userAgentRaw.includes('Chrome')) browser = 'Safari';
        else if (userAgentRaw.includes('Firefox')) browser = 'Firefox';
        else if (userAgentRaw.includes('Edg')) browser = 'Edge';

        const userAgent = `${browser} on ${os}`;

        const sessionId = `${req.user.id}-${ip}-${userAgent}`;
        const session = activeSessions.get(sessionId);
        return session?.status === 'revoked';
    },

    // Used for tests so we can clear states
    _clearState: () => {
        activeSessions = new Map();
        blacklistedTokens = new Set();
    }
};

import { Server as SocketIOServer, Socket } from 'socket.io';
import jwt from 'jsonwebtoken';
import { query } from '../database';

interface AuthenticatedSocket extends Socket {
    userId?: string;
    userName?: string;
}

let ioInstance: SocketIOServer | null = null;

export const setupChatSocket = (io: SocketIOServer) => {
    ioInstance = io;
    // Authentication middleware for Socket.IO
    io.use((socket: AuthenticatedSocket, next) => {
        try {
            const token = socket.handshake.auth.token;

            // Dev mode bypass for mock tokens
            if (process.env.NODE_ENV !== 'production' && token === 'mock-jwt-token') {
                socket.userId = 'a0eebc99-9c0b-4ef8-bb6d-6bb9bd380a11'; // Standard test UUID
                socket.userName = 'Test Admin';
                return next();
            }

            if (!token) {
                return next(new Error('Authentication error: No token provided'));
            }

            const secret = process.env.JWT_SECRET || 'your-secret-key-change-this-in-production';
            const decoded = jwt.verify(token, secret) as any;

            socket.userId = decoded.id || decoded.userId;
            socket.userName = decoded.name;

            next();
        } catch (error) {
            next(new Error('Authentication error: Invalid token'));
        }
    });

    io.on('connection', (socket: AuthenticatedSocket) => {
        console.log(`✅ User connected: ${socket.userName} (${socket.userId})`);

        // Join user's personal room for direct notifications
        socket.join(`user:${socket.userId}`);

        // Broadcast user online status
        io.emit('user:online', { userId: socket.userId });

        // ========================================================================
        // CHANNEL EVENTS
        // ========================================================================

        // Join a channel room
        socket.on('channel:join', async (data: { channelId: string }, callback?: Function) => {
            try {
                const { channelId } = data;

                // Check if user has access to this channel
                const accessCheck = await query(`
                  SELECT 1 FROM chat_channels c
                  LEFT JOIN chat_channel_members cm ON cm.channel_id = c.id AND cm.user_id = $2
                  WHERE c.id = $1 AND (c.type = 'public' OR cm.user_id IS NOT NULL)
                `, [channelId, socket.userId]);

                if (accessCheck.rows.length === 0) {
                    console.warn(`Unauthorized join attempt from ${socket.userName} for channel ${channelId}`);
                    if (callback) callback({ success: false, error: 'Access denied' });
                    return;
                }

                socket.join(`channel:${channelId}`);
                console.log(`User ${socket.userName} joined channel ${channelId}`);
                if (callback) callback({ success: true });
            } catch (error) {
                console.error('Error joining channel:', error);
                if (callback) callback({ success: false, error: 'Failed to join' });
            }
        });

        // Leave a channel room
        socket.on('channel:leave', (data: { channelId: string }) => {
            const { channelId } = data;
            socket.leave(`channel:${channelId}`);
            console.log(`User ${socket.userName} left channel ${channelId}`);
        });

        // ========================================================================
        // MESSAGE EVENTS
        // ========================================================================

        // Send a message
        socket.on('message:send', async (data: { channelId: string; text: string; parentMessageId?: string }) => {
            try {
                const { channelId, text, parentMessageId } = data;

                // Enforce channel access check
                const accessCheck = await query(`
                  SELECT 1 FROM chat_channels c
                  LEFT JOIN chat_channel_members cm ON cm.channel_id = c.id AND cm.user_id = $2
                  WHERE c.id = $1 AND (c.type = 'public' OR cm.user_id IS NOT NULL)
                `, [channelId, socket.userId]);

                if (accessCheck.rows.length === 0) {
                    socket.emit('error', { message: 'Access denied to this channel' });
                    return;
                }

                // Extract mentions
                const mentionRegex = /@(\w+)/g;
                const mentions: string[] = [];
                let match;
                while ((match = mentionRegex.exec(text)) !== null) {
                    mentions.push(match[1]);
                }

                // Insert message
                const result = await query(`
          INSERT INTO chat_messages (
            channel_id, text, sender_id, sender_name, parent_message_id, mentions
          )
          VALUES ($1, $2, $3, $4, $5, $6)
          RETURNING *
        `, [channelId, text, socket.userId, socket.userName, parentMessageId, JSON.stringify(mentions)]);

                const message = result.rows[0];

                // Broadcast to channel
                io.to(`channel:${channelId}`).emit('message:new', {
                    id: message.id,
                    channelId: message.channel_id,
                    text: message.text,
                    senderId: message.sender_id,
                    senderName: message.sender_name,
                    parentMessageId: message.parent_message_id,
                    mentions: message.mentions,
                    timestamp: message.created_at,
                    reactions: [],
                    attachments: [],
                    isSystem: false,
                    isDeleted: false,
                });

                // Create notifications for mentions
                if (mentions.length > 0) {
                    for (const mention of mentions) {
                        try {
                            // Find the user by mention (case insensitive name match with spaces removed, or direct UUID)
                            const userMatch = await query(`
                                SELECT id FROM profiles 
                                WHERE REPLACE(LOWER(full_name), ' ', '') = LOWER($1)
                                   OR id::text = $1
                                LIMIT 1
                            `, [mention]);

                            if (userMatch.rows.length > 0) {
                                const mentionedUserId = userMatch.rows[0].id;

                                // Don't notify self
                                if (mentionedUserId === socket.userId) continue;

                                await query(`
                                    INSERT INTO chat_notifications (user_id, type, title, message, channel_id, message_id)
                                    VALUES ($1, 'mention', $2, $3, $4, $5)
                                `, [
                                    mentionedUserId,
                                    `Mentioned by ${socket.userName}`,
                                    text.substring(0, 100),
                                    channelId,
                                    message.id
                                ]);

                                // Push real-time notification to the mentioned user
                                io.to(`user:${mentionedUserId}`).emit('notification:new', {
                                    type: 'mention',
                                    title: `Mentioned by ${socket.userName}`,
                                    message: text.substring(0, 100),
                                    channelId,
                                    messageId: message.id
                                });
                            }
                        } catch (err) {
                            console.error('Error resolving mention:', err);
                        }
                    }
                }
            } catch (error) {
                console.error('Error sending message:', error);
                socket.emit('error', { message: 'Failed to send message' });
            }
        });

        // Edit a message
        socket.on('message:edit', async (data: { messageId: string; text: string }) => {
            try {
                const { messageId, text } = data;

                // Verify ownership
                const ownerCheck = await query(`
          SELECT sender_id, channel_id FROM chat_messages WHERE id = $1
        `, [messageId]);

                if (ownerCheck.rows.length === 0 || ownerCheck.rows[0].sender_id !== socket.userId) {
                    socket.emit('error', { message: 'You can only edit your own messages' });
                    return;
                }

                // Update message
                const result = await query(`
          UPDATE chat_messages
          SET text = $2, edited_at = CURRENT_TIMESTAMP
          WHERE id = $1
          RETURNING *
        `, [messageId, text]);

                const message = result.rows[0];

                // Broadcast to channel
                io.to(`channel:${message.channel_id}`).emit('message:updated', {
                    id: message.id,
                    text: message.text,
                    editedAt: message.edited_at,
                });
            } catch (error) {
                console.error('Error editing message:', error);
                socket.emit('error', { message: 'Failed to edit message' });
            }
        });

        // Delete a message
        socket.on('message:delete', async (data: { messageId: string }) => {
            try {
                const { messageId } = data;

                // Verify ownership or admin
                const ownerCheck = await query(`
          SELECT m.sender_id, m.channel_id, cm.role
          FROM chat_messages m
          LEFT JOIN chat_channel_members cm ON cm.channel_id = m.channel_id AND cm.user_id = $2
          WHERE m.id = $1
        `, [messageId, socket.userId]);

                if (ownerCheck.rows.length === 0) {
                    socket.emit('error', { message: 'Message not found' });
                    return;
                }

                const isOwner = ownerCheck.rows[0].sender_id === socket.userId;
                const isAdmin = ownerCheck.rows[0].role && ['owner', 'admin'].includes(ownerCheck.rows[0].role);

                if (!isOwner && !isAdmin) {
                    socket.emit('error', { message: 'You can only delete your own messages or be a channel admin' });
                    return;
                }

                // Soft delete
                await query(`
          UPDATE chat_messages
          SET is_deleted = TRUE, text = '[Message deleted]'
          WHERE id = $1
        `, [messageId]);

                // Broadcast to channel
                io.to(`channel:${ownerCheck.rows[0].channel_id}`).emit('message:deleted', {
                    messageId,
                    channelId: ownerCheck.rows[0].channel_id,
                });
            } catch (error) {
                console.error('Error deleting message:', error);
                socket.emit('error', { message: 'Failed to delete message' });
            }
        });

        // ========================================================================
        // REACTION EVENTS
        // ========================================================================

        // Add reaction
        socket.on('reaction:add', async (data: { messageId: string; emoji: string }) => {
            try {
                const { messageId, emoji } = data;

                // Get message channel
                const messageCheck = await query(`
          SELECT channel_id FROM chat_messages WHERE id = $1
        `, [messageId]);

                if (messageCheck.rows.length === 0) {
                    socket.emit('error', { message: 'Message not found' });
                    return;
                }

                const channelId = messageCheck.rows[0].channel_id;

                // Add reaction
                await query(`
          INSERT INTO chat_message_reactions (message_id, emoji, user_id, user_name)
          VALUES ($1, $2, $3, $4)
          ON CONFLICT (message_id, emoji, user_id) DO NOTHING
        `, [messageId, emoji, socket.userId, socket.userName]);

                // Get updated reactions
                const result = await query(`
          SELECT 
            emoji,
            COUNT(*) as count,
            json_agg(
              json_build_object('id', user_id, 'name', user_name)
            ) as users
          FROM chat_message_reactions
          WHERE message_id = $1 AND emoji = $2
          GROUP BY emoji
        `, [messageId, emoji]);

                // Broadcast to channel
                io.to(`channel:${channelId}`).emit('reaction:added', {
                    messageId,
                    reaction: result.rows[0],
                });
            } catch (error) {
                console.error('Error adding reaction:', error);
                socket.emit('error', { message: 'Failed to add reaction' });
            }
        });

        // Remove reaction
        socket.on('reaction:remove', async (data: { messageId: string; emoji: string }) => {
            try {
                const { messageId, emoji } = data;

                // Get message channel
                const messageCheck = await query(`
          SELECT channel_id FROM chat_messages WHERE id = $1
        `, [messageId]);

                if (messageCheck.rows.length === 0) {
                    socket.emit('error', { message: 'Message not found' });
                    return;
                }

                const channelId = messageCheck.rows[0].channel_id;

                // Remove reaction
                await query(`
          DELETE FROM chat_message_reactions
          WHERE message_id = $1 AND emoji = $2 AND user_id = $3
        `, [messageId, emoji, socket.userId]);

                // Broadcast to channel
                io.to(`channel:${channelId}`).emit('reaction:removed', {
                    messageId,
                    emoji,
                    userId: socket.userId,
                });
            } catch (error) {
                console.error('Error removing reaction:', error);
                socket.emit('error', { message: 'Failed to remove reaction' });
            }
        });

        // ========================================================================
        // TYPING INDICATORS
        // ========================================================================

        // User started typing
        socket.on('typing:start', async (data: { channelId: string }) => {
            try {
                const { channelId } = data;

