import { supabase } from './supabase';

// Cache the user ID to avoid repeated async lookups
let _cachedUserId: string | null = null;

export class AuditService {
    /**
     * Set the current user ID (call this on login/auth state change)
     * This ensures audit logs are always attributed correctly.
     */
    static setCurrentUser(userId: string | null) {
        _cachedUserId = userId;
    }

    /**
     * Get the current cached user ID, with a fallback to supabase.auth.getUser()
     */
    static async getCurrentUserId(): Promise<string | undefined> {
        if (_cachedUserId) return _cachedUserId;
        try {
            const { data: { user } } = await supabase.auth.getUser();
            if (user) {
                _cachedUserId = user.id;
                return user.id;
            }
        } catch { /* ignore */ }
        return undefined;
    }

    /**
     * Logs an action to the audit_logs table for tracking user activity.
     */
    static async log(action: string, details?: any, userIdOverride?: string) {
        try {
            // Priority: explicit override > cached ID > live lookup
            let user_id = userIdOverride || _cachedUserId;

            if (!user_id) {
                try {
                    const { data: { user } } = await supabase.auth.getUser();
                    if (user) {
                        user_id = user.id;
                        _cachedUserId = user.id; // Cache for future calls
                    }
                } catch { /* ignore */ }
            }

            const ip_address = 'Client-Side';

            const payload: any = {
                action,
                ip_address
            };

            if (details) payload.details = details;
            if (user_id) payload.user_id = user_id;

            const { error } = await supabase.from('audit_logs').insert([payload]);

            if (error) {
                console.warn('Failed to insert audit log:', error);
            }
        } catch (e) {
            console.error('Audit log error:', e);
        }
    }
}

/**
 * BackupService — Enterprise-Grade Backup & Restore Engine
 * 
 * Features:
 * - Full system snapshots (candidates, jobs, partners, finance, settings, audit logs)
 * - Version-stamped JSON backup files with SHA-256 checksums
 * - Plug-and-play restore: forward and backward compatible
 * - Backup history stored in localStorage with metadata
 * - Selective restore (pick which modules to restore)
 * - Diff viewer to compare backups with current state
 * - Auto-backup scheduling
 */

import { get, set, del } from 'idb-keyval';
import { CandidateService } from './candidateService';
import { JobService } from './jobService';
import { PartnerService } from './partnerService';
import { FinanceService } from './financeService';
import { AuditService } from './auditService';
import { supabase } from './supabase';

// ─── Types ──────────────────────────────────────────────────
export interface BackupManifest {
    id: string;
    version: string;             // Schema version for forward/backward compat
    appVersion: string;
    createdAt: string;
    createdBy: string;
    label: string;               // User-friendly name
    description: string;
    checksum: string;             // SHA-256 hash of the data payload
    modules: BackupModule[];      // Which modules are included
    stats: BackupStats;           // Quick stats summary
    sizeBytes: number;
    isAutoBackup: boolean;
    tags: string[];
}

export interface BackupStats {
    candidates: number;
    jobs: number;
    employers: number;
    transactions: number;
    invoices: number;
    auditLogs: number;
    settings: number;
}

export type BackupModule =
    | 'candidates'
    | 'jobs'
    | 'employers'
    | 'finance_transactions'
    | 'finance_invoices'
    | 'audit_logs'
    | 'settings'
    | 'profiles';

export interface BackupData {
    manifest: BackupManifest;
    payload: {
        candidates?: any[];
        jobs?: any[];
        employers?: any[];
        finance_transactions?: any[];
        finance_invoices?: any[];
        audit_logs?: any[];
        settings?: Record<string, any>;
        profiles?: any[];
    };
}

export interface BackupHistoryEntry {
    id: string;
    label: string;
    createdAt: string;
    createdBy: string;
    modules: BackupModule[];
    stats: BackupStats;
    sizeBytes: number;
    isAutoBackup: boolean;
    checksum: string;
    tags: string[];
    restoredAt?: string;         // If this backup was ever restored
    description: string;
}

export interface RestoreResult {
    success: boolean;
    modulesRestored: BackupModule[];
    errors: string[];
    warnings: string[];
    restoredAt: string;
    rollbackAvailable: boolean;
}

export interface BackupDiff {
    module: BackupModule;
    added: number;
    removed: number;
    modified: number;
    unchanged: number;
}

// Current schema version - increment when breaking changes occur
const BACKUP_SCHEMA_VERSION = '2.0.0';
const APP_VERSION = '1.0.0';
const BACKUP_HISTORY_KEY = 'suhara_backup_history';
const BACKUP_DATA_PREFIX = 'suhara_backup_data_';
const AUTO_BACKUP_INTERVAL_KEY = 'suhara_auto_backup_interval';
const LAST_AUTO_BACKUP_KEY = 'suhara_last_auto_backup';

// ─── Service Implementation ────────────────────────────────
export class BackupService {

    // ═══════════════════════════════════════════
    //  CREATE BACKUP
    // ═══════════════════════════════════════════

    /**
     * Creates a full system backup snapshot.
     * Fetches all data from Supabase, packages it with metadata,
     * generates a checksum, and stores it.
     */
    static async createBackup(options: {
        label?: string;
        description?: string;
        modules?: BackupModule[];
        isAutoBackup?: boolean;
        createdBy?: string;
        tags?: string[];
    } = {}): Promise<BackupData> {

        const {
            label = `Backup ${new Date().toLocaleDateString()} ${new Date().toLocaleTimeString()}`,
            description = '',
            modules = ['candidates', 'jobs', 'employers', 'finance_transactions', 'finance_invoices', 'audit_logs', 'settings', 'profiles'] as BackupModule[],
            isAutoBackup = false,
            createdBy = 'System',
            tags = []
        } = options;

        const payload: BackupData['payload'] = {};
        const stats: BackupStats = {
            candidates: 0,
            jobs: 0,
            employers: 0,
            transactions: 0,
            invoices: 0,
            auditLogs: 0,
            settings: 0
        };

        // ── Fetch Each Module ──
        if (modules.includes('candidates')) {
            try {
                const candidates = await CandidateService.getCandidates();
                payload.candidates = candidates;
                stats.candidates = candidates.length;
            } catch (e) {
                console.warn('Backup: Failed to fetch candidates', e);
                payload.candidates = [];
            }
        }

        if (modules.includes('jobs')) {
            try {
                const jobs = await JobService.getJobs();
                payload.jobs = jobs;
                stats.jobs = jobs.length;
            } catch (e) {
                console.warn('Backup: Failed to fetch jobs', e);
                payload.jobs = [];
            }
        }

        if (modules.includes('employers')) {
            try {
                const employers = await PartnerService.getEmployers();
                payload.employers = employers;
                stats.employers = employers.length;
            } catch (e) {
                console.warn('Backup: Failed to fetch employers', e);
                payload.employers = [];
            }
        }

        if (modules.includes('finance_transactions')) {
            try {
                const transactions = await FinanceService.getTransactions();
                payload.finance_transactions = transactions;
                stats.transactions = transactions.length;
            } catch (e) {
                console.warn('Backup: Failed to fetch transactions', e);
                payload.finance_transactions = [];
            }
        }

        if (modules.includes('finance_invoices')) {
            try {
                const invoices = await FinanceService.getInvoices();
                payload.finance_invoices = invoices;
                stats.invoices = invoices.length;
            } catch (e) {
                console.warn('Backup: Failed to fetch invoices', e);
                payload.finance_invoices = [];
            }
        }

        if (modules.includes('audit_logs')) {
            try {
                const { data } = await supabase
                    .from('audit_logs')
                    .select('*')
                    .order('created_at', { ascending: false })
                    .limit(5000);
                payload.audit_logs = data || [];
                stats.auditLogs = (data || []).length;
            } catch (e) {
                console.warn('Backup: Failed to fetch audit logs', e);
                payload.audit_logs = [];
            }
        }

        if (modules.includes('settings')) {
            try {
                // Gather all localStorage settings
                const settingsKeys = [
                    'globalworkforce_gemini_api_key',
                    'suhara_security_config',
                    'suhara_auto_backup_interval',
                    'suhara_last_auto_backup'
                ];
                const settings: Record<string, any> = {};
                settingsKeys.forEach(key => {
                    const val = localStorage.getItem(key);
                    if (val) settings[key] = val;
                });
                payload.settings = settings;
                stats.settings = Object.keys(settings).length;
            } catch (e) {
                console.warn('Backup: Failed to fetch settings', e);
                payload.settings = {};
            }
        }

        if (modules.includes('profiles')) {
            try {
                const { data } = await supabase
                    .from('profiles')
                    .select('*');
                payload.profiles = data || [];
            } catch (e) {
                console.warn('Backup: Failed to fetch profiles', e);
                payload.profiles = [];
            }
        }

        // ── Build Manifest ──
        const payloadStr = JSON.stringify(payload);
        const checksum = await this.generateChecksum(payloadStr);
        const id = `bkp_${Date.now()}_${Math.random().toString(36).substring(2, 8)}`;

        const manifest: BackupManifest = {
            id,
            version: BACKUP_SCHEMA_VERSION,
            appVersion: APP_VERSION,
            createdAt: new Date().toISOString(),
            createdBy,
            label,
            description,
            checksum,
            modules,
            stats,
            sizeBytes: new Blob([payloadStr]).size,
            isAutoBackup,
            tags
        };

        const backup: BackupData = { manifest, payload };

        // ── Store Backup ──
        await this.storeBackup(backup);

        // ── Log to audit ──
        AuditService.log('SYSTEM_BACKUP_CREATED', {
            backupId: id,
            label,
            modules,
            stats,
            isAutoBackup,
            sizeBytes: manifest.sizeBytes
        });

        return backup;
    }

    // ═══════════════════════════════════════════
    //  RESTORE BACKUP
    // ═══════════════════════════════════════════

    /**
     * Restores a backup by its ID.
     * Supports selective module restore and automatic pre-restore backup.
     */
    static async restoreBackup(
        backupId: string,
        options: {
            modules?: BackupModule[];
            createPreRestoreBackup?: boolean;
            createdBy?: string;
        } = {}
    ): Promise<RestoreResult> {

        const {
            modules,
            createPreRestoreBackup = true,
            createdBy = 'System'
        } = options;

        const result: RestoreResult = {
            success: false,
            modulesRestored: [],
            errors: [],
            warnings: [],
            restoredAt: new Date().toISOString(),
            rollbackAvailable: false
        };

        // 1. Load the backup
        const backup = await this.loadBackup(backupId);
        if (!backup) {
            result.errors.push('Backup not found');
            return result;
        }

        // 2. Verify integrity
        const payloadStr = JSON.stringify(backup.payload);
        const currentChecksum = await this.generateChecksum(payloadStr);
        if (currentChecksum !== backup.manifest.checksum) {
            result.warnings.push('Backup integrity check failed — checksum mismatch. Proceeding with caution.');
        }

        // 3. Version compatibility check
        const backupVersion = backup.manifest.version;
        if (!this.isVersionCompatible(backupVersion)) {
            result.errors.push(`Backup version ${backupVersion} is not compatible with current schema version ${BACKUP_SCHEMA_VERSION}`);
            return result;
        }

        // 4. Create a pre-restore safety backup
        if (createPreRestoreBackup) {
            try {
                await this.createBackup({
                    label: `Pre-restore safety backup (before restoring ${backup.manifest.label})`,
                    description: `Automatic safety backup created before restoring backup "${backup.manifest.label}"`,
                    isAutoBackup: true,
                    createdBy,
                    tags: ['pre-restore', 'safety']
                });
                result.rollbackAvailable = true;
            } catch (e) {
                result.warnings.push('Could not create pre-restore safety backup');
            }
        }

        // 5. Determine which modules to restore
        const modulesToRestore = modules || backup.manifest.modules;

        // 6. Restore each module
        for (const mod of modulesToRestore) {
            try {
                const data = backup.payload[mod as keyof typeof backup.payload];
                if (!data) {
                    result.warnings.push(`Module "${mod}" not found in backup payload`);
                    continue;
                }

                await this.restoreModule(mod, data);
                result.modulesRestored.push(mod);
            } catch (e: any) {
                result.errors.push(`Failed to restore module "${mod}": ${e.message || e}`);
            }
        }

        // 7. Update history
        const history = this.getBackupHistory();
        const entry = history.find(h => h.id === backupId);
        if (entry) {
            entry.restoredAt = result.restoredAt;
            this.saveBackupHistory(history);
        }

        result.success = result.errors.length === 0;

        // 8. Audit log
        AuditService.log('SYSTEM_BACKUP_RESTORED', {
            backupId,
            modulesRestored: result.modulesRestored,
            errors: result.errors,
            warnings: result.warnings
        });

        return result;
    }

    /**
     * Restores a single module from backup data.
     */
    private static async restoreModule(module: BackupModule, data: any): Promise<void> {
        switch (module) {
            case 'candidates': {
                // Upsert candidates to Supabase
                if (Array.isArray(data)) {
                    for (const candidate of data) {
                        try {
                            const row = CandidateService.mapCandidateToRow(candidate);
                            await supabase.from('candidates').upsert(row, { onConflict: 'id' });
                        } catch (e) {
                            console.warn('Restore: Failed to upsert candidate', candidate.id, e);
                        }
                    }
                }
                break;
            }
            case 'jobs': {
                if (Array.isArray(data)) {
                    for (const job of data) {
                        const dbJob = {
                            id: job.id,
                            title: job.title,
                            company: job.company,
                            location: job.location,
                            salary_range: job.salaryRange,
                            type: job.type,
                            description: job.description,
                            status: job.status,
                            posted_date: job.postedDate,
                            employer_id: job.employerId,
                            data: {
                                requirements: job.requirements,
                                matchedCandidateIds: job.matchedCandidateIds,
                                category: job.category,
                                positions: job.positions,
                                filledPositions: job.filledPositions,
                                deadline: job.deadline,
                                demandOrderId: job.demandOrderId,
                                contactPerson: job.contactPerson,
                                benefits: job.benefits
                            }
                        };
                        await supabase.from('jobs').upsert(dbJob, { onConflict: 'id' });
                    }
                }
                break;
            }
            case 'employers': {
                if (Array.isArray(data)) {
                    for (const emp of data) {
                        const dbEmp = {
                            id: emp.id,
                            name: emp.companyName,
                            location: emp.country,
                            contact_person: emp.contactPerson,
                            email: emp.email,
                            phone: emp.phone,
                            status: emp.status,
                            data: {
                                regNumber: emp.regNumber,
                                website: emp.website,
                                joinedDate: emp.joinedDate,
                                commissionPerHire: emp.commissionPerHire,
                                paymentTermDays: emp.paymentTermDays,
                                quotaTotal: emp.quotaTotal,
                                quotaUsed: emp.quotaUsed,
                                selectionRatio: emp.selectionRatio,
                                documents: emp.documents,
                                activityLog: emp.activityLog,
                                notes: emp.notes
                            }
                        };
                        await supabase.from('employers').upsert(dbEmp, { onConflict: 'id' });
                    }
                }
                break;
            }
            case 'finance_transactions': {
                if (Array.isArray(data)) {
                    for (const tx of data) {
                        await supabase.from('finance_transactions').upsert(tx, { onConflict: 'id' });
                    }
                }
                break;
            }
            case 'finance_invoices': {
                if (Array.isArray(data)) {
                    for (const inv of data) {
                        await supabase.from('invoices').upsert(inv, { onConflict: 'id' });
                    }
                }
                break;
            }
            case 'audit_logs': {
                if (Array.isArray(data)) {
                    for (const log of data) {
                        await supabase.from('audit_logs').upsert(log, { onConflict: 'id' });
                    }
                }
                break;
            }
            case 'settings': {
                if (data && typeof data === 'object') {
                    Object.entries(data).forEach(([key, value]) => {
                        if (typeof value === 'string') {
                            localStorage.setItem(key, value);
                        }
                    });
                }
                break;
            }
            case 'profiles': {
                if (Array.isArray(data)) {
                    for (const profile of data) {
                        await supabase.from('profiles').upsert(profile, { onConflict: 'id' });
                    }
                }
                break;
            }
        }
    }

    // ═══════════════════════════════════════════
    //  EXPORT / IMPORT (File-Based)
    // ═══════════════════════════════════════════

    /**
     * Exports a backup as a downloadable JSON file.
     */
    static exportBackupToFile(backup: BackupData): void {
        const json = JSON.stringify(backup, null, 2);
        const blob = new Blob([json], { type: 'application/json' });
        const url = URL.createObjectURL(blob);

        const a = document.createElement('a');
        a.href = url;
        a.download = `suhara-backup-${backup.manifest.id}-${new Date().toISOString().split('T')[0]}.json`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    }

    /**
     * Downloads a backup from storage as a file.
     */
    static async downloadBackup(backupId: string): Promise<boolean> {
        const backup = await this.loadBackup(backupId);
        if (!backup) return false;
        this.exportBackupToFile(backup);
        return true;
    }

    /**
     * Imports a backup from a JSON file.
     * Validates format, version, and checksum before importing.
     */
    static async importBackupFromFile(file: File): Promise<{ success: boolean; backup?: BackupData; error?: string }> {
        try {
            const text = await file.text();
            const backup: BackupData = JSON.parse(text);

            // Validate structure
            if (!backup.manifest || !backup.payload) {
                return { success: false, error: 'Invalid backup file format: missing manifest or payload' };
            }

            if (!backup.manifest.id || !backup.manifest.version) {
                return { success: false, error: 'Invalid backup manifest: missing id or version' };
            }

            // Version check
            if (!this.isVersionCompatible(backup.manifest.version)) {
                return {
                    success: false,
                    error: `Backup version ${backup.manifest.version} is not compatible with current version ${BACKUP_SCHEMA_VERSION}`
                };
            }

            // Verify checksum
            const payloadStr = JSON.stringify(backup.payload);
            const computedChecksum = await this.generateChecksum(payloadStr);
            if (computedChecksum !== backup.manifest.checksum) {
                // Don't block — just warn. The backup might have been manually edited
                console.warn('Imported backup checksum mismatch — file may have been modified');
            }

            // Recalculate size
            backup.manifest.sizeBytes = new Blob([payloadStr]).size;

            // Store it
            await this.storeBackup(backup);

            AuditService.log('SYSTEM_BACKUP_IMPORTED', {
                backupId: backup.manifest.id,
                label: backup.manifest.label,
                originalDate: backup.manifest.createdAt
            });

            return { success: true, backup };
        } catch (e: any) {
            return { success: false, error: e.message || 'Failed to parse backup file' };
        }
    }

    // ═══════════════════════════════════════════
    //  BACKUP HISTORY & STORAGE
    // ═══════════════════════════════════════════

    /**
     * Gets the history of all backups (metadata only).
     */
    static getBackupHistory(): BackupHistoryEntry[] {
        try {
            const raw = localStorage.getItem(BACKUP_HISTORY_KEY);
            return raw ? JSON.parse(raw) : [];
        } catch {
            return [];
        }
    }

    /**
     * Saves backup history to localStorage.
     */
    private static saveBackupHistory(history: BackupHistoryEntry[]): void {
        localStorage.setItem(BACKUP_HISTORY_KEY, JSON.stringify(history));
    }

    /**
     * Stores a full backup (metadata + data). Data goes to IndexedDB, history goes to localStorage.
     */
    private static async storeBackup(backup: BackupData): Promise<void> {
        const key = BACKUP_DATA_PREFIX + backup.manifest.id;
        try {
            await set(key, backup);
        } catch (e) {
            console.warn('IndexedDB full or error, removing oldest backup...');
            await this.removeOldestBackup();
            try {
                await set(key, backup);
            } catch (e2) {
                console.error('Failed to store backup even after cleanup', e2);
            }
        }

        // Update history synchronously in LocalStorage
        const history = this.getBackupHistory();
        const entry: BackupHistoryEntry = {
            id: backup.manifest.id,
            label: backup.manifest.label,
            createdAt: backup.manifest.createdAt,
            createdBy: backup.manifest.createdBy,
            modules: backup.manifest.modules,
            stats: backup.manifest.stats,
            sizeBytes: backup.manifest.sizeBytes,
            isAutoBackup: backup.manifest.isAutoBackup,
            checksum: backup.manifest.checksum,
            tags: backup.manifest.tags,
            description: backup.manifest.description
        };

        const filtered = history.filter(h => h.id !== entry.id);
        filtered.unshift(entry); // newest first
        this.saveBackupHistory(filtered.slice(0, 50));
    }

    /**
     * Loads a full backup by ID from IndexedDB.
     */
    static async loadBackup(backupId: string): Promise<BackupData | null> {
        try {
            const backup = await get<BackupData>(BACKUP_DATA_PREFIX + backupId);
            return backup || null;
        } catch {
            return null;
        }
    }

    /**
     * Deletes a backup by ID.
     */
    static async deleteBackup(backupId: string): Promise<boolean> {
        try {
            await del(BACKUP_DATA_PREFIX + backupId);
            const history = this.getBackupHistory().filter(h => h.id !== backupId);
            this.saveBackupHistory(history);

            AuditService.log('SYSTEM_BACKUP_DELETED', { backupId });
            return true;
        } catch {
            return false;
        }
    }

    /**
     * Removes the oldest backup to free space.
     */
    private static async removeOldestBackup(): Promise<void> {
        const history = this.getBackupHistory();
        if (history.length > 0) {
            const oldest = history[history.length - 1];
            await this.deleteBackup(oldest.id);
        }
    }

    // ═══════════════════════════════════════════
    //  COMPARISON / DIFF
    // ═══════════════════════════════════════════

    /**
     * Compares a backup's contents with the current live data.
     */
    static async compareWithCurrent(backupId: string): Promise<BackupDiff[]> {
        const backup = await this.loadBackup(backupId);
        if (!backup) return [];

        const diffs: BackupDiff[] = [];

        // Compare candidates
        if (backup.payload.candidates) {
            const currentCandidates = await CandidateService.getCandidates();
            const backupIds = new Set(backup.payload.candidates.map((c: any) => c.id));
            const currentIds = new Set(currentCandidates.map(c => c.id));

            diffs.push({
                module: 'candidates',
                added: [...currentIds].filter(id => !backupIds.has(id)).length,
                removed: [...backupIds].filter(id => !currentIds.has(id)).length,
                modified: [...currentIds].filter(id => backupIds.has(id)).length,
                unchanged: 0 // Simplified — would need deep comparison for accuracy
            });
        }

        // Compare jobs
        if (backup.payload.jobs) {
            const currentJobs = await JobService.getJobs();
            const backupIds = new Set(backup.payload.jobs.map((j: any) => j.id));
            const currentIds = new Set(currentJobs.map(j => j.id));

            diffs.push({
                module: 'jobs',
                added: [...currentIds].filter(id => !backupIds.has(id)).length,
                removed: [...backupIds].filter(id => !currentIds.has(id)).length,
                modified: [...currentIds].filter(id => backupIds.has(id)).length,
                unchanged: 0
            });
        }

        // Compare employers
        if (backup.payload.employers) {
            const currentEmployers = await PartnerService.getEmployers();
            const backupIds = new Set(backup.payload.employers.map((e: any) => e.id));
            const currentIds = new Set(currentEmployers.map(e => e.id));

            diffs.push({
                module: 'employers',
                added: [...currentIds].filter(id => !backupIds.has(id)).length,
                removed: [...backupIds].filter(id => !currentIds.has(id)).length,
                modified: [...currentIds].filter(id => backupIds.has(id)).length,
                unchanged: 0
            });
        }

        return diffs;
    }

    // ═══════════════════════════════════════════
    //  AUTO-BACKUP SCHEDULING
    // ═══════════════════════════════════════════

    /**
     * Gets the auto-backup interval in hours (0 = disabled).
     */
    static getAutoBackupInterval(): number {
        const val = localStorage.getItem(AUTO_BACKUP_INTERVAL_KEY);
        return val ? parseInt(val, 10) : 0;
    }

    /**
     * Sets the auto-backup interval in hours (0 = disabled).
     */
    static setAutoBackupInterval(hours: number): void {
        localStorage.setItem(AUTO_BACKUP_INTERVAL_KEY, String(hours));
    }

    /**
     * Gets the timestamp of the last auto-backup.
     */
    static getLastAutoBackupTime(): string | null {
        return localStorage.getItem(LAST_AUTO_BACKUP_KEY);
    }

    /**
     * Checks if an auto-backup is due and creates one if needed.
     */
    static async checkAndRunAutoBackup(): Promise<boolean> {
        const interval = this.getAutoBackupInterval();
        if (interval <= 0) return false;

        const lastBackup = this.getLastAutoBackupTime();
        const now = Date.now();

        if (!lastBackup || (now - new Date(lastBackup).getTime()) >= interval * 60 * 60 * 1000) {
            try {
                await this.createBackup({
                    label: `Auto-backup ${new Date().toLocaleDateString()} ${new Date().toLocaleTimeString()}`,
                    description: 'Automatic scheduled backup',
                    isAutoBackup: true,
                    createdBy: 'Auto-Scheduler',
                    tags: ['auto', 'scheduled']
                });
                localStorage.setItem(LAST_AUTO_BACKUP_KEY, new Date().toISOString());
                return true;
            } catch (e) {
                console.error('Auto-backup failed:', e);
                return false;
            }
        }

        return false;
    }

    // ═══════════════════════════════════════════
    //  UTILITIES
    // ═══════════════════════════════════════════

    /**
     * Generates a SHA-256 checksum of the given string.
     */
    private static async generateChecksum(data: string): Promise<string> {
        try {
            const encoder = new TextEncoder();
            const dataBuffer = encoder.encode(data);
            const hashBuffer = await crypto.subtle.digest('SHA-256', dataBuffer);
            const hashArray = Array.from(new Uint8Array(hashBuffer));
            return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
        } catch {
            // Fallback for environments without crypto.subtle
            let hash = 0;
            for (let i = 0; i < data.length; i++) {
                const char = data.charCodeAt(i);
                hash = ((hash << 5) - hash) + char;
                hash = hash & hash; // Convert to 32bit integer
            }
            return Math.abs(hash).toString(16).padStart(8, '0');
        }
    }

    /**
     * Checks version compatibility using semver-light logic.
     * Major version must match. Minor/patch can differ.
     */
    private static isVersionCompatible(backupVersion: string): boolean {
        const [backupMajor] = backupVersion.split('.').map(Number);
        const [currentMajor] = BACKUP_SCHEMA_VERSION.split('.').map(Number);
        return backupMajor === currentMajor;
    }

    /**
     * Formats bytes into human readable format.
     */
    static formatBytes(bytes: number): string {
        if (bytes === 0) return '0 B';
        const k = 1024;
        const sizes = ['B', 'KB', 'MB', 'GB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
    }

    /**
     * Gets total storage used by backups.
     */
    static getStorageUsed(): { used: number; count: number } {
        const history = this.getBackupHistory();
        const used = history.reduce((acc, h) => acc + h.sizeBytes, 0);
        return { used, count: history.length };
    }
}

import {
    Candidate,
    WorkflowStage,
    StageStatus,
    TimelineEvent,
    CandidateComment,
    ComplianceFlag
} from '../types';
import { supabase } from './supabase';
import { logger } from './loggerService';
import WorkflowEngine from './workflowEngine.v2';
import { OfflineSyncService } from './offlineSyncService';
import { AuditService } from './auditService';
import { DataSyncService } from './dataSyncService';


export class CandidateService {

    private static _candidatesCache: Candidate[] | null = null;
    private static _candidatesCacheTime: number = 0;

    // Fetch all candidates from Supabase (Used for Dashboard/Pipeline where aggregations are needed)
    static async getCandidates(forceRefresh: boolean = false): Promise<Candidate[]> {
        if (!forceRefresh && this._candidatesCache && Date.now() - this._candidatesCacheTime < 60000) {
            return this._candidatesCache;
        }

        const { data, error } = await supabase
            .from('candidates')
            .select('*')
            .order('updated_at', { ascending: false });

        if (error) {
            logger.error('Error fetching candidates:', error);
            return [];
        }

        this._candidatesCache = (data || []).map(row => this.mapRowToCandidate(row));
        this._candidatesCacheTime = Date.now();
        return this._candidatesCache;
    }

    // Server-side paginated & filtered search for CandidateList
    static async searchCandidates(
        limit: number = 50,
        offset: number = 0,
        filters?: {
            status?: string | 'ALL',
            stage?: WorkflowStage | 'ALL',
            query?: string,
            countries?: string[]
        }
    ): Promise<{ candidates: Candidate[], count: number }> {
        let queryBuilder = supabase
            .from('candidates')
            .select('*', { count: 'exact' });

        if (filters?.stage && filters.stage !== 'ALL') {
            queryBuilder = queryBuilder.eq('stage', filters.stage);
        }

        if (filters?.status && filters.status !== 'ALL') {
            if (filters.status === 'COMPLETE') {
                queryBuilder = queryBuilder.or('data->>profileCompletionStatus.eq.COMPLETE,data->profileCompletionPercentage.gte.75');
            } else if (filters.status === 'PARTIAL') {
                queryBuilder = queryBuilder.or('and(data->>profileCompletionStatus.eq.PARTIAL,data->profileCompletionPercentage.lt.75)');
            } else {
                queryBuilder = queryBuilder.contains('data', { profileCompletionStatus: filters.status });
            }
        }

        if (filters?.query) {
            const q = filters.query.trim();
            if (q.startsWith('"') && q.endsWith('"')) {
                // Exact match mode (SURGICAL)
                const exact = q.slice(1, -1);
                queryBuilder = queryBuilder.or(`candidate_code.ilike.${exact},data->>regNo.ilike.${exact},nic.ilike.${exact}`);
            } else {
                // Fuzzy match mode prioritizing REG NO
                const searchTerm = `%${q}%`;
                queryBuilder = queryBuilder.or(`candidate_code.ilike.${searchTerm},data->>regNo.ilike.${searchTerm},name.ilike.${searchTerm},nic.ilike.${searchTerm},phone.ilike.${searchTerm}`);
            }
        }

        if (filters?.countries && filters.countries.length > 0) {
            // Use 'OR' logic for countries: show candidates matching ANY of the selected countries
            const orFilter = filters.countries
                .map(country => `data->preferredCountries.cs.["${country}"]`)
                .join(',');
            queryBuilder = queryBuilder.or(orFilter);
        }

        const { data, error, count } = await queryBuilder
            .order('updated_at', { ascending: false })
            .range(offset, offset + limit - 1);

        if (error) {
            logger.error('Error in searchCandidates:', error);
            return { candidates: [], count: 0 };
        }

        return {
            candidates: (data || []).map(row => this.mapRowToCandidate(row)),
            count: count || 0
        };
    }

    static async getCandidate(id: string): Promise<Candidate | undefined> {
        const { data, error } = await supabase
            .from('candidates')
            .select('*')
            .eq('id', id)
            .single();

        if (error) {
            logger.error('Error fetching candidate (Supabase):', {
                code: error.code,
                message: error.message,
                details: error.details,
                id
            });
            return undefined;
        }

        return this.mapRowToCandidate(data);
    }

    // Alias for backward compatibility
    static async getCandidateById(id: string): Promise<Candidate | undefined> {
        return this.getCandidate(id);
    }
    static async createCandidate(candidateData: Partial<Candidate>): Promise<Candidate | null> {
        const id = candidateData.id || crypto.randomUUID();
        const candidateCode = candidateData.candidateCode || this.generateCandidateCode();

        const fullCandidate = {
            ...candidateData,
            id,
            candidateCode,
            regNo: candidateData.regNo || candidateCode, // REG NO defaults to candidateCode if not provided
            regDate: candidateData.regDate || new Date().toISOString(),
            updated_at: new Date().toISOString()
        };

        // Standardize data structure before saving
        const syncedCandidate = DataSyncService.fullSync(fullCandidate as any);

        const row = {
            id,
            candidate_code: candidateCode,
            name: syncedCandidate.name,
            email: syncedCandidate.email || null,
            phone: syncedCandidate.phone,
            stage: syncedCandidate.stage || WorkflowStage.REGISTERED,
            stage_status: syncedCandidate.stageStatus || StageStatus.PENDING,
            nic: syncedCandidate.nic || null,
            dob: syncedCandidate.dob || null,
            gender: syncedCandidate.gender || null,
            data: syncedCandidate,
            updated_at: new Date().toISOString()
        };

        // OPTIMISTIC OFFLINE MODE
        if (!OfflineSyncService.isAppOnline()) {
            OfflineSyncService.enqueue({ type: 'INSERT', table: 'candidates', payload: row });
            return this.mapRowToCandidate(row);
        }

        const { data, error } = await supabase
            .from('candidates')
            .insert(row)
            .select()
            .single();

        if (error) {
            logger.error('Error creating candidate:', error, { candidateData });
            // Fallback to queue if it's a network-level fetch failure
            if (error.message === 'Failed to fetch') {
                OfflineSyncService.enqueue({ type: 'INSERT', table: 'candidates', payload: row });
                return this.mapRowToCandidate(row);
            }
            throw error;
        }

        // SYSLOG: Track Audit (explicit userId for bulletproof attribution)
        const auditUserId = await AuditService.getCurrentUserId();
        AuditService.log('CANDIDATE_CREATED', { candidateId: id, name: candidateData.name, candidateCode }, auditUserId);

        this._candidatesCache = null; // Invalidate cache

        return this.mapRowToCandidate(data);
    }

    // Alias for backward compatibility
    static async addCandidate(candidate: Candidate): Promise<Candidate | null> {
        return this.createCandidate(candidate);
    }

    // Specialized quick add creation
    static async createQuickCandidate(formData: any): Promise<Candidate | null> {
        const candidateData: Partial<Candidate> = {
            ...formData,
            stage: WorkflowStage.REGISTERED,
            stageStatus: StageStatus.PENDING,
            registrationSource: 'QUICK_ADD' as any
        };
        return this.createCandidate(candidateData);
    }

    static async updateCandidate(candidate: Candidate): Promise<void> {
        // Ensure data parity before update
        const syncedCandidate = DataSyncService.fullSync(candidate);
        const row = this.mapCandidateToRow(syncedCandidate);

        // OPTIMISTIC OFFLINE MODE
        if (!OfflineSyncService.isAppOnline()) {
            OfflineSyncService.enqueue({ type: 'UPDATE', table: 'candidates', payload: { id: candidate.id, ...row } });
            return;
        }

        const { error } = await supabase
            .from('candidates')
            .update(row)
            .eq('id', candidate.id);

        if (error) {
            if (error.message === 'Failed to fetch') {
                OfflineSyncService.enqueue({ type: 'UPDATE', table: 'candidates', payload: { id: candidate.id, ...row } });
                return;
            }
            throw error;
        }

        // SYSLOG: Track Audit (explicit userId for bulletproof attribution)
        const auditUserId = await AuditService.getCurrentUserId();
        AuditService.log('CANDIDATE_UPDATED', {
            candidateId: candidate.id,
            name: candidate.name,
            candidateCode: candidate.candidateCode,
            stage: candidate.stage,
            completionRate: candidate.profileCompletionPercentage
        }, auditUserId);

        this._candidatesCache = null; // Invalidate cache
    }

    static async saveCandidates(candidates: Candidate[]): Promise<void> {
        const rows = candidates.map(c => this.mapCandidateToRow(c));
        const { error } = await supabase
            .from('candidates')
            .upsert(rows);

        if (error) {
            throw error;
        }
    }

    static async deleteCandidate(id: string): Promise<void> {
        // OPTIMISTIC OFFLINE MODE
        if (!OfflineSyncService.isAppOnline()) {
            OfflineSyncService.enqueue({ type: 'DELETE', table: 'candidates', payload: { id } });
            return;
        }

        const { error } = await supabase
            .from('candidates')
            .delete()
            .eq('id', id);

        if (error) {
            if (error.message === 'Failed to fetch') {
                OfflineSyncService.enqueue({ type: 'DELETE', table: 'candidates', payload: { id } });
                return;
            }
            throw error;
        }

        // SYSLOG: Track Audit (explicit userId for bulletproof attribution)
        const auditUserId = await AuditService.getCurrentUserId();
        AuditService.log('CANDIDATE_DELETED', { candidateId: id }, auditUserId);

        this._candidatesCache = null; // Invalidate cache
    }

    // --- Helpers for mapping between JSONB and Typed Object ---

    private static mapRowToCandidate(row: any): Candidate {
        if (!row) return {} as Candidate;

        // The 'data' column holds the complex nested structure
        const json = row.data || {};

        // Extract top-level flat fields with row-level overrides
        const name = row.name || json.name || 'Unknown Candidate';
        const email = row.email || json.email || '';
        const phone = row.phone || json.phone || '';
        const nic = row.nic || json.nic || '';
        const dob = row.dob || json.dob || '';
        const gender = row.gender || json.gender || '';

        // Construct personalInfo with fallbacks from flat fields
        const personalInfo = {
            fullName: name,
            firstName: json.firstName || '',
            middleName: json.middleName || '',
            nic,
            dob,
            gender,
            address: json.address || '',
            city: json.city || '',
            district: json.district || '',
            province: json.province || '',
            divisionalSecretariat: json.divisionalSecretariat || '',
            gsDivision: json.gsDivision || '',
            drivingLicenseNo: json.drivingLicenseNo || '',
            height: json.height,
            weight: json.weight,
            religion: json.religion || '',
            maritalStatus: json.maritalStatus || 'Single',
            spouseName: json.spouseName || '',
            fatherName: json.fatherName || '',
            motherName: json.motherName || '',
            school: json.school || '',
            ...(json.personalInfo || {}),
        };

        // Construct contactInfo with fallbacks from flat fields
        const contactInfo = {
            primaryPhone: phone,
            whatsappPhone: json.whatsapp || '',
            email,
            additionalPhones: Array.isArray(json.additionalContactNumbers) ? json.additionalContactNumbers : [],
            ...(json.contactInfo || {}),
        };

        // Construct professionalProfile with fallbacks from flat fields
        const professionalProfile = {
            jobRoles: Array.isArray(json.jobRoles) ? json.jobRoles : [],
            experienceYears: json.experienceYears || 0,
            skills: Array.isArray(json.skills) ? json.skills : [],
            education: Array.isArray(json.education) ? json.education : [],
            educationalQualifications: Array.isArray(json.educationalQualifications) ? json.educationalQualifications : [],
            employmentHistory: Array.isArray(json.employmentHistory) ? json.employmentHistory : [],
            school: json.school || '',
            ...(json.professionalProfile || {}),
        };

        const candidate = {
            ...json,
            id: row.id,
            candidateCode: row.candidate_code || json.candidateCode || 'N/A',
            regNo: json.regNo || row.candidate_code || json.candidateCode || 'N/A',
            regDate: json.regDate || row.created_at || new Date().toISOString(),
            name,
            email,
            phone,
            nic,
            dob,
            gender,
            stage: (row.stage || json.stage || WorkflowStage.REGISTERED) as WorkflowStage,
            stageStatus: (row.stage_status || json.stageStatus || StageStatus.PENDING) as StageStatus,

            // Normalized nested objects (with flat fallbacks baked in)
            personalInfo,
            contactInfo,
            professionalProfile,

            // Ensure nested objects exist
            skills: Array.isArray(json.skills) ? json.skills : [],
            preferredCountries: Array.isArray(json.preferredCountries) ? json.preferredCountries : [],
            jobRoles: Array.isArray(json.jobRoles) ? json.jobRoles : [],
            documents: Array.isArray(json.documents) ? json.documents : [],
            avatarUrl: json.avatarUrl || (Array.isArray(json.documents) ? json.documents.find((d: any) => d.type === 'Full Photo (1)' && d.status === 'Approved')?.url : undefined) || '',
            timelineEvents: Array.isArray(json.timelineEvents) ? json.timelineEvents : [],

            // Reconstruct nested stageData if missing
            stageData: {
                paymentHistory: [],
                ...(json.stageData || {})
            },

            // Ensure ID matches and audit dates are fresh from DB
            audit: {
                createdAt: row.created_at || new Date().toISOString(),
                updatedAt: row.updated_at || new Date().toISOString(),
                ...(json.audit || {})
            }
        };

        // FINAL SYNC PASS: Ensure any mismatches between row and json are resolved
        return DataSyncService.fullSync(candidate);
    }

    static mapCandidateToRow(candidate: Candidate): any {
        return {
            id: candidate.id,
            candidate_code: candidate.candidateCode,
            name: candidate.name,
            email: candidate.email,
            phone: candidate.phone,
            stage: candidate.stage,
            stage_status: candidate.stageStatus,
            nic: candidate.nic || null,
            dob: candidate.dob || null,
            gender: candidate.gender || null,
            data: candidate, // Store full object in JSONB for schema flexibility
            updated_at: new Date().toISOString()
        };
    }

    // --- Helper for generating codes ---
    static generateCandidateCode(): string {
        const year = new Date().getFullYear();
        const random = Math.floor(1000 + Math.random() * 9000);
        return `GW-${year}-${random}`;
    }

    static async addComment(candidateId: string, author: string, text: string, isInternal: boolean = true): Promise<void> {
        const candidate = await this.getCandidate(candidateId);
        if (!candidate) return;

        const newComment: CandidateComment = {
            id: `msg-${Date.now()}`,
            candidateId,
            author,
            text,
            timestamp: new Date().toISOString(),
            isInternal
        };

        candidate.comments = [newComment, ...(candidate.comments || [])];
        await this.updateCandidate(candidate);

        // Also log as timeline event for audit trail
        await this.addTimelineEvent(candidateId, {
            type: 'SYSTEM',
            title: isInternal ? 'Internal Comment Added' : 'Comment Added',
            description: `Author: ${author} - Content: ${text.substring(0, 50)}${text.length > 50 ? '...' : ''}`,
            actor: author
        });
    }

    static async addComplianceFlag(candidateId: string, flag: Partial<ComplianceFlag>): Promise<void> {
        const candidate = await this.getCandidate(candidateId);
        if (!candidate) return;

        const newFlag: ComplianceFlag = {
            id: `flag-${Date.now()}`,
            type: flag.type || 'OTHER',
            severity: flag.severity || 'WARNING',
            reason: flag.reason || 'No reason provided',
            createdBy: flag.createdBy || 'System',
            createdAt: new Date().toISOString(),
            isResolved: false,
            ...flag
        } as ComplianceFlag;

        candidate.complianceFlags = [newFlag, ...(candidate.complianceFlags || [])];
        await this.updateCandidate(candidate);

        // Also log as timeline event
        await this.addTimelineEvent(candidateId, {
            type: flag.severity === 'CRITICAL' ? 'ALERT' : 'SYSTEM',
            title: `Compliance Flag Added: ${flag.type}`,
            description: flag.reason,
            actor: flag.createdBy,
            isCritical: flag.severity === 'CRITICAL'
        });
    }

    static async resolveComplianceFlag(candidateId: string, flagId: string, notes: string, resolvedBy: string): Promise<void> {
        const candidate = await this.getCandidate(candidateId);
        if (!candidate) return;

        candidate.complianceFlags = (candidate.complianceFlags || []).map(f => {
            if (f.id === flagId) {
                return {
                    ...f,
                    isResolved: true,
                    resolvedAt: new Date().toISOString(),
                    resolvedBy,
                    resolutionNotes: notes
                };
            }
            return f;
        });

        await this.updateCandidate(candidate);

        // Also log as timeline event
        await this.addTimelineEvent(candidateId, {
            type: 'SYSTEM',
            title: `Compliance Flag Resolved`,
            description: notes,
            actor: resolvedBy
        });
    }

    // --- Helper for adding timeline events ---
    static async addTimelineEvent(candidateId: string, event: Partial<TimelineEvent>): Promise<void> {
        const candidate = await this.getCandidate(candidateId);
        if (!candidate) return;

        const newEvent: TimelineEvent = {
            id: `evt-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
            timestamp: new Date().toISOString(),
            type: event.type || 'SYSTEM',
            title: event.title || 'Action Performed',
            description: event.description || '',
            actor: event.actor || 'System',
            userId: event.userId,
            stage: candidate.stage,
            metadata: event.metadata
        };

        candidate.timelineEvents = [newEvent, ...(candidate.timelineEvents || [])];
        await this.updateCandidate(candidate);
    }

    // --- Workflow Integration methods ---

    static async advanceStage(candidateId: string, userId: string, reason?: string): Promise<{ success: boolean, error?: string }> {
        const candidate = await this.getCandidate(candidateId);
        if (!candidate) return { success: false, error: 'Candidate not found' };

        const nextStage = WorkflowEngine.getNextStage(candidate.stage);
        if (!nextStage) return { success: false, error: 'No next stage available' };

        const result = WorkflowEngine.performTransition(candidate, nextStage, userId, reason);
        if (!result.success) return { success: false, error: result.error };

        candidate.stage = nextStage;
        candidate.stageEnteredAt = new Date().toISOString();
        if (result.event) {
            candidate.timelineEvents = [result.event as any, ...(candidate.timelineEvents || [])];
        }
        await this.updateCandidate(candidate);
        return { success: true };
    }

    static async rollbackStage(candidateId: string, toStage: WorkflowStage, userId: string, reason: string): Promise<{ success: boolean, error?: string }> {
        const candidate = await this.getCandidate(candidateId);
        if (!candidate) return { success: false, error: 'Candidate not found' };

        const result = WorkflowEngine.performTransition(candidate, toStage, userId, reason);
        if (!result.success) return { success: false, error: result.error };

        candidate.stage = toStage;
        candidate.stageEnteredAt = new Date().toISOString();
        if (result.event) {
            candidate.timelineEvents = [result.event as any, ...(candidate.timelineEvents || [])];
        }
        await this.updateCandidate(candidate);
        return { success: true };
    }
}

import { supabase, getCurrentUser } from './supabase';
import { ChatChannel, ChatMessage, ChatUser, ChatMessageContext, ChatNotification, ChatAttachment, MessageReaction } from '../types';
import { UserService } from './userService';
import { AuditService } from './auditService';

const STORAGE_KEY_CHANNELS = 'caditare_chat_channels_v2';

interface IChatService {
    getChannels: (currentUserRole?: string) => Promise<ChatChannel[]>;
    getUsers: () => Promise<ChatUser[]>;
    getMessages: (channelId: string, options?: { limit?: number; offset?: number }) => Promise<{ messages: ChatMessage[], hasMore: boolean }>;
    sendMessage: (channelId: string, text: string, senderId: string, senderName: string, context?: ChatMessageContext, attachments?: ChatAttachment[]) => Promise<ChatMessage>;
    systemPost: (channelId: string, text: string, context?: ChatMessageContext) => Promise<ChatMessage>;
    createChannel: (name: string, type: 'public' | 'private', allowedRoles?: string[]) => Promise<ChatChannel>;
    updateChannel: (channelId: string, updates: Partial<ChatChannel>) => Promise<ChatChannel | undefined>;
    deleteChannel: (channelId: string) => Promise<boolean>;
    getDmChannelId: (userId1: string, userId2?: string) => string;
    getChannelDisplay: (channelId: string, users: ChatUser[], currentUserId?: string) => { name: string; avatar?: string; isUser: boolean; status?: string };
    getNotifications: () => Promise<ChatNotification[]>;
    markNotificationRead: (id: string) => Promise<void>;
    markAllNotificationsRead: () => Promise<void>;
    markChannelAsRead: (channelId: string) => void;
    addReaction: (channelId: string, messageId: string, emoji: string) => Promise<void>;
    removeReaction: (channelId: string, messageId: string, emoji: string) => Promise<void>;
    on: (event: string, callback: Function) => void;
    off: (event: string, callback: Function) => void;
    emit: (event: string, data?: any) => void;
    isConnected: () => boolean;
    startTyping: (channelId: string) => void;
    stopTyping: (channelId: string) => void;
    joinChannel: (channelId: string) => void;
    leaveChannel: (channelId: string) => void;
    subscribeToMessages: (channelId: string, callback: (payload: any) => void) => () => void;
    initialize: () => void;
}

// Add Socket.IO style event emitters to the service
const eventListeners: Map<string, Set<Function>> = new Map();

// Helper to map DB row to ChatMessage
const mapRowToMessage = (row: any): ChatMessage => ({
    id: row.id,
    channelId: row.channel_id,
    text: row.text,
    senderId: row.sender_id,
    senderName: row.sender_name,
    timestamp: row.timestamp,
    attachments: row.attachments || [],
    context: row.context,
    isMe: false, // determined at call time if needed, or by component
    isSystem: row.sender_id === 'system' || row.sender_id === '00000000-0000-0000-0000-000000000000',
    reactions: [] // Reactions logic would go here if persisted
});

let isInitialized = false;

export const ChatService: IChatService = {
    initialize: () => {
        if (isInitialized) return;
        isInitialized = true;

        // Subscribe to global notifications for the current user
        // We can't easily filter by auth.uidIn realtime unless we use RLS and row level changes.
        // Assuming RLS is on, we receive what we are allowed to see.
        supabase
            .channel('global_notifications')
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'notifications',
                },
                (payload) => {
                    const n = payload.new;
                    // Check if it's a chat notification type
                    if (['mention', 'reply', 'channel_invite', 'system'].includes(n.type)) {
                        const chatNotif: ChatNotification = {
                            id: n.id,
                            userId: n.user_id,
                            channelId: n.metadata?.channelId || '',
                            messageId: n.metadata?.messageId,
                            title: n.title,
                            message: n.message,
                            type: n.type as any,
                            isRead: n.is_read,
                            createdAt: n.created_at
                        };
                        ChatService.emit('notification:new', chatNotif);
                    }
                }
            )
            .subscribe();
    },

    getChannels: async (currentUserRole?: string): Promise<ChatChannel[]> => {
        const { data, error } = await supabase
            .from('chat_channels')
            .select('*');

        if (error) {
            console.error('Error fetching channels:', error);
            return [];
        }

        let channels: ChatChannel[] = (data || []).map(c => ({
            id: c.id,
            name: c.name,
            type: c.type || 'public',
            unreadCount: 0, // Simplified for now, real unread count requires joining chat_reads
            allowedRoles: c.allowed_roles
        }));

        // Fallback/Seed for dev if empty
        if (channels.length === 0) {
            const seedRows = [
                { id: 'c1', name: 'General', type: 'public' },
                { id: 'c2', name: 'Announcements', type: 'public' },
                { id: 'c3', name: 'Visa Processing', type: 'public' },
                { id: 'c4', name: 'Management', type: 'private', allowed_roles: ['Admin', 'Manager', 'HR Manager'] },
            ];
            await supabase.from('chat_channels').insert(seedRows);
            channels = seedRows.map(c => ({
                id: c.id,
                name: c.name,
                type: c.type as 'public' | 'private',
                unreadCount: 0,
                allowedRoles: (c as any).allowed_roles
            }));
        }

        // FRICTIONLESS: RBAC channel filtering bypassed — all channels visible to all users
        return channels;
    },

    getUsers: async (): Promise<ChatUser[]> => {
        try {
            const users = await UserService.getUsers();
            return users.map(u => ({
                id: u.id,
                name: u.name,
                avatar: u.avatar,
                role: u.role,
                status: u.status === 'Active' ? 'online' : 'offline'
            }));
        } catch (error) {
            console.error('Failed to fetch system users:', error);
            return [];
        }
    },

    getMessages: async (channelId: string, options: { limit?: number; offset?: number } = {}): Promise<{ messages: ChatMessage[], hasMore: boolean }> => {
        const { limit = 50, offset = 0 } = options;

        const { data, error, count } = await supabase
            .from('chat_messages')
            .select('*', { count: 'exact' })
            .eq('channel_id', channelId)
            .order('timestamp', { ascending: false }) // Fetch NEWEST first
            .range(offset, offset + limit - 1);

        if (error) {
            console.error('Error fetching messages:', error);
            return { messages: [], hasMore: false };
        }

        const messages: ChatMessage[] = (data || []).map(mapRowToMessage).reverse(); // Reverse back to chronological

        return {
            messages,
            hasMore: count ? (offset + limit < count) : false
        };
    },

    sendMessage: async (channelId: string, text: string, senderId: string, senderName: string, context?: ChatMessageContext, attachments?: ChatAttachment[]) => {
        // First ensure channel exists (for DMs)
        const { data: channel } = await supabase.from('chat_channels').select('id').eq('id', channelId).single();
        if (!channel) {
            await supabase.from('chat_channels').insert({
                id: channelId,
                name: channelId.startsWith('dm-') ? 'Direct Message' : channelId,
                type: channelId.startsWith('dm-') ? 'private' : 'public'
            });
        }

        const newMessageData = {
            channel_id: channelId,
            text,
            sender_id: senderId,
            sender_name: senderName,
            attachments: attachments || [],
            context: context || null
        };

        const { data, error } = await supabase
            .from('chat_messages')
            .insert(newMessageData)
            .select()
            .single();

        if (error) throw error;

        const message = mapRowToMessage(data);
        message.isMe = true;

        // Skip logging system level messages to avoid bloating the audit log excessively,
        // but log actual human team chat.
        if (senderId !== 'system' && senderId !== '00000000-0000-0000-0000-000000000000') {
            AuditService.log('TEAM_CHAT_MESSAGE_SENT', {
                channelId,
                messageId: message.id,
                hasAttachments: (attachments && attachments.length > 0)
            }, senderId);
        }

        return message;
    },

    subscribeToMessages: (channelId: string, callback: (payload: any) => void) => {
        // Ensure initialized
        ChatService.initialize();

        const channel = supabase
            .channel(`channel:${channelId}`)
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'chat_messages',
                    filter: `channel_id=eq.${channelId}`
                },
                (payload) => {
                    // Start async process to fetch sender details if needed, 
                    // but for now we map what we have.
                    // IMPORTANT: The callback likely expects a ChatMessage object, not raw row.
                    const message = mapRowToMessage(payload.new);
                    callback(message);
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    },

    // Automated System Post
    systemPost: async (channelId: string, text: string, context?: ChatMessageContext) => {
        return ChatService.sendMessage(channelId, text, '00000000-0000-0000-0000-000000000000', 'System Engine', context);
    },

    createChannel: async (name: string, type: 'public' | 'private', allowedRoles?: string[]) => {
        const id = `c-${Date.now()}`;
        const { data, error } = await supabase
            .from('chat_channels')
            .insert({
                id,
                name,
                type,
                allowed_roles: allowedRoles
            })
            .select()
            .single();

        if (error) throw error;

        return {
            id: data.id,
            name: data.name,
            type: data.type,
            unreadCount: 0,
            allowedRoles: data.allowed_roles
        };
    },

    updateChannel: async (channelId: string, updates: Partial<ChatChannel>) => {
        const { data, error } = await supabase
            .from('chat_channels')
            .update({
                name: updates.name,
                type: updates.type,
                allowed_roles: updates.allowedRoles
            })
            .eq('id', channelId)
            .select()
            .single();

        if (error) return undefined;
        return {
            id: data.id,
            name: data.name,
            type: data.type,
            unreadCount: 0,
            allowedRoles: data.allowed_roles
        };
    },

    deleteChannel: async (channelId: string) => {
        const { error } = await supabase
            .from('chat_channels')
            .delete()
            .eq('id', channelId);

        return !error;
    },

    getDmChannelId: (userId1: string, userId2?: string) => {
        if (!userId2) {
            return `dm-${userId1}`;
        }
        const ids = [userId1, userId2].sort();
        return `dm-${ids[0]}-${ids[1]}`;
    },

    getChannelDisplay: (channelId: string, users: ChatUser[], currentUserId?: string) => {
        if (channelId.startsWith('dm-')) {
            const userIds = channelId.replace('dm-', '').split('-');
            const otherUserId = userIds.find(id => id !== currentUserId) || userIds[0];
            const user = users.find(u => u.id === otherUserId);
            return {
                name: user?.name || 'Direct Message',
                avatar: user?.avatar,
                isUser: true,
                status: user?.status
            };
        }
        return { name: channelId, isUser: false };
    },

    getNotifications: async (): Promise<ChatNotification[]> => {
        ChatService.initialize();
        // Fetch from notifications table filtering by chat types
        const { data, error } = await supabase
            .from('notifications')
            .select('*')
            .in('type', ['mention', 'reply', 'channel_invite', 'system'])
            .eq('is_read', false)
            .order('created_at', { ascending: false });

        if (error || !data) return [];

        return data.map(n => ({
            id: n.id,
            userId: n.user_id,
            channelId: n.metadata?.channelId || '',
            messageId: n.metadata?.messageId,
            title: n.title,
            message: n.message,
            type: n.type as any,
            isRead: n.is_read,
            createdAt: n.created_at
        }));
    },

    markNotificationRead: async (id: string) => {
        await supabase.from('notifications').update({ is_read: true }).eq('id', id);
    },

    markAllNotificationsRead: async () => {
        const user = await getCurrentUser();
        if (user) {
            await supabase.from('notifications')
                .update({ is_read: true })
                .eq('user_id', user.id)
                .in('type', ['mention', 'reply', 'channel_invite', 'system']);
        }
    },

    markChannelAsRead: async (channelId: string) => {
        // Upsert chat_reads
        const user = await getCurrentUser();
        if (user) {
            await supabase.from('chat_reads').upsert({
                channel_id: channelId,
                user_id: user.id,
                last_read_at: new Date().toISOString()
            });
        }
    },

    addReaction: async () => { },
    removeReaction: async () => { },

    on: (event, callback) => {
        if (!eventListeners.has(event)) eventListeners.set(event, new Set());
        eventListeners.get(event)!.add(callback);
    },
    off: (event, callback) => {
        eventListeners.get(event)?.delete(callback);
    },
    emit: (event, data) => {
        eventListeners.get(event)?.forEach(cb => cb(data));
    },

    isConnected: () => !!supabase.realtime.accessToken, // weak check but better than true
    startTyping: () => { },
    stopTyping: () => { },
    joinChannel: () => { },
    leaveChannel: () => { }
};

export default ChatService;

import { Candidate, DocumentStatus, DocumentType, MedicalStatus, PassportStatus, PCCStatus, WorkflowStage, AppNotification } from '../../types';
import { ComplianceDomain, ComplianceIssue, ComplianceRuleResult, ComplianceScoreCard, ComplianceSeverity, FullComplianceReport } from './ComplianceTypes';
import { COMPLIANCE_CONSTANTS, getCountryRule } from './CountryRules';

export class ComplianceEngine {

    /**
     * Main entry point to evaluate a candidate's compliance.
     */
    static evaluateCandidate(candidate: Candidate): FullComplianceReport {
        const results: ComplianceRuleResult[] = [];
        const countryRule = getCountryRule(candidate.targetCountry || candidate.country);

        // 1. Evaluate Passport
        const passportResult = this.evaluatePassport(candidate);
        results.push(passportResult);

        // 2. Evaluate PCC
        const pccResult = this.evaluatePCC(candidate, countryRule.checksPCC);
        results.push(pccResult);

        // 3. Evaluate Medical
        const medicalResult = this.evaluateMedical(candidate, countryRule.medicalRequired);
        results.push(medicalResult);

        // 4. Evaluate Age
        const ageResult = this.evaluateAge(candidate, countryRule);
        results.push(ageResult);

        // 5. Evaluate Documents
        const docResult = this.evaluateDocuments(candidate, countryRule.mandatoryDocuments);
        results.push(...docResult);

        // 6. Evaluate Compliance Flags (New Phase 13)
        const flagResults = this.evaluateFlags(candidate);
        results.push(...flagResults);

        // Calculate Score
        const scoreCard = this.calculateScore(results);
        const isProcessable = !results.some(r => r.issue?.severity === ComplianceSeverity.CRITICAL);

        return {
            candidateId: candidate.id,
            timestamp: new Date(),
            scoreCard,
            results,
            isProcessable
        };
    }

    // --- DOMAIN EVALUATORS ---

    private static evaluatePassport(candidate: Candidate): ComplianceRuleResult {
        const data = candidate.passportData || (candidate.passports && candidate.passports.length > 0 ? candidate.passports[0] : null);
        if (!data) {
            return {
                ruleId: 'PASSPORT_MISSING',
                domain: ComplianceDomain.PASSPORT,
                passed: false,
                scoreImpact: 0,
                issue: {
                    id: 'PASSPORT_MISSING',
                    domain: ComplianceDomain.PASSPORT,
                    severity: ComplianceSeverity.CRITICAL,
                    message: 'Passport data is missing.',
                    remedy: 'Upload and enter passport details.',
                    blockingStages: [WorkflowStage.EMBASSY_APPLIED, WorkflowStage.VISA_RECEIVED, WorkflowStage.DEPARTED]
                }
            };
        }

        if (data.status === PassportStatus.EXPIRED) {
            return {
                ruleId: 'PASSPORT_EXPIRED',
                domain: ComplianceDomain.PASSPORT,
                passed: false,
                scoreImpact: 0,
                issue: {
                    id: 'PASSPORT_EXPIRED',
                    domain: ComplianceDomain.PASSPORT,
                    severity: ComplianceSeverity.CRITICAL,
                    message: `Passport expired on ${data.expiryDate}.`,
                    remedy: 'Renew passport immediately.',
                    blockingStages: [WorkflowStage.EMBASSY_APPLIED, WorkflowStage.VISA_RECEIVED, WorkflowStage.DEPARTED, WorkflowStage.SLBFE_REGISTRATION]
                }
            };
        }

        if (data.status === PassportStatus.EXPIRING) {
            return {
                ruleId: 'PASSPORT_EXPIRING',
                domain: ComplianceDomain.PASSPORT,
                passed: true, // It's technically valid but with warning
                scoreImpact: 50, // Half points
                issue: {
                    id: 'PASSPORT_EXPIRING',
                    domain: ComplianceDomain.PASSPORT,
                    severity: ComplianceSeverity.WARNING,
                    message: `Passport expires in ${data.validityDays} days(less than ${COMPLIANCE_CONSTANTS.PASSPORT_WARNING_DAYS} days).`,
                    remedy: 'Advise candidate to renew soon.',
                    blockingStages: []
                }
            };
        }

        return {
            ruleId: 'PASSPORT_VALID',
            domain: ComplianceDomain.PASSPORT,
            passed: true,
            scoreImpact: 100
        };
    }

    private static evaluatePCC(candidate: Candidate, required: boolean): ComplianceRuleResult {
        if (!required) {
            return {
                ruleId: 'PCC_NOT_REQUIRED',
                domain: ComplianceDomain.PCC,
                passed: true,
                scoreImpact: 100
            };
        }

        const data = candidate.pccData;
        if (!data) {
            return {
                ruleId: 'PCC_MISSING',
                domain: ComplianceDomain.PCC,
                passed: false,
                scoreImpact: 0,
                issue: {
                    id: 'PCC_MISSING',
                    domain: ComplianceDomain.PCC,
                    severity: ComplianceSeverity.CRITICAL,
                    message: 'Police Clearance Certificate is missing.',
                    remedy: 'Request PCC immediately.',
                    blockingStages: [WorkflowStage.EMBASSY_APPLIED, WorkflowStage.VISA_RECEIVED, WorkflowStage.SLBFE_REGISTRATION]
                }
            };
        }

        if (data.status === PCCStatus.EXPIRED) {
            return {
                ruleId: 'PCC_EXPIRED',
                domain: ComplianceDomain.PCC,
                passed: false,
                scoreImpact: 0,
                issue: {
                    id: 'PCC_EXPIRED',
                    domain: ComplianceDomain.PCC,
                    severity: ComplianceSeverity.CRITICAL,
                    message: `PCC expired(Issued > ${COMPLIANCE_CONSTANTS.PCC_EXPIRY_DAYS} days ago).`,
                    remedy: 'Obtain new PCC.',
                    blockingStages: [WorkflowStage.EMBASSY_APPLIED, WorkflowStage.VISA_RECEIVED, WorkflowStage.SLBFE_REGISTRATION]
                }
            };
        }

        if (data.status === PCCStatus.EXPIRING) {
            return {
                ruleId: 'PCC_EXPIRING',
                domain: ComplianceDomain.PCC,
                passed: true,
                scoreImpact: 50,
                issue: {
                    id: 'PCC_EXPIRING',
                    domain: ComplianceDomain.PCC,
                    severity: ComplianceSeverity.WARNING,
                    message: `PCC is aging(${data.ageDays} days old).`,
                    remedy: 'Monitor PCC validity closely.',
                    blockingStages: []
                }
            };
        }

        return {
            ruleId: 'PCC_VALID',
            domain: ComplianceDomain.PCC,
            passed: true,
            scoreImpact: 100
        };
    }

    private static evaluateMedical(candidate: Candidate, required: boolean): ComplianceRuleResult {
        const status = candidate.medicalData?.status || candidate.stageData?.medicalStatus;

        // Logic: Medical is "Process Dependent". 
        // If status is FAILED, it's CRITICAL regardless of "required" (if they took it and failed, that's bad).
        // If required and NOT_STARTED, it's a warning but not blocking *early* stages, but blocking *late* stages.

        if (status === MedicalStatus.FAILED) {
            return {
                ruleId: 'MEDICAL_FAILED',
                domain: ComplianceDomain.MEDICAL,
                passed: false,
                scoreImpact: 0,
                issue: {
                    id: 'MEDICAL_FAILED',
                    domain: ComplianceDomain.MEDICAL,
                    severity: ComplianceSeverity.CRITICAL,
                    message: 'Medical test failed.',
                    remedy: 'Candidate cannot proceed. Check if re-test is possible.',
                    blockingStages: [WorkflowStage.VISA_RECEIVED, WorkflowStage.SLBFE_REGISTRATION, WorkflowStage.DEPARTED]
                }
            };
        }

        if (required && (!status || status === MedicalStatus.NOT_STARTED)) {
            // It's okay for Registration stage, but not for Visa.
            // We'll mark it as WARNING/Info here, but specific stages will block.
            return {
                ruleId: 'MEDICAL_PENDING',
                domain: ComplianceDomain.MEDICAL,
                passed: true,
                scoreImpact: 50,
                issue: {
                    id: 'MEDICAL_PENDING',
                    domain: ComplianceDomain.MEDICAL,
                    severity: ComplianceSeverity.WARNING,
                    message: 'Medical not started.',
                    blockingStages: [WorkflowStage.VISA_RECEIVED]
                }
            };
        }

        if (status === MedicalStatus.SCHEDULED) {
            // Check if date is in past
            const scheduledDate = (candidate.medicalData?.scheduledDate || candidate.stageData?.medicalScheduledDate) ?
                new Date(candidate.medicalData?.scheduledDate || candidate.stageData?.medicalScheduledDate as string) : null;
            const now = new Date();
            if (scheduledDate && scheduledDate < now) {
                return {
                    ruleId: 'MEDICAL_OVERDUE',
                    domain: ComplianceDomain.MEDICAL,
                    passed: false,
                    scoreImpact: 20,
                    issue: {
                        id: 'MEDICAL_OVERDUE',
                        domain: ComplianceDomain.MEDICAL,
                        severity: ComplianceSeverity.WARNING,
                        message: 'Medical appointment overdue.',
                        blockingStages: []
                    }
                };
            }
        }

        if (status === MedicalStatus.COMPLETED) {
            return {
                ruleId: 'MEDICAL_COMPLETED',
                domain: ComplianceDomain.MEDICAL,
                passed: true,
                scoreImpact: 100
            };
        }

        return {
            ruleId: 'MEDICAL_STATUS_UNKNOWN',
            domain: ComplianceDomain.MEDICAL,
            passed: true,
            scoreImpact: 50
        };
    }

    private static evaluateAge(candidate: Candidate, rule: any): ComplianceRuleResult {
        // Calculate Age
        const dob = candidate.personalInfo?.dob || candidate.dob;
        if (!dob) {
            return {
                ruleId: 'DOB_MISSING',
                domain: ComplianceDomain.AGE,
                passed: false,
                scoreImpact: 0,
                issue: {
                    id: 'DOB_MISSING',
                    domain: ComplianceDomain.AGE,
                    severity: ComplianceSeverity.CRITICAL, // Cannot verify compliance
                    message: 'Date of Birth missing.',
                    blockingStages: [WorkflowStage.VERIFIED, WorkflowStage.APPLIED]
                }
            };
        }

        const birthDate = new Date(dob);
        const ageDifMs = Date.now() - birthDate.getTime();
        const ageDate = new Date(ageDifMs); // miliseconds from epoch
        const age = Math.abs(ageDate.getUTCFullYear() - 1970);

        // Determine limits
        let limits = rule.defaultAgeLimit;

        // Check specific role limits
        // Simple string match on candidate.role or jobRoles for now
        if (rule.roleSpecificAgeLimits) {
            for (const roleKey in rule.roleSpecificAgeLimits) {
                if (candidate.role?.toLowerCase().includes(roleKey.toLowerCase())) {
                    limits = rule.roleSpecificAgeLimits[roleKey];
                    break;
                }
            }
        }

        if (age < limits.min) {
            return {
                ruleId: 'AGE_TOO_YOUNG',
                domain: ComplianceDomain.AGE,
                passed: false,
                scoreImpact: 0,
                issue: {
                    id: 'AGE_TOO_YOUNG',
                    domain: ComplianceDomain.AGE,
                    severity: ComplianceSeverity.CRITICAL,
                    message: `Candidate is ${age} (Min: ${limits.min}).`,
                    blockingStages: [WorkflowStage.REGISTERED, WorkflowStage.VERIFIED, WorkflowStage.APPLIED]
                }
            };
        }

        if (age > limits.max) {
            return {
                ruleId: 'AGE_TOO_OLD',
                domain: ComplianceDomain.AGE,
                passed: false,
                scoreImpact: 0,
                issue: {
                    id: 'AGE_TOO_OLD',
                    domain: ComplianceDomain.AGE,
                    severity: ComplianceSeverity.CRITICAL,
                    message: `Candidate is ${age} (Max: ${limits.max}).`,
                    blockingStages: [WorkflowStage.REGISTERED, WorkflowStage.VERIFIED, WorkflowStage.APPLIED]
                }
            };
        }

        return {
            ruleId: 'AGE_VALID',
            domain: ComplianceDomain.AGE,
            passed: true,
            scoreImpact: 100
        };
    }

    private static evaluateDocuments(candidate: Candidate, mandatoryDocs: DocumentType[]): ComplianceRuleResult[] {
        const results: ComplianceRuleResult[] = [];

        if (!mandatoryDocs || mandatoryDocs.length === 0) return results;

        const docs = candidate.documents || [];
        const uploadedDocs = new Set(docs.map(d => d.type));
        const approvedDocs = new Set(docs.filter(d => d.status === DocumentStatus.APPROVED).map(d => d.type));

        for (const docType of mandatoryDocs) {
            if (!uploadedDocs.has(docType)) {
                results.push({
                    ruleId: `DOC_MISSING_${docType} `,
                    domain: ComplianceDomain.DOCUMENTS,
                    passed: false,
                    scoreImpact: 0,
                    issue: {
                        id: `DOC_MISSING_${docType} `,
                        domain: ComplianceDomain.DOCUMENTS,
                        severity: ComplianceSeverity.CRITICAL, // Mandatory docs prevent meaningful progress
                        message: `Missing mandatory document: ${docType} `,
                        blockingStages: [WorkflowStage.VERIFIED, WorkflowStage.APPLIED]
                    }
                });
            } else if (!approvedDocs.has(docType)) {
                // Uploaded but not approved
                results.push({
                    ruleId: `DOC_PENDING_${docType} `,
                    domain: ComplianceDomain.DOCUMENTS,
                    passed: true,
                    scoreImpact: 50,
                    issue: {
                        id: `DOC_PENDING_${docType} `,
                        domain: ComplianceDomain.DOCUMENTS,
                        severity: ComplianceSeverity.WARNING,
                        message: `Document pending approval: ${docType} `,
                        blockingStages: [WorkflowStage.VERIFIED]
                    }
                });
            } else {
                results.push({
                    ruleId: `DOC_OK_${docType} `,
                    domain: ComplianceDomain.DOCUMENTS,
                    passed: true,
                    scoreImpact: 100
                });
            }
        }

        return results;
    }

    private static evaluateFlags(candidate: Candidate): ComplianceRuleResult[] {
        const results: ComplianceRuleResult[] = [];

        if (!candidate.complianceFlags || candidate.complianceFlags.length === 0) {
            return [{
                ruleId: 'NO_FLAGS',
                domain: ComplianceDomain.FLAGS,
                passed: true,
                scoreImpact: 100
            }];
        }

        const activeFlags = candidate.complianceFlags.filter(f => !f.isResolved);

        if (activeFlags.length === 0) {
            return [{
                ruleId: 'FLAGS_RESOLVED',
                domain: ComplianceDomain.FLAGS,
                passed: true,
                scoreImpact: 100
            }];
        }

        for (const flag of activeFlags) {
            results.push({
                ruleId: `FLAG_${flag.id}`,
                domain: ComplianceDomain.FLAGS,
                passed: flag.severity !== 'CRITICAL',
                scoreImpact: flag.severity === 'CRITICAL' ? 0 : 50,
                issue: {
                    id: `FLAG_${flag.id}`,
                    domain: ComplianceDomain.FLAGS,
                    severity: flag.severity === 'CRITICAL' ? ComplianceSeverity.CRITICAL : ComplianceSeverity.WARNING,
                    message: `Compliance Flag: ${flag.reason}`,
                    remedy: 'Resolve the flag in Compliance Widget.',
                    blockingStages: flag.severity === 'CRITICAL'
                        ? Object.values(WorkflowStage) // Blocks EVERYTHING
                        : []
                }
            });
        }

        return results;
    }

    private static calculateScore(results: ComplianceRuleResult[]): ComplianceScoreCard {
        const breakdown: Record<string, { score: number; maxScore: number }> = {};
        let totalScore = 0;
        let totalMax = 0;
        let criticalCount = 0;
        let warningCount = 0;

        // Group by Domain
        const domainMap = new Map<ComplianceDomain, ComplianceRuleResult[]>();

        results.forEach(r => {
            if (!domainMap.has(r.domain)) domainMap.set(r.domain, []);
            domainMap.get(r.domain)?.push(r);

            if (r.issue?.severity === ComplianceSeverity.CRITICAL) criticalCount++;
            if (r.issue?.severity === ComplianceSeverity.WARNING) warningCount++;
        });

        // Calculate per domain
        domainMap.forEach((rules, domain) => {
            const domainTotal = rules.reduce((acc, r) => acc + r.scoreImpact, 0);
            const domainMax = rules.length * 100;

            breakdown[domain] = { score: domainTotal, maxScore: domainMax };

            totalScore += domainTotal;
            totalMax += domainMax;
        });

        // Handle missing domains (if any) with 0? No, just don't include or init them.

        const overallPercentage = totalMax > 0 ? Math.round((totalScore / totalMax) * 100) : 100;

        return {
            overallScore: overallPercentage,
            domainBreakdown: breakdown as Record<ComplianceDomain, { score: number; maxScore: number }>,
            criticalIssuesCount: criticalCount,
            warningIssuesCount: warningCount
        };
    }

    /**
     * Generates alerts based on the compliance report.
     */
    static generateAlerts(report: FullComplianceReport): AppNotification[] {
        const alerts: AppNotification[] = [];
        const now = new Date();

        report.results.forEach(result => {
            if (result.issue && (result.issue.severity === ComplianceSeverity.CRITICAL || result.issue.severity === ComplianceSeverity.WARNING)) {
                alerts.push({
                    id: `compliance - ${result.issue.id} -${report.candidateId} `,
                    type: result.issue.severity === ComplianceSeverity.CRITICAL ? 'DELAY' : 'WARNING',
                    title: `Compliance Alert: ${result.domain} `,
                    message: result.issue.message,
                    timestamp: now.toISOString(),
                    isRead: false,
                    candidateId: report.candidateId,
                    link: `/ candidates / ${report.candidateId} `
                });
            }
        });

        return alerts;
    }
}

