import { Candidate, WorkflowStage, StageStatus, ProfileCompletionStatus, RegistrationSource, PersonalInfo, ContactInfo, ProfessionalProfile } from '../types';

/**
 * DataSyncService
 * Handles bidirectional synchronization between Flat Legacy Fields and Normalized Nested Structures.
 * Ensures data integrity across forms, profile views, and services.
 */
export class DataSyncService {
    /**
     * Synchronizes flat fields TO nested structures.
     * Useful when data is coming from a form that uses flat fields (like QuickAddForm).
     */
    static syncToNested(candidate: Partial<Candidate>): Partial<Candidate> {
        const result = { ...candidate };

        // 1. Personal Info Sync
        const currentPI = result.personalInfo || {} as PersonalInfo;

        // Surname + OtherNames -> Full Name fallback
        const surname = currentPI.surname || result.surname || '';
        const otherNames = currentPI.otherNames || result.otherNames || '';
        const name = currentPI.fullName || result.name || `${otherNames} ${surname}`.trim();

        const personalInfo: PersonalInfo = {
            ...currentPI,
            fullName: name,
            surname: surname,
            otherNames: otherNames,
            firstName: currentPI.firstName || result.firstName || otherNames,
            middleName: currentPI.middleName || result.middleName || '',
            nic: currentPI.nic || result.nic || '',
            dob: currentPI.dob || result.dob || '',
            gender: currentPI.gender || result.gender || '',
            address: currentPI.address || result.address || '',
            city: currentPI.city || result.city || '',
            province: currentPI.province || result.province || '',
            district: currentPI.district || result.district || result.city || '',
            divisionalSecretariat: currentPI.divisionalSecretariat || result.divisionalSecretariat || '',
            gsDivision: currentPI.gsDivision || result.gsDivision || '',
            drivingLicenseNo: currentPI.drivingLicenseNo || result.drivingLicenseNo || '',
            nationality: currentPI.nationality || result.nationality || 'Sri Lankan',
            placeOfBirth: currentPI.placeOfBirth || result.placeOfBirth || '',
            passportProfession: currentPI.passportProfession || result.passportProfession || '',
            maritalStatus: (currentPI.maritalStatus || result.maritalStatus || 'Single') as any,
            spouseName: currentPI.spouseName || result.spouseName || '',
            fatherName: currentPI.fatherName || result.fatherName || '',
            motherName: currentPI.motherName || result.motherName || '',
        };
        result.personalInfo = personalInfo;

        // 2. Contact Info Sync
        const currentCI = result.contactInfo || {} as ContactInfo;
        const contactInfo: ContactInfo = {
            ...currentCI,
            primaryPhone: currentCI.primaryPhone || result.phone || '',
            whatsappPhone: currentCI.whatsappPhone || result.whatsapp || result.phone || '',
            email: currentCI.email || result.email || '',
            additionalPhones: currentCI.additionalPhones || result.additionalContactNumbers || (result.secondaryPhone ? [result.secondaryPhone] : [])
        };
        result.contactInfo = contactInfo;

        // 3. Professional Profile Sync
        const currentPP = result.professionalProfile || {} as ProfessionalProfile;
        const professionalProfile: ProfessionalProfile = {
            ...currentPP,
            jobRoles: currentPP.jobRoles !== undefined ? currentPP.jobRoles : (result.jobRoles || (result.position ? [result.position] : (result.role ? [result.role] : []))),
            experienceYears: currentPP.experienceYears ?? result.experienceYears,
            skills: currentPP.skills !== undefined ? currentPP.skills : (result.skills || []),
            education: currentPP.education !== undefined ? currentPP.education : (result.education || []),
            educationalQualifications: currentPP.educationalQualifications !== undefined ? currentPP.educationalQualifications : (result.educationalQualifications || []),
            employmentHistory: currentPP.employmentHistory !== undefined ? currentPP.employmentHistory : (result.employmentHistory || []),
            trainingDetails: currentPP.trainingDetails || result.trainingDetails || '',
            specialAchievements: currentPP.specialAchievements || result.specialAchievements || '',
            school: currentPP.school || result.school || ''
        };
        result.professionalProfile = professionalProfile;

        // 4. Application Intent Sync
        result.targetCountry = result.targetCountry || result.country || '';
        result.country = result.targetCountry;

        result.position = result.position || result.role || '';
        result.role = result.position;

        return result;
    }

    /**
     * Synchronizes nested structures BACK to flat fields.
     * Useful for legacy components, search indexing, or backward compatibility.
     */
    static syncToFlat(candidate: Partial<Candidate>): Partial<Candidate> {
        const result = { ...candidate };

        if (result.personalInfo) {
            const pi = result.personalInfo;
            result.name = pi.fullName || result.name || '';
            result.surname = pi.surname || result.surname || '';
            result.otherNames = pi.otherNames || result.otherNames || '';
            result.firstName = pi.firstName || result.firstName || '';
            result.nic = pi.nic || result.nic || '';
            result.dob = pi.dob || result.dob || '';
            result.gender = pi.gender || result.gender || '';
            result.address = pi.address || result.address || '';
            result.city = pi.city || result.city || '';
            result.province = pi.province || result.province || '';
            result.district = pi.district || result.district || '';
            result.divisionalSecretariat = pi.divisionalSecretariat || result.divisionalSecretariat || '';
            result.gsDivision = pi.gsDivision || result.gsDivision || '';
            result.nationality = pi.nationality || result.nationality || '';
            result.placeOfBirth = pi.placeOfBirth || result.placeOfBirth || '';
            result.passportProfession = pi.passportProfession || result.passportProfession || '';
            result.drivingLicenseNo = pi.drivingLicenseNo || result.drivingLicenseNo || '';
            result.religion = pi.religion || result.religion || '';
            result.maritalStatus = pi.maritalStatus || result.maritalStatus || 'Single';
            result.fatherName = pi.fatherName || result.fatherName || '';
            result.motherName = pi.motherName || result.motherName || '';
            result.spouseName = pi.spouseName || result.spouseName || '';
            result.school = pi.school || result.school || '';
            result.height = pi.height || result.height;
            result.weight = pi.weight || result.weight;

            // Paper form header & specific family fields
            result.companyName = (pi as any).companyName || (result as any).companyName || '';
            result.fatherAge = (pi as any).fatherAge || (result as any).fatherAge;
            result.fatherNic = (pi as any).fatherNic || (result as any).fatherNic;
            result.motherAge = (pi as any).motherAge || (result as any).motherAge;
            result.motherNic = (pi as any).motherNic || (result as any).motherNic;
            result.spouseAge = (pi as any).spouseAge || (result as any).spouseAge;
            result.spouseNic = (pi as any).spouseNic || (result as any).spouseNic;
            result.usdRateEmb = (result as any).usdRateEmb;
            result.usdRateFA = (result as any).usdRateFA;
        }

        if (result.contactInfo) {
            const ci = result.contactInfo;
            result.phone = ci.primaryPhone || result.phone || '';
            result.whatsapp = ci.whatsappPhone || result.whatsapp || '';
            result.email = ci.email || result.email || '';
            result.secondaryPhone = (ci.additionalPhones && ci.additionalPhones.length > 0) ? ci.additionalPhones[0] : (result.secondaryPhone || '');
            result.additionalContactNumbers = ci.additionalPhones || result.additionalContactNumbers || [];
        }

        if (result.professionalProfile) {
            const pp = result.professionalProfile;
            result.skills = pp.skills || result.skills || [];
            result.education = pp.education || result.education || [];
            result.experienceYears = pp.experienceYears ?? result.experienceYears;
            result.jobRoles = pp.jobRoles || result.jobRoles || [];
            result.educationalQualifications = pp.educationalQualifications || result.educationalQualifications || [];
            result.employmentHistory = pp.employmentHistory || result.employmentHistory || [];
            result.trainingDetails = pp.trainingDetails || result.trainingDetails || '';
            result.specialAchievements = pp.specialAchievements || result.specialAchievements || '';
            result.school = pp.school || result.school || '';

            // First job role title as main role
            if (pp.jobRoles && pp.jobRoles.length > 0) {
                const firstRole = pp.jobRoles[0];
                result.role = typeof firstRole === 'string' ? firstRole : firstRole.title;
            }
        }

        // Shared field sync for paper forms and specific mappings
        result.companyName = (result.personalInfo as any)?.companyName || (result as any).companyName || '';
        result.fatherAge = (result.personalInfo as any)?.fatherAge || (result as any).fatherAge;
        result.fatherNic = (result.personalInfo as any)?.fatherNic || (result as any).fatherNic;
        result.motherAge = (result.personalInfo as any)?.motherAge || (result as any).motherAge;
        result.motherNic = (result.personalInfo as any)?.motherNic || (result as any).motherNic;
        result.spouseAge = (result.personalInfo as any)?.spouseAge || (result as any).spouseAge;
        result.spouseNic = (result.personalInfo as any)?.spouseNic || (result as any).spouseNic;
        result.usdRateEmb = (result as any).usdRateEmb;
        result.usdRateFA = (result as any).usdRateFA;
        result.placeOfBirth = result.personalInfo?.placeOfBirth || result.placeOfBirth || '';
        result.passportProfession = result.personalInfo?.passportProfession || result.passportProfession || '';
        result.drivingLicenseNo = result.personalInfo?.drivingLicenseNo || result.drivingLicenseNo || '';
        result.religion = result.personalInfo?.religion || result.religion || '';
        result.weight = result.personalInfo?.weight ?? result.weight;

        // Cross-sync intention fields
        result.targetCountry = result.targetCountry || result.country || '';
        result.country = result.targetCountry;
        result.position = result.position || result.role || '';
        result.role = result.position;

        return result;
    }

    /**
     * Performs a full bidirectional sync to ensure absolute parity.
     */
    static fullSync(candidate: Partial<Candidate>): Candidate {
        // Sync to nested first (treats flat as priority if both exist but differ)
        let synced = this.syncToNested(candidate);
        // Then sync back to flat to ensure consistency
        synced = this.syncToFlat(synced);
        return synced as Candidate;
    }
}

import { DemandOrder, DemandOrderStatus, EmployerActivity } from '../types';
import { supabase } from './supabase';
import { OfflineSyncService } from './offlineSyncService';
import { AuditService } from './auditService';

export class DemandOrderService {
    private static _ordersCache: DemandOrder[] | null = null;
    private static _ordersCacheTime: number = 0;

    static async getAll(forceRefresh: boolean = false): Promise<DemandOrder[]> {
        if (!forceRefresh && this._ordersCache && Date.now() - this._ordersCacheTime < 60000) {
            return this._ordersCache;
        }

        const { data, error } = await supabase
            .from('demand_orders')
            .select('*')
            .order('created_at', { ascending: false });

        if (error) {
            console.error('Error fetching demand orders:', error);
            return [];
        }

        this._ordersCache = data.map((d: any) => this.mapDatabaseToOrder(d));
        this._ordersCacheTime = Date.now();
        return this._ordersCache;
    }

    static async getById(id: string): Promise<DemandOrder | undefined> {
        const { data, error } = await supabase
            .from('demand_orders')
            .select('*')
            .eq('id', id)
            .single();

        if (error) {
            console.error('Error fetching demand order:', error);
            return undefined;
        }

        return this.mapDatabaseToOrder(data);
    }

    static async getByEmployerId(employerId: string): Promise<DemandOrder[]> {
        const { data, error } = await supabase
            .from('demand_orders')
            .select('*')
            .eq('employer_id', employerId)
            .order('created_at', { ascending: false });

        if (error) {
            console.error('Error fetching demand orders for employer:', error);
            return [];
        }

        return data.map((d: any) => this.mapDatabaseToOrder(d));
    }

    static async getOpenOrders(): Promise<DemandOrder[]> {
        const { data, error } = await supabase
            .from('demand_orders')
            .select('*')
            .in('status', [DemandOrderStatus.OPEN, DemandOrderStatus.PARTIALLY_FILLED])
            .order('created_at', { ascending: false });

        if (error) {
            console.error('Error fetching open orders:', error);
            return [];
        }

        return data.map((d: any) => this.mapDatabaseToOrder(d));
    }

    static async add(order: DemandOrder): Promise<DemandOrder | null> {
        const dbOrder = {
            employer_id: order.employerId,
            order_number: order.id, // Or generate new if ID not provided
            title: order.title,
            category: order.jobCategory,
            positions: order.positionsRequired,
            salary_range: order.salaryRange,
            location: order.location,
            status: order.status,
            requirements: order.requirements,
            created_at: order.createdAt || new Date().toISOString(),
            data: {
                positionsFilled: order.positionsFilled,
                contractDuration: order.contractDuration,
                benefits: order.benefits,
                deadline: order.deadline,
                notes: order.notes,
                country: order.country,
                activityLog: order.activityLog || [{
                    id: `act-${Date.now()}`,
                    type: 'Note',
                    content: 'Demand order manually created',
                    timestamp: new Date().toISOString(),
                    actor: 'System',
                }]
            }
        };

        // OPTIMISTIC OFFLINE MODE
        if (!OfflineSyncService.isAppOnline()) {
            OfflineSyncService.enqueue({ type: 'INSERT', table: 'demand_orders', payload: dbOrder });
            return this.mapDatabaseToOrder({ id: `do_tmp_${Date.now()}`, ...dbOrder });
        }

        const { data, error } = await supabase
            .from('demand_orders')
            .insert(dbOrder)
            .select()
            .single();

        if (error) {
            console.error('Error adding demand order:', error);
            // Fallback to queue if it's a network-level fetch failure
            if (error.message === 'Failed to fetch') {
                OfflineSyncService.enqueue({ type: 'INSERT', table: 'demand_orders', payload: dbOrder });
                return this.mapDatabaseToOrder({ id: `do_tmp_${Date.now()}`, ...dbOrder });
            }
            return null;
        }

        // SYSLOG: Track Audit
        const auditUserId = await AuditService.getCurrentUserId();
        AuditService.log('DEMAND_ORDER_CREATED', { orderId: dbOrder.order_number || data.id, title: dbOrder.title }, auditUserId);

        this._ordersCache = null; // Invalidate cache

        return this.mapDatabaseToOrder(data);
    }

    static async update(updated: DemandOrder): Promise<DemandOrder | null> {
        const dbUpdate = {
            title: updated.title,
            category: updated.jobCategory,
            positions: updated.positionsRequired,
            salary_range: updated.salaryRange,
            location: updated.location,
            status: updated.status,
            requirements: updated.requirements,
            updated_at: new Date().toISOString(),
            data: {
                positionsFilled: updated.positionsFilled,
                contractDuration: updated.contractDuration,
                benefits: updated.benefits,
                deadline: updated.deadline,
                notes: updated.notes,
                country: updated.country,
                activityLog: updated.activityLog || []
            }
        };

        // OPTIMISTIC OFFLINE MODE
        if (!OfflineSyncService.isAppOnline()) {
            OfflineSyncService.enqueue({ type: 'UPDATE', table: 'demand_orders', payload: { id: updated.id, ...dbUpdate } });
            return this.mapDatabaseToOrder({ id: updated.id, ...dbUpdate });
        }

        const { data, error } = await supabase
            .from('demand_orders')
            .update(dbUpdate)
            .eq('id', updated.id)
            .select()
            .single();

        if (error) {
            console.error('Error updating demand order:', error);
            if (error.message === 'Failed to fetch') {
                OfflineSyncService.enqueue({ type: 'UPDATE', table: 'demand_orders', payload: { id: updated.id, ...dbUpdate } });
                return this.mapDatabaseToOrder({ id: updated.id, ...dbUpdate });
            }
            return null;
        }

        // SYSLOG: Track Audit
        const auditUserId = await AuditService.getCurrentUserId();
        AuditService.log('DEMAND_ORDER_UPDATED', { orderId: updated.id, status: updated.status }, auditUserId);

        this._ordersCache = null; // Invalidate cache

        return this.mapDatabaseToOrder(data);
    }

    static async delete(id: string): Promise<boolean> {
        // OPTIMISTIC OFFLINE MODE
        if (!OfflineSyncService.isAppOnline()) {
            OfflineSyncService.enqueue({ type: 'DELETE', table: 'demand_orders', payload: { id } });
            return true;
        }

        const { error } = await supabase
            .from('demand_orders')
            .delete()
            .eq('id', id);

        if (error) {
            console.error('Error deleting demand order:', error);
            if (error.message === 'Failed to fetch') {
                OfflineSyncService.enqueue({ type: 'DELETE', table: 'demand_orders', payload: { id } });
                return true;
            }
            return false;
        }

        // SYSLOG: Track Audit
        const auditUserId = await AuditService.getCurrentUserId();
        AuditService.log('DEMAND_ORDER_DELETED', { orderId: id }, auditUserId);

        this._ordersCache = null; // Invalidate cache

        return true;
    }

    static async incrementFilled(orderId: string): Promise<void> {
        const order = await this.getById(orderId);
        if (order) {
            order.positionsFilled = Math.min(order.positionsFilled + 1, order.positionsRequired);
            if (order.positionsFilled >= order.positionsRequired) {
                order.status = DemandOrderStatus.FILLED;
            } else if (order.positionsFilled > 0) {
                order.status = DemandOrderStatus.PARTIALLY_FILLED;
            }
            await this.update(order);
        }
    }

    private static mapDatabaseToOrder(dbRecord: any): DemandOrder {
        return {
            id: dbRecord.id,
            employerId: dbRecord.employer_id,
            title: dbRecord.title || '',
            jobCategory: dbRecord.category || '',
            country: dbRecord.data?.country || dbRecord.location?.split(',').pop()?.trim() || 'Qatar', // Use data value if available, or try to infer from location
            location: dbRecord.location || '',
            positionsRequired: dbRecord.positions || 1,
            positionsFilled: dbRecord.data?.positionsFilled || 0,
            salaryRange: dbRecord.salary_range || '',
            contractDuration: dbRecord.data?.contractDuration || '',
            benefits: dbRecord.data?.benefits || [],
            requirements: dbRecord.requirements || [],
            status: (dbRecord.status as DemandOrderStatus) || DemandOrderStatus.OPEN,
            createdAt: dbRecord.created_at,
            deadline: dbRecord.data?.deadline,
            notes: dbRecord.data?.notes,
            activityLog: dbRecord.data?.activityLog || []
        };
    }

    static async addActivity(orderId: string, activity: Omit<EmployerActivity, 'id' | 'timestamp'>): Promise<boolean> {
        const order = await this.getById(orderId);
        if (!order) return false;

        const newActivity: EmployerActivity = {
            id: `act-${Date.now()}`,
            timestamp: new Date().toISOString(),
            ...activity
        };

        order.activityLog = [...(order.activityLog || []), newActivity];
        const updated = await this.update(order);
        return updated !== null;
    }
}

import { supabase } from './supabase';
import { CandidateDocument, DocumentStatus, DocumentCategory, DocumentType } from '../types';
import { AuditService } from './auditService';

export class DocumentService {
    private static BUCKET_NAME = 'documents';

    /**
     * Uploads a file to Supabase Storage and returns the file metadata.
     * Use this before updating the Candidate profile with the new document record.
     */
    static async uploadDocument(
        file: File,
        candidateId: string,
        docType: DocumentType
    ): Promise<{ path: string; url: string; error?: any }> {
        try {
            // Generate a unique file path: candidateId/docType_timestamp.ext
            const fileExt = file.name.split('.').pop();
            const fileName = `${docType}_${Date.now()}.${fileExt}`;
            const filePath = `${candidateId}/${fileName}`;

            const { data, error } = await supabase.storage
                .from(this.BUCKET_NAME)
                .upload(filePath, file, {
                    cacheControl: '3600',
                    upsert: false
                });

            if (error) {
                console.error('Error uploading file:', error);
                return { path: '', url: '', error };
            }

            // Get Public URL
            const { data: { publicUrl } } = supabase.storage
                .from(this.BUCKET_NAME)
                .getPublicUrl(filePath);

            const auditUserId = await AuditService.getCurrentUserId();
            AuditService.log('DOCUMENT_UPLOADED', {
                candidateId,
                documentType: docType,
                fileName,
                path: filePath
            }, auditUserId);

            return { path: filePath, url: publicUrl };

        } catch (err) {
            console.error('Unexpected error during upload:', err);
            return { path: '', url: '', error: err };
        }
    }

    /**
     * Deletes a document from storage.
     */
    static async deleteDocument(path: string): Promise<{ success: boolean; error?: any }> {
        try {
            const { error } = await supabase.storage
                .from(this.BUCKET_NAME)
                .remove([path]);

            if (error) {
                console.error('Error deleting file:', error);
                return { success: false, error };
            }

            const auditUserId = await AuditService.getCurrentUserId();
            AuditService.log('DOCUMENT_DELETED', {
                path
            }, auditUserId);

            return { success: true };
        } catch (err) {
            console.error('Unexpected error during delete:', err);
            return { success: false, error: err };
        }
    }
}

import {
    FinanceTransaction, TransactionType, TransactionCategory,
    Invoice, InvoiceStatus, Candidate, WorkflowStage, Employer
} from '../types';
import { supabase } from './supabase';
import { AuditService } from './auditService';

export class FinanceService {

    // --- TRANSACTIONS ---

    static async getTransactions(): Promise<FinanceTransaction[]> {
        const { data, error } = await supabase
            .from('finance_transactions')
            .select('*')
            .order('timestamp', { ascending: false });

        if (error) {
            console.error('Error fetching transactions:', error);
            return [];
        }

        return (data || []).map((row: any) => ({
            id: row.id,
            candidateId: row.candidate_id,
            employerId: row.employer_id,
            type: row.type as TransactionType,
            category: row.category as TransactionCategory,
            amount: parseFloat(row.amount),
            status: row.status as any,
            timestamp: row.timestamp,
            description: row.description,
            referenceId: row.reference_id
        }));
    }

    static async addTransaction(tx: Omit<FinanceTransaction, 'id' | 'timestamp' | 'status'>): Promise<FinanceTransaction | null> {
        const newTx = {
            id: `tx-${Date.now()}`, // Keep frontend ID generation for now to match TEXT type in DB
            candidate_id: tx.candidateId === 'system' ? null : tx.candidateId, // Handle 'system' placeholder
            employer_id: tx.employerId === 'system' ? null : tx.employerId,    // Handle 'system' placeholder
            type: tx.type,
            category: tx.category,
            amount: tx.amount,
            status: 'Completed',
            timestamp: new Date().toISOString(),
            description: tx.description
        };

        const { data, error } = await supabase
            .from('finance_transactions')
            .insert(newTx)
            .select()
            .single();

        if (error) {
            console.error('Error adding transaction:', error);
            return null;
        }

        const result = {
            id: data.id,
            candidateId: data.candidate_id || 'system',
            employerId: data.employer_id || 'system',
            type: data.type as TransactionType,
            category: data.category as TransactionCategory,
            amount: parseFloat(data.amount),
            status: data.status as any,
            timestamp: data.timestamp,
            description: data.description,
            referenceId: data.reference_id
        };

        const auditUserId = await AuditService.getCurrentUserId();
        AuditService.log('FINANCE_TRANSACTION_CREATED', {
            transactionId: result.id,
            type: result.type,
            amount: result.amount,
            candidateId: result.candidateId,
            employerId: result.employerId
        }, auditUserId);

        return result;
    }

    static async updateTransaction(id: string, updates: Partial<FinanceTransaction>): Promise<boolean> {
        const dbUpdates: any = {};
        if (updates.type) dbUpdates.type = updates.type;
        if (updates.category) dbUpdates.category = updates.category;
        if (updates.amount !== undefined) dbUpdates.amount = updates.amount;
        if (updates.description) dbUpdates.description = updates.description;
        if (updates.candidateId) dbUpdates.candidate_id = updates.candidateId === 'system' ? null : updates.candidateId;
        if (updates.employerId) dbUpdates.employer_id = updates.employerId === 'system' ? null : updates.employerId;

        const { error } = await supabase
            .from('finance_transactions')
            .update(dbUpdates)
            .eq('id', id);

        if (error) {
            console.error('Error updating transaction:', error);
            return false;
        }

        const auditUserId = await AuditService.getCurrentUserId();
        AuditService.log('FINANCE_TRANSACTION_UPDATED', { transactionId: id, updates: dbUpdates }, auditUserId);
        return true;
    }

    static async deleteTransaction(id: string): Promise<boolean> {
        const { error } = await supabase
            .from('finance_transactions')
            .delete()
            .eq('id', id);

        if (error) {
            console.error('Error deleting transaction:', error);
            return false;
        }

        const auditUserId = await AuditService.getCurrentUserId();
        AuditService.log('FINANCE_TRANSACTION_DELETED', { transactionId: id }, auditUserId);
        return true;
    }

    // --- INVOICES ---

    static async getInvoices(): Promise<Invoice[]> {
        const { data, error } = await supabase
            .from('invoices')
            .select('*')
            .order('issued_date', { ascending: false });

        if (error) {
            console.error('Error fetching invoices:', error);
            return [];
        }

        return (data || []).map((row: any) => ({
            id: row.id,
            employerId: row.employer_id,
            candidateId: row.candidate_id,
            amount: parseFloat(row.amount),
            issuedDate: row.issued_date,
            dueDate: row.due_date,
            status: row.status as InvoiceStatus,
            items: row.items,
            billingAddress: row.billing_address
        }));
    }

    static async generateInvoice(candidate: Candidate, employer: Employer): Promise<Invoice | null> {
        // Generate ID
        const year = new Date().getFullYear();
        const { count } = await supabase.from('invoices').select('id', { count: 'exact', head: true });
        const nextNum = (count || 0) + 101;
        const invId = `INV-${year}-${nextNum}`;

        const amount = employer.commissionPerHire || 450;

        const newInv = {
            id: invId,
            employer_id: employer.id,
            candidate_id: candidate.id,
            amount,
            issued_date: new Date().toISOString(),
            due_date: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString(), // 30 days
            status: InvoiceStatus.DRAFT,
            items: [
                { description: `Recruitment Commission - ${candidate.role}`, amount }
            ],
            billing_address: `${employer.companyName}, ${employer.country}`
        };

        const { data, error } = await supabase
            .from('invoices')
            .insert(newInv)
            .select()
            .single();

        if (error) {
            console.error('Error generating invoice:', error);
            return null;
        }

        const result = {
            id: data.id,
            employerId: data.employer_id,
            candidateId: data.candidate_id,
            amount: parseFloat(data.amount),
            issuedDate: data.issued_date,
            dueDate: data.due_date,
            status: data.status as InvoiceStatus,
            items: data.items,
            billingAddress: data.billing_address
        };

        const auditUserId = await AuditService.getCurrentUserId();
        AuditService.log('INVOICE_GENERATED', {
            invoiceId: result.id,
            amount: result.amount,
            candidateId: result.candidateId,
            employerId: result.employerId
        }, auditUserId);

        return result;
    }

    static async updateInvoice(id: string, updates: Partial<Invoice>): Promise<boolean> {
        const dbUpdates: any = {};
        if (updates.status) dbUpdates.status = updates.status;
        if (updates.amount !== undefined) dbUpdates.amount = updates.amount;
        if (updates.dueDate) dbUpdates.due_date = updates.dueDate;
        if (updates.billingAddress) dbUpdates.billing_address = updates.billingAddress;

        const { error } = await supabase
            .from('invoices')
            .update(dbUpdates)
            .eq('id', id);

        if (error) {
            console.error('Error updating invoice:', error);
            return false;
        }

        const auditUserId = await AuditService.getCurrentUserId();
        AuditService.log('INVOICE_UPDATED', { invoiceId: id, updates: dbUpdates }, auditUserId);
        return true;
    }

    static async deleteInvoice(id: string): Promise<boolean> {
        const { error } = await supabase
            .from('invoices')
            .delete()
            .eq('id', id);

        if (error) {
            console.error('Error deleting invoice:', error);
            return false;
        }

        const auditUserId = await AuditService.getCurrentUserId();
        AuditService.log('INVOICE_DELETED', { invoiceId: id }, auditUserId);
        return true;
    }

    // --- CALCULATIONS (Stateless) ---

    /**
     * REVENUE PROJECTION LOGIC
     * Calculates potential revenue based on active candidates in the pipeline
     */
    static getProjectedRevenue(candidates: Candidate[], employers: Employer[] = []): number {
        const HIGH_PROBABILITY_STAGES = [
            WorkflowStage.VISA_RECEIVED,
            WorkflowStage.SLBFE_REGISTRATION,
            WorkflowStage.TICKET_ISSUED
        ];

        return candidates.reduce((total, candidate) => {
            if (!candidate) return total;

            // Only count candidates who are in the late, high-probability stages
            if (!HIGH_PROBABILITY_STAGES.includes(candidate.stage)) return total;

            const employer = employers.find(e => e.id === candidate.jobId || (candidate as Candidate & { employerId?: string }).employerId); // fallback
            const commission = employer?.commissionPerHire || 450; // Use default if no specific employer found

            return total + commission;
        }, 0);
    }

    /**
     * ACTUAL REVENUE
     * Sum of all REVENUE transactions in the provided list
     */
    static calculateTotalActualRevenue(transactions: FinanceTransaction[]): number {
        return transactions
            .filter(tx => tx && tx.type === TransactionType.REVENUE && tx.status === 'Completed' && typeof tx.amount === 'number')
            .reduce((sum, tx) => sum + (tx.amount || 0), 0);
    }

    /**
     * TOTAL EXPENSES
     * Sum of all EXPENSE transactions in the provided list
     */
    static calculateTotalExpenses(transactions: FinanceTransaction[]): number {
        return transactions
            .filter(tx => tx && tx.type === TransactionType.EXPENSE && tx.status === 'Completed' && typeof tx.amount === 'number')
            .reduce((sum, tx) => sum + (tx.amount || 0), 0);
    }

    /**
     * NET PROFIT
     */
    static calculateNetProfit(revenue: number, expenses: number): number {
        return revenue - expenses;
    }
}

