import { describe, it, expect } from 'vitest';
import { generateMRZ } from '../mrzGenerator';

describe('mrzGenerator', () => {
    describe('generateMRZ', () => {
        it('should generate a valid 2-line MRZ for a typical Sri Lankan passport', () => {
            const candidate = {
                personalInfo: {
                    surname: 'HITIHAMILLAGE',
                    otherNames: 'DILHANI MENAKA JAYASINGHE',
                    nic: '197162410030',
                    gender: 'Female',
                    dob: '1971-05-03'
                }
            };
            const passport = {
                passportNumber: 'N9121618',
                expiryDate: '2031-11-03'
            };

            const [line1, line2] = generateMRZ(candidate as any, passport as any);

            expect(line1).toHaveLength(44);
            expect(line2).toHaveLength(44);

            // Line 1: P<LKA<HITIHAMILLAGE<<DILHANI<MENAKA<JAYASINGHE<
            expect(line1.startsWith('PB')).toBe(true); // Sri Lankan passports use PB type now in our impl
            expect(line1).toContain('HITIHAMILLAGE');
            expect(line1).toContain('DILHANI');

            // Line 2: Passport No (9) + Check (1) + Nationality (3) + DOB (6) + Check (1) + Sex (1) + Expiry (6) + Check (1) + Optional (14) + Check (1) + Composite Check (1)
            // N9121618 (8 chars) + < + Check
            expect(line2.startsWith('N9121618')).toBe(true);
            // Gender Female -> F
            expect(line2[20]).toBe('F');
            // DOB 1971-05-03 -> 710503
            expect(line2.substring(13, 19)).toBe('710503');
            // Expiry 2031-11-03 -> 311103
            expect(line2.substring(21, 27)).toBe('311103');
        });

        it('should handle missing fields gracefully with placeholders', () => {
            const candidate = {};
            const passport = {};

            const [line1, line2] = generateMRZ(candidate as any, passport as any);

            expect(line1).toHaveLength(44);
            expect(line2).toHaveLength(44);
        });

        it('should format names correctly according to ICAO standards', () => {
            const candidate = {
                personalInfo: {
                    surname: 'STEVENS',
                    otherNames: 'JOHN ALBERT'
                }
            };
            const passport = { passportNumber: 'N1234567', expiryDate: '2030-01-01' };
            const [line1, line2] = generateMRZ(candidate as any, passport as any);

            // PBLKA STEVENS<<JOHN<ALBERT<<<<...
            expect(line1.startsWith('PBLKASTEVENS<<JOHN<ALBERT')).toBe(true);
        });
    });
});

/**
 * Format file size to human-readable format
 */
export const formatFileSize = (bytes: number): string => {
    if (bytes === 0) return '0 Bytes';

    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));

    return Math.round((bytes / Math.pow(k, i)) * 100) / 100 + ' ' + sizes[i];
};

/**
 * Format timestamp to relative time (e.g., "2 hours ago")
 */
export const formatRelativeTime = (timestamp: string | Date): string => {
    const date = typeof timestamp === 'string' ? new Date(timestamp) : timestamp;
    const now = new Date();
    const diffInSeconds = Math.floor((now.getTime() - date.getTime()) / 1000);

    if (diffInSeconds < 60) return 'just now';
    if (diffInSeconds < 3600) return `${Math.floor(diffInSeconds / 60)}m ago`;
    if (diffInSeconds < 86400) return `${Math.floor(diffInSeconds / 3600)}h ago`;
    if (diffInSeconds < 604800) return `${Math.floor(diffInSeconds / 86400)}d ago`;

    return date.toLocaleDateString();
};

/**
 * Format timestamp to time (e.g., "2:30 PM")
 */
export const formatTime = (timestamp: string | Date): string => {
    const date = typeof timestamp === 'string' ? new Date(timestamp) : timestamp;
    return date.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' });
};

/**
 * Format timestamp to full date and time
 */
export const formatDateTime = (timestamp: string | Date): string => {
    const date = typeof timestamp === 'string' ? new Date(timestamp) : timestamp;
    return date.toLocaleString('en-US', {
        month: 'short',
        day: 'numeric',
        year: 'numeric',
        hour: 'numeric',
        minute: '2-digit'
    });
};

/**
 * Group messages by date
 */
export const groupMessagesByDate = (messages: any[]): Map<string, any[]> => {
    const groups = new Map<string, any[]>();

    messages.forEach(message => {
        const date = new Date(message.timestamp);
        const today = new Date();
        const yesterday = new Date(today);
        yesterday.setDate(yesterday.getDate() - 1);

        let dateKey: string;
        if (date.toDateString() === today.toDateString()) {
            dateKey = 'Today';
        } else if (date.toDateString() === yesterday.toDateString()) {
            dateKey = 'Yesterday';
        } else {
            dateKey = date.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
        }

        if (!groups.has(dateKey)) {
            groups.set(dateKey, []);
        }
        groups.get(dateKey)!.push(message);
    });

    return groups;
};

/**
 * Extract mentions from text
 */
export const extractMentions = (text: string): string[] => {
    const mentionRegex = /@(\w+)/g;
    const mentions: string[] = [];
    let match;

    while ((match = mentionRegex.exec(text)) !== null) {
        mentions.push(match[1]);
    }

    return mentions;
};

/**
 * Highlight mentions in text
 */
export const highlightMentions = (text: string): string => {
    return text.replace(/@(\w+)/g, '<span class="mention">@$1</span>');
};

/**
 * Get file icon based on file type
 */
export const getFileIcon = (mimeType: string): string => {
    if (mimeType.startsWith('image/')) return '🖼️';
    if (mimeType.startsWith('video/')) return '🎥';
    if (mimeType.startsWith('audio/')) return '🎵';
    if (mimeType === 'application/pdf') return '📄';
    if (mimeType.includes('word')) return '📝';
    if (mimeType.includes('excel') || mimeType.includes('spreadsheet')) return '📊';
    if (mimeType.includes('powerpoint') || mimeType.includes('presentation')) return '📽️';
    if (mimeType.includes('zip') || mimeType.includes('rar')) return '📦';
    return '📎';
};

/**
 * Check if file is an image
 */
export const isImage = (mimeType: string): boolean => {
    return mimeType.startsWith('image/');
};

/**
 * Check if file is previewable
 */
export const isPreviewable = (mimeType: string): boolean => {
    const previewableTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp', 'application/pdf'];
    return previewableTypes.includes(mimeType);
};

/**
 * Truncate text to specified length
 */
export const truncateText = (text: string, maxLength: number): string => {
    if (text.length <= maxLength) return text;
    return text.substring(0, maxLength) + '...';
};

/**
 * Get initials from name
 */
export const getInitials = (name: string): string => {
    const parts = name.split(' ');
    if (parts.length >= 2) {
        return (parts[0][0] + parts[1][0]).toUpperCase();
    }
    return name.substring(0, 2).toUpperCase();
};

/**
 * Generate a color from string (for avatars)
 */
export const stringToColor = (str: string): string => {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        hash = str.charCodeAt(i) + ((hash << 5) - hash);
    }

    const hue = hash % 360;
    return `hsl(${hue}, 65%, 50%)`;
};

/**
 * Sanitize HTML to prevent XSS
 */
export const sanitizeHtml = (html: string): string => {
    const div = document.createElement('div');
    div.textContent = html;
    return div.innerHTML;
};

/**
 * Format typing indicator text
 */
export const formatTypingIndicator = (users: { userName: string }[]): string => {
    if (users.length === 0) return '';
    if (users.length === 1) return `${users[0].userName} is typing...`;
    if (users.length === 2) return `${users[0].userName} and ${users[1].userName} are typing...`;
    return `${users[0].userName} and ${users.length - 1} others are typing...`;
};

/**
 * Check if message is from today
 */
export const isToday = (timestamp: string | Date): boolean => {
    const date = typeof timestamp === 'string' ? new Date(timestamp) : timestamp;
    const today = new Date();
    return date.toDateString() === today.toDateString();
};

/**
 * Validate file upload
 */
export const validateFileUpload = (file: File, maxSize: number = 10 * 1024 * 1024): { valid: boolean; error?: string } => {
    if (file.size > maxSize) {
        return { valid: false, error: `File size exceeds ${formatFileSize(maxSize)}` };
    }

    const allowedTypes = [
        'image/jpeg',
        'image/png',
        'image/gif',
        'image/webp',
        'application/pdf',
        'application/msword',
        'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'application/vnd.ms-excel',
        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        'text/plain',
        'text/csv',
    ];

    if (!allowedTypes.includes(file.type)) {
        return { valid: false, error: 'File type not allowed' };
    }

    return { valid: true };
};

export function charValue(c: string): number {
    if (c >= '0' && c <= '9') return parseInt(c, 10);
    if (c >= 'A' && c <= 'Z') return c.charCodeAt(0) - 55; // 'A' is 65. 65 - 55 = 10.
    if (c === '<') return 0;
    return 0; // fallback
}

export function calculateCheckDigit(str: string): number {
    const weights = [7, 3, 1];
    let sum = 0;
    for (let i = 0; i < str.length; i++) {
        sum += charValue(str[i]) * weights[i % 3];
    }
    return sum % 10;
}

export function pad(str: string, len: number, padChar: string = '<'): string {
    return str.padEnd(len, padChar).substring(0, len);
}

export function convertDate(dateStr: string): string {
    // expects 'YYYY-MM-DD' returns 'YYMMDD'
    if (!dateStr) return '<<<<<<';
    const parts = dateStr.split('-');
    if (parts.length === 3) {
        return parts[0].substring(2, 4) + parts[1] + parts[2];
    }
    return '<<<<<<';
}

export function generateMRZ(candidate: any, passport: any): [string, string] {
    if (!candidate || !passport) {
        return ['<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<', '<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<'];
    }

    // Determine Country Codes
    // Usually ISO 3166-1 alpha-3, e.g., 'LKA' for Sri Lanka
    const countryMap: Record<string, string> = {
        'Sri Lanka': 'LKA',
        // add others if needed.. fallback is LKA for now
    };
    const issuingCountry = countryMap[passport.country] || 'LKA';
    // Assume nationality is the same as issuing country for now
    const nationality = issuingCountry;

    // Line 1
    const pType = issuingCountry === 'LKA' ? 'PB' : 'P<'; // Using PB for Sri Lanka
    const line1Prefix = pType + pad(issuingCountry, 3);

    // Names
    const pi = candidate.personalInfo || {};
    let surname = pi.surname || pi.firstName || candidate.firstName || '';
    let otherNames = pi.otherNames || pi.middleName || candidate.middleName || '';

    // Split words by space and rejoin with <
    surname = surname.toUpperCase().trim().replace(/[^A-Z\s]/g, '').replace(/\s+/g, '<');
    otherNames = otherNames.toUpperCase().trim().replace(/[^A-Z\s]/g, '').replace(/\s+/g, '<');

    let nameStr = `${surname}<<${otherNames}`;
    if (!surname) {
        nameStr = `${otherNames}`;
    } else if (!otherNames) {
        nameStr = `${surname}`;
    }

    const line1 = line1Prefix + pad(nameStr, 39);

    // Line 2
    const pptNoRaw = (passport.passportNumber || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
    const pptNo = pad(pptNoRaw, 9);
    const pptCheck = pptNoRaw ? calculateCheckDigit(pptNo).toString() : '<';

    const dob = convertDate(pi.dob || candidate.dob);
    const dobCheck = (pi.dob || candidate.dob) ? calculateCheckDigit(dob).toString() : '<';

    let sex = pi.gender || candidate.gender || '<';
    sex = sex.toUpperCase().charAt(0);
    if (sex !== 'M' && sex !== 'F') sex = '<';

    const exp = convertDate(passport.expiryDate);
    const expCheck = passport.expiryDate ? calculateCheckDigit(exp).toString() : '<';

    const nicRaw = (pi.nic || candidate.nic || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
    const nic = pad(nicRaw, 14);
    const nicCheck = nicRaw ? calculateCheckDigit(nic).toString() : '<';

    // Composite Check
    // Over pptNo + pptCheck + dob + dobCheck + exp + expCheck + nic + nicCheck
    const compositeStr = pptNo + (pptCheck === '<' ? '0' : pptCheck) + dob + (dobCheck === '<' ? '0' : dobCheck) + exp + (expCheck === '<' ? '0' : expCheck) + nic + (nicCheck === '<' ? '0' : nicCheck);
    const compositeCheck = calculateCheckDigit(compositeStr).toString();

    const line2 = pptNo + pptCheck + pad(nationality, 3) + dob + dobCheck + sex + exp + expCheck + nic + nicCheck + compositeCheck;

    return [line1, line2];
}
